dot3(a, b) = a[1] * b[1] + a[2] * b[2] + a[3] * b[3]
norm3(a) = sqrt(dot3(a, a))

function spherical_shell_transport_cell_advection_timescale(grid, velocities)
    u, v, w = velocities
    τ = KernelFunctionOperation{Center, Center, Center}(transport_cell_advection_timescaleᶜᶜᶜ, grid, u, v, w)
    return minimum(τ)
end

