function test_octahealpix_time_series_horizontal_advective_forcing_refreshes_state_for_tracer_tendencies_and_timescale(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))

    qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(one(FT))
    u_bcs = FieldBoundaryConditions(grid, (Face(), Center(), Center());
                                    south = qcov,
                                    north = qcov)
    v_bcs = FieldBoundaryConditions(grid, (Center(), Face(), Center());
                                    west = qcov,
                                    east = qcov)

    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    forcing_u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times;
                                                                       boundary_conditions = u_bcs)
    forcing_v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times;
                                                                       boundary_conditions = v_bcs)

    set!(forcing_u_fts, (λ, φ, z, t) -> convert(FT, 2) * sind(λ) + convert(FT, 3) * t)
    set!(forcing_v_fts, (λ, φ, z, t) -> cosd(φ) - convert(FT, 2) * t)

    function build_model()
        source_clock = Oceananigans.Clock(time = zero(FT))
        forcing_u_tsi = Oceananigans.OutputReaders.TimeSeriesInterpolation(forcing_u_fts, grid; clock = source_clock)
        forcing_v_tsi = Oceananigans.OutputReaders.TimeSeriesInterpolation(forcing_v_fts, grid; clock = source_clock)

        model = HydrostaticFreeSurfaceModel(grid;
                                            tracers = :c,
                                            buoyancy = nothing,
                                            free_surface = nothing,
                                            momentum_advection = nothing,
                                            tracer_advection = Centered(FT),
                                            forcing = (c = AdvectiveForcing(u = forcing_u_tsi, v = forcing_v_tsi),))

        set!(model,
             u = (λ, φ, z) -> convert(FT, 1//10) * sind(φ),
             v = (λ, φ, z) -> convert(FT, 1//10) * cosd(λ),
             c = (λ, φ, z) -> convert(FT, 3//10) + convert(FT, 1//5) * sind(λ / 2) * cosd(φ))

        compute_transport_velocities!(model, model.free_surface)
        return model
    end

    timescale_model = build_model()
    tracer_model = build_model()

    reference_u = deepcopy(tracer_model.velocities.u)
    reference_v = deepcopy(tracer_model.velocities.v)
    stale_u = deepcopy(tracer_model.velocities.u)
    stale_v = deepcopy(tracer_model.velocities.v)

    set!(reference_u, (λ, φ, z) -> convert(FT, 2) * sind(λ) + convert(FT, 3) * half)
    set!(reference_v, (λ, φ, z) -> cosd(φ) - convert(FT, 2) * half)
    set!(stale_u, (λ, φ, z) -> convert(FT, 2) * sind(λ))
    set!(stale_v, (λ, φ, z) -> cosd(φ))

    fill_halo_regions!((reference_u, reference_v))
    fill_halo_regions!((stale_u, stale_v))

    reference_forcing = AdvectiveForcing(u = reference_u, v = reference_v)
    stale_forcing = AdvectiveForcing(u = stale_u, v = stale_v)

    timescale_model.clock.time = half
    computed_timescale = cell_advection_timescale(timescale_model)

    reference_auxiliary_velocities =
        Oceananigans.Models.HydrostaticFreeSurfaceModels.tracer_auxiliary_velocities(nothing,
                                                                                     nothing,
                                                                                     reference_forcing)
    stale_auxiliary_velocities =
        Oceananigans.Models.HydrostaticFreeSurfaceModels.tracer_auxiliary_velocities(nothing,
                                                                                     nothing,
                                                                                     stale_forcing)

    reference_total_transport_velocities =
        Oceananigans.Models.HydrostaticFreeSurfaceModels.total_tracer_advection_velocities(
            grid, timescale_model.transport_velocities, reference_auxiliary_velocities)
    stale_total_transport_velocities =
        Oceananigans.Models.HydrostaticFreeSurfaceModels.total_tracer_advection_velocities(
            grid, timescale_model.transport_velocities, stale_auxiliary_velocities)

    base_timescale = spherical_shell_transport_cell_advection_timescale(grid, timescale_model.transport_velocities)
    expected_timescale = min(base_timescale,
                             spherical_shell_transport_cell_advection_timescale(grid, reference_total_transport_velocities))
    stale_timescale = min(base_timescale,
                          spherical_shell_transport_cell_advection_timescale(grid, stale_total_transport_velocities))

    timescale_tolerance = 1000eps(FT) * max(abs(expected_timescale), one(FT))
    @test abs(computed_timescale - expected_timescale) ≤ timescale_tolerance
    @test abs(computed_timescale - stale_timescale) > 100eps(FT) * max(abs(expected_timescale), one(FT))

    tracer_model.clock.time = half
    compute_tracer_tendencies!(tracer_model)

    reference_total_transport_velocities =
        Oceananigans.Models.HydrostaticFreeSurfaceModels.total_tracer_advection_velocities(
            grid, tracer_model.transport_velocities, reference_auxiliary_velocities)
    stale_total_transport_velocities =
        Oceananigans.Models.HydrostaticFreeSurfaceModels.total_tracer_advection_velocities(
            grid, tracer_model.transport_velocities, stale_auxiliary_velocities)

    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    stale_difference = zero(FT)

    for (i, j) in sampled_points
        expected_Gc = -div_Uc(i, j, 1, grid, tracer_model.advection.c, reference_total_transport_velocities, tracer_model.tracers.c)
        stale_Gc = -div_Uc(i, j, 1, grid, tracer_model.advection.c, stale_total_transport_velocities, tracer_model.tracers.c)
        computed_Gc = tracer_model.timestepper.Gⁿ.c[i, j, 1]

        tendency_scale = max(abs(expected_Gc), one(FT))
        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale
        stale_difference = max(stale_difference, abs(expected_Gc - stale_Gc))
    end

    @test stale_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_time_series_horizontal_momentum_advective_forcing_refreshes_state_for_momentum_tendencies(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))

    qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(one(FT))
    u_bcs = FieldBoundaryConditions(grid, (Face(), Center(), Center());
                                    south = qcov,
                                    north = qcov)
    v_bcs = FieldBoundaryConditions(grid, (Center(), Face(), Center());
                                    west = qcov,
                                    east = qcov)

    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    forcing_u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times;
                                                                       boundary_conditions = u_bcs)
    forcing_v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times;
                                                                       boundary_conditions = v_bcs)

    set!(forcing_u_fts, (λ, φ, z, t) -> convert(FT, 2) * cosd(λ) + convert(FT, 4) * t)
    set!(forcing_v_fts, (λ, φ, z, t) -> sind(φ) - convert(FT, 3) * t)

    source_clock = Oceananigans.Clock(time = zero(FT))
    forcing_u_tsi = Oceananigans.OutputReaders.TimeSeriesInterpolation(forcing_u_fts, grid; clock = source_clock)
    forcing_v_tsi = Oceananigans.OutputReaders.TimeSeriesInterpolation(forcing_v_fts, grid; clock = source_clock)

    forcing = (u = AdvectiveForcing(u = forcing_u_tsi, v = forcing_v_tsi),
               v = AdvectiveForcing(u = forcing_u_tsi, v = forcing_v_tsi))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = Centered(FT),
                                        tracer_advection = nothing,
                                        forcing)

    set!(model,
         u = (λ, φ, z) -> convert(FT, 1//5) * sind(φ),
         v = (λ, φ, z) -> convert(FT, 1//6) * cosd(λ))

    reference_u = deepcopy(model.velocities.u)
    reference_v = deepcopy(model.velocities.v)
    stale_u = deepcopy(model.velocities.u)
    stale_v = deepcopy(model.velocities.v)

    set!(reference_u, (λ, φ, z) -> convert(FT, 2) * cosd(λ) + convert(FT, 4) * half)
    set!(reference_v, (λ, φ, z) -> sind(φ) - convert(FT, 3) * half)
    set!(stale_u, (λ, φ, z) -> convert(FT, 2) * cosd(λ))
    set!(stale_v, (λ, φ, z) -> sind(φ))

    fill_halo_regions!((reference_u, reference_v))
    fill_halo_regions!((stale_u, stale_v))

    reference_forcing = AdvectiveForcing(u = reference_u, v = reference_v)
    stale_forcing = AdvectiveForcing(u = stale_u, v = stale_v)

    reference_velocity_state = Oceananigans.Forcings.with_advective_forcing(reference_forcing, model.velocities)
    stale_velocity_state = Oceananigans.Forcings.with_advective_forcing(stale_forcing, model.velocities)

    model.clock.time = half
    compute_momentum_tendencies!(model, ())

    sampled_points = ((N + 2, N + 2),
                      (2, N + 1),
                      (N + 1, 2),
                      (2N, N + 1),
                      (N + 1, 2N))

    stale_difference = zero(FT)

    for (i, j) in sampled_points
        expected_Gu = -U_dot_∇u(i, j, 1, grid, model.advection.momentum, reference_velocity_state) -
                       U_dot_∇u_hydrostatic_metric(i, j, 1, grid, model.advection.momentum, reference_velocity_state, model.velocities)
        expected_Gv = -U_dot_∇v(i, j, 1, grid, model.advection.momentum, reference_velocity_state) -
                       U_dot_∇v_hydrostatic_metric(i, j, 1, grid, model.advection.momentum, reference_velocity_state, model.velocities)
        stale_Gu = -U_dot_∇u(i, j, 1, grid, model.advection.momentum, stale_velocity_state) -
                    U_dot_∇u_hydrostatic_metric(i, j, 1, grid, model.advection.momentum, stale_velocity_state, model.velocities)
        stale_Gv = -U_dot_∇v(i, j, 1, grid, model.advection.momentum, stale_velocity_state) -
                    U_dot_∇v_hydrostatic_metric(i, j, 1, grid, model.advection.momentum, stale_velocity_state, model.velocities)
        computed_Gu = model.timestepper.Gⁿ.u[i, j, 1]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, 1]

        u_scale = max(abs(expected_Gu), one(FT))
        v_scale = max(abs(expected_Gv), one(FT))

        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * u_scale
        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * v_scale

        stale_difference = max(stale_difference,
                               abs(expected_Gu - stale_Gu),
                               abs(expected_Gv - stale_Gv))
    end

    @test stale_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_variance_dissipation_cache_fluxes_refreshes_prescribed_transport_state(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))

    qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(one(FT))
    u_bcs = FieldBoundaryConditions(grid, (Face(), Center(), Center());
                                    south = qcov,
                                    north = qcov)
    v_bcs = FieldBoundaryConditions(grid, (Center(), Face(), Center());
                                    west = qcov,
                                    east = qcov)

    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times;
                                                               boundary_conditions = u_bcs)
    v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times;
                                                               boundary_conditions = v_bcs)

    set!(u_fts, (λ, φ, z, t) -> sind(λ) + convert(FT, 3) * t)
    set!(v_fts, (λ, φ, z, t) -> cosd(φ) - convert(FT, 2) * t)

    function build_model()
        source_clock = Oceananigans.Clock(time = zero(FT))
        u_tsi = Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, grid; clock = source_clock)
        v_tsi = Oceananigans.OutputReaders.TimeSeriesInterpolation(v_fts, grid; clock = source_clock)

        model = HydrostaticFreeSurfaceModel(grid;
                                            velocities = PrescribedVelocityFields(u = u_tsi, v = v_tsi),
                                            tracers = :c,
                                            buoyancy = nothing,
                                            free_surface = nothing,
                                            momentum_advection = nothing,
                                            tracer_advection = Centered(FT),
                                            timestepper = :QuasiAdamsBashforth2)

        set!(model, c = (λ, φ, z) -> convert(FT, 1//4) + convert(FT, 1//5) * sind(λ / 2) * cosd(φ))
        return model
    end

    live_model = build_model()
    reference_model = build_model()
    stale_model = build_model()

    ϵ = Oceananigans.Models.VarianceDissipationComputations.VarianceDissipation(:c, grid)
    ϵ_reference = Oceananigans.Models.VarianceDissipationComputations.VarianceDissipation(:c, grid)
    ϵ_stale = Oceananigans.Models.VarianceDissipationComputations.VarianceDissipation(:c, grid)

    live_model.clock.time = half
    reference_model.clock.time = half

    Oceananigans.Models.VarianceDissipationComputations.cache_fluxes!(ϵ, live_model, :c)
    Oceananigans.Models.VarianceDissipationComputations.cache_fluxes!(ϵ_reference, reference_model, :c)
    Oceananigans.Models.VarianceDissipationComputations.cache_fluxes!(ϵ_stale, stale_model, :c)

    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    stale_difference = zero(FT)

    for (i, j) in sampled_points
        computed_transport_u = live_model.transport_velocities.u[i, j, 1]
        computed_transport_v = live_model.transport_velocities.v[i, j, 1]
        reference_transport_u = reference_model.transport_velocities.u[i, j, 1]
        reference_transport_v = reference_model.transport_velocities.v[i, j, 1]
        stale_transport_u = stale_model.transport_velocities.u[i, j, 1]
        stale_transport_v = stale_model.transport_velocities.v[i, j, 1]

        computed_Uu = ϵ.previous_state.Uⁿ.u[i, j, 1]
        computed_Uv = ϵ.previous_state.Uⁿ.v[i, j, 1]
        reference_Uu = ϵ_reference.previous_state.Uⁿ.u[i, j, 1]
        reference_Uv = ϵ_reference.previous_state.Uⁿ.v[i, j, 1]
        stale_Uu = ϵ_stale.previous_state.Uⁿ.u[i, j, 1]
        stale_Uv = ϵ_stale.previous_state.Uⁿ.v[i, j, 1]

        computed_Fx = ϵ.advective_fluxes.Fⁿ.x[i, j, 1]
        computed_Fy = ϵ.advective_fluxes.Fⁿ.y[i, j, 1]
        reference_Fx = ϵ_reference.advective_fluxes.Fⁿ.x[i, j, 1]
        reference_Fy = ϵ_reference.advective_fluxes.Fⁿ.y[i, j, 1]
        stale_Fx = ϵ_stale.advective_fluxes.Fⁿ.x[i, j, 1]
        stale_Fy = ϵ_stale.advective_fluxes.Fⁿ.y[i, j, 1]

        transport_scale = max(abs(reference_transport_u), abs(reference_transport_v), one(FT))
        flux_scale = max(abs(reference_Fx), abs(reference_Fy), one(FT))

        @test abs(computed_transport_u - reference_transport_u) ≤ 1000eps(FT) * transport_scale
        @test abs(computed_transport_v - reference_transport_v) ≤ 1000eps(FT) * transport_scale
        @test abs(computed_Uu - reference_Uu) ≤ 1000eps(FT) * transport_scale
        @test abs(computed_Uv - reference_Uv) ≤ 1000eps(FT) * transport_scale
        @test abs(computed_Fx - reference_Fx) ≤ 1000eps(FT) * flux_scale
        @test abs(computed_Fy - reference_Fy) ≤ 1000eps(FT) * flux_scale

        stale_difference = max(stale_difference,
                               abs(reference_transport_u - stale_transport_u),
                               abs(reference_transport_v - stale_transport_v),
                               abs(reference_Uu - stale_Uu),
                               abs(reference_Uv - stale_Uv),
                               abs(reference_Fx - stale_Fx),
                               abs(reference_Fy - stale_Fy))
    end

    @test stale_difference > 100eps(FT)

    return nothing
end

@testset "OctaHEALPix hydrostatic time-dependent advective forcing refresh" begin
    FT = float(Int)
    N = 8

    test_octahealpix_time_series_horizontal_advective_forcing_refreshes_state_for_tracer_tendencies_and_timescale(FT, N)
    test_octahealpix_time_series_horizontal_momentum_advective_forcing_refreshes_state_for_momentum_tendencies(FT, N)
    test_octahealpix_variance_dissipation_cache_fluxes_refreshes_prescribed_transport_state(FT, N)
end

struct OctaHEALPixConvertedTransportV{G, U, V}
    grid :: G
    u    :: U
    v    :: V
end

@inline Base.getindex(U::OctaHEALPixConvertedTransportU, i, j, k) =
    covariant_to_volume_flux_uᶠᶜᶜ(i, j, k, U.grid, U.u, U.v)

@inline Base.getindex(V::OctaHEALPixConvertedTransportV, i, j, k) =
    covariant_to_volume_flux_vᶜᶠᶜ(i, j, k, V.grid, V.u, V.v)

struct OctaHEALPixHorizontalDriftBiogeochemistry{D} <: AbstractBiogeochemistry
    drift_velocity :: D
end

@inline required_biogeochemical_tracers(::OctaHEALPixHorizontalDriftBiogeochemistry) = (:c,)
@inline biogeochemical_drift_velocity(bgc::OctaHEALPixHorizontalDriftBiogeochemistry, ::Val{:c}) = bgc.drift_velocity

function test_octahealpix_reference_formulas(N)
    mapping = OctaHEALPixMapping(N)

    @test octahealpix_number_of_cells(mapping) == 4N^2
    @test octahealpix_matrix_size(mapping) == (2N, 2N)
    @test octahealpix_number_of_latitude_rings(mapping) == 2N - 1
    @test octahealpix_solid_angle(mapping) ≈ 4π / 4N^2

    for j in 1:(2N - 1)
        @test octahealpix_nlon_per_ring(mapping, j) == min(4j, 8N - 4j)

        if j <= N
            z = 1 - (j / N)^2
            @test sind(octahealpix_latitude(mapping, j)) ≈ z atol=1e-14
        else
            @test octahealpix_latitude(mapping, j) ≈ - octahealpix_latitude(mapping, 2N - j)
        end

        nlon = octahealpix_nlon_per_ring(mapping, j)
        @test octahealpix_longitude(mapping, j, 1) ≈ 180 / nlon
        @test octahealpix_longitude(mapping, j, nlon) ≈ 360 - 180 / nlon
    end

    return nothing
end

function test_octahealpix_indexing(N)
    mapping = OctaHEALPixMapping(N)
    connectivity = OctaHEALPixConnectivity(mapping)
    number_of_cells = octahealpix_number_of_cells(mapping)
    matrix_linear_indices = Vector{Int}(undef, number_of_cells)

    @test size(connectivity.matrix_to_ring) == (2N, 2N)

    for ij in 1:number_of_cells
        @test octahealpix_rcq2ring(octahealpix_ring2rcq(ij, mapping)..., mapping) == ij

        i, j = octahealpix_ring2matrix(ij, mapping)
        @test 1 <= i <= 2N
        @test 1 <= j <= 2N
        matrix_linear_indices[ij] = (j - 1) * 2N + i

        @test connectivity.matrix_to_ring[i, j] == ij
        @test connectivity.ring_to_i[ij] == i
        @test connectivity.ring_to_j[ij] == j
        @test (connectivity.ring_to_r[ij], connectivity.ring_to_c[ij], connectivity.ring_to_q[ij]) == octahealpix_ring2rcq(ij, mapping)

        latitude_ring = connectivity.ring_to_latitude_ring[ij]
        index_in_ring = connectivity.ring_to_index_in_ring[ij]

        @test 1 <= latitude_ring <= 2N - 1
        @test 1 <= index_in_ring <= octahealpix_nlon_per_ring(mapping, latitude_ring)

        i⁻, j⁻ = Oceananigans.Grids.octahealpix_wrap_matrix_neighbor(i, j, -1, 0, mapping)
        i⁺, j⁺ = Oceananigans.Grids.octahealpix_wrap_matrix_neighbor(i, j, +1, 0, mapping)
        i_minus_j, j_minus = Oceananigans.Grids.octahealpix_wrap_matrix_neighbor(i, j, 0, -1, mapping)
        i_plus_j, j_plus = Oceananigans.Grids.octahealpix_wrap_matrix_neighbor(i, j, 0, +1, mapping)

        minus_i_neighbor = connectivity.ring_to_minus_i_neighbor[ij]
        plus_i_neighbor = connectivity.ring_to_plus_i_neighbor[ij]
        minus_j_neighbor = connectivity.ring_to_minus_j_neighbor[ij]
        plus_j_neighbor = connectivity.ring_to_plus_j_neighbor[ij]

        @test Oceananigans.Grids.octahealpix_wrapped_ring_index(i, j, 2N, 2N, connectivity) == ij
        @test Oceananigans.Grids.octahealpix_wrapped_ring_index(i - 1, j, 2N, 2N, connectivity) == minus_i_neighbor
        @test Oceananigans.Grids.octahealpix_wrapped_ring_index(i + 1, j, 2N, 2N, connectivity) == plus_i_neighbor
        @test Oceananigans.Grids.octahealpix_wrapped_ring_index(i, j - 1, 2N, 2N, connectivity) == minus_j_neighbor
        @test Oceananigans.Grids.octahealpix_wrapped_ring_index(i, j + 1, 2N, 2N, connectivity) == plus_j_neighbor
        source_ring = Oceananigans.Grids.octahealpix_wrapped_ring_index(i, j, 2N, 2N, connectivity)
        @test (connectivity.ring_to_i[source_ring], connectivity.ring_to_j[source_ring]) == (i, j)

        corner_i, corner_j = Oceananigans.Grids.octahealpix_wrap_matrix_neighbor(i, j, -1, 0, mapping)
        corner_i, corner_j = Oceananigans.Grids.octahealpix_wrap_matrix_neighbor(corner_i, corner_j, 0, -1, mapping)
        minus_i_minus_j_neighbor = connectivity.matrix_to_ring[corner_i, corner_j]

        @test Oceananigans.Grids.octahealpix_wrapped_ring_index(i - 1, j - 1, 2N, 2N, connectivity) == minus_i_minus_j_neighbor

        @test minus_i_neighbor == connectivity.matrix_to_ring[i⁻, j⁻]
        @test plus_i_neighbor == connectivity.matrix_to_ring[i⁺, j⁺]
        @test minus_j_neighbor == connectivity.matrix_to_ring[i_minus_j, j_minus]
        @test plus_j_neighbor == connectivity.matrix_to_ring[i_plus_j, j_plus]

        @test 1 <= minus_i_neighbor <= number_of_cells
        @test 1 <= plus_i_neighbor <= number_of_cells
        @test 1 <= minus_j_neighbor <= number_of_cells
        @test 1 <= plus_j_neighbor <= number_of_cells

        @test connectivity.ring_to_plus_i_neighbor[minus_i_neighbor] == ij
        @test connectivity.ring_to_minus_i_neighbor[plus_i_neighbor] == ij
        @test connectivity.ring_to_plus_j_neighbor[minus_j_neighbor] == ij
        @test connectivity.ring_to_minus_j_neighbor[plus_j_neighbor] == ij

        @test length(unique((minus_i_neighbor, plus_i_neighbor, minus_j_neighbor, plus_j_neighbor))) == 4
    end

    @test sort(matrix_linear_indices) == collect(1:number_of_cells)
    @test sort(vec(connectivity.matrix_to_ring)) == collect(1:number_of_cells)

    for j in 1:(2N - 1)
        @test length(octahealpix_index_range_in_ring(mapping, j)) == octahealpix_nlon_per_ring(mapping, j)
        @test count(==(j), connectivity.ring_to_latitude_ring) == octahealpix_nlon_per_ring(mapping, j)
    end

    return nothing
end

function test_seam_transform_interface()
    Grids = Oceananigans.Grids
    Nx, Ny = 6, 4
    i, j = 2, 3

    @test Grids.seam_permute_indices(i, j, Nx, Ny, Grids.SeamIndexPermutation(Val(false), Val(false), Val(false))) == (2, 3)
    @test Grids.seam_permute_indices(i, j, Nx, Ny, Grids.seam_index_permutation(Val(:reverse_first))) == (5, 3)
    @test Grids.seam_permute_indices(i, j, Nx, Ny, Grids.seam_index_permutation(Val(:reverse_second))) == (2, 2)
    @test Grids.seam_permute_indices(i, j, Nx, Ny, Grids.seam_index_permutation(Val(:reverse_both))) == (5, 2)
    @test Grids.seam_permute_indices(i, j, Nx, Ny, Grids.seam_index_permutation(Val(:swap))) == (3, 2)
    @test Grids.seam_permute_indices(i, j, Nx, Ny, Grids.seam_index_permutation(Val(:swap_reverse_first))) == (2, 2)
    @test Grids.seam_permute_indices(i, j, Nx, Ny, Grids.seam_index_permutation(Val(:swap_reverse_second))) == (3, 5)
    @test Grids.seam_permute_indices(i, j, Nx, Ny, Grids.seam_index_permutation(Val(:swap_reverse_both))) == (2, 5)

    rotations = ((:identity,             (1,  1), (2,  1)),
                 (:rotate_90,            (2, -1), (1,  1)),
                 (:rotate_180,           (1, -1), (2, -1)),
                 (:rotate_270,           (2,  1), (1, -1)),
                 (:reflect_first,        (1, -1), (2,  1)),
                 (:reflect_second,       (1,  1), (2, -1)),
                 (:reflect_diagonal,     (2,  1), (1,  1)),
                 (:reflect_antidiagonal, (2, -1), (1, -1)))

    for (rotation_name, u_source, v_source) in rotations
        rotation = Grids.seam_vector_rotation(Val(rotation_name))
        @test Grids.vector_source_component_and_sign(Val(:u), rotation) == u_source
        @test Grids.vector_source_component_and_sign(Val(:v), rotation) == v_source
    end

    scalar_transform = Grids.ScalarSeamTransform(Val(:swap_reverse_first))
    vector_transform = Grids.CovariantVectorSeamTransform(Val(:swap_reverse_first), Val(:rotate_90))
    topology = TestSeamTopology()

    @test Grids.seam_halo_source(i, j, Nx, Ny, topology, scalar_transform) == (2, 2)
    @test Grids.seam_halo_source(i, j, Nx, Ny, topology, Val(:u), vector_transform) == (2, 2, 2, 1)
    @test Grids.seam_halo_source(i, j, Nx, Ny, topology, Val(:v), vector_transform) == (1, 2, 2, -1)

    return nothing
end

function test_octahealpix_rossby_haurwitz_style_dynamics(FT, N, momentum_advection)
    radius = one(FT)
    depth = one(FT)
    gravity = one(FT)

    grid = SphericalShellGrid(CPU(), FT; mapping = OctaHEALPixMapping(N),
                              size = (2N, 2N, 1),
                              z = (-depth, zero(FT)),
                              radius,
                              halo = (3, 3, 3))

    free_surface = ExplicitFreeSurface(gravitational_acceleration = gravity)

    model = HydrostaticFreeSurfaceModel(grid; free_surface,
                                        buoyancy = nothing,
                                        tracers = nothing,
                                        momentum_advection)

    R = radius
    ω = zero(FT)
    K = convert(FT, 1//10)
    n = 4
    Ω = zero(FT)

    function rossby_haurwitz_coefficients(latitude)
        cos_latitude = cos(latitude)
        sin_latitude = sin(latitude)
        cos² = cos_latitude^2
        cos²ⁿ = cos_latitude^(2n)

        A = ω / 2 * (2Ω + ω) * cos² +
            convert(FT, 1//4) * K^2 * ((n + 1) * cos_latitude^(2n + 2) +
                                       (2n^2 - n - 2) * cos²ⁿ -
                                       2n^2 * cos_latitude^(2n - 2))

        B = 2K * (Ω + ω) / ((n + 1) * (n + 2)) *
            cos_latitude^n *
            (n^2 + 2n + 2 - (n + 1)^2 * cos²)

        C = convert(FT, 1//4) * K^2 *
            ((n + 1) * cos_latitude^(2n + 2) - (n + 2) * cos²ⁿ)

        return A, B, C, cos_latitude, sin_latitude
    end

    function uᵢ(λ, φ, z)
        latitude = deg2rad(φ)
        longitude = deg2rad(λ)
        _, _, _, cos_latitude, sin_latitude = rossby_haurwitz_coefficients(latitude)

        return R * ω * cos_latitude +
               R * K * cos_latitude^(n - 1) *
               (n * sin_latitude^2 - cos_latitude^2) *
               cos(n * longitude)
    end

    function vᵢ(λ, φ, z)
        latitude = deg2rad(φ)
        longitude = deg2rad(λ)
        _, _, _, cos_latitude, sin_latitude = rossby_haurwitz_coefficients(latitude)

        return -n * K * R * cos_latitude^(n - 1) *
               sin_latitude *
               sin(n * longitude)
    end

    function ηᵢ(λ, φ, z)
        latitude = deg2rad(φ)
        longitude = deg2rad(λ)
        A, B, C, _, _ = rossby_haurwitz_coefficients(latitude)

        return R^2 / gravity *
               (A + B * cos(n * longitude) + C * cos(2n * longitude))
    end

    η = model.free_surface.displacement

    set!(model, u = uᵢ, v = vᵢ)
    set!(η, ηᵢ)
    fill_halo_regions!(η)

    k_top = grid.Nz + 1

    surface_volume() = sum(Oceananigans.Operators.Azᶜᶜᵃ(i, j, 1, grid) * η[i, j, k_top]
                           for j in 1:grid.Ny, i in 1:grid.Nx)

    initial_surface_volume = surface_volume()
    initial_surface = Array(interior(η))

    Δt = convert(FT, 1//200)

    for _ in 1:3
        time_step!(model, Δt)
    end

    final_surface_volume = surface_volume()
    final_surface = Array(interior(η))

    surface_volume_tolerance = convert(FT, 3//1000000) * max(one(FT), abs(initial_surface_volume))

    @test model.clock.iteration == 3
    @test all(isfinite, Array(interior(model.velocities.u)))
    @test all(isfinite, Array(interior(model.velocities.v)))
    @test all(isfinite, final_surface)
    @test maximum(abs, final_surface - initial_surface) > 10eps(FT)
    @test abs(final_surface_volume - initial_surface_volume) ≤ surface_volume_tolerance

    return nothing
end

function test_nonorthogonal_momentum_advection_validation(FT)
    radius = convert(FT, 3)
    mapping = EquiangularGnomonicCubedSpherePanel(FT)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size=(8, 8, 1),
                              topology = (Periodic, Periodic, Bounded),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant())

    @test model.advection.momentum isa VectorInvariant

    @test_throws ArgumentError HydrostaticFreeSurfaceModel(grid;
                                                        buoyancy = nothing,
                                                        free_surface = nothing,
                                                        momentum_advection = WENOVectorInvariant())

    @test_throws ArgumentError HydrostaticFreeSurfaceModel(grid;
                                                        buoyancy = nothing,
                                                        free_surface = nothing,
                                                        momentum_advection = WENOVectorInvariant(order=5))

    model = HydrostaticFreeSurfaceModel(grid;
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing)

    @test model.advection.momentum === nothing

    return nothing
end

function test_octahealpix_tracer_advection_validation(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (2, 2, 2))

    supported_scheme = Oceananigans.Advection.WENO(FT; order = 1)
    supported_model = HydrostaticFreeSurfaceModel(grid;
                                                  tracers = :c,
                                                  buoyancy = nothing,
                                                  free_surface = nothing,
                                                  momentum_advection = nothing,
                                                  tracer_advection = supported_scheme)

    @test supported_model isa HydrostaticFreeSurfaceModel

    supported_flux_form = Oceananigans.Advection.FluxFormAdvection(Oceananigans.Advection.Centered(FT),
                                                                   Oceananigans.Advection.WENO(FT; order = 1),
                                                                   Oceananigans.Advection.Centered(FT))

    supported_flux_form_model = HydrostaticFreeSurfaceModel(grid;
                                                            tracers = :c,
                                                            buoyancy = nothing,
                                                            free_surface = nothing,
                                                            momentum_advection = nothing,
                                                            tracer_advection = supported_flux_form)

    @test supported_flux_form_model isa HydrostaticFreeSurfaceModel

    bounds_preserving_scheme = Oceananigans.Advection.WENO(FT; order = 1, bounds = (zero(FT), one(FT)))

    bounds_preserving_model = HydrostaticFreeSurfaceModel(grid;
                                                          tracers = :c,
                                                          buoyancy = nothing,
                                                          free_surface = nothing,
                                                          momentum_advection = nothing,
                                                          tracer_advection = bounds_preserving_scheme)

    @test bounds_preserving_model isa HydrostaticFreeSurfaceModel

    bounds_preserving_flux_form = Oceananigans.Advection.FluxFormAdvection(bounds_preserving_scheme,
                                                                           Oceananigans.Advection.Centered(FT),
                                                                           Oceananigans.Advection.Centered(FT))

    bounds_preserving_flux_form_model = HydrostaticFreeSurfaceModel(grid;
                                                                    tracers = :c,
                                                                    buoyancy = nothing,
                                                                    free_surface = nothing,
                                                                    momentum_advection = nothing,
                                                                    tracer_advection = bounds_preserving_flux_form)

    @test bounds_preserving_flux_form_model isa HydrostaticFreeSurfaceModel

    bounds_preserving_tuple_model = HydrostaticFreeSurfaceModel(grid;
                                                                tracers = :c,
                                                                buoyancy = nothing,
                                                                free_surface = nothing,
                                                                momentum_advection = nothing,
                                                                tracer_advection = (c = bounds_preserving_scheme,))

    @test bounds_preserving_tuple_model isa HydrostaticFreeSurfaceModel

    return nothing
end

function test_equiangular_gnomonic_vector_invariant_momentum_tendencies(FT)
    radius = convert(FT, 3)
    mapping = EquiangularGnomonicCubedSpherePanel(FT)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (8, 8, 1),
                              topology = (Periodic, Periodic, Bounded),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant())

    set!(model,
         u = (λ, φ, z) -> sind(λ) * cosd(φ),
         v = (λ, φ, z) -> cosd(λ) * sind(φ))

    fill_halo_regions!(model.velocities.u)
    fill_halo_regions!(model.velocities.v)

    momentum = model.advection.momentum
    U = (u = model.velocities.u, v = model.velocities.v, w = model.velocities.w)

    i, j = 3, 3
    k = 1

    expected_Gu = -U_dot_∇u(i, j, k, grid, momentum, U)
    expected_Gv = -U_dot_∇v(i, j, k, grid, momentum, U)

    magnitude_scale = max(abs(expected_Gu), abs(expected_Gv), one(FT))

    compute_momentum_tendencies!(model, ())

    computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
    computed_Gv = model.timestepper.Gⁿ.v[i, j, k]

    @test abs(expected_Gu) > 100eps(FT)
    @test abs(expected_Gv) > 100eps(FT)
    @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * magnitude_scale
    @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * magnitude_scale
    @test !any(isnan, Array(interior(model.timestepper.Gⁿ.u)))
    @test !any(isnan, Array(interior(model.timestepper.Gⁿ.v)))

    return nothing
end

