function test_octahealpix_vector_invariant_validation(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    supported_scheme = Oceananigans.Advection.VectorInvariant(FT;
                                                              vorticity_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                                              vertical_advection_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                                              kinetic_energy_gradient_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                                              divergence_scheme = Oceananigans.Advection.EnergyConserving(FT))

    supported_model = HydrostaticFreeSurfaceModel(grid;
                                                  tracers = nothing,
                                                  buoyancy = nothing,
                                                  free_surface = nothing,
                                                  momentum_advection = supported_scheme)

    @test supported_model isa HydrostaticFreeSurfaceModel

    supported_upwind_vorticity_scheme = Oceananigans.Advection.VectorInvariant(FT;
                                                                               vorticity_scheme = Oceananigans.Advection.WENO(FT; order = 5),
                                                                               vertical_advection_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                                                               kinetic_energy_gradient_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                                                               divergence_scheme = Oceananigans.Advection.EnergyConserving(FT))

    supported_upwind_model = HydrostaticFreeSurfaceModel(grid;
                                                         tracers = nothing,
                                                         buoyancy = nothing,
                                                         free_surface = nothing,
                                                         momentum_advection = supported_upwind_vorticity_scheme)

    @test supported_upwind_model isa HydrostaticFreeSurfaceModel

    supported_vertical_scheme = Oceananigans.Advection.VectorInvariant(FT;
                                                                       vorticity_scheme = Oceananigans.Advection.EnstrophyConserving(FT),
                                                                       vertical_advection_scheme = Oceananigans.Advection.WENO(FT; order = 5),
                                                                       kinetic_energy_gradient_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                                                       divergence_scheme = Oceananigans.Advection.WENO(FT; order = 5))

    supported_vertical_model = HydrostaticFreeSurfaceModel(grid;
                                                           tracers = nothing,
                                                           buoyancy = nothing,
                                                           free_surface = nothing,
                                                           momentum_advection = supported_vertical_scheme)

    @test supported_vertical_model isa HydrostaticFreeSurfaceModel

    supported_ke_gradient_scheme = Oceananigans.Advection.VectorInvariant(FT;
                                                                          vorticity_scheme = Oceananigans.Advection.EnstrophyConserving(FT),
                                                                          vertical_advection_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                                                          kinetic_energy_gradient_scheme = Oceananigans.Advection.WENO(FT; order = 5),
                                                                          divergence_scheme = Oceananigans.Advection.EnergyConserving(FT))

    supported_ke_gradient_model = HydrostaticFreeSurfaceModel(grid;
                                                              tracers = nothing,
                                                              buoyancy = nothing,
                                                              free_surface = nothing,
                                                              momentum_advection = supported_ke_gradient_scheme)

    @test supported_ke_gradient_model isa HydrostaticFreeSurfaceModel

    supported_weno_model = HydrostaticFreeSurfaceModel(grid;
                                                       tracers = nothing,
                                                       buoyancy = nothing,
                                                       free_surface = nothing,
                                                       momentum_advection = Oceananigans.Advection.WENOVectorInvariant(FT))

    @test supported_weno_model isa HydrostaticFreeSurfaceModel

    unsupported_vertical_divergence_scheme = Oceananigans.Advection.VectorInvariant(FT;
                                                                                     vorticity_scheme = Oceananigans.Advection.EnstrophyConserving(FT),
                                                                                     vertical_advection_scheme = Oceananigans.Advection.WENO(FT; order = 5),
                                                                                     kinetic_energy_gradient_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                                                                     divergence_scheme = Oceananigans.Advection.EnergyConserving(FT))

    @test_throws ArgumentError HydrostaticFreeSurfaceModel(grid;
                                                           tracers = nothing,
                                                           buoyancy = nothing,
                                                           free_surface = nothing,
                                                           momentum_advection = unsupported_vertical_divergence_scheme)

    unsupported_upwinding_scheme = Oceananigans.Advection.VectorInvariant(FT;
                                                                          vorticity_scheme = Oceananigans.Advection.WENO(FT; order = 5),
                                                                          vertical_advection_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                                                          kinetic_energy_gradient_scheme = Oceananigans.Advection.WENO(FT; order = 5),
                                                                          divergence_scheme = Oceananigans.Advection.WENO(FT; order = 5),
                                                                          upwinding = Oceananigans.Advection.VelocityUpwinding(Oceananigans.Advection.Centered(FT)))

    @test_throws ArgumentError HydrostaticFreeSurfaceModel(grid;
                                                           tracers = nothing,
                                                           buoyancy = nothing,
                                                           free_surface = nothing,
                                                           momentum_advection = unsupported_upwinding_scheme)

    return nothing
end

function test_octahealpix_upwind_vorticity_vector_invariant_momentum_tendencies(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    supported_upwind_scheme = Oceananigans.Advection.VectorInvariant(FT;
                                                                     vorticity_scheme = Oceananigans.Advection.WENO(FT; order = 5),
                                                                     vertical_advection_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                                                     kinetic_energy_gradient_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                                                     divergence_scheme = Oceananigans.Advection.EnergyConserving(FT))

    centered_scheme = Oceananigans.Advection.VectorInvariant(FT;
                                                             vorticity_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                                             vertical_advection_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                                             kinetic_energy_gradient_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                                             divergence_scheme = Oceananigans.Advection.EnergyConserving(FT))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = supported_upwind_scheme)

    set!(model, u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.04) * cosd(φ),
                v = (λ, φ, z) -> convert(FT, 0.08) * cosd(λ) - convert(FT, 0.03) * sind(φ))

    compute_momentum_tendencies!(model, ())

    samples = ((2, div(N, 2), 1),
               (N - 1, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (div(N, 2), N - 1, 1))
    maximum_centered_difference = zero(FT)

    for (i, j, k) in samples
        expected_Gu = -Oceananigans.Advection.U_dot_∇u(i, j, k, grid, supported_upwind_scheme, model.velocities)
        expected_Gv = -Oceananigans.Advection.U_dot_∇v(i, j, k, grid, supported_upwind_scheme, model.velocities)
        centered_Gu = -Oceananigans.Advection.U_dot_∇u(i, j, k, grid, centered_scheme, model.velocities)
        centered_Gv = -Oceananigans.Advection.U_dot_∇v(i, j, k, grid, centered_scheme, model.velocities)
        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        u_scale = max(one(FT), abs(expected_Gu), abs(computed_Gu))
        v_scale = max(one(FT), abs(expected_Gv), abs(computed_Gv))

        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * u_scale
        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * v_scale

        maximum_centered_difference = max(maximum_centered_difference,
                                          abs(expected_Gu - centered_Gu),
                                          abs(expected_Gv - centered_Gv))
    end

    @test maximum_centered_difference > 100eps(FT)

    return nothing
end

