function test_octahealpix_cross_upwind_divergence_vector_invariant_momentum_tendencies(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    supported_cross_scheme = Oceananigans.Advection.VectorInvariant(FT;
                                                                    vorticity_scheme = Oceananigans.Advection.EnstrophyConserving(FT),
                                                                    vertical_advection_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                                                    kinetic_energy_gradient_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                                                    divergence_scheme = Oceananigans.Advection.WENO(FT; order = 5),
                                                                    upwinding = Oceananigans.Advection.CrossAndSelfUpwinding(cross_scheme = Oceananigans.Advection.Centered(FT)))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = supported_cross_scheme)

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.14) * sind(λ) + convert(FT, 0.09) * z + convert(FT, 0.03) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.07) * cosd(λ) - convert(FT, 0.05) * z + convert(FT, 0.02) * sind(φ),
         w = (λ, φ, z) -> convert(FT, 0.03) * sind(φ) * (z - convert(FT, 1//2)))

    samples = ((2, div(N, 2), 1),
               (2, div(N, 2), 2),
               (N, div(N, 2), 1),
               (N, div(N, 2), 2))

    maximum_naive_difference = zero(FT)

    for (i, j, k) in samples
        û = @inbounds model.velocities.u[i, j, k]
        v̂ = @inbounds model.velocities.v[i, j, k]
        δ_stencil = supported_cross_scheme.upwinding.divergence_stencil
        cross_scheme = supported_cross_scheme.upwinding.cross_scheme

        expected_flux_u =
            û * (Oceananigans.Advection._biased_interpolate_xᶠᵃᵃ(i, j, k, grid, supported_cross_scheme,
                                                                 supported_cross_scheme.divergence_scheme,
                                                                 Oceananigans.Advection.bias(û),
                                                                 Oceananigans.Operators.horizontal_volume_flux_div_xyᶜᶜᶜ,
                                                                 δ_stencil,
                                                                 model.velocities.u,
                                                                 model.velocities.v) +
                  Oceananigans.Advection._symmetric_interpolate_xᶠᵃᵃ(i, j, k, grid, supported_cross_scheme,
                                                                     cross_scheme,
                                                                     Oceananigans.Advection.Az_Δr_∂t_σ))

        expected_flux_v =
            v̂ * (Oceananigans.Advection._biased_interpolate_yᵃᶠᵃ(i, j, k, grid, supported_cross_scheme,
                                                                 supported_cross_scheme.divergence_scheme,
                                                                 Oceananigans.Advection.bias(v̂),
                                                                 Oceananigans.Operators.horizontal_volume_flux_div_xyᶜᶜᶜ,
                                                                 δ_stencil,
                                                                 model.velocities.u,
                                                                 model.velocities.v) +
                  Oceananigans.Advection._symmetric_interpolate_yᵃᶠᵃ(i, j, k, grid, supported_cross_scheme,
                                                                     cross_scheme,
                                                                     Oceananigans.Advection.Az_Δr_∂t_σ))

        naive_flux_u =
            û * (Oceananigans.Advection._biased_interpolate_xᶠᵃᵃ(i, j, k, grid, supported_cross_scheme,
                                                                 supported_cross_scheme.divergence_scheme,
                                                                 Oceananigans.Advection.bias(û),
                                                                 Oceananigans.Operators.flux_div_xyᶜᶜᶜ,
                                                                 δ_stencil,
                                                                 model.velocities.u,
                                                                 model.velocities.v) +
                  Oceananigans.Advection._symmetric_interpolate_xᶠᵃᵃ(i, j, k, grid, supported_cross_scheme,
                                                                     cross_scheme,
                                                                     Oceananigans.Advection.Az_Δr_∂t_σ))

        naive_flux_v =
            v̂ * (Oceananigans.Advection._biased_interpolate_yᵃᶠᵃ(i, j, k, grid, supported_cross_scheme,
                                                                 supported_cross_scheme.divergence_scheme,
                                                                 Oceananigans.Advection.bias(v̂),
                                                                 Oceananigans.Operators.flux_div_xyᶜᶜᶜ,
                                                                 δ_stencil,
                                                                 model.velocities.u,
                                                                 model.velocities.v) +
                  Oceananigans.Advection._symmetric_interpolate_yᵃᶠᵃ(i, j, k, grid, supported_cross_scheme,
                                                                     cross_scheme,
                                                                     Oceananigans.Advection.Az_Δr_∂t_σ))

        computed_flux_u = Oceananigans.Advection.upwinded_divergence_flux_Uᶠᶜᶜ(i, j, k, grid, supported_cross_scheme,
                                                                                model.velocities.u, model.velocities.v)
        computed_flux_v = Oceananigans.Advection.upwinded_divergence_flux_Vᶜᶠᶜ(i, j, k, grid, supported_cross_scheme,
                                                                                model.velocities.u, model.velocities.v)

        u_scale = max(one(FT), abs(expected_flux_u), abs(computed_flux_u))
        v_scale = max(one(FT), abs(expected_flux_v), abs(computed_flux_v))

        @test abs(computed_flux_u - expected_flux_u) ≤ 1000eps(FT) * u_scale
        @test abs(computed_flux_v - expected_flux_v) ≤ 1000eps(FT) * v_scale

        maximum_naive_difference = max(maximum_naive_difference,
                                       abs(expected_flux_u - naive_flux_u),
                                       abs(expected_flux_v - naive_flux_v))
    end

    @test maximum_naive_difference > 100eps(FT)

    compute_momentum_tendencies!(model, ())

    for (i, j, k) in samples
        expected_Gu = -Oceananigans.Advection.U_dot_∇u(i, j, k, grid, supported_cross_scheme, model.velocities)
        expected_Gv = -Oceananigans.Advection.U_dot_∇v(i, j, k, grid, supported_cross_scheme, model.velocities)
        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        u_scale = max(one(FT), abs(expected_Gu), abs(computed_Gu))
        v_scale = max(one(FT), abs(expected_Gv), abs(computed_Gv))

        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * u_scale
        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * v_scale
    end

    return nothing
end

