function test_octahealpix_generic_momentum_advection_validation(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    supported_centered_model = HydrostaticFreeSurfaceModel(grid;
                                                           tracers = nothing,
                                                           buoyancy = nothing,
                                                           free_surface = nothing,
                                                           momentum_advection = Centered(FT),
                                                           tracer_advection = Centered(FT))

    @test supported_centered_model isa HydrostaticFreeSurfaceModel

    supported_flux_form_model = HydrostaticFreeSurfaceModel(
        grid;
        tracers = nothing,
        buoyancy = nothing,
        free_surface = nothing,
        momentum_advection = Oceananigans.Advection.FluxFormAdvection(Centered(FT),
                                                                      Centered(FT),
                                                                      Oceananigans.Advection.WENO(FT; order = 5)),
        tracer_advection = Centered(FT))

    @test supported_flux_form_model isa HydrostaticFreeSurfaceModel

    supported_upwind_flux_form_model = HydrostaticFreeSurfaceModel(
        grid;
        tracers = nothing,
        buoyancy = nothing,
        free_surface = nothing,
        momentum_advection = Oceananigans.Advection.FluxFormAdvection(Oceananigans.Advection.WENO(FT; order = 5),
                                                                      Oceananigans.Advection.WENO(FT; order = 5),
                                                                      Oceananigans.Advection.Centered(FT)),
        tracer_advection = Centered(FT))

    @test supported_upwind_flux_form_model isa HydrostaticFreeSurfaceModel

    error_message = try
        HydrostaticFreeSurfaceModel(grid;
                                    tracers = nothing,
                                    buoyancy = nothing,
                                    free_surface = nothing,
                                    momentum_advection = Oceananigans.Advection.WENO(FT; order = 5),
                                    tracer_advection = Centered(FT))
        ""
    catch err
        sprint(showerror, err)
    end

    @test !isempty(error_message)
    @test occursin("FluxFormAdvection(...)", error_message)
    @test occursin("Centered()", error_message)

    return nothing
end

function test_octahealpix_centered_flux_form_momentum_matches_vector_invariant(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    centered_model = HydrostaticFreeSurfaceModel(grid;
                                                 tracers = nothing,
                                                 buoyancy = nothing,
                                                 free_surface = nothing,
                                                 momentum_advection = Centered(FT))

    vector_invariant_model = HydrostaticFreeSurfaceModel(grid;
                                                         tracers = nothing,
                                                         buoyancy = nothing,
                                                         free_surface = nothing,
                                                         momentum_advection = VectorInvariant())

    u_velocity(λ, φ, z) = convert(FT, 0.15) * sind(λ) + convert(FT, 0.04) * cosd(φ)
    v_velocity(λ, φ, z) = convert(FT, 0.08) * cosd(λ) - convert(FT, 0.03) * sind(φ)

    set!(centered_model, u = u_velocity, v = v_velocity, w = zero(FT))
    set!(vector_invariant_model, u = u_velocity, v = v_velocity, w = zero(FT))

    compute_momentum_tendencies!(centered_model, ())
    compute_momentum_tendencies!(vector_invariant_model, ())

    samples = ((2, div(N, 2), 1),
               (N - 1, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (div(N, 2), N - 1, 1))
    maximum_naive_difference = zero(FT)

    for (i, j, k) in samples
        centered_Gu = centered_model.timestepper.Gⁿ.u[i, j, k]
        centered_Gv = centered_model.timestepper.Gⁿ.v[i, j, k]
        vector_invariant_Gu = vector_invariant_model.timestepper.Gⁿ.u[i, j, k]
        vector_invariant_Gv = vector_invariant_model.timestepper.Gⁿ.v[i, j, k]
        naive_Gu = -Oceananigans.Advection.div_𝐯u(i, j, k, grid, Centered(FT), centered_model.velocities, centered_model.velocities.u)
        naive_Gv = -Oceananigans.Advection.div_𝐯v(i, j, k, grid, Centered(FT), centered_model.velocities, centered_model.velocities.v)
        u_scale = max(one(FT), abs(centered_Gu), abs(vector_invariant_Gu))
        v_scale = max(one(FT), abs(centered_Gv), abs(vector_invariant_Gv))

        @test abs(centered_Gu - vector_invariant_Gu) ≤ 1000eps(FT) * u_scale
        @test abs(centered_Gv - vector_invariant_Gv) ≤ 1000eps(FT) * v_scale

        maximum_naive_difference = max(maximum_naive_difference,
                                       abs(centered_Gu - naive_Gu),
                                       abs(centered_Gv - naive_Gv))
    end

    @test maximum_naive_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_upwind_flux_form_momentum_uses_nonorthogonal_metric_correction(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    upwind_flux_form = Oceananigans.Advection.FluxFormAdvection(Oceananigans.Advection.WENO(FT; order = 5),
                                                                Oceananigans.Advection.WENO(FT; order = 5),
                                                                Oceananigans.Advection.Centered(FT))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = upwind_flux_form)

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.04) * cosd(φ) + convert(FT, 0.03) * z,
         v = (λ, φ, z) -> convert(FT, 0.08) * cosd(λ) - convert(FT, 0.03) * sind(φ) - convert(FT, 0.02) * z,
         w = (λ, φ, z) -> convert(FT, 0.02) * sind(φ) * (z - convert(FT, 1//2)))

    compute_momentum_tendencies!(model, ())

    samples = ((2, div(N, 2), 1),
               (2, div(N, 2), 2),
               (N, div(N, 2), 1),
               (N, div(N, 2), 2))
    maximum_naive_difference = zero(FT)

    for (i, j, k) in samples
        expected_Gu = -(Oceananigans.Advection.div_𝐯u(i, j, k, grid, upwind_flux_form, model.velocities, model.velocities.u) +
                        Oceananigans.Advection.U_dot_∇u_hydrostatic_metric(i, j, k, grid, upwind_flux_form, model.velocities, model.velocities))
        expected_Gv = -(Oceananigans.Advection.div_𝐯v(i, j, k, grid, upwind_flux_form, model.velocities, model.velocities.v) +
                        Oceananigans.Advection.U_dot_∇v_hydrostatic_metric(i, j, k, grid, upwind_flux_form, model.velocities, model.velocities))

        naive_Gu = -Oceananigans.Advection.div_𝐯u(i, j, k, grid, upwind_flux_form, model.velocities, model.velocities.u)
        naive_Gv = -Oceananigans.Advection.div_𝐯v(i, j, k, grid, upwind_flux_form, model.velocities, model.velocities.v)

        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        u_scale = max(one(FT), abs(expected_Gu), abs(computed_Gu))
        v_scale = max(one(FT), abs(expected_Gv), abs(computed_Gv))

        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * u_scale
        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * v_scale

        maximum_naive_difference = max(maximum_naive_difference,
                                       abs(expected_Gu - naive_Gu),
                                       abs(expected_Gv - naive_Gv))
    end

    @test maximum_naive_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_vector_invariant_primitives(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing)

    set!(model,
         u = (λ, φ, z) -> sind(λ) * cosd(φ),
         v = (λ, φ, z) -> cosd(λ) * sind(φ))

    fill_halo_regions!(model.velocities)

    energy_scheme = Oceananigans.Advection.VectorInvariant(FT;
                                                           vorticity_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                                           vertical_advection_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                                           kinetic_energy_gradient_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                                           divergence_scheme = Oceananigans.Advection.EnergyConserving(FT))

    enstrophy_scheme = Oceananigans.Advection.VectorInvariant(FT;
                                                              vorticity_scheme = Oceananigans.Advection.EnstrophyConserving(FT),
                                                              vertical_advection_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                                              kinetic_energy_gradient_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                                              divergence_scheme = Oceananigans.Advection.EnergyConserving(FT))

    contravariant_operations = contravariant_velocities(model)
    diagnostic_contravariant_u = Field(contravariant_operations.u)
    diagnostic_contravariant_v = Field(contravariant_operations.v)
    compute!(diagnostic_contravariant_u)
    compute!(diagnostic_contravariant_v)

    diagnostic_kinetic_energy = Field(kinetic_energy(model))
    compute!(diagnostic_kinetic_energy)

    diagnostic_relative_vorticity = Field(relative_vorticity(model))
    compute!(diagnostic_relative_vorticity)

    diagnostic_vorticity = Field(vertical_vorticity(model))
    compute!(diagnostic_vorticity)

    interior_indices = vcat(collect(2:(N - 1)),
                            collect((N + 2):(2N - 1)))

    contravariant_u_error = zero(FT)
    contravariant_v_error = zero(FT)
    kinetic_energy_error = zero(FT)
    relative_vorticity_error = zero(FT)
    vorticity_error = zero(FT)
    bernoulli_head_u_error = zero(FT)
    bernoulli_head_v_error = zero(FT)
    energy_advection_u_error = zero(FT)
    energy_advection_v_error = zero(FT)
    enstrophy_advection_u_error = zero(FT)
    enstrophy_advection_v_error = zero(FT)

    contravariant_u_scale = one(FT)
    contravariant_v_scale = one(FT)
    kinetic_energy_scale = one(FT)
    relative_vorticity_scale = one(FT)
    vorticity_scale = one(FT)
    bernoulli_head_u_scale = one(FT)
    bernoulli_head_v_scale = one(FT)
    rotational_advection_u_scale = one(FT)
    rotational_advection_v_scale = one(FT)

    for j in interior_indices, i in interior_indices
        expected_contravariant_u = covariant_to_contravariant_velocity_uᶠᶜᶜ(i, j, 1, grid, model.velocities.u, model.velocities.v)
        expected_contravariant_v = covariant_to_contravariant_velocity_vᶜᶠᶜ(i, j, 1, grid, model.velocities.u, model.velocities.v)
        expected_kinetic_energy = covariant_kinetic_energyᶜᶜᶜ(i, j, 1, grid, model.velocities.u, model.velocities.v)
        expected_relative_vorticity = covariant_vertical_vorticity_componentᶠᶠᶜ(i, j, 1, grid, model.velocities.u, model.velocities.v)
        expected_vorticity = covariant_vertical_vorticityᶠᶠᶜ(i, j, 1, grid, model.velocities.u, model.velocities.v)
        expected_bernoulli_head_u = covariant_bernoulli_head_uᶠᶜᶜ(i, j, 1, grid, model.velocities.u, model.velocities.v)
        expected_bernoulli_head_v = covariant_bernoulli_head_vᶜᶠᶜ(i, j, 1, grid, model.velocities.u, model.velocities.v)
        expected_rotational_advection_u = covariant_rotational_advection_uᶠᶜᶜ(i, j, 1, grid, model.velocities.u, model.velocities.v)
        expected_rotational_advection_v = covariant_rotational_advection_vᶜᶠᶜ(i, j, 1, grid, model.velocities.u, model.velocities.v)

        computed_energy_bernoulli_head_u = Oceananigans.Advection.bernoulli_head_U(i, j, 1, grid, energy_scheme, model.velocities.u, model.velocities.v)
        computed_energy_bernoulli_head_v = Oceananigans.Advection.bernoulli_head_V(i, j, 1, grid, energy_scheme, model.velocities.u, model.velocities.v)
        computed_energy_advection_u = Oceananigans.Advection.horizontal_advection_U(i, j, 1, grid, energy_scheme, model.velocities.u, model.velocities.v)
        computed_energy_advection_v = Oceananigans.Advection.horizontal_advection_V(i, j, 1, grid, energy_scheme, model.velocities.u, model.velocities.v)
        computed_enstrophy_advection_u = Oceananigans.Advection.horizontal_advection_U(i, j, 1, grid, enstrophy_scheme, model.velocities.u, model.velocities.v)
        computed_enstrophy_advection_v = Oceananigans.Advection.horizontal_advection_V(i, j, 1, grid, enstrophy_scheme, model.velocities.u, model.velocities.v)

        contravariant_u_error = max(contravariant_u_error,
                                    abs(diagnostic_contravariant_u[i, j, 1] - expected_contravariant_u))
        contravariant_v_error = max(contravariant_v_error,
                                    abs(diagnostic_contravariant_v[i, j, 1] - expected_contravariant_v))
        kinetic_energy_error = max(kinetic_energy_error,
                                   abs(diagnostic_kinetic_energy[i, j, 1] - expected_kinetic_energy))
        relative_vorticity_error = max(relative_vorticity_error,
                                       abs(diagnostic_relative_vorticity[i, j, 1] - expected_relative_vorticity))
        vorticity_error = max(vorticity_error,
                              abs(diagnostic_vorticity[i, j, 1] - expected_vorticity))
        bernoulli_head_u_error = max(bernoulli_head_u_error,
                                     abs(computed_energy_bernoulli_head_u - expected_bernoulli_head_u))
        bernoulli_head_v_error = max(bernoulli_head_v_error,
                                     abs(computed_energy_bernoulli_head_v - expected_bernoulli_head_v))
        energy_advection_u_error = max(energy_advection_u_error,
                                       abs(computed_energy_advection_u - expected_rotational_advection_u))
        energy_advection_v_error = max(energy_advection_v_error,
                                       abs(computed_energy_advection_v - expected_rotational_advection_v))
        enstrophy_advection_u_error = max(enstrophy_advection_u_error,
                                          abs(computed_enstrophy_advection_u - expected_rotational_advection_u))
        enstrophy_advection_v_error = max(enstrophy_advection_v_error,
                                          abs(computed_enstrophy_advection_v - expected_rotational_advection_v))

        contravariant_u_scale = max(contravariant_u_scale, abs(expected_contravariant_u))
        contravariant_v_scale = max(contravariant_v_scale, abs(expected_contravariant_v))
        kinetic_energy_scale = max(kinetic_energy_scale, abs(expected_kinetic_energy))
        relative_vorticity_scale = max(relative_vorticity_scale, abs(expected_relative_vorticity))
        vorticity_scale = max(vorticity_scale, abs(expected_vorticity))
        bernoulli_head_u_scale = max(bernoulli_head_u_scale, abs(expected_bernoulli_head_u))
        bernoulli_head_v_scale = max(bernoulli_head_v_scale, abs(expected_bernoulli_head_v))
        rotational_advection_u_scale = max(rotational_advection_u_scale, abs(expected_rotational_advection_u))
        rotational_advection_v_scale = max(rotational_advection_v_scale, abs(expected_rotational_advection_v))
    end

    @test contravariant_operations.u.kernel_function === covariant_to_contravariant_velocity_uᶠᶜᶜ
    @test contravariant_operations.v.kernel_function === covariant_to_contravariant_velocity_vᶜᶠᶜ
    @test kinetic_energy(model).kernel_function === covariant_kinetic_energyᶜᶜᶜ
    @test relative_vorticity(model).kernel_function === covariant_vertical_vorticity_componentᶠᶠᶜ
    @test vertical_vorticity(model).kernel_function === covariant_vertical_vorticityᶠᶠᶜ

    @test contravariant_u_error ≤ 1000eps(FT) * contravariant_u_scale
    @test contravariant_v_error ≤ 1000eps(FT) * contravariant_v_scale
    @test kinetic_energy_error ≤ 1000eps(FT) * kinetic_energy_scale
    @test relative_vorticity_error ≤ 1000eps(FT) * relative_vorticity_scale
    @test vorticity_error ≤ 1000eps(FT) * vorticity_scale
    @test bernoulli_head_u_error ≤ 1000eps(FT) * bernoulli_head_u_scale
    @test bernoulli_head_v_error ≤ 1000eps(FT) * bernoulli_head_v_scale
    @test energy_advection_u_error ≤ 1000eps(FT) * rotational_advection_u_scale
    @test energy_advection_v_error ≤ 1000eps(FT) * rotational_advection_v_scale
    @test enstrophy_advection_u_error ≤ 1000eps(FT) * rotational_advection_u_scale
    @test enstrophy_advection_v_error ≤ 1000eps(FT) * rotational_advection_v_scale

    return nothing
end

function test_equiangular_gnomonic_panel_metrics(FT)
    mapping = EquiangularGnomonicCubedSpherePanel(FT)
    radius = convert(FT, 3)
    αs = range(mapping.α[1], mapping.α[2], length=9)
    βs = range(mapping.β[1], mapping.β[2], length=9)

    @test mapping.α == (convert(FT, -π/4), convert(FT, π/4))
    @test mapping.β == (convert(FT, -π/4), convert(FT, π/4))

    unit_radius_error = maximum((β, α) for β in βs, α in αs) do (β, α)
        x, y, z = equiangular_gnomonic_panel_unit_vector(α, β)
        return abs(sqrt(x^2 + y^2 + z^2) - one(FT))
    end

    radius_error = maximum((β, α) for β in βs, α in αs) do (β, α)
        x, y, z = equiangular_gnomonic_panel_cartesian_node(α, β, radius)
        return abs(sqrt(x^2 + y^2 + z^2) - radius) / radius
    end

    metric_inverse_error = maximum((β, α) for β in βs, α in αs) do (β, α)
        J, g₁₁, g₁₂, g₂₂, g¹¹, g¹², g²², G¹¹, G¹², G²² =
            equiangular_gnomonic_panel_metric_tensor(α, β, radius)

        δ¹₁_error = abs(g₁₁ * g¹¹ + g₁₂ * g¹² - one(FT))
        δ¹₂_error = abs(g₁₁ * g¹² + g₁₂ * g²²)
        δ²₁_error = abs(g₁₂ * g¹¹ + g₂₂ * g¹²)
        δ²₂_error = abs(g₁₂ * g¹² + g₂₂ * g²² - one(FT))

        return max(δ¹₁_error, δ¹₂_error, δ²₁_error, δ²₂_error)
    end

    determinant_error = maximum((β, α) for β in βs, α in αs) do (β, α)
        J, g₁₁, g₁₂, g₂₂ = equiangular_gnomonic_panel_metric_tensor(α, β, radius)
        determinant = g₁₁ * g₂₂ - g₁₂^2
        return abs(J^2 - determinant) / determinant
    end

    metric_density_error = maximum((β, α) for β in βs, α in αs) do (β, α)
        J, g₁₁, g₁₂, g₂₂, g¹¹, g¹², g²², G¹¹, G¹², G²² =
            equiangular_gnomonic_panel_metric_tensor(α, β, radius)

        G¹¹_error = abs(G¹¹ - J * g¹¹)
        G¹²_error = abs(G¹² - J * g¹²)
        G²²_error = abs(G²² - J * g²²)

        return max(G¹¹_error, G¹²_error, G²²_error)
    end

    minimum_determinant = minimum((begin
        J, g₁₁, g₁₂, g₂₂ = equiangular_gnomonic_panel_metric_tensor(α, β, radius)
        g₁₁ * g₂₂ - g₁₂^2
    end) for β in βs, α in αs)

    maximum_off_diagonal = maximum(abs(equiangular_gnomonic_panel_metric_tensor(α, β, radius)[3]) for β in βs, α in αs)
    maximum_metric_scale = maximum(sqrt(equiangular_gnomonic_panel_metric_tensor(α, β, radius)[2] *
                                        equiangular_gnomonic_panel_metric_tensor(α, β, radius)[4]) for β in βs, α in αs)

    @test unit_radius_error ≤ 100eps(FT)
    @test radius_error ≤ 100eps(FT)
    @test metric_inverse_error ≤ 100eps(FT)
    @test determinant_error ≤ 100eps(FT)
    @test metric_density_error ≤ 100eps(FT)
    @test minimum_determinant > zero(FT)
    @test maximum_off_diagonal / maximum_metric_scale > convert(FT, 1//1000)

    return nothing
end

function test_equiangular_gnomonic_spherical_shell_grid(FT, N)
    radius = convert(FT, 3)
    mapping = EquiangularGnomonicCubedSpherePanel(FT)
    grid = SphericalShellGrid(CPU(), FT; mapping, size=(N, N, 1), z=(zero(FT), one(FT)), radius, halo=(1, 1, 1))

    @test grid isa SphericalShellGrid
    @test grid isa AbstractHorizontallyCurvilinearGrid
    @test grid.metrics isa SphericalShellMetrics
    @test topology(grid) == (Bounded, Bounded, Bounded)
    @test size(grid) == (N, N, 1)
    @test halo_size(grid) == (1, 1, 1)
    @test grid.mapping isa EquiangularGnomonicCubedSpherePanel

    λ, φ, z = nodes(grid, Center(), Center(), Center())

    @test size(λ) == (N, N)
    @test size(φ) == (N, N)
    @test length(z) == 1
    @test all(isfinite, λ)
    @test all(isfinite, φ)

    radius_error = maximum((j, i) for j in 1:N, i in 1:N) do (j, i)
        x, y, z = spherical_shell_cartesian_node(i, j, 1, grid, Center(), Center(), Center())
        return abs(sqrt(x^2 + y^2 + z^2) - radius) / radius
    end

    cartesian_metric_error = maximum((j, i) for j in 1:N, i in 1:N) do (j, i)
        α = equiangular_gnomonic_coordinate(i, N, Center(), mapping.α)
        β = equiangular_gnomonic_coordinate(j, N, Center(), mapping.β)
        x, y, z = equiangular_gnomonic_panel_cartesian_node(α, β, radius)
        x_error = abs(grid.metrics.xᶜᶜᵃ[i, j] - x)
        y_error = abs(grid.metrics.yᶜᶜᵃ[i, j] - y)
        z_error = abs(grid.metrics.zᶜᶜᵃ[i, j] - z)
        return max(x_error, y_error, z_error) / radius
    end

    function numerical_gnomonic_metric_tensor(i, j, location)
        ℓx, ℓy = location

        α₀ = equiangular_gnomonic_coordinate(i, N, ℓx, mapping.α)
        β₀ = equiangular_gnomonic_coordinate(j, N, ℓy, mapping.β)

        # True central-difference derivative ∂x/∂α, ∂x/∂β with step h in (α, β).
        # The stored metric is g_ij = (∂x/∂α^i)·(∂x/∂α^j) per-α/β step (standard
        # differential-geometry convention), NOT per-matrix-index step. Operators
        # convert matrix-index spacing to α/β via computational_width.
        h = cbrt(eps(FT))  # balances FD truncation error against roundoff

        x⁺ᶦ, y⁺ᶦ, z⁺ᶦ = equiangular_gnomonic_panel_cartesian_node(α₀ + h, β₀, radius)
        x⁻ᶦ, y⁻ᶦ, z⁻ᶦ = equiangular_gnomonic_panel_cartesian_node(α₀ - h, β₀, radius)
        x⁺ʲ, y⁺ʲ, z⁺ʲ = equiangular_gnomonic_panel_cartesian_node(α₀, β₀ + h, radius)
        x⁻ʲ, y⁻ʲ, z⁻ʲ = equiangular_gnomonic_panel_cartesian_node(α₀, β₀ - h, radius)

        a₁x = (x⁺ᶦ - x⁻ᶦ) / (2h)
        a₁y = (y⁺ᶦ - y⁻ᶦ) / (2h)
        a₁z = (z⁺ᶦ - z⁻ᶦ) / (2h)
        a₂x = (x⁺ʲ - x⁻ʲ) / (2h)
        a₂y = (y⁺ʲ - y⁻ʲ) / (2h)
        a₂z = (z⁺ʲ - z⁻ʲ) / (2h)

        g₁₁ = a₁x^2 + a₁y^2 + a₁z^2
        g₁₂ = a₁x * a₂x + a₁y * a₂y + a₁z * a₂z
        g₂₂ = a₂x^2 + a₂y^2 + a₂z^2

        determinant = g₁₁ * g₂₂ - g₁₂^2
        J = sqrt(determinant)
        determinant⁻¹ = inv(determinant)

        g¹¹ = g₂₂ * determinant⁻¹
        g¹² = - g₁₂ * determinant⁻¹
        g²² = g₁₁ * determinant⁻¹

        G¹¹ = J * g¹¹
        G¹² = J * g¹²
        G²² = J * g²²

        return J, g₁₁, g₁₂, g₂₂, g¹¹, g¹², g²², G¹¹, G¹², G²²
    end

    metric_formula_error = maximum((j, i) for j in 1:N, i in 1:N) do (j, i)
        α = equiangular_gnomonic_coordinate(i, N, Center(), mapping.α)
        β = equiangular_gnomonic_coordinate(j, N, Center(), mapping.β)
        expected_metrics = equiangular_gnomonic_panel_metric_tensor(α, β, radius)
        stored_metrics = (grid.metrics.Jᶜᶜᵃ[i, j],
                          grid.metrics.g₁₁ᶜᶜᵃ[i, j],
                          grid.metrics.g₁₂ᶜᶜᵃ[i, j],
                          grid.metrics.g₂₂ᶜᶜᵃ[i, j],
                          grid.metrics.g¹¹ᶜᶜᵃ[i, j],
                          grid.metrics.g¹²ᶜᶜᵃ[i, j],
                          grid.metrics.g²²ᶜᶜᵃ[i, j],
                          grid.metrics.G¹¹ᶜᶜᵃ[i, j],
                          grid.metrics.G¹²ᶜᶜᵃ[i, j],
                          grid.metrics.G²²ᶜᶜᵃ[i, j])

        return maximum(abs(stored - expected) for (stored, expected) in zip(stored_metrics, expected_metrics))
    end

    numerical_metric_error = maximum((j, i) for j in 2:(N - 1), i in 2:(N - 1)) do (j, i)
        expected_metrics = numerical_gnomonic_metric_tensor(i, j, (Center(), Center()))
        stored_metrics = (grid.metrics.Jᶜᶜᵃ[i, j],
                          grid.metrics.g₁₁ᶜᶜᵃ[i, j],
                          grid.metrics.g₁₂ᶜᶜᵃ[i, j],
                          grid.metrics.g₂₂ᶜᶜᵃ[i, j],
                          grid.metrics.g¹¹ᶜᶜᵃ[i, j],
                          grid.metrics.g¹²ᶜᶜᵃ[i, j],
                          grid.metrics.g²²ᶜᶜᵃ[i, j],
                          grid.metrics.G¹¹ᶜᶜᵃ[i, j],
                          grid.metrics.G¹²ᶜᶜᵃ[i, j],
                          grid.metrics.G²²ᶜᶜᵃ[i, j])

        return maximum(abs(stored - expected) for (stored, expected) in zip(stored_metrics, expected_metrics))
    end

    fcc_metric_formula_error = maximum((j, i) for j in 1:N, i in 1:(N + 1)) do (j, i)
        α = equiangular_gnomonic_coordinate(i, N, Face(), mapping.α)
        β = equiangular_gnomonic_coordinate(j, N, Center(), mapping.β)
        J, _, _, _, g¹¹, g¹², _, G¹¹, G¹², _ =
            equiangular_gnomonic_panel_metric_tensor(α, β, radius)

        expected_metrics = (J, g¹¹, g¹², G¹¹, G¹²)
        stored_metrics = (grid.metrics.Jᶠᶜᵃ[i, j],
                          grid.metrics.g¹¹ᶠᶜᵃ[i, j],
                          grid.metrics.g¹²ᶠᶜᵃ[i, j],
                          grid.metrics.G¹¹ᶠᶜᵃ[i, j],
                          grid.metrics.G¹²ᶠᶜᵃ[i, j])

        return maximum(abs(stored - expected) for (stored, expected) in zip(stored_metrics, expected_metrics))
    end

    cfc_metric_formula_error = maximum((j, i) for j in 1:(N + 1), i in 1:N) do (j, i)
        α = equiangular_gnomonic_coordinate(i, N, Center(), mapping.α)
        β = equiangular_gnomonic_coordinate(j, N, Face(), mapping.β)
        J, _, _, _, _, g¹², g²², _, G¹², G²² =
            equiangular_gnomonic_panel_metric_tensor(α, β, radius)

        expected_metrics = (J, g¹², g²², G¹², G²²)
        stored_metrics = (grid.metrics.Jᶜᶠᵃ[i, j],
                          grid.metrics.g²¹ᶜᶠᵃ[i, j],
                          grid.metrics.g²²ᶜᶠᵃ[i, j],
                          grid.metrics.G²¹ᶜᶠᵃ[i, j],
                          grid.metrics.G²²ᶜᶠᵃ[i, j])

        return maximum(abs(stored - expected) for (stored, expected) in zip(stored_metrics, expected_metrics))
    end

    fcc_numerical_metric_error = maximum((j, i) for j in 2:(N - 1), i in 2:N) do (j, i)
        J, _, _, _, g¹¹, g¹², _, G¹¹, G¹², _ =
            numerical_gnomonic_metric_tensor(i, j, (Face(), Center()))

        expected_metrics = (J, g¹¹, g¹², G¹¹, G¹²)
        stored_metrics = (grid.metrics.Jᶠᶜᵃ[i, j],
                          grid.metrics.g¹¹ᶠᶜᵃ[i, j],
                          grid.metrics.g¹²ᶠᶜᵃ[i, j],
                          grid.metrics.G¹¹ᶠᶜᵃ[i, j],
                          grid.metrics.G¹²ᶠᶜᵃ[i, j])

        return maximum(abs(stored - expected) for (stored, expected) in zip(stored_metrics, expected_metrics))
    end

    cfc_numerical_metric_error = maximum((j, i) for j in 2:N, i in 2:(N - 1)) do (j, i)
        J, _, _, _, _, g¹², g²², _, G¹², G²² =
            numerical_gnomonic_metric_tensor(i, j, (Center(), Face()))

        expected_metrics = (J, g¹², g²², G¹², G²²)
        stored_metrics = (grid.metrics.Jᶜᶠᵃ[i, j],
                          grid.metrics.g²¹ᶜᶠᵃ[i, j],
                          grid.metrics.g²²ᶜᶠᵃ[i, j],
                          grid.metrics.G²¹ᶜᶠᵃ[i, j],
                          grid.metrics.G²²ᶜᶠᵃ[i, j])

        return maximum(abs(stored - expected) for (stored, expected) in zip(stored_metrics, expected_metrics))
    end

    u₁ = convert(FT, 2)
    u₂ = - convert(FT, 3)
    Δα = (mapping.α[2] - mapping.α[1]) / N
    Δβ = (mapping.β[2] - mapping.β[1]) / N

    fcc_hodge_error = maximum((j, i) for j in 1:N, i in 1:(N + 1)) do (j, i)
        expected_flux = grid.metrics.G¹¹ᶠᶜᵃ[i, j] * u₁ + grid.metrics.G¹²ᶠᶜᵃ[i, j] * u₂
        expected_volume_flux = Δzᶠᶜᶜ(i, j, 1, grid) * Δβ * expected_flux
        flux = covariant_to_contravariant_flux_uᶠᶜᶜ(i, j, 1, grid, u₁, u₂)
        volume_flux = covariant_to_volume_flux_uᶠᶜᶜ(i, j, 1, grid, u₁, u₂)
        return max(abs(flux - expected_flux), abs(volume_flux - expected_volume_flux))
    end

    cfc_hodge_error = maximum((j, i) for j in 1:(N + 1), i in 1:N) do (j, i)
        expected_flux = grid.metrics.G²¹ᶜᶠᵃ[i, j] * u₁ + grid.metrics.G²²ᶜᶠᵃ[i, j] * u₂
        expected_volume_flux = Δzᶜᶠᶜ(i, j, 1, grid) * Δα * expected_flux
        flux = covariant_to_contravariant_flux_vᶜᶠᶜ(i, j, 1, grid, u₁, u₂)
        volume_flux = covariant_to_volume_flux_vᶜᶠᶜ(i, j, 1, grid, u₁, u₂)
        return max(abs(flux - expected_flux), abs(volume_flux - expected_volume_flux))
    end

    u₁_field = fill(u₁, N + 1, N, 1)
    u₂_field = fill(u₂, N, N + 1, 1)

    fcc_hodge_array_error = maximum((j, i) for j in 1:N, i in 2:N) do (j, i)
        expected_flux = grid.metrics.G¹¹ᶠᶜᵃ[i, j] * u₁ + grid.metrics.G¹²ᶠᶜᵃ[i, j] * u₂
        flux = covariant_to_contravariant_flux_uᶠᶜᶜ(i, j, 1, grid, u₁_field, u₂_field)
        return abs(flux - expected_flux)
    end

    cfc_hodge_array_error = maximum((j, i) for j in 2:N, i in 1:N) do (j, i)
        expected_flux = grid.metrics.G²¹ᶜᶠᵃ[i, j] * u₁ + grid.metrics.G²²ᶜᶠᵃ[i, j] * u₂
        flux = covariant_to_contravariant_flux_vᶜᶠᶜ(i, j, 1, grid, u₁_field, u₂_field)
        return abs(flux - expected_flux)
    end

    total_area = sum(Az(i, j, 1, grid, Center(), Center(), Center()) for j in 1:N, i in 1:N)
    expected_area = radius^2 * equiangular_gnomonic_panel_solid_angle(mapping.α[1], mapping.α[2], mapping.β[1], mapping.β[2])
    one_sixth_sphere_area = convert(FT, 4π) * radius^2 / convert(FT, 6)

    maximum_off_diagonal = maximum(abs(grid.metrics.g₁₂ᶜᶜᵃ[i, j]) for j in 1:N, i in 1:N)
    maximum_metric_scale = maximum(sqrt(grid.metrics.g₁₁ᶜᶜᵃ[i, j] * grid.metrics.g₂₂ᶜᶜᵃ[i, j]) for j in 1:N, i in 1:N)
    minimum_metric_determinant = minimum((grid.metrics.g₁₁ᶜᶜᵃ[i, j] * grid.metrics.g₂₂ᶜᶜᵃ[i, j] - grid.metrics.g₁₂ᶜᶜᵃ[i, j]^2) for j in 1:N, i in 1:N)

    @test radius_error ≤ 100eps(FT)
    @test cartesian_metric_error ≤ 100eps(FT)
    @test metric_formula_error ≤ 100eps(FT)
    # numerical_*_metric_error uses central-difference derivatives with step
    # h = cbrt(eps(FT)); central-difference truncation is O(h²) ≈ eps(FT)^(2/3),
    # not roundoff-tight. Tolerance scaled to the metric magnitude (typical
    # g_ij ~ radius² ≈ 9 for the gnomonic panel tests).
    numerical_metric_tolerance = convert(FT, 100) * eps(FT)^(2//3) * radius^2
    @test numerical_metric_error ≤ numerical_metric_tolerance
    @test fcc_metric_formula_error ≤ 100eps(FT)
    @test cfc_metric_formula_error ≤ 100eps(FT)
    @test fcc_numerical_metric_error ≤ numerical_metric_tolerance
    @test cfc_numerical_metric_error ≤ numerical_metric_tolerance
    @test fcc_hodge_error ≤ 100eps(FT)
    @test cfc_hodge_error ≤ 100eps(FT)
    @test fcc_hodge_array_error ≤ 100eps(FT)
    @test cfc_hodge_array_error ≤ 100eps(FT)
    @test total_area ≈ expected_area rtol=100eps(FT)
    @test total_area ≈ one_sixth_sphere_area rtol=100eps(FT)
    @test maximum_off_diagonal / maximum_metric_scale > convert(FT, 1//1000)
    @test minimum_metric_determinant > zero(FT)
    @test all(volume(i, j, 1, grid, Center(), Center(), Center()) > zero(FT) for j in 1:N, i in 1:N)

    cpu_grid = on_architecture(CPU(), grid)
    @test cpu_grid isa SphericalShellGrid
    @test size(cpu_grid) == size(grid)
    @test topology(cpu_grid) == topology(grid)
    @test cpu_grid.metrics.G¹²ᶜᶜᵃ == grid.metrics.G¹²ᶜᶜᵃ
    @test cpu_grid.metrics.G¹²ᶠᶜᵃ == grid.metrics.G¹²ᶠᶜᵃ
    @test cpu_grid.metrics.G²¹ᶜᶠᵃ == grid.metrics.G²¹ᶜᶠᵃ

    return nothing
end

function test_equiangular_gnomonic_tracer_advection_operator(FT, N)
    radius = convert(FT, 3)
    mapping = EquiangularGnomonicCubedSpherePanel(FT)
    grid = SphericalShellGrid(CPU(), FT; mapping, size=(N, N, 1), z=(zero(FT), one(FT)), radius, halo=(1, 1, 1))
    u₁ = Array{FT}(undef, N + 1, N, 1)
    u₂ = Array{FT}(undef, N, N + 1, 1)
    c₀ = convert(FT, 5//2)
    c = fill(c₀, N, N, 1)
    U = (u = u₁, v = u₂, w = ZeroField())

    for j in 1:N, i in 1:(N + 1)
        u₁[i, j, 1] = convert(FT, i) / convert(FT, N + 1) +
                      convert(FT, 1//3) * convert(FT, j) / convert(FT, N)
    end

    for j in 1:(N + 1), i in 1:N
        u₂[i, j, 1] = convert(FT, 2//3) * convert(FT, i) / convert(FT, N) -
                      convert(FT, j) / convert(FT, N + 1)
    end

    Δα = (mapping.α[2] - mapping.α[1]) / N
    Δβ = (mapping.β[2] - mapping.β[1]) / N
    quarter = convert(FT, 1//4)

    u₂_on_fcc(i, j) = quarter * (u₂[i-1, j, 1] + u₂[i, j, 1] +
                                 u₂[i-1, j+1, 1] + u₂[i, j+1, 1])

    u₁_on_cfc(i, j) = quarter * (u₁[i, j-1, 1] + u₁[i+1, j-1, 1] +
                                 u₁[i, j, 1] + u₁[i+1, j, 1])

    volume_flux_x(i, j) = Δzᶠᶜᶜ(i, j, 1, grid) * Δβ *
                          (grid.metrics.G¹¹ᶠᶜᵃ[i, j] * u₁[i, j, 1] +
                           grid.metrics.G¹²ᶠᶜᵃ[i, j] * u₂_on_fcc(i, j))

    volume_flux_y(i, j) = Δzᶜᶠᶜ(i, j, 1, grid) * Δα *
                          (grid.metrics.G²¹ᶜᶠᵃ[i, j] * u₁_on_cfc(i, j) +
                           grid.metrics.G²²ᶜᶠᵃ[i, j] * u₂[i, j, 1])

    advection = Centered(FT)

    divergence_formula_error = maximum((j, i) for j in 2:(N - 1), i in 2:(N - 1)) do (j, i)
        computed_divergence = div_Uc(i, j, 1, grid, advection, U, c)
        expected_divergence = c₀ * (volume_flux_x(i+1, j) - volume_flux_x(i, j) +
                                    volume_flux_y(i, j+1) - volume_flux_y(i, j)) /
                              volume(i, j, 1, grid, Center(), Center(), Center())

        return abs(computed_divergence - expected_divergence)
    end

    integrated_divergence = sum(volume(i, j, 1, grid, Center(), Center(), Center()) *
                                div_Uc(i, j, 1, grid, advection, U, c)
                                for j in 2:(N - 1), i in 2:(N - 1))

    boundary_flux = c₀ * (sum(volume_flux_x(N, j) - volume_flux_x(2, j) for j in 2:(N - 1)) +
                          sum(volume_flux_y(i, N) - volume_flux_y(i, 2) for i in 2:(N - 1)))

    scale = maximum(abs(c₀ * volume_flux_x(i, j)) for j in 2:(N - 1), i in 2:N)
    scale = max(scale, maximum(abs(c₀ * volume_flux_y(i, j)) for j in 2:N, i in 2:(N - 1)))

    @test divergence_formula_error ≤ 1000eps(FT) * scale
    @test abs(integrated_divergence - boundary_flux) ≤ 1000eps(FT) * scale

    return nothing
end

function test_equiangular_gnomonic_vector_invariant_primitives(FT, N)
    radius = convert(FT, 3)
    mapping = EquiangularGnomonicCubedSpherePanel(FT)
    grid = SphericalShellGrid(CPU(), FT; mapping, size=(N, N, 1), z=(zero(FT), one(FT)), radius, halo=(1, 1, 1))

    u₁₀ = convert(FT, 3//7)
    u₁α = - convert(FT, 2//5)
    u₁β = convert(FT, 5//11)
    u₂₀ = - convert(FT, 4//9)
    u₂α = convert(FT, 7//13)
    u₂β = convert(FT, 2//3)

    u₁_function(α, β) = u₁₀ + u₁α * α + u₁β * β
    u₂_function(α, β) = u₂₀ + u₂α * α + u₂β * β

    function expected_contravariant_velocity_u(i, j)
        α = equiangular_gnomonic_coordinate(i, N, Face(), mapping.α)
        β = equiangular_gnomonic_coordinate(j, N, Center(), mapping.β)
        _, _, _, _, g¹¹, g¹² = equiangular_gnomonic_panel_metric_tensor(α, β, radius)
        return g¹¹ * u₁_function(α, β) + g¹² * u₂_function(α, β)
    end

    function expected_contravariant_velocity_v(i, j)
        α = equiangular_gnomonic_coordinate(i, N, Center(), mapping.α)
        β = equiangular_gnomonic_coordinate(j, N, Face(), mapping.β)
        _, _, _, _, _, g¹², g²² = equiangular_gnomonic_panel_metric_tensor(α, β, radius)
        return g¹² * u₁_function(α, β) + g²² * u₂_function(α, β)
    end

    expected_contravariant_velocity_uᶠᶠ(i, j) =
        convert(FT, 1//2) * (expected_contravariant_velocity_u(i, j-1) +
                             expected_contravariant_velocity_u(i, j))

    expected_contravariant_velocity_vᶠᶠ(i, j) =
        convert(FT, 1//2) * (expected_contravariant_velocity_v(i-1, j) +
                             expected_contravariant_velocity_v(i, j))

    function expected_kinetic_energy(i, j)
        α = equiangular_gnomonic_coordinate(i, N, Center(), mapping.α)
        β = equiangular_gnomonic_coordinate(j, N, Center(), mapping.β)
        _, _, _, _, g¹¹, g¹², g²² = equiangular_gnomonic_panel_metric_tensor(α, β, radius)
        u₁ᶜᶜᶜ = u₁_function(α, β)
        u₂ᶜᶜᶜ = u₂_function(α, β)

        return convert(FT, 1//2) * (g¹¹ * u₁ᶜᶜᶜ^2 +
                                    (g¹² + g¹²) * u₁ᶜᶜᶜ * u₂ᶜᶜᶜ +
                                    g²² * u₂ᶜᶜᶜ^2)
    end

    u₁ = Array{FT}(undef, N + 1, N, 1)
    u₂ = Array{FT}(undef, N, N + 1, 1)

    for j in 1:N, i in 1:(N + 1)
        α = equiangular_gnomonic_coordinate(i, N, Face(), mapping.α)
        β = equiangular_gnomonic_coordinate(j, N, Center(), mapping.β)
        u₁[i, j, 1] = u₁_function(α, β)
    end

    for j in 1:(N + 1), i in 1:N
        α = equiangular_gnomonic_coordinate(i, N, Center(), mapping.α)
        β = equiangular_gnomonic_coordinate(j, N, Face(), mapping.β)
        u₂[i, j, 1] = u₂_function(α, β)
    end

    kinetic_energy_error = maximum((j, i) for j in 1:N, i in 1:N) do (j, i)
        computed_kinetic_energy = covariant_kinetic_energyᶜᶜᶜ(i, j, 1, grid, u₁, u₂)
        return abs(computed_kinetic_energy - expected_kinetic_energy(i, j))
    end

    Δα = (mapping.α[2] - mapping.α[1]) / N
    Δβ = (mapping.β[2] - mapping.β[1]) / N
    expected_circulation = Δα * Δβ * (u₂α - u₁β)
    expected_vorticity_component = u₂α - u₁β

    contravariant_velocity_u_error = maximum((j, i) for j in 2:(N - 1), i in 2:(N - 1)) do (j, i)
        computed_velocity = covariant_to_contravariant_velocity_uᶠᶜᶜ(i, j, 1, grid, u₁, u₂)
        return abs(computed_velocity - expected_contravariant_velocity_u(i, j))
    end

    contravariant_velocity_v_error = maximum((j, i) for j in 2:(N - 1), i in 2:(N - 1)) do (j, i)
        computed_velocity = covariant_to_contravariant_velocity_vᶜᶠᶜ(i, j, 1, grid, u₁, u₂)
        return abs(computed_velocity - expected_contravariant_velocity_v(i, j))
    end

    bernoulli_head_u_error = maximum((j, i) for j in 1:N, i in 2:N) do (j, i)
        expected_bernoulli_head = (expected_kinetic_energy(i, j) - expected_kinetic_energy(i-1, j)) / Δα
        computed_bernoulli_head = covariant_bernoulli_head_uᶠᶜᶜ(i, j, 1, grid, u₁, u₂)
        return abs(computed_bernoulli_head - expected_bernoulli_head)
    end

    bernoulli_head_v_error = maximum((j, i) for j in 2:N, i in 1:N) do (j, i)
        expected_bernoulli_head = (expected_kinetic_energy(i, j) - expected_kinetic_energy(i, j-1)) / Δβ
        computed_bernoulli_head = covariant_bernoulli_head_vᶜᶠᶜ(i, j, 1, grid, u₁, u₂)
        return abs(computed_bernoulli_head - expected_bernoulli_head)
    end

    circulation_error = maximum((j, i) for j in 2:N, i in 2:N) do (j, i)
        computed_circulation = covariant_vertical_circulationᶠᶠᶜ(i, j, 1, grid, u₁, u₂)
        return abs(computed_circulation - expected_circulation)
    end

    vorticity_component_error = maximum((j, i) for j in 2:N, i in 2:N) do (j, i)
        computed_vorticity = covariant_vertical_vorticity_componentᶠᶠᶜ(i, j, 1, grid, u₁, u₂)
        return abs(computed_vorticity - expected_vorticity_component)
    end

    vorticity_error = maximum((j, i) for j in 2:N, i in 2:N) do (j, i)
        expected_vorticity = expected_circulation / Az(i, j, 1, grid, Face(), Face(), Center())
        computed_vorticity = covariant_vertical_vorticityᶠᶠᶜ(i, j, 1, grid, u₁, u₂)
        return abs(computed_vorticity - expected_vorticity)
    end

    rotational_advection_u_error = maximum((j, i) for j in 2:(N - 1), i in 2:N) do (j, i)
        expected_advection = - convert(FT, 1//2) * expected_vorticity_component *
                             (expected_contravariant_velocity_vᶠᶠ(i, j) +
                              expected_contravariant_velocity_vᶠᶠ(i, j+1))
        computed_advection = covariant_rotational_advection_uᶠᶜᶜ(i, j, 1, grid, u₁, u₂)
        return abs(computed_advection - expected_advection)
    end

    rotational_advection_v_error = maximum((j, i) for j in 2:N, i in 2:(N - 1)) do (j, i)
        expected_advection = + convert(FT, 1//2) * expected_vorticity_component *
                             (expected_contravariant_velocity_uᶠᶠ(i, j) +
                              expected_contravariant_velocity_uᶠᶠ(i+1, j))
        computed_advection = covariant_rotational_advection_vᶜᶠᶜ(i, j, 1, grid, u₁, u₂)
        return abs(computed_advection - expected_advection)
    end

    model = HydrostaticFreeSurfaceModel(grid;
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing)

    set!(model, u = u₁, v = u₂)
    ζ_operation = vertical_vorticity(model)
    ζ = Field(ζ_operation)
    compute!(ζ)

    diagnostic_vorticity_error = maximum((j, i) for j in 2:N, i in 2:N) do (j, i)
        expected_vorticity = expected_circulation / Az(i, j, 1, grid, Face(), Face(), Center())
        return abs(ζ[i, j, 1] - expected_vorticity)
    end

    contravariant_operations = contravariant_velocities(model)
    diagnostic_contravariant_u = Field(contravariant_operations.u)
    diagnostic_contravariant_v = Field(contravariant_operations.v)
    compute!(diagnostic_contravariant_u)
    compute!(diagnostic_contravariant_v)

    contravariant_u_error = maximum((j, i) for j in 2:(N - 1), i in 2:(N - 1)) do (j, i)
        return abs(diagnostic_contravariant_u[i, j, 1] - expected_contravariant_velocity_u(i, j))
    end

    contravariant_v_error = maximum((j, i) for j in 2:(N - 1), i in 2:(N - 1)) do (j, i)
        return abs(diagnostic_contravariant_v[i, j, 1] - expected_contravariant_velocity_v(i, j))
    end

    diagnostic_kinetic_energy = Field(kinetic_energy(model))
    compute!(diagnostic_kinetic_energy)

    kinetic_energy_diagnostic_error = maximum((j, i) for j in 2:(N - 1), i in 2:(N - 1)) do (j, i)
        return abs(diagnostic_kinetic_energy[i, j, 1] - expected_kinetic_energy(i, j))
    end

    diagnostic_relative_vorticity = Field(relative_vorticity(model))
    compute!(diagnostic_relative_vorticity)

    relative_vorticity_error = maximum((j, i) for j in 2:N, i in 2:N) do (j, i)
        return abs(diagnostic_relative_vorticity[i, j, 1] - expected_vorticity_component)
    end

    kinetic_energy_scale = maximum(abs(covariant_kinetic_energyᶜᶜᶜ(i, j, 1, grid, u₁, u₂)) for j in 2:(N - 1), i in 2:(N - 1))
    contravariant_velocity_u_scale = maximum(abs(covariant_to_contravariant_velocity_uᶠᶜᶜ(i, j, 1, grid, u₁, u₂)) for j in 2:(N - 1), i in 2:(N - 1))
    contravariant_velocity_v_scale = maximum(abs(covariant_to_contravariant_velocity_vᶜᶠᶜ(i, j, 1, grid, u₁, u₂)) for j in 2:(N - 1), i in 2:(N - 1))
    bernoulli_head_u_scale = maximum(abs(covariant_bernoulli_head_uᶠᶜᶜ(i, j, 1, grid, u₁, u₂)) for j in 2:(N - 1), i in 2:(N - 1))
    bernoulli_head_v_scale = maximum(abs(covariant_bernoulli_head_vᶜᶠᶜ(i, j, 1, grid, u₁, u₂)) for j in 2:(N - 1), i in 2:(N - 1))
    circulation_scale = abs(expected_circulation)
    vorticity_component_scale = abs(expected_vorticity_component)
    vorticity_scale = maximum(abs(covariant_vertical_vorticityᶠᶠᶜ(i, j, 1, grid, u₁, u₂)) for j in 2:N, i in 2:N)
    rotational_advection_u_scale = maximum(abs(covariant_rotational_advection_uᶠᶜᶜ(i, j, 1, grid, u₁, u₂)) for j in 2:(N - 1), i in 2:N)
    rotational_advection_v_scale = maximum(abs(covariant_rotational_advection_vᶜᶠᶜ(i, j, 1, grid, u₁, u₂)) for j in 2:N, i in 2:(N - 1))

    @test ζ_operation.kernel_function === covariant_vertical_vorticityᶠᶠᶜ
    @test contravariant_operations.u.kernel_function === covariant_to_contravariant_velocity_uᶠᶜᶜ
    @test contravariant_operations.v.kernel_function === covariant_to_contravariant_velocity_vᶜᶠᶜ
    @test diagnostic_kinetic_energy.grid === grid
    @test kinetic_energy(model).kernel_function === covariant_kinetic_energyᶜᶜᶜ
    @test relative_vorticity(model).kernel_function === covariant_vertical_vorticity_componentᶠᶠᶜ
    @test kinetic_energy_error ≤ 1000eps(FT) * kinetic_energy_scale
    @test contravariant_velocity_u_error ≤ 1000eps(FT) * contravariant_velocity_u_scale
    @test contravariant_velocity_v_error ≤ 1000eps(FT) * contravariant_velocity_v_scale
    @test bernoulli_head_u_error ≤ 1000eps(FT) * bernoulli_head_u_scale
    @test bernoulli_head_v_error ≤ 1000eps(FT) * bernoulli_head_v_scale
    @test circulation_error ≤ 1000eps(FT) * circulation_scale
    @test vorticity_component_error ≤ 1000eps(FT) * vorticity_component_scale
    @test vorticity_error ≤ 1000eps(FT) * vorticity_scale
    @test rotational_advection_u_error ≤ 1000eps(FT) * rotational_advection_u_scale
    @test rotational_advection_v_error ≤ 1000eps(FT) * rotational_advection_v_scale
    @test diagnostic_vorticity_error ≤ 1000eps(FT) * vorticity_scale
    @test contravariant_u_error ≤ 1000eps(FT) * contravariant_velocity_u_scale
    @test contravariant_v_error ≤ 1000eps(FT) * contravariant_velocity_v_scale
    @test kinetic_energy_diagnostic_error ≤ 1000eps(FT) * kinetic_energy_scale
    @test relative_vorticity_error ≤ 1000eps(FT) * vorticity_component_scale

    return nothing
end

function test_equiangular_gnomonic_covariant_gradient(FT, N)
    radius = convert(FT, 3)
    mapping = EquiangularGnomonicCubedSpherePanel(FT)
    grid = SphericalShellGrid(CPU(), FT; mapping, size=(N, N, 1), z=(zero(FT), one(FT)), radius, halo=(1, 1, 1))

    p₀ = convert(FT, 2//7)
    pα = - convert(FT, 3//5)
    pβ = convert(FT, 4//9)
    pαα = convert(FT, 5//13)
    pββ = - convert(FT, 2//11)
    pαβ = convert(FT, 7//17)

    scalar_function(α, β) = p₀ + pα * α + pβ * β + pαα * α^2 + pββ * β^2 + pαβ * α * β
    scalar_gradient_α(α, β) = pα + (pαα + pαα) * α + pαβ * β
    scalar_gradient_β(α, β) = pβ + (pββ + pββ) * β + pαβ * α

    ϕ = Array{FT}(undef, N, N, 1)

    for j in 1:N, i in 1:N
        α = equiangular_gnomonic_coordinate(i, N, Center(), mapping.α)
        β = equiangular_gnomonic_coordinate(j, N, Center(), mapping.β)
        ϕ[i, j, 1] = scalar_function(α, β)
    end

    gradient_x_error = maximum((j, i) for j in 1:N, i in 2:N) do (j, i)
        α = equiangular_gnomonic_coordinate(i, N, Face(), mapping.α)
        β = equiangular_gnomonic_coordinate(j, N, Center(), mapping.β)
        computed_gradient = covariant_gradient_xᶠᶜᶜ(i, j, 1, grid, ϕ)
        return abs(computed_gradient - scalar_gradient_α(α, β))
    end

    gradient_y_error = maximum((j, i) for j in 2:N, i in 1:N) do (j, i)
        α = equiangular_gnomonic_coordinate(i, N, Center(), mapping.α)
        β = equiangular_gnomonic_coordinate(j, N, Face(), mapping.β)
        computed_gradient = covariant_gradient_yᶜᶠᶜ(i, j, 1, grid, ϕ)
        return abs(computed_gradient - scalar_gradient_β(α, β))
    end

    u₁ = zeros(FT, N + 1, N, 1)
    u₂ = zeros(FT, N, N + 1, 1)

    for j in 1:N, i in 2:N
        u₁[i, j, 1] = covariant_gradient_xᶠᶜᶜ(i, j, 1, grid, ϕ)
    end

    for j in 2:N, i in 1:N
        u₂[i, j, 1] = covariant_gradient_yᶜᶠᶜ(i, j, 1, grid, ϕ)
    end

    gradient_circulation_error = maximum(abs(covariant_vertical_circulationᶠᶠᶜ(i, j, 1, grid, u₁, u₂))
                                         for j in 2:N, i in 2:N)

    gradient_scale = max(maximum(abs(covariant_gradient_xᶠᶜᶜ(i, j, 1, grid, ϕ)) for j in 1:N, i in 2:N),
                         maximum(abs(covariant_gradient_yᶜᶠᶜ(i, j, 1, grid, ϕ)) for j in 2:N, i in 1:N))

    @test gradient_x_error ≤ 1000eps(FT) * gradient_scale
    @test gradient_y_error ≤ 1000eps(FT) * gradient_scale
    @test gradient_circulation_error ≤ 1000eps(FT) * gradient_scale

    return nothing
end

function test_octahealpix_covariant_gradient(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    p₀ = convert(FT, 2//7)
    pᵢ = - convert(FT, 3//5)
    pⱼ = convert(FT, 4//9)
    pᵢᵢ = convert(FT, 5//13)
    pⱼⱼ = - convert(FT, 2//11)
    pᵢⱼ = convert(FT, 7//17)

    scalar_function(i, j) = p₀ + pᵢ * i + pⱼ * j + pᵢᵢ * i^2 + pⱼⱼ * j^2 + pᵢⱼ * i * j
    scalar_gradient_i(i, j) = pᵢ + pᵢᵢ * (2i - one(FT)) + pᵢⱼ * j
    scalar_gradient_j(i, j) = pⱼ + pⱼⱼ * (2j - one(FT)) + pᵢⱼ * i

    ϕ = Array{FT}(undef, 2N, 2N, 1)

    for j in 1:(2N), i in 1:(2N)
        ϕ[i, j, 1] = scalar_function(convert(FT, i), convert(FT, j))
    end

    interior_indices = vcat(collect(2:(N - 1)),
                            collect((N + 2):(2N - 1)))
    circulation_indices = vcat(collect(3:(N - 1)),
                               collect((N + 3):(2N - 1)))

    gradient_x_error = zero(FT)
    gradient_y_error = zero(FT)

    for j in interior_indices, i in interior_indices
        computed_gradient = covariant_gradient_xᶠᶜᶜ(i, j, 1, grid, ϕ)
        expected_gradient = scalar_gradient_i(convert(FT, i), convert(FT, j))
        gradient_x_error = max(gradient_x_error, abs(computed_gradient - expected_gradient))
    end

    for j in interior_indices, i in interior_indices
        computed_gradient = covariant_gradient_yᶜᶠᶜ(i, j, 1, grid, ϕ)
        expected_gradient = scalar_gradient_j(convert(FT, i), convert(FT, j))
        gradient_y_error = max(gradient_y_error, abs(computed_gradient - expected_gradient))
    end

    u₁ = zeros(FT, 2N + 1, 2N, 1)
    u₂ = zeros(FT, 2N, 2N + 1, 1)

    for j in interior_indices, i in interior_indices
        u₁[i, j, 1] = covariant_gradient_xᶠᶜᶜ(i, j, 1, grid, ϕ)
        u₂[i, j, 1] = covariant_gradient_yᶜᶠᶜ(i, j, 1, grid, ϕ)
    end

    gradient_circulation_error = zero(FT)

    for j in circulation_indices, i in circulation_indices
        gradient_circulation_error = max(gradient_circulation_error,
                                         abs(covariant_vertical_circulationᶠᶠᶜ(i, j, 1, grid, u₁, u₂)))
    end

    gradient_scale = max(maximum(abs(covariant_gradient_xᶠᶜᶜ(i, j, 1, grid, ϕ)) for j in interior_indices, i in interior_indices),
                         maximum(abs(covariant_gradient_yᶜᶠᶜ(i, j, 1, grid, ϕ)) for j in interior_indices, i in interior_indices))

    @test gradient_x_error ≤ 100eps(FT) * gradient_scale
    @test gradient_y_error ≤ 100eps(FT) * gradient_scale
    @test gradient_circulation_error ≤ 100eps(FT) * gradient_scale

    return nothing
end

function test_octahealpix_covariant_hodge_flux_operators(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    u₁ = convert(FT, 2)
    u₂ = - convert(FT, 3)
    u₁_field = fill(u₁, 2N + 1, 2N, 1)
    u₂_field = fill(u₂, 2N, 2N + 1, 1)

    interior_indices = vcat(collect(2:(N - 1)),
                            collect((N + 2):(2N - 1)))

    fcc_flux_error = zero(FT)
    cfc_flux_error = zero(FT)
    fcc_volume_flux_error = zero(FT)
    cfc_volume_flux_error = zero(FT)
    fcc_array_flux_error = zero(FT)
    cfc_array_flux_error = zero(FT)
    flux_scale = one(FT)
    volume_flux_scale = one(FT)

    for j in interior_indices, i in interior_indices
        expected_flux = grid.metrics.G¹¹ᶠᶜᵃ[i, j] * u₁ + grid.metrics.G¹²ᶠᶜᵃ[i, j] * u₂
        computed_flux = covariant_to_contravariant_flux_uᶠᶜᶜ(i, j, 1, grid, u₁, u₂)
        computed_volume_flux = covariant_to_volume_flux_uᶠᶜᶜ(i, j, 1, grid, u₁, u₂)
        expected_volume_flux = Δzᶠᶜᶜ(i, j, 1, grid) * expected_flux
        array_flux = covariant_to_contravariant_flux_uᶠᶜᶜ(i, j, 1, grid, u₁_field, u₂_field)

        fcc_flux_error = max(fcc_flux_error, abs(computed_flux - expected_flux))
        fcc_volume_flux_error = max(fcc_volume_flux_error, abs(computed_volume_flux - expected_volume_flux))
        fcc_array_flux_error = max(fcc_array_flux_error, abs(array_flux - expected_flux))
        flux_scale = max(flux_scale, abs(expected_flux), abs(computed_flux), abs(array_flux))
        volume_flux_scale = max(volume_flux_scale, abs(expected_volume_flux), abs(computed_volume_flux))
    end

    for j in interior_indices, i in interior_indices
        expected_flux = grid.metrics.G²¹ᶜᶠᵃ[i, j] * u₁ + grid.metrics.G²²ᶜᶠᵃ[i, j] * u₂
        computed_flux = covariant_to_contravariant_flux_vᶜᶠᶜ(i, j, 1, grid, u₁, u₂)
        computed_volume_flux = covariant_to_volume_flux_vᶜᶠᶜ(i, j, 1, grid, u₁, u₂)
        expected_volume_flux = Δzᶜᶠᶜ(i, j, 1, grid) * expected_flux
        array_flux = covariant_to_contravariant_flux_vᶜᶠᶜ(i, j, 1, grid, u₁_field, u₂_field)

        cfc_flux_error = max(cfc_flux_error, abs(computed_flux - expected_flux))
        cfc_volume_flux_error = max(cfc_volume_flux_error, abs(computed_volume_flux - expected_volume_flux))
        cfc_array_flux_error = max(cfc_array_flux_error, abs(array_flux - expected_flux))
        flux_scale = max(flux_scale, abs(expected_flux), abs(computed_flux), abs(array_flux))
        volume_flux_scale = max(volume_flux_scale, abs(expected_volume_flux), abs(computed_volume_flux))
    end

    @test fcc_flux_error ≤ 100eps(FT) * flux_scale
    @test cfc_flux_error ≤ 100eps(FT) * flux_scale
    @test fcc_volume_flux_error ≤ 100eps(FT) * volume_flux_scale
    @test cfc_volume_flux_error ≤ 100eps(FT) * volume_flux_scale
    @test fcc_array_flux_error ≤ 100eps(FT) * flux_scale
    @test cfc_array_flux_error ≤ 100eps(FT) * flux_scale

    return nothing
end

function test_octahealpix_covariant_hodge_flux_operators_with_affine_fields(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    a₀ = convert(FT, 2//7)
    aᵢ = - convert(FT, 3//11)
    aⱼ = convert(FT, 5//13)
    b₀ = - convert(FT, 4//9)
    bᵢ = convert(FT, 7//15)
    bⱼ = - convert(FT, 1//6)

    u₁_field = Array{FT}(undef, 2N + 1, 2N, 1)
    u₂_field = Array{FT}(undef, 2N, 2N + 1, 1)

    for j in 1:(2N), i in 1:(2N + 1)
        u₁_field[i, j, 1] = a₀ + aᵢ * convert(FT, i) + aⱼ * convert(FT, j)
    end

    for j in 1:(2N + 1), i in 1:(2N)
        u₂_field[i, j, 1] = b₀ + bᵢ * convert(FT, i) + bⱼ * convert(FT, j)
    end

    interior_indices = vcat(collect(2:(N - 1)),
                            collect((N + 2):(2N - 1)))
    quarter = convert(FT, 1//4)

    fcc_flux_error = zero(FT)
    cfc_flux_error = zero(FT)
    fcc_volume_flux_error = zero(FT)
    cfc_volume_flux_error = zero(FT)
    flux_scale = one(FT)
    volume_flux_scale = one(FT)

    for j in interior_indices, i in interior_indices
        interpolated_u₂ = quarter * (u₂_field[i - 1, j,     1] + u₂_field[i, j,     1] +
                                     u₂_field[i - 1, j + 1, 1] + u₂_field[i, j + 1, 1])
        expected_flux = grid.metrics.G¹¹ᶠᶜᵃ[i, j] * u₁_field[i, j, 1] +
                        grid.metrics.G¹²ᶠᶜᵃ[i, j] * interpolated_u₂
        computed_flux = covariant_to_contravariant_flux_uᶠᶜᶜ(i, j, 1, grid, u₁_field, u₂_field)
        expected_volume_flux = Δzᶠᶜᶜ(i, j, 1, grid) * expected_flux
        computed_volume_flux = covariant_to_volume_flux_uᶠᶜᶜ(i, j, 1, grid, u₁_field, u₂_field)

        fcc_flux_error = max(fcc_flux_error, abs(computed_flux - expected_flux))
        fcc_volume_flux_error = max(fcc_volume_flux_error, abs(computed_volume_flux - expected_volume_flux))
        flux_scale = max(flux_scale, abs(expected_flux), abs(computed_flux))
        volume_flux_scale = max(volume_flux_scale, abs(expected_volume_flux), abs(computed_volume_flux))
    end

    for j in interior_indices, i in interior_indices
        interpolated_u₁ = quarter * (u₁_field[i,     j - 1, 1] + u₁_field[i + 1, j - 1, 1] +
                                     u₁_field[i,     j,     1] + u₁_field[i + 1, j,     1])
        expected_flux = grid.metrics.G²¹ᶜᶠᵃ[i, j] * interpolated_u₁ +
                        grid.metrics.G²²ᶜᶠᵃ[i, j] * u₂_field[i, j, 1]
        computed_flux = covariant_to_contravariant_flux_vᶜᶠᶜ(i, j, 1, grid, u₁_field, u₂_field)
        expected_volume_flux = Δzᶜᶠᶜ(i, j, 1, grid) * expected_flux
        computed_volume_flux = covariant_to_volume_flux_vᶜᶠᶜ(i, j, 1, grid, u₁_field, u₂_field)

        cfc_flux_error = max(cfc_flux_error, abs(computed_flux - expected_flux))
        cfc_volume_flux_error = max(cfc_volume_flux_error, abs(computed_volume_flux - expected_volume_flux))
        flux_scale = max(flux_scale, abs(expected_flux), abs(computed_flux))
        volume_flux_scale = max(volume_flux_scale, abs(expected_volume_flux), abs(computed_volume_flux))
    end

    @test fcc_flux_error ≤ 100eps(FT) * flux_scale
    @test cfc_flux_error ≤ 100eps(FT) * flux_scale
    @test fcc_volume_flux_error ≤ 100eps(FT) * volume_flux_scale
    @test cfc_volume_flux_error ≤ 100eps(FT) * volume_flux_scale

    return nothing
end

function test_octahealpix_vector_invariant_primitives_with_affine_fields(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    a₀ = convert(FT, 2//7)
    aᵢ = - convert(FT, 3//11)
    aⱼ = convert(FT, 5//13)
    b₀ = - convert(FT, 4//9)
    bᵢ = convert(FT, 7//15)
    bⱼ = - convert(FT, 1//6)

    half = convert(FT, 1//2)
    quarter = convert(FT, 1//4)

    u₁_field = Array{FT}(undef, 2N + 1, 2N, 1)
    u₂_field = Array{FT}(undef, 2N, 2N + 1, 1)

    for j in 1:(2N), i in 1:(2N + 1)
        u₁_field[i, j, 1] = a₀ + aᵢ * convert(FT, i) + aⱼ * convert(FT, j)
    end

    for j in 1:(2N + 1), i in 1:(2N)
        u₂_field[i, j, 1] = b₀ + bᵢ * convert(FT, i) + bⱼ * convert(FT, j)
    end

    interior_indices = vcat(collect(2:(N - 1)),
                            collect((N + 2):(2N - 1)))
    rotational_indices = vcat(collect(2:(N - 2)),
                              collect((N + 2):(2N - 2)))

    u₁_center_value(i, j) = half * (u₁_field[i,     j, 1] +
                                    u₁_field[i + 1, j, 1])
    u₂_center_value(i, j) = half * (u₂_field[i, j,     1] +
                                    u₂_field[i, j + 1, 1])

    function expected_contravariant_velocity_u(i, j)
        interpolated_u₂ = quarter * (u₂_field[i - 1, j,     1] + u₂_field[i, j,     1] +
                                     u₂_field[i - 1, j + 1, 1] + u₂_field[i, j + 1, 1])

        return grid.metrics.g¹¹ᶠᶜᵃ[i, j] * u₁_field[i, j, 1] +
               grid.metrics.g¹²ᶠᶜᵃ[i, j] * interpolated_u₂
    end

    function expected_contravariant_velocity_v(i, j)
        interpolated_u₁ = quarter * (u₁_field[i,     j - 1, 1] + u₁_field[i + 1, j - 1, 1] +
                                     u₁_field[i,     j,     1] + u₁_field[i + 1, j,     1])

        return grid.metrics.g²¹ᶜᶠᵃ[i, j] * interpolated_u₁ +
               grid.metrics.g²²ᶜᶠᵃ[i, j] * u₂_field[i, j, 1]
    end

    expected_contravariant_velocity_uᶠᶠ(i, j) =
        half * (expected_contravariant_velocity_u(i, j - 1) +
                expected_contravariant_velocity_u(i, j))

    expected_contravariant_velocity_vᶠᶠ(i, j) =
        half * (expected_contravariant_velocity_v(i - 1, j) +
                expected_contravariant_velocity_v(i, j))

    function expected_kinetic_energy(i, j)
        u₁ᶜᶜᶜ = u₁_center_value(i, j)
        u₂ᶜᶜᶜ = u₂_center_value(i, j)

        return half * (grid.metrics.g¹¹ᶜᶜᵃ[i, j] * u₁ᶜᶜᶜ^2 +
                       (grid.metrics.g¹²ᶜᶜᵃ[i, j] + grid.metrics.g¹²ᶜᶜᵃ[i, j]) * u₁ᶜᶜᶜ * u₂ᶜᶜᶜ +
                       grid.metrics.g²²ᶜᶜᵃ[i, j] * u₂ᶜᶜᶜ^2)
    end

    expected_circulation = bᵢ - aⱼ

    kinetic_energy_error = zero(FT)
    contravariant_velocity_u_error = zero(FT)
    contravariant_velocity_v_error = zero(FT)
    bernoulli_head_u_error = zero(FT)
    bernoulli_head_v_error = zero(FT)
    circulation_error = zero(FT)
    vorticity_component_error = zero(FT)
    vorticity_error = zero(FT)
    rotational_advection_u_error = zero(FT)
    rotational_advection_v_error = zero(FT)

    for j in interior_indices, i in interior_indices
        computed_kinetic_energy = covariant_kinetic_energyᶜᶜᶜ(i, j, 1, grid, u₁_field, u₂_field)
        kinetic_energy_error = max(kinetic_energy_error,
                                   abs(computed_kinetic_energy - expected_kinetic_energy(i, j)))
    end

    for j in interior_indices, i in interior_indices
        computed_velocity = covariant_to_contravariant_velocity_uᶠᶜᶜ(i, j, 1, grid, u₁_field, u₂_field)
        contravariant_velocity_u_error = max(contravariant_velocity_u_error,
                                             abs(computed_velocity - expected_contravariant_velocity_u(i, j)))
    end

    for j in interior_indices, i in interior_indices
        computed_velocity = covariant_to_contravariant_velocity_vᶜᶠᶜ(i, j, 1, grid, u₁_field, u₂_field)
        contravariant_velocity_v_error = max(contravariant_velocity_v_error,
                                             abs(computed_velocity - expected_contravariant_velocity_v(i, j)))
    end

    for j in interior_indices, i in interior_indices
        expected_bernoulli_head = expected_kinetic_energy(i, j) - expected_kinetic_energy(i - 1, j)
        computed_bernoulli_head = covariant_bernoulli_head_uᶠᶜᶜ(i, j, 1, grid, u₁_field, u₂_field)
        bernoulli_head_u_error = max(bernoulli_head_u_error,
                                     abs(computed_bernoulli_head - expected_bernoulli_head))
    end

    for j in interior_indices, i in interior_indices
        expected_bernoulli_head = expected_kinetic_energy(i, j) - expected_kinetic_energy(i, j - 1)
        computed_bernoulli_head = covariant_bernoulli_head_vᶜᶠᶜ(i, j, 1, grid, u₁_field, u₂_field)
        bernoulli_head_v_error = max(bernoulli_head_v_error,
                                     abs(computed_bernoulli_head - expected_bernoulli_head))
    end

    for j in interior_indices, i in interior_indices
        computed_circulation = covariant_vertical_circulationᶠᶠᶜ(i, j, 1, grid, u₁_field, u₂_field)
        circulation_error = max(circulation_error,
                                abs(computed_circulation - expected_circulation))
    end

    for j in interior_indices, i in interior_indices
        computed_vorticity = covariant_vertical_vorticity_componentᶠᶠᶜ(i, j, 1, grid, u₁_field, u₂_field)
        vorticity_component_error = max(vorticity_component_error,
                                        abs(computed_vorticity - expected_circulation))
    end

    for j in interior_indices, i in interior_indices
        expected_vorticity = expected_circulation / Az(i, j, 1, grid, Face(), Face(), Center())
        computed_vorticity = covariant_vertical_vorticityᶠᶠᶜ(i, j, 1, grid, u₁_field, u₂_field)
        vorticity_error = max(vorticity_error,
                              abs(computed_vorticity - expected_vorticity))
    end

    for j in rotational_indices, i in interior_indices
        expected_advection = - half * expected_circulation *
                             (expected_contravariant_velocity_vᶠᶠ(i, j) +
                              expected_contravariant_velocity_vᶠᶠ(i, j + 1))
        computed_advection = covariant_rotational_advection_uᶠᶜᶜ(i, j, 1, grid, u₁_field, u₂_field)
        rotational_advection_u_error = max(rotational_advection_u_error,
                                           abs(computed_advection - expected_advection))
    end

    for j in interior_indices, i in rotational_indices
        expected_advection = + half * expected_circulation *
                             (expected_contravariant_velocity_uᶠᶠ(i, j) +
                              expected_contravariant_velocity_uᶠᶠ(i + 1, j))
        computed_advection = covariant_rotational_advection_vᶜᶠᶜ(i, j, 1, grid, u₁_field, u₂_field)
        rotational_advection_v_error = max(rotational_advection_v_error,
                                           abs(computed_advection - expected_advection))
    end

    kinetic_energy_scale = max(one(FT),
                               maximum(abs(expected_kinetic_energy(i, j)) for j in interior_indices, i in interior_indices),
                               maximum(abs(covariant_kinetic_energyᶜᶜᶜ(i, j, 1, grid, u₁_field, u₂_field)) for j in interior_indices, i in interior_indices))
    contravariant_velocity_u_scale = max(one(FT),
                                         maximum(abs(expected_contravariant_velocity_u(i, j)) for j in interior_indices, i in interior_indices),
                                         maximum(abs(covariant_to_contravariant_velocity_uᶠᶜᶜ(i, j, 1, grid, u₁_field, u₂_field)) for j in interior_indices, i in interior_indices))
    contravariant_velocity_v_scale = max(one(FT),
                                         maximum(abs(expected_contravariant_velocity_v(i, j)) for j in interior_indices, i in interior_indices),
                                         maximum(abs(covariant_to_contravariant_velocity_vᶜᶠᶜ(i, j, 1, grid, u₁_field, u₂_field)) for j in interior_indices, i in interior_indices))
    bernoulli_head_u_scale = max(one(FT),
                                 maximum(abs(covariant_bernoulli_head_uᶠᶜᶜ(i, j, 1, grid, u₁_field, u₂_field)) for j in interior_indices, i in interior_indices))
    bernoulli_head_v_scale = max(one(FT),
                                 maximum(abs(covariant_bernoulli_head_vᶜᶠᶜ(i, j, 1, grid, u₁_field, u₂_field)) for j in interior_indices, i in interior_indices))
    circulation_scale = max(one(FT), abs(expected_circulation))
    vorticity_component_scale = circulation_scale
    vorticity_scale = max(one(FT),
                          maximum(abs(expected_circulation / Az(i, j, 1, grid, Face(), Face(), Center())) for j in interior_indices, i in interior_indices),
                          maximum(abs(covariant_vertical_vorticityᶠᶠᶜ(i, j, 1, grid, u₁_field, u₂_field)) for j in interior_indices, i in interior_indices))
    rotational_advection_u_scale = max(one(FT),
                                       maximum(abs(covariant_rotational_advection_uᶠᶜᶜ(i, j, 1, grid, u₁_field, u₂_field)) for j in rotational_indices, i in interior_indices))
    rotational_advection_v_scale = max(one(FT),
                                       maximum(abs(covariant_rotational_advection_vᶜᶠᶜ(i, j, 1, grid, u₁_field, u₂_field)) for j in interior_indices, i in rotational_indices))

    model = HydrostaticFreeSurfaceModel(grid;
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing)

    set!(model, u = u₁_field, v = u₂_field, intrinsic_velocities = true)

    ζ_operation = vertical_vorticity(model)
    ζ = Field(ζ_operation)
    compute!(ζ)

    diagnostic_vorticity_error = zero(FT)

    for j in interior_indices, i in interior_indices
        expected_vorticity = expected_circulation / Az(i, j, 1, grid, Face(), Face(), Center())
        diagnostic_vorticity_error = max(diagnostic_vorticity_error,
                                         abs(ζ[i, j, 1] - expected_vorticity))
    end

    contravariant_operations = contravariant_velocities(model)
    diagnostic_contravariant_u = Field(contravariant_operations.u)
    diagnostic_contravariant_v = Field(contravariant_operations.v)
    compute!(diagnostic_contravariant_u)
    compute!(diagnostic_contravariant_v)

    diagnostic_contravariant_u_error = zero(FT)
    diagnostic_contravariant_v_error = zero(FT)

    for j in interior_indices, i in interior_indices
        diagnostic_contravariant_u_error = max(diagnostic_contravariant_u_error,
                                               abs(diagnostic_contravariant_u[i, j, 1] - expected_contravariant_velocity_u(i, j)))
        diagnostic_contravariant_v_error = max(diagnostic_contravariant_v_error,
                                               abs(diagnostic_contravariant_v[i, j, 1] - expected_contravariant_velocity_v(i, j)))
    end

    diagnostic_kinetic_energy = Field(kinetic_energy(model))
    compute!(diagnostic_kinetic_energy)

    diagnostic_kinetic_energy_error = zero(FT)

    for j in interior_indices, i in interior_indices
        diagnostic_kinetic_energy_error = max(diagnostic_kinetic_energy_error,
                                              abs(diagnostic_kinetic_energy[i, j, 1] - expected_kinetic_energy(i, j)))
    end

    diagnostic_relative_vorticity = Field(relative_vorticity(model))
    compute!(diagnostic_relative_vorticity)

    diagnostic_relative_vorticity_error = zero(FT)

    for j in interior_indices, i in interior_indices
        diagnostic_relative_vorticity_error = max(diagnostic_relative_vorticity_error,
                                                  abs(diagnostic_relative_vorticity[i, j, 1] - expected_circulation))
    end

    @test ζ_operation.kernel_function === covariant_vertical_vorticityᶠᶠᶜ
    @test contravariant_operations.u.kernel_function === covariant_to_contravariant_velocity_uᶠᶜᶜ
    @test contravariant_operations.v.kernel_function === covariant_to_contravariant_velocity_vᶜᶠᶜ
    @test diagnostic_kinetic_energy.grid === grid
    @test kinetic_energy(model).kernel_function === covariant_kinetic_energyᶜᶜᶜ
    @test relative_vorticity(model).kernel_function === covariant_vertical_vorticity_componentᶠᶠᶜ
    @test kinetic_energy_error ≤ 1000eps(FT) * kinetic_energy_scale
    @test contravariant_velocity_u_error ≤ 1000eps(FT) * contravariant_velocity_u_scale
    @test contravariant_velocity_v_error ≤ 1000eps(FT) * contravariant_velocity_v_scale
    @test bernoulli_head_u_error ≤ 1000eps(FT) * bernoulli_head_u_scale
    @test bernoulli_head_v_error ≤ 1000eps(FT) * bernoulli_head_v_scale
    @test circulation_error ≤ 1000eps(FT) * circulation_scale
    @test vorticity_component_error ≤ 1000eps(FT) * vorticity_component_scale
    @test vorticity_error ≤ 1000eps(FT) * vorticity_scale
    @test rotational_advection_u_error ≤ 1000eps(FT) * rotational_advection_u_scale
    @test rotational_advection_v_error ≤ 1000eps(FT) * rotational_advection_v_scale
    @test diagnostic_vorticity_error ≤ 1000eps(FT) * vorticity_scale
    @test diagnostic_contravariant_u_error ≤ 1000eps(FT) * contravariant_velocity_u_scale
    @test diagnostic_contravariant_v_error ≤ 1000eps(FT) * contravariant_velocity_v_scale
    @test diagnostic_kinetic_energy_error ≤ 1000eps(FT) * kinetic_energy_scale
    @test diagnostic_relative_vorticity_error ≤ 1000eps(FT) * vorticity_component_scale

    return nothing
end

function test_octahealpix_vector_invariant_momentum_tendency_with_affine_fields(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    a₀ = convert(FT, 2//7)
    aᵢ = - convert(FT, 3//11)
    aⱼ = convert(FT, 5//13)
    b₀ = - convert(FT, 4//9)
    bᵢ = convert(FT, 7//15)
    bⱼ = - convert(FT, 1//6)

    u₁_field = Array{FT}(undef, 2N + 1, 2N, 1)
    u₂_field = Array{FT}(undef, 2N, 2N + 1, 1)

    for j in 1:(2N), i in 1:(2N + 1)
        u₁_field[i, j, 1] = a₀ + aᵢ * convert(FT, i) + aⱼ * convert(FT, j)
    end

    for j in 1:(2N + 1), i in 1:(2N)
        u₂_field[i, j, 1] = b₀ + bᵢ * convert(FT, i) + bⱼ * convert(FT, j)
    end

    model = HydrostaticFreeSurfaceModel(grid;
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant())

    set!(model, u = u₁_field, v = u₂_field, intrinsic_velocities = true)
    fill_halo_regions!(model.velocities)
    compute_momentum_tendencies!(model, ())

    u, v = model.velocities

    interior_indices = vcat(collect(2:(N - 1)),
                            collect((N + 2):(2N - 1)))
    rotational_indices = vcat(collect(2:(N - 2)),
                              collect((N + 2):(2N - 2)))

    momentum_u_error = zero(FT)
    momentum_v_error = zero(FT)
    momentum_u_scale = one(FT)
    momentum_v_scale = one(FT)
    momentum_advection = model.advection.momentum

    for j in rotational_indices, i in interior_indices
        expected_tendency = - U_dot_∇u(i, j, 1, grid, momentum_advection, model.velocities)
        computed_tendency = model.timestepper.Gⁿ.u[i, j, 1]

        momentum_u_error = max(momentum_u_error, abs(computed_tendency - expected_tendency))
        momentum_u_scale = max(momentum_u_scale, abs(expected_tendency), abs(computed_tendency))
    end

    for j in interior_indices, i in rotational_indices
        expected_tendency = - U_dot_∇v(i, j, 1, grid, momentum_advection, model.velocities)
        computed_tendency = model.timestepper.Gⁿ.v[i, j, 1]

        momentum_v_error = max(momentum_v_error, abs(computed_tendency - expected_tendency))
        momentum_v_scale = max(momentum_v_scale, abs(expected_tendency), abs(computed_tendency))
    end

    @test momentum_u_error ≤ 1000eps(FT) * momentum_u_scale
    @test momentum_v_error ≤ 1000eps(FT) * momentum_v_scale

    return nothing
end

function test_equiangular_gnomonic_hydrostatic_model_smoke(FT, N)
    radius = convert(FT, 3)
    mapping = EquiangularGnomonicCubedSpherePanel(FT)
    grid = SphericalShellGrid(CPU(), FT; mapping, size=(N, N, 1), z=(zero(FT), one(FT)), radius, halo=(3, 3, 3))
    advection = Centered(FT)

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = advection)

    set!(model, c = one(FT))
    time_step!(model, convert(FT, 1//100))

    c = Array(interior(model.tracers.c))
    constant_tracer_error = maximum(abs(cᵢ - one(FT)) for cᵢ in c)

    @test model.grid isa SphericalShellGrid
    @test propertynames(model.tracers) == (:c,)
    @test constant_tracer_error ≤ 100eps(FT)

    return nothing
end

function test_equiangular_gnomonic_transport_state_synchronization(FT)
    radius = convert(FT, 3)
    mapping = EquiangularGnomonicCubedSpherePanel(FT)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (8, 8, 1),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    u₁ = [convert(FT, i) / 9 + convert(FT, 1//3) * convert(FT, j) / 8 for i in 1:9, j in 1:8, k in 1:1]
    u₂ = [convert(FT, 4//3) * convert(FT, i) / 8 - convert(FT, j) / 9 for i in 1:8, j in 1:9, k in 1:1]
    expected_Ũ = zeros(FT, 9, 8, 1)
    expected_Ṽ = zeros(FT, 8, 9, 1)

    for j in 1:8, i in 1:9
        expected_Ũ[i, j, 1] = covariant_to_volume_flux_uᶠᶜᶜ(i, j, 1, grid, u₁, u₂)
    end

    for j in 1:9, i in 1:8
        expected_Ṽ[i, j, 1] = covariant_to_volume_flux_vᶜᶠᶜ(i, j, 1, grid, u₁, u₂)
    end

    set!(model, u = u₁, v = u₂)
    compute_transport_velocities!(model, model.free_surface)

    transport_u_error = maximum(abs.(Array(interior(model.transport_velocities.u)) - expected_Ũ))
    transport_v_error = maximum(abs.(Array(interior(model.transport_velocities.v)) - expected_Ṽ))

    @test transport_u_error ≤ 100eps(FT)
    @test transport_v_error ≤ 100eps(FT)

    scale = max(maximum(abs, Array(interior(model.velocities.u))),
                maximum(abs, Array(interior(model.velocities.v))),
                one(FT))
    transport_u_model_velocity_mismatch = maximum(abs.(Array(interior(model.velocities.u)) -
                                                     Array(interior(model.transport_velocities.u))))
    transport_v_model_velocity_mismatch = maximum(abs.(Array(interior(model.velocities.v)) -
                                                     Array(interior(model.transport_velocities.v))))
    @test transport_u_model_velocity_mismatch / scale > convert(FT, 1e-6)
    @test transport_v_model_velocity_mismatch / scale > convert(FT, 1e-6)

    perturbed_u = 2 .* u₁
    perturbed_v = 3 .* u₂
    for j in 1:8, i in 1:9
        expected_Ũ[i, j, 1] = covariant_to_volume_flux_uᶠᶜᶜ(i, j, 1, grid, perturbed_u, perturbed_v)
    end
    for j in 1:9, i in 1:8
        expected_Ṽ[i, j, 1] = covariant_to_volume_flux_vᶜᶠᶜ(i, j, 1, grid, perturbed_u, perturbed_v)
    end

    set!(model, u = perturbed_u, v = perturbed_v)
    compute_transport_velocities!(model, model.free_surface)

    transport_u_error = maximum(abs.(Array(interior(model.transport_velocities.u)) - expected_Ũ))
    transport_v_error = maximum(abs.(Array(interior(model.transport_velocities.v)) - expected_Ṽ))
    transport_u_model_velocity_mismatch = maximum(abs.(Array(interior(model.velocities.u)) -
                                                     Array(interior(model.transport_velocities.u))))
    transport_v_model_velocity_mismatch = maximum(abs.(Array(interior(model.velocities.v)) -
                                                     Array(interior(model.transport_velocities.v))))

    @test transport_u_error ≤ 100eps(FT)
    @test transport_v_error ≤ 100eps(FT)
    @test transport_u_model_velocity_mismatch / scale > convert(FT, 1e-6)
    @test transport_v_model_velocity_mismatch / scale > convert(FT, 1e-6)

    # Keep independent storage for model/transport fields.
    @test parent(model.transport_velocities.u) !== parent(model.velocities.u)
    @test parent(model.transport_velocities.v) !== parent(model.velocities.v)
    @test parent(model.transport_velocities.w) !== parent(model.velocities.w)

    w_scale = maximum(abs, Array(interior(model.transport_velocities.w)))
    @test w_scale < scale

    return nothing
end

function test_transport_state_drives_tracer_tendency(FT)
    radius = convert(FT, 3)
    mapping = EquiangularGnomonicCubedSpherePanel(FT)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (8, 8, 1),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities = PrescribedVelocityFields(),
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    u = [convert(FT, i) / 9 + convert(FT, 1//3) * convert(FT, j) / 8 for i in 1:9, j in 1:8, k in 1:1]
    v = [convert(FT, 4//3) * convert(FT, i) / 8 - convert(FT, j) / 9 for i in 1:8, j in 1:9, k in 1:1]

    tracer = Array{FT}(undef, 8, 8, 1)
    for j in 1:8, i in 1:8
        tracer[i, j, 1] = sin(convert(FT, i) / convert(FT, 8)) * cos(convert(FT, j) / convert(FT, 8))
    end

    set!(model, u = u, v = v, c = tracer)
    compute_transport_velocities!(model, model.free_surface)
    compute_tracer_tendencies!(model)
    forward = Array(interior(model.timestepper.Gⁿ.c))

    compute_transport_velocities!(model, model.free_surface)
    set!(model.transport_velocities.u, -model.transport_velocities.u)
    set!(model.transport_velocities.v, -model.transport_velocities.v)
    compute_tracer_tendencies!(model)
    reverse = Array(interior(model.timestepper.Gⁿ.c))

    @test forward ≈ -reverse atol = 200 * eps(FT) * max(one(FT), max(maximum(abs, forward), maximum(abs, reverse)))

    return nothing
end

function test_octahealpix_transport_state_drives_tracer_tendency(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))
    connectivity = grid.connectivity

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model,
         u = (λ, φ, z) -> sind(λ) * cosd(φ),
         v = (λ, φ, z) -> cosd(λ) * sind(φ),
         c = (λ, φ, z) -> sind(λ / 2) * cosd(φ))

    fill_halo_regions!(model.velocities)
    compute_transport_velocities!(model, model.free_surface)

    source_field, source_i, source_j, sign = octahealpix_transport_face_halo_source(0, N + 1, connectivity, grid.Nx, grid.Ny, N, :u)
    expected_u_halo = source_field === :u ? sign * model.transport_velocities.u[source_i, source_j, 1] :
                                            sign * model.transport_velocities.v[source_i, source_j, 1]

    source_field, source_i, source_j, sign = octahealpix_transport_face_halo_source(N + 1, 0, connectivity, grid.Nx, grid.Ny, N, :v)
    expected_v_halo = source_field === :u ? sign * model.transport_velocities.u[source_i, source_j, 1] :
                                            sign * model.transport_velocities.v[source_i, source_j, 1]

    @test model.transport_velocities.u[0, N + 1, 1] == expected_u_halo
    @test model.transport_velocities.v[N + 1, 0, 1] == expected_v_halo

    compute_tracer_tendencies!(model)
    forward = Array(interior(model.timestepper.Gⁿ.c))
    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    for (i, j) in sampled_points
        expected_Gc = -div_Uc(i, j, 1, grid, model.advection.c, model.transport_velocities, model.tracers.c)
        computed_Gc = model.timestepper.Gⁿ.c[i, j, 1]
        tendency_scale = max(abs(expected_Gc), one(FT))
        @test abs(expected_Gc) > 100eps(FT)
        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale
    end

    fill_halo_regions!(model.velocities)
    compute_transport_velocities!(model, model.free_surface)
    set!(model.transport_velocities.u, -model.transport_velocities.u)
    set!(model.transport_velocities.v, -model.transport_velocities.v)
    fill_halo_regions!(model.transport_velocities)
    compute_tracer_tendencies!(model)
    reverse = Array(interior(model.timestepper.Gⁿ.c))

    tolerance = 200 * eps(FT) * max(one(FT), max(maximum(abs, forward), maximum(abs, reverse)))

    @test forward ≈ -reverse atol = tolerance
    @test !any(isnan, forward)
    @test !any(isnan, reverse)

    return nothing
end

function test_octahealpix_split_explicit_transport_velocity_conversion_uses_fresh_corrected_covariant_halos(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = SplitExplicitFreeSurface(substeps = 8),
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    target_u(λ, φ) = convert(FT, 1//5) * sind(λ) + convert(FT, 3//25) * cosd(φ)
    target_v(λ, φ) = -convert(FT, 2//15) * cosd(λ) + convert(FT, 1//10) * sind(φ)

    set!(model, u = zero(FT), v = zero(FT), c = one(FT))
    fill_halo_regions!(model.velocities)

    free_surface = model.free_surface
    Ũ = free_surface.filtered_state.Ũ
    Ṽ = free_surface.filtered_state.Ṽ

    for j in 1:grid.Ny, i in 1:(grid.Nx + 1)
        λ = grid.λᶠᶜᵃ[i, j]
        φ = grid.φᶠᶜᵃ[i, j]
        @inbounds Ũ[i, j, 1] = column_depthᶠᶜᵃ(i, j, grid) * target_u(λ, φ)
    end

    for j in 1:(grid.Ny + 1), i in 1:grid.Nx
        λ = grid.λᶜᶠᵃ[i, j]
        φ = grid.φᶜᶠᵃ[i, j]
        @inbounds Ṽ[i, j, 1] = column_depthᶜᶠᵃ(i, j, grid) * target_v(λ, φ)
    end

    fill_halo_regions!((Ũ, Ṽ))

    expected_covariant_u = similar(model.velocities.u)
    expected_covariant_v = similar(model.velocities.v)
    set!(expected_covariant_u, (λ, φ, z) -> target_u(λ, φ))
    set!(expected_covariant_v, (λ, φ, z) -> target_v(λ, φ))
    fill_halo_regions!((expected_covariant_u, expected_covariant_v))

    expected_transport_u = similar(model.transport_velocities.u)
    expected_transport_v = similar(model.transport_velocities.v)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.convert_to_volume_flux_velocities!(expected_transport_u,
                                                                                        expected_transport_v,
                                                                                        grid,
                                                                                        expected_covariant_u,
                                                                                        expected_covariant_v)
    fill_halo_regions!((expected_transport_u, expected_transport_v))

    stale_covariant_u = similar(model.velocities.u)
    stale_covariant_v = similar(model.velocities.v)
    parent(stale_covariant_u) .= zero(FT)
    parent(stale_covariant_v) .= zero(FT)

    for j in 1:grid.Ny, i in 1:(grid.Nx + 1)
        λ = grid.λᶠᶜᵃ[i, j]
        φ = grid.φᶠᶜᵃ[i, j]
        @inbounds stale_covariant_u[i, j, 1] = target_u(λ, φ)
    end

    for j in 1:(grid.Ny + 1), i in 1:grid.Nx
        λ = grid.λᶜᶠᵃ[i, j]
        φ = grid.φᶜᶠᵃ[i, j]
        @inbounds stale_covariant_v[i, j, 1] = target_v(λ, φ)
    end

    stale_transport_u = similar(model.transport_velocities.u)
    stale_transport_v = similar(model.transport_velocities.v)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.convert_to_volume_flux_velocities!(stale_transport_u,
                                                                                        stale_transport_v,
                                                                                        grid,
                                                                                        stale_covariant_u,
                                                                                        stale_covariant_v)
    fill_halo_regions!((stale_transport_u, stale_transport_v))

    compute_transport_velocities!(model, free_surface)

    max_u_error = zero(FT)
    max_v_error = zero(FT)
    stale_difference = zero(FT)

    sampled_u_points = ((1, N, 1),
                        (1, N + 1, 1),
                        (N + 1, N, 1),
                        (N + 1, N + 1, 1),
                        (grid.Nx + 1, N, 1),
                        (grid.Nx + 1, N + 1, 1))
    sampled_v_points = ((N, 1, 1),
                        (N + 1, 1, 1),
                        (N, N + 1, 1),
                        (N + 1, N + 1, 1),
                        (N, grid.Ny + 1, 1),
                        (N + 1, grid.Ny + 1, 1))

    for (i, j, k) in sampled_u_points
        computed = model.transport_velocities.u[i, j, k]
        expected = expected_transport_u[i, j, k]
        stale = stale_transport_u[i, j, k]
        max_u_error = max(max_u_error, abs(computed - expected))
        stale_difference = max(stale_difference, abs(expected - stale))
    end

    for (i, j, k) in sampled_v_points
        computed = model.transport_velocities.v[i, j, k]
        expected = expected_transport_v[i, j, k]
        stale = stale_transport_v[i, j, k]
        max_v_error = max(max_v_error, abs(computed - expected))
        stale_difference = max(stale_difference, abs(expected - stale))
    end

    u_scale = max(one(FT), maximum(abs, Array(interior(expected_transport_u))))
    v_scale = max(one(FT), maximum(abs, Array(interior(expected_transport_v))))

    @test max_u_error ≤ 1000eps(FT) * u_scale
    @test max_v_error ≤ 1000eps(FT) * v_scale
    @test stale_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_nonhydrostatic_tracer_tendency_uses_converted_transport_velocities(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))

    model = NonhydrostaticModel(grid;
                                timestepper = :QuasiAdamsBashforth2,
                                tracers = :c,
                                buoyancy = nothing,
                                advection = Centered(FT))

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.2) * sind(λ) + convert(FT, 0.1) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.15) * cosd(λ) - convert(FT, 0.05) * sind(φ),
         w = (λ, φ, z) -> zero(FT),
         c = (λ, φ, z) -> sind(λ / 2) * cosd(φ) + convert(FT, 0.1) * z)

    Oceananigans.TimeSteppers.update_state!(model)
    Oceananigans.TimeSteppers.compute_tendencies!(model, ())

    converted_transport = (u = OctaHEALPixConvertedTransportU(grid, model.velocities.u, model.velocities.v),
                           v = OctaHEALPixConvertedTransportV(grid, model.velocities.u, model.velocities.v),
                           w = model.velocities.w)

    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    maximum_naive_difference = zero(FT)

    for (i, j) in sampled_points
        expected_Gc = -div_Uc(i, j, 1, grid, model.advection, converted_transport, model.tracers.c)
        naive_Gc = -div_Uc(i, j, 1, grid, model.advection, model.velocities, model.tracers.c)
        computed_Gc = model.timestepper.Gⁿ.c[i, j, 1]
        tendency_scale = max(one(FT), abs(expected_Gc), abs(computed_Gc))

        @test abs(expected_Gc) > 100eps(FT)
        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale

        maximum_naive_difference = max(maximum_naive_difference, abs(expected_Gc - naive_Gc))
    end

    @test maximum_naive_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_horizontal_scalar_diffusivity_uses_converted_transport_fluxes(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))

    κh = convert(FT, 0.2)
    closure = Oceananigans.TurbulenceClosures.HorizontalScalarDiffusivity(FT;
                                                                          ν = zero(FT),
                                                                          κ = (c = κh,))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        closure = closure,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    set!(model, c = (λ, φ, z) -> sind(λ / 2) * cosd(φ) + convert(FT, 0.1) * sind(3φ) + convert(FT, 0.05) * z)

    Oceananigans.TimeSteppers.update_state!(model)
    Oceananigans.TurbulenceClosures.compute_closure_fields!(model.closure_fields, model.closure, model)

    disc = Oceananigans.TurbulenceClosures.time_discretization(model.closure)
    tracer_index = Val(1)
    tracer = model.tracers.c
    closure_fields = model.closure_fields
    model_fields = Oceananigans.Models.fields(model)

    transport_diffusive_flux_x(i, j, k, grid, disc, closure, K, id, c, clock, fields, buoyancy) =
        Oceananigans.Operators.transverse_computational_width_uᶠᶜᶜ(i, j, k, grid) *
        Oceananigans.Operators.covariant_to_contravariant_flux_uᶠᶜᶜ(i, j, k, grid,
                                                                    Oceananigans.TurbulenceClosures._diffusive_flux_x(i, j, k, grid, disc, closure, K, id, c, clock, fields, buoyancy),
                                                                    Oceananigans.TurbulenceClosures._diffusive_flux_y(i, j, k, grid, disc, closure, K, id, c, clock, fields, buoyancy))

    transport_diffusive_flux_y(i, j, k, grid, disc, closure, K, id, c, clock, fields, buoyancy) =
        Oceananigans.Operators.transverse_computational_width_vᶜᶠᶜ(i, j, k, grid) *
        Oceananigans.Operators.covariant_to_contravariant_flux_vᶜᶠᶜ(i, j, k, grid,
                                                                    Oceananigans.TurbulenceClosures._diffusive_flux_x(i, j, k, grid, disc, closure, K, id, c, clock, fields, buoyancy),
                                                                    Oceananigans.TurbulenceClosures._diffusive_flux_y(i, j, k, grid, disc, closure, K, id, c, clock, fields, buoyancy))

    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    maximum_naive_difference = zero(FT)

    for (i, j) in sampled_points
        expected_Gc = - Oceananigans.Operators.V⁻¹ᶜᶜᶜ(i, j, 1, grid) *
                        (Oceananigans.Operators.δxᶜᵃᵃ(i, j, 1, grid, transport_diffusive_flux_x,
                                                      disc, model.closure, closure_fields, tracer_index, tracer,
                                                      model.clock, model_fields, model.buoyancy) +
                         Oceananigans.Operators.δyᵃᶜᵃ(i, j, 1, grid, transport_diffusive_flux_y,
                                                      disc, model.closure, closure_fields, tracer_index, tracer,
                                                      model.clock, model_fields, model.buoyancy))

        naive_Gc = - Oceananigans.Operators.V⁻¹ᶜᶜᶜ(i, j, 1, grid) *
                     (Oceananigans.Operators.δxᶜᵃᵃ(i, j, 1, grid, Oceananigans.Operators.Ax_qᶠᶜᶜ,
                                                   Oceananigans.TurbulenceClosures._diffusive_flux_x,
                                                   disc, model.closure, closure_fields, tracer_index, tracer,
                                                   model.clock, model_fields, model.buoyancy) +
                      Oceananigans.Operators.δyᵃᶜᵃ(i, j, 1, grid, Oceananigans.Operators.Ay_qᶜᶠᶜ,
                                                   Oceananigans.TurbulenceClosures._diffusive_flux_y,
                                                   disc, model.closure, closure_fields, tracer_index, tracer,
                                                   model.clock, model_fields, model.buoyancy))

        computed_Gc = - Oceananigans.TurbulenceClosures.∇_dot_qᶜ(i, j, 1, grid, model.closure,
                                                                 closure_fields, tracer_index, tracer,
                                                                 model.clock, model_fields, model.buoyancy)

        tendency_scale = max(one(FT), abs(expected_Gc), abs(computed_Gc))

        @test abs(expected_Gc) > 100eps(FT)
        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale

        maximum_naive_difference = max(maximum_naive_difference, abs(expected_Gc - naive_Gc))
    end

    @test maximum_naive_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_variance_dissipation_uses_converted_diffusive_transport_fluxes(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))

    κh = convert(FT, 0.2)
    closure = Oceananigans.TurbulenceClosures.HorizontalScalarDiffusivity(FT;
                                                                          ν = zero(FT),
                                                                          κ = (c = κh,))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        closure = closure,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    set!(model, c = (λ, φ, z) -> sind(λ / 2) * cosd(φ) + convert(FT, 0.1) * sind(3φ) + convert(FT, 0.05) * z)

    Oceananigans.TimeSteppers.update_state!(model)
    Oceananigans.TurbulenceClosures.compute_closure_fields!(model.closure_fields, model.closure, model)

    ϵ = Oceananigans.Models.VarianceDissipationComputations.VarianceDissipation(:c, grid)
    Oceananigans.Models.VarianceDissipationComputations.cache_fluxes!(ϵ, model, :c)

    transport_diffusive_flux_x(i, j, k, grid, closure, K, id, c, clock, fields, buoyancy) =
        Oceananigans.Operators.transverse_computational_width_uᶠᶜᶜ(i, j, k, grid) *
        Oceananigans.Operators.covariant_to_contravariant_flux_uᶠᶜᶜ(i, j, k, grid,
                                                                    Oceananigans.TurbulenceClosures._diffusive_flux_x(i, j, k, grid, Oceananigans.TurbulenceClosures.ExplicitTimeDiscretization(), closure, K, id, c, clock, fields, buoyancy),
                                                                    Oceananigans.TurbulenceClosures._diffusive_flux_y(i, j, k, grid, Oceananigans.TurbulenceClosures.ExplicitTimeDiscretization(), closure, K, id, c, clock, fields, buoyancy))

    transport_diffusive_flux_y(i, j, k, grid, closure, K, id, c, clock, fields, buoyancy) =
        Oceananigans.Operators.transverse_computational_width_vᶜᶠᶜ(i, j, k, grid) *
        Oceananigans.Operators.covariant_to_contravariant_flux_vᶜᶠᶜ(i, j, k, grid,
                                                                    Oceananigans.TurbulenceClosures._diffusive_flux_x(i, j, k, grid, Oceananigans.TurbulenceClosures.ExplicitTimeDiscretization(), closure, K, id, c, clock, fields, buoyancy),
                                                                    Oceananigans.TurbulenceClosures._diffusive_flux_y(i, j, k, grid, Oceananigans.TurbulenceClosures.ExplicitTimeDiscretization(), closure, K, id, c, clock, fields, buoyancy))

    tracer = model.tracers.c
    tracer_index = Val(1)
    closure_fields = model.closure_fields
    model_fields = Oceananigans.Models.fields(model)
    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    maximum_naive_difference = zero(FT)

    for (i, j) in sampled_points
        expected_Vx =
            transport_diffusive_flux_x(i, j, 1, grid, model.closure, closure_fields, tracer_index, tracer, model.clock, model_fields, model.buoyancy) *
            Oceananigans.Models.VarianceDissipationComputations.σⁿ(i, j, 1, grid,
                                                                   Oceananigans.Models.VarianceDissipationComputations.f,
                                                                   Oceananigans.Models.VarianceDissipationComputations.c,
                                                                   Oceananigans.Models.VarianceDissipationComputations.c)

        expected_Vy =
            transport_diffusive_flux_y(i, j, 1, grid, model.closure, closure_fields, tracer_index, tracer, model.clock, model_fields, model.buoyancy) *
            Oceananigans.Models.VarianceDissipationComputations.σⁿ(i, j, 1, grid,
                                                                   Oceananigans.Models.VarianceDissipationComputations.c,
                                                                   Oceananigans.Models.VarianceDissipationComputations.f,
                                                                   Oceananigans.Models.VarianceDissipationComputations.c)

        naive_Vx =
            Oceananigans.TurbulenceClosures._diffusive_flux_x(i, j, 1, grid, Oceananigans.TurbulenceClosures.ExplicitTimeDiscretization(), model.closure, closure_fields, tracer_index, tracer, model.clock, model_fields, model.buoyancy) *
            Oceananigans.Operators.Axᶠᶜᶜ(i, j, 1, grid) *
            Oceananigans.Models.VarianceDissipationComputations.σⁿ(i, j, 1, grid,
                                                                   Oceananigans.Models.VarianceDissipationComputations.f,
                                                                   Oceananigans.Models.VarianceDissipationComputations.c,
                                                                   Oceananigans.Models.VarianceDissipationComputations.c)

        naive_Vy =
            Oceananigans.TurbulenceClosures._diffusive_flux_y(i, j, 1, grid, Oceananigans.TurbulenceClosures.ExplicitTimeDiscretization(), model.closure, closure_fields, tracer_index, tracer, model.clock, model_fields, model.buoyancy) *
            Oceananigans.Operators.Ayᶜᶠᶜ(i, j, 1, grid) *
            Oceananigans.Models.VarianceDissipationComputations.σⁿ(i, j, 1, grid,
                                                                   Oceananigans.Models.VarianceDissipationComputations.c,
                                                                   Oceananigans.Models.VarianceDissipationComputations.f,
                                                                   Oceananigans.Models.VarianceDissipationComputations.c)

        computed_Vx = ϵ.diffusive_fluxes.Vⁿ.x[i, j, 1]
        computed_Vy = ϵ.diffusive_fluxes.Vⁿ.y[i, j, 1]

        x_scale = max(one(FT), abs(expected_Vx), abs(computed_Vx))
        y_scale = max(one(FT), abs(expected_Vy), abs(computed_Vy))

        @test abs(expected_Vx) > 100eps(FT)
        @test abs(expected_Vy) > 100eps(FT)
        @test abs(computed_Vx - expected_Vx) ≤ 1000eps(FT) * x_scale
        @test abs(computed_Vy - expected_Vy) ≤ 1000eps(FT) * y_scale

        maximum_naive_difference = max(maximum_naive_difference,
                                       abs(expected_Vx - naive_Vx),
                                       abs(expected_Vy - naive_Vy))
    end

    @test maximum_naive_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_nonhydrostatic_background_metric_cross_terms_contribute_to_momentum_tendency(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))

    background_fields = (
        u = (λ, φ, z, t) -> convert(FT, 0.12) * cosd(λ) + convert(FT, 0.04) * sind(φ),
        v = (λ, φ, z, t) -> convert(FT, 0.09) * sind(λ / 2) - convert(FT, 0.03) * cosd(φ),
        w = (λ, φ, z, t) -> zero(FT)
    )

    model = NonhydrostaticModel(grid;
                                tracers = :c,
                                buoyancy = nothing,
                                advection = Centered(FT),
                                background_fields)

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.2) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.18) * cosd(λ) - convert(FT, 0.06) * sind(φ),
         w = (λ, φ, z) -> convert(FT, 0.03) * sind(λ / 2) * cosd(φ),
         c = (λ, φ, z) -> zero(FT))

    Oceananigans.TimeSteppers.update_state!(model)
    Oceananigans.TimeSteppers.compute_tendencies!(model, ())

    total_velocities = Oceananigans.Utils.sum_of_velocities(model.velocities, model.background_fields.velocities)
    background_velocities = model.background_fields.velocities

    sampled_points = ((N + 2, N + 2, 1),
                      (1, N + 1, 1),
                      (N + 1, 1, 1),
                      (2N, N + 1, 1),
                      (N + 1, 2N, 1))

    maximum_naive_u_difference = zero(FT)
    maximum_naive_v_difference = zero(FT)
    maximum_naive_w_difference = zero(FT)

    for (i, j, k) in sampled_points
        expected_Gu = -(Oceananigans.Advection.div_𝐯u(i, j, k, grid, model.advection, total_velocities, model.velocities.u) +
                        Oceananigans.Advection.div_𝐯u(i, j, k, grid, model.advection, model.velocities, background_velocities.u) +
                        Oceananigans.Advection.U_dot_∇u_metric(i, j, k, grid, model.advection, total_velocities, model.velocities) +
                        Oceananigans.Advection.U_dot_∇u_metric(i, j, k, grid, model.advection, model.velocities, background_velocities))

        expected_Gv = -(Oceananigans.Advection.div_𝐯v(i, j, k, grid, model.advection, total_velocities, model.velocities.v) +
                        Oceananigans.Advection.div_𝐯v(i, j, k, grid, model.advection, model.velocities, background_velocities.v) +
                        Oceananigans.Advection.U_dot_∇v_metric(i, j, k, grid, model.advection, total_velocities, model.velocities) +
                        Oceananigans.Advection.U_dot_∇v_metric(i, j, k, grid, model.advection, model.velocities, background_velocities))

        expected_Gw = -(Oceananigans.Advection.div_𝐯w(i, j, k, grid, model.advection, total_velocities, model.velocities.w) +
                        Oceananigans.Advection.div_𝐯w(i, j, k, grid, model.advection, model.velocities, background_velocities.w) +
                        Oceananigans.Advection.U_dot_∇w_metric(i, j, k, grid, model.advection, total_velocities, model.velocities) +
                        Oceananigans.Advection.U_dot_∇w_metric(i, j, k, grid, model.advection, model.velocities, background_velocities))

        naive_Gu = -(Oceananigans.Advection.div_𝐯u(i, j, k, grid, model.advection, total_velocities, model.velocities.u) +
                     Oceananigans.Advection.div_𝐯u(i, j, k, grid, model.advection, model.velocities, background_velocities.u) +
                     Oceananigans.Advection.U_dot_∇u_metric(i, j, k, grid, model.advection, model.velocities, model.velocities))

        naive_Gv = -(Oceananigans.Advection.div_𝐯v(i, j, k, grid, model.advection, total_velocities, model.velocities.v) +
                     Oceananigans.Advection.div_𝐯v(i, j, k, grid, model.advection, model.velocities, background_velocities.v) +
                     Oceananigans.Advection.U_dot_∇v_metric(i, j, k, grid, model.advection, model.velocities, model.velocities))

        naive_Gw = -(Oceananigans.Advection.div_𝐯w(i, j, k, grid, model.advection, total_velocities, model.velocities.w) +
                     Oceananigans.Advection.div_𝐯w(i, j, k, grid, model.advection, model.velocities, background_velocities.w) +
                     Oceananigans.Advection.U_dot_∇w_metric(i, j, k, grid, model.advection, model.velocities, model.velocities))

        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        computed_Gw = model.timestepper.Gⁿ.w[i, j, k]

        u_scale = max(one(FT), abs(expected_Gu), abs(computed_Gu))
        v_scale = max(one(FT), abs(expected_Gv), abs(computed_Gv))
        w_scale = max(one(FT), abs(expected_Gw), abs(computed_Gw))

        @test abs(computed_Gu - expected_Gu) ≤ 2000eps(FT) * u_scale
        @test abs(computed_Gv - expected_Gv) ≤ 2000eps(FT) * v_scale
        @test abs(computed_Gw - expected_Gw) ≤ 2000eps(FT) * w_scale

        maximum_naive_u_difference = max(maximum_naive_u_difference, abs(expected_Gu - naive_Gu))
        maximum_naive_v_difference = max(maximum_naive_v_difference, abs(expected_Gv - naive_Gv))
        maximum_naive_w_difference = max(maximum_naive_w_difference, abs(expected_Gw - naive_Gw))
    end

    @test maximum_naive_u_difference > 100eps(FT)
    @test maximum_naive_v_difference > 100eps(FT)
    @test maximum_naive_w_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_nonhydrostatic_cell_advection_timescale_uses_transport_scaling(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = NonhydrostaticModel(grid;
                                timestepper = :QuasiAdamsBashforth2,
                                tracers = :c,
                                buoyancy = nothing,
                                advection = Centered(FT))

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.2) * sind(λ) + convert(FT, 0.08) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.14) * cosd(λ) - convert(FT, 0.06) * sind(φ),
         w = (λ, φ, z) -> convert(FT, 0.03) * sind(λ / 2) * cosd(φ),
         c = (λ, φ, z) -> zero(FT))

    computed = Oceananigans.Models.NonhydrostaticModels.cell_advection_timescale(model)

    converted_transport = (u = OctaHEALPixConvertedTransportU(grid, model.velocities.u, model.velocities.v),
                           v = OctaHEALPixConvertedTransportV(grid, model.velocities.u, model.velocities.v),
                           w = model.velocities.w)

    expected = minimum((k, j, i) for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx) do (k, j, i)
        inverse_timescale_x = abs(converted_transport.u[i, j, k]) * Oceananigans.Operators.V⁻¹ᶜᶜᶜ(i, j, k, grid)
        inverse_timescale_y = abs(converted_transport.v[i, j, k]) * Oceananigans.Operators.V⁻¹ᶜᶜᶜ(i, j, k, grid)
        inverse_timescale_z = abs(model.velocities.w[i, j, k]) * Oceananigans.Operators.Δz⁻¹ᶜᶜᶠ(i, j, k, grid)
        return one(FT) / (inverse_timescale_x + inverse_timescale_y + inverse_timescale_z)
    end

    naive = minimum((k, j, i) for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx) do (k, j, i)
        inverse_timescale_x = abs(model.velocities.u[i, j, k]) * Oceananigans.Operators.Δx⁻¹ᶠᶜᶜ(i, j, k, grid)
        inverse_timescale_y = abs(model.velocities.v[i, j, k]) * Oceananigans.Operators.Δy⁻¹ᶜᶠᶜ(i, j, k, grid)
        inverse_timescale_z = abs(model.velocities.w[i, j, k]) * Oceananigans.Operators.Δz⁻¹ᶜᶜᶠ(i, j, k, grid)
        return one(FT) / (inverse_timescale_x + inverse_timescale_y + inverse_timescale_z)
    end

    scale = max(one(FT), abs(expected), abs(computed))

    @test abs(computed - expected) ≤ 1000eps(FT) * scale
    @test abs(expected - naive) > 100eps(FT)

    return nothing
end

function test_octahealpix_nonhydrostatic_cell_advection_timescale_includes_horizontal_biogeochemical_drift(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    drift_u = XFaceField(grid)
    drift_v = YFaceField(grid)

    set!((u = drift_u, v = drift_v);
         u = (λ, φ, z) -> convert(FT, 0.07) * sind(λ) + convert(FT, 0.02) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.05) * cosd(λ) - convert(FT, 0.015) * sind(φ))

    fill_halo_regions!((drift_u, drift_v))

    drift_velocity = (u = drift_u, v = drift_v, w = ZeroField())
    biogeochemistry = OctaHEALPixHorizontalDriftBiogeochemistry(drift_velocity)

    model = NonhydrostaticModel(grid;
                                tracers = :c,
                                buoyancy = nothing,
                                biogeochemistry,
                                advection = Centered(FT))

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.2) * sind(λ) + convert(FT, 0.08) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.14) * cosd(λ) - convert(FT, 0.06) * sind(φ),
         w = (λ, φ, z) -> convert(FT, 0.03) * sind(λ / 2) * cosd(φ),
         c = (λ, φ, z) -> zero(FT))

    computed = Oceananigans.Models.NonhydrostaticModels.cell_advection_timescale(model)

    total_velocities = Oceananigans.Utils.sum_of_velocities(model.velocities,
                                                            model.background_fields.velocities,
                                                            drift_velocity)

    converted_transport = (u = OctaHEALPixConvertedTransportU(grid, total_velocities.u, total_velocities.v),
                           v = OctaHEALPixConvertedTransportV(grid, total_velocities.u, total_velocities.v),
                           w = total_velocities.w)

    velocity_transport = (u = OctaHEALPixConvertedTransportU(grid, model.velocities.u, model.velocities.v),
                          v = OctaHEALPixConvertedTransportV(grid, model.velocities.u, model.velocities.v),
                          w = model.velocities.w)

    expected = minimum((k, j, i) for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx) do (k, j, i)
        inverse_timescale_x = abs(converted_transport.u[i, j, k]) * Oceananigans.Operators.V⁻¹ᶜᶜᶜ(i, j, k, grid)
        inverse_timescale_y = abs(converted_transport.v[i, j, k]) * Oceananigans.Operators.V⁻¹ᶜᶜᶜ(i, j, k, grid)
        inverse_timescale_z = abs(converted_transport.w[i, j, k]) * Oceananigans.Operators.Δz⁻¹ᶜᶜᶠ(i, j, k, grid)
        return one(FT) / (inverse_timescale_x + inverse_timescale_y + inverse_timescale_z)
    end

    naive = minimum((k, j, i) for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx) do (k, j, i)
        inverse_timescale_x = abs(velocity_transport.u[i, j, k]) * Oceananigans.Operators.V⁻¹ᶜᶜᶜ(i, j, k, grid)
        inverse_timescale_y = abs(velocity_transport.v[i, j, k]) * Oceananigans.Operators.V⁻¹ᶜᶜᶜ(i, j, k, grid)
        inverse_timescale_z = abs(velocity_transport.w[i, j, k]) * Oceananigans.Operators.Δz⁻¹ᶜᶜᶠ(i, j, k, grid)
        return one(FT) / (inverse_timescale_x + inverse_timescale_y + inverse_timescale_z)
    end

    scale = max(one(FT), abs(expected), abs(computed))

    @test abs(computed - expected) ≤ 1000eps(FT) * scale
    @test abs(expected - naive) > 100eps(FT)

    return nothing
end

function test_octahealpix_nonhydrostatic_cell_advection_timescale_includes_horizontal_momentum_advective_forcing(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    forcing_u = XFaceField(grid)
    forcing_v = YFaceField(grid)

    set!((u = forcing_u, v = forcing_v);
         u = (λ, φ, z) -> convert(FT, 0.18) * sind(λ) + convert(FT, 0.06) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.11) * cosd(λ) - convert(FT, 0.04) * sind(φ))

    fill_halo_regions!((forcing_u, forcing_v))

    forcing = (u = AdvectiveForcing(u = forcing_u, v = forcing_v),)

    model = NonhydrostaticModel(grid;
                                tracers = :c,
                                buoyancy = nothing,
                                forcing,
                                advection = Centered(FT))

    set!(model,
         u = zero(FT),
         v = zero(FT),
         w = zero(FT),
         c = zero(FT))

    computed = Oceananigans.Models.NonhydrostaticModels.cell_advection_timescale(model)

    base_velocities = Oceananigans.Utils.sum_of_velocities(model.velocities,
                                                           model.background_fields.velocities)

    forced_velocities = Oceananigans.Forcings.with_advective_forcing(model.forcing.u, base_velocities)
    expected = Oceananigans.Advection.cell_advection_timescale(grid, forced_velocities)
    naive = Oceananigans.Advection.cell_advection_timescale(grid, base_velocities)
    scale = max(one(FT), abs(expected), abs(computed))

    @test abs(computed - expected) ≤ 1000eps(FT) * scale
    @test isfinite(expected)
    @test isinf(naive)

    return nothing
end

function test_octahealpix_nonhydrostatic_horizontal_momentum_advective_forcing_refreshes_halos(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    forcing_u = XFaceField(grid)
    forcing_v = YFaceField(grid)
    reference_u = XFaceField(grid)
    reference_v = YFaceField(grid)

    set!((u = forcing_u, v = forcing_v);
         u = (λ, φ, z) -> convert(FT, 0.13) * sind(λ) + convert(FT, 0.04) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.09) * cosd(λ) - convert(FT, 0.03) * sind(φ))

    set!((u = reference_u, v = reference_v);
         u = (λ, φ, z) -> convert(FT, 0.13) * sind(λ) + convert(FT, 0.04) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.09) * cosd(λ) - convert(FT, 0.03) * sind(φ))

    fill_halo_regions!((reference_u, reference_v))

    forcing = (u = AdvectiveForcing(u = forcing_u, v = forcing_v),
               v = AdvectiveForcing(u = forcing_u, v = forcing_v))

    model = NonhydrostaticModel(grid;
                                tracers = :c,
                                buoyancy = nothing,
                                forcing,
                                advection = Centered(FT))

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.16) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.12) * cosd(λ) - convert(FT, 0.04) * sind(φ),
         w = zero(FT),
         c = zero(FT))

    for j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue
        forcing_u[i, j, 1] = convert(FT, 111)
        forcing_v[i, j, 1] = convert(FT, -222)
    end

    compute_tendencies!(model)

    base_velocities = Oceananigans.Utils.sum_of_velocities(model.velocities,
                                                           model.background_fields.velocities)

    expected_total_velocities = Oceananigans.Forcings.with_advective_forcing(AdvectiveForcing(u = reference_u, v = reference_v),
                                                                             base_velocities)

    corrupted_total_velocities = Oceananigans.Forcings.with_advective_forcing(AdvectiveForcing(u = forcing_u, v = forcing_v),
                                                                              base_velocities)

    samples = ((2, div(N, 2), 1),
               (N - 1, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (div(N, 2), N - 1, 1))

    maximum_corrupted_u_difference = zero(FT)
    maximum_corrupted_v_difference = zero(FT)

    for (i, j, k) in samples
        expected_Gu = -(Oceananigans.Advection.div_𝐯u(i, j, k, grid, model.advection, expected_total_velocities, model.velocities.u) +
                        Oceananigans.Advection.U_dot_∇u_metric(i, j, k, grid, model.advection, expected_total_velocities, model.velocities))

        expected_Gv = -(Oceananigans.Advection.div_𝐯v(i, j, k, grid, model.advection, expected_total_velocities, model.velocities.v) +
                        Oceananigans.Advection.U_dot_∇v_metric(i, j, k, grid, model.advection, expected_total_velocities, model.velocities))

        corrupted_Gu = -(Oceananigans.Advection.div_𝐯u(i, j, k, grid, model.advection, corrupted_total_velocities, model.velocities.u) +
                         Oceananigans.Advection.U_dot_∇u_metric(i, j, k, grid, model.advection, corrupted_total_velocities, model.velocities))

        corrupted_Gv = -(Oceananigans.Advection.div_𝐯v(i, j, k, grid, model.advection, corrupted_total_velocities, model.velocities.v) +
                         Oceananigans.Advection.U_dot_∇v_metric(i, j, k, grid, model.advection, corrupted_total_velocities, model.velocities))

        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]

        u_scale = max(one(FT), abs(expected_Gu), abs(computed_Gu))
        v_scale = max(one(FT), abs(expected_Gv), abs(computed_Gv))

        @test abs(computed_Gu - expected_Gu) ≤ 2000eps(FT) * u_scale
        @test abs(computed_Gv - expected_Gv) ≤ 2000eps(FT) * v_scale

        maximum_corrupted_u_difference = max(maximum_corrupted_u_difference, abs(expected_Gu - corrupted_Gu))
        maximum_corrupted_v_difference = max(maximum_corrupted_v_difference, abs(expected_Gv - corrupted_Gv))
    end

    @test maximum_corrupted_u_difference > 100eps(FT)
    @test maximum_corrupted_v_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_nonhydrostatic_background_momentum_uses_horizontal_advective_forcing(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    forcing_u = XFaceField(grid)
    forcing_v = YFaceField(grid)
    background_u = XFaceField(grid)
    background_v = YFaceField(grid)

    set!((u = forcing_u, v = forcing_v);
         u = (λ, φ, z) -> convert(FT, 0.13) * sind(λ) + convert(FT, 0.04) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.09) * cosd(λ) - convert(FT, 0.03) * sind(φ))

    set!((u = background_u, v = background_v);
         u = (λ, φ, z) -> convert(FT, 0.17) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.12) * cosd(λ) - convert(FT, 0.04) * sind(φ))

    fill_halo_regions!((forcing_u, forcing_v))
    fill_halo_regions!((background_u, background_v))

    background_fields = BackgroundFields(u = background_u, v = background_v)
    forcing = (u = AdvectiveForcing(u = forcing_u, v = forcing_v),
               v = AdvectiveForcing(u = forcing_u, v = forcing_v))

    model = NonhydrostaticModel(grid;
                                tracers = :c,
                                buoyancy = nothing,
                                background_fields,
                                forcing,
                                advection = Centered(FT))

    set!(model,
         u = zero(FT),
         v = zero(FT),
         w = zero(FT),
         c = zero(FT))

    compute_tendencies!(model)

    total_velocities = Oceananigans.Forcings.with_advective_forcing(model.forcing.u,
                                                                    Oceananigans.Utils.sum_of_velocities(model.velocities,
                                                                                                         model.background_fields.velocities))

    background_total_velocities = Oceananigans.Forcings.with_advective_forcing(model.forcing.u, model.velocities)

    samples = ((2, div(N, 2), 1),
               (N - 1, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (div(N, 2), N - 1, 1))

    maximum_naive_u_difference = zero(FT)
    maximum_naive_v_difference = zero(FT)

    for (i, j, k) in samples
        expected_Gu = -(Oceananigans.Advection.div_𝐯u(i, j, k, grid, model.advection, total_velocities, model.velocities.u) +
                        Oceananigans.Advection.div_𝐯u(i, j, k, grid, model.advection, background_total_velocities, model.background_fields.velocities.u) +
                        Oceananigans.Advection.U_dot_∇u_metric(i, j, k, grid, model.advection, total_velocities, model.velocities) +
                        Oceananigans.Advection.U_dot_∇u_metric(i, j, k, grid, model.advection, background_total_velocities, model.background_fields.velocities))

        expected_Gv = -(Oceananigans.Advection.div_𝐯v(i, j, k, grid, model.advection, total_velocities, model.velocities.v) +
                        Oceananigans.Advection.div_𝐯v(i, j, k, grid, model.advection, background_total_velocities, model.background_fields.velocities.v) +
                        Oceananigans.Advection.U_dot_∇v_metric(i, j, k, grid, model.advection, total_velocities, model.velocities) +
                        Oceananigans.Advection.U_dot_∇v_metric(i, j, k, grid, model.advection, background_total_velocities, model.background_fields.velocities))

        naive_Gu = -(Oceananigans.Advection.div_𝐯u(i, j, k, grid, model.advection, total_velocities, model.velocities.u) +
                     Oceananigans.Advection.div_𝐯u(i, j, k, grid, model.advection, model.velocities, model.background_fields.velocities.u) +
                     Oceananigans.Advection.U_dot_∇u_metric(i, j, k, grid, model.advection, total_velocities, model.velocities) +
                     Oceananigans.Advection.U_dot_∇u_metric(i, j, k, grid, model.advection, model.velocities, model.background_fields.velocities))

        naive_Gv = -(Oceananigans.Advection.div_𝐯v(i, j, k, grid, model.advection, total_velocities, model.velocities.v) +
                     Oceananigans.Advection.div_𝐯v(i, j, k, grid, model.advection, model.velocities, model.background_fields.velocities.v) +
                     Oceananigans.Advection.U_dot_∇v_metric(i, j, k, grid, model.advection, total_velocities, model.velocities) +
                     Oceananigans.Advection.U_dot_∇v_metric(i, j, k, grid, model.advection, model.velocities, model.background_fields.velocities))

        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]

        u_scale = max(one(FT), abs(expected_Gu), abs(computed_Gu))
        v_scale = max(one(FT), abs(expected_Gv), abs(computed_Gv))

        @test abs(computed_Gu - expected_Gu) ≤ 2000eps(FT) * u_scale
        @test abs(computed_Gv - expected_Gv) ≤ 2000eps(FT) * v_scale

        maximum_naive_u_difference = max(maximum_naive_u_difference, abs(expected_Gu - naive_Gu))
        maximum_naive_v_difference = max(maximum_naive_v_difference, abs(expected_Gv - naive_Gv))
    end

    @test maximum_naive_u_difference > 100eps(FT)
    @test maximum_naive_v_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_nonhydrostatic_background_field_halos_refresh_for_timescale_momentum_and_tracer(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    background_u = XFaceField(grid)
    background_v = YFaceField(grid)
    background_c = CenterField(grid)

    reference_u = XFaceField(grid)
    reference_v = YFaceField(grid)
    reference_c = CenterField(grid)

    set!((u = background_u, v = background_v);
         u = (λ, φ, z) -> convert(FT, 0.17) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.12) * cosd(λ) - convert(FT, 0.04) * sind(φ))

    set!((u = reference_u, v = reference_v);
         u = (λ, φ, z) -> convert(FT, 0.17) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.12) * cosd(λ) - convert(FT, 0.04) * sind(φ))

    set!(background_c, (λ, φ, z) -> convert(FT, 0.4) + convert(FT, 0.2) * sind(λ) + convert(FT, 0.1) * cosd(φ))
    set!(reference_c, (λ, φ, z) -> convert(FT, 0.4) + convert(FT, 0.2) * sind(λ) + convert(FT, 0.1) * cosd(φ))

    fill_halo_regions!((reference_u, reference_v))
    fill_halo_regions!(reference_c)

    background_fields = BackgroundFields(u = background_u, v = background_v, c = background_c)

    model = NonhydrostaticModel(grid;
                                tracers = :c,
                                buoyancy = nothing,
                                advection = Centered(FT),
                                background_fields)

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.16) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.11) * cosd(λ) - convert(FT, 0.03) * sind(φ),
         w = (λ, φ, z) -> convert(FT, 0.02) * sind(λ / 2) * cosd(φ),
         c = zero(FT))

    for j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue
        background_u[i, j, 1] = convert(FT, 111)
        background_v[i, j, 1] = convert(FT, -222)
        background_c[i, j, 1] = convert(FT, 333)
    end

    computed_timescale = Oceananigans.Models.NonhydrostaticModels.cell_advection_timescale(model)
    Oceananigans.TimeSteppers.compute_tendencies!(model, ())

    expected_total_velocities = Oceananigans.Utils.sum_of_velocities(model.velocities,
                                                                     (u = reference_u, v = reference_v, w = model.background_fields.velocities.w))

    stale_total_velocities = Oceananigans.Utils.sum_of_velocities(model.velocities,
                                                                  (u = background_u, v = background_v, w = model.background_fields.velocities.w))

    expected_advective_velocities = (u = OctaHEALPixConvertedTransportU(grid, expected_total_velocities.u, expected_total_velocities.v),
                                     v = OctaHEALPixConvertedTransportV(grid, expected_total_velocities.u, expected_total_velocities.v),
                                     w = expected_total_velocities.w)

    stale_advective_velocities = (u = OctaHEALPixConvertedTransportU(grid, stale_total_velocities.u, stale_total_velocities.v),
                                  v = OctaHEALPixConvertedTransportV(grid, stale_total_velocities.u, stale_total_velocities.v),
                                  w = stale_total_velocities.w)

    background_tracer_advection_velocities =
        Oceananigans.Models.NonhydrostaticModels.tracer_advection_velocities(grid, model.velocities)

    expected_timescale = Oceananigans.Advection.cell_advection_timescale(grid, expected_total_velocities)
    stale_timescale = Oceananigans.Advection.cell_advection_timescale(grid, stale_total_velocities)

    samples = ((N + 2, N + 2, 1),
               (2, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (N - 1, div(N, 2), 1))

    maximum_stale_u_difference = zero(FT)
    maximum_stale_v_difference = zero(FT)
    maximum_stale_c_difference = zero(FT)

    for (i, j, k) in samples
        expected_Gu = -(Oceananigans.Advection.div_𝐯u(i, j, k, grid, model.advection, expected_total_velocities, model.velocities.u) +
                        Oceananigans.Advection.div_𝐯u(i, j, k, grid, model.advection, model.velocities, reference_u) +
                        Oceananigans.Advection.U_dot_∇u_metric(i, j, k, grid, model.advection, expected_total_velocities, model.velocities) +
                        Oceananigans.Advection.U_dot_∇u_metric(i, j, k, grid, model.advection, model.velocities, (u = reference_u, v = reference_v, w = model.background_fields.velocities.w)))

        expected_Gv = -(Oceananigans.Advection.div_𝐯v(i, j, k, grid, model.advection, expected_total_velocities, model.velocities.v) +
                        Oceananigans.Advection.div_𝐯v(i, j, k, grid, model.advection, model.velocities, reference_v) +
                        Oceananigans.Advection.U_dot_∇v_metric(i, j, k, grid, model.advection, expected_total_velocities, model.velocities) +
                        Oceananigans.Advection.U_dot_∇v_metric(i, j, k, grid, model.advection, model.velocities, (u = reference_u, v = reference_v, w = model.background_fields.velocities.w)))

        expected_Gc = - div_Uc(i, j, k, grid, model.advection, background_tracer_advection_velocities, reference_c)

        stale_Gu = -(Oceananigans.Advection.div_𝐯u(i, j, k, grid, model.advection, stale_total_velocities, model.velocities.u) +
                     Oceananigans.Advection.div_𝐯u(i, j, k, grid, model.advection, model.velocities, background_u) +
                     Oceananigans.Advection.U_dot_∇u_metric(i, j, k, grid, model.advection, stale_total_velocities, model.velocities) +
                     Oceananigans.Advection.U_dot_∇u_metric(i, j, k, grid, model.advection, model.velocities, (u = background_u, v = background_v, w = model.background_fields.velocities.w)))

        stale_Gv = -(Oceananigans.Advection.div_𝐯v(i, j, k, grid, model.advection, stale_total_velocities, model.velocities.v) +
                     Oceananigans.Advection.div_𝐯v(i, j, k, grid, model.advection, model.velocities, background_v) +
                     Oceananigans.Advection.U_dot_∇v_metric(i, j, k, grid, model.advection, stale_total_velocities, model.velocities) +
                     Oceananigans.Advection.U_dot_∇v_metric(i, j, k, grid, model.advection, model.velocities, (u = background_u, v = background_v, w = model.background_fields.velocities.w)))

        stale_Gc = - div_Uc(i, j, k, grid, model.advection, background_tracer_advection_velocities, background_c)

        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        computed_Gc = model.timestepper.Gⁿ.c[i, j, k]

        u_scale = max(one(FT), abs(expected_Gu), abs(computed_Gu))
        v_scale = max(one(FT), abs(expected_Gv), abs(computed_Gv))
        c_scale = max(one(FT), abs(expected_Gc), abs(computed_Gc))

        @test abs(computed_Gu - expected_Gu) ≤ 2000eps(FT) * u_scale
        @test abs(computed_Gv - expected_Gv) ≤ 2000eps(FT) * v_scale
        @test abs(computed_Gc - expected_Gc) ≤ 2000eps(FT) * c_scale

        maximum_stale_u_difference = max(maximum_stale_u_difference, abs(expected_Gu - stale_Gu))
        maximum_stale_v_difference = max(maximum_stale_v_difference, abs(expected_Gv - stale_Gv))
        maximum_stale_c_difference = max(maximum_stale_c_difference, abs(expected_Gc - stale_Gc))
    end

    timescale_scale = max(one(FT), abs(expected_timescale), abs(computed_timescale))

    @test abs(computed_timescale - expected_timescale) ≤ 1000eps(FT) * timescale_scale
    @test abs(expected_timescale - stale_timescale) > 100eps(FT)
    @test maximum_stale_u_difference > 100eps(FT)
    @test maximum_stale_v_difference > 100eps(FT)
    @test maximum_stale_c_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_nonhydrostatic_time_series_background_fields_refresh_for_timescale_momentum_and_tracer(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    background_u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times)
    background_v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times)
    background_c_fts = Oceananigans.FieldTimeSeries{Center, Center, Center}(grid, times)

    set!(background_u_fts, (λ, φ, z, t) -> convert(FT, 0.17) * sind(λ) + convert(FT, 0.05) * cosd(φ) + convert(FT, 0.11) * t)
    set!(background_v_fts, (λ, φ, z, t) -> convert(FT, 0.12) * cosd(λ) - convert(FT, 0.04) * sind(φ) - convert(FT, 0.07) * t)
    set!(background_c_fts, (λ, φ, z, t) -> convert(FT, 0.4) + convert(FT, 0.2) * sind(λ) + convert(FT, 0.1) * cosd(φ) + convert(FT, 0.09) * t)

    source_clock = Oceananigans.Clock(time = zero(FT))
    background_u_tsi = Oceananigans.OutputReaders.TimeSeriesInterpolation(background_u_fts, grid; clock = source_clock)
    background_v_tsi = Oceananigans.OutputReaders.TimeSeriesInterpolation(background_v_fts, grid; clock = source_clock)
    background_c_tsi = Oceananigans.OutputReaders.TimeSeriesInterpolation(background_c_fts, grid; clock = source_clock)

    model = NonhydrostaticModel(grid;
                                tracers = :c,
                                buoyancy = nothing,
                                advection = Centered(FT),
                                background_fields = (u = background_u_tsi,
                                                     v = background_v_tsi,
                                                     c = background_c_tsi))

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.16) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.11) * cosd(λ) - convert(FT, 0.03) * sind(φ),
         w = (λ, φ, z) -> convert(FT, 0.02) * sind(λ / 2) * cosd(φ))

    set!(model.tracers.c, (λ, φ, z) -> convert(FT, 0.15) * sind(λ / 2) * cosd(φ))

    reference_u = XFaceField(grid)
    reference_v = YFaceField(grid)
    reference_c = CenterField(grid)
    stale_u = XFaceField(grid)
    stale_v = YFaceField(grid)
    stale_c = CenterField(grid)

    set!((u = reference_u, v = reference_v);
         u = (λ, φ, z) -> convert(FT, 0.17) * sind(λ) + convert(FT, 0.05) * cosd(φ) + convert(FT, 0.11) * half,
         v = (λ, φ, z) -> convert(FT, 0.12) * cosd(λ) - convert(FT, 0.04) * sind(φ) - convert(FT, 0.07) * half)

    set!((u = stale_u, v = stale_v);
         u = (λ, φ, z) -> convert(FT, 0.17) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.12) * cosd(λ) - convert(FT, 0.04) * sind(φ))

    set!(reference_c, (λ, φ, z) -> convert(FT, 0.4) + convert(FT, 0.2) * sind(λ) + convert(FT, 0.1) * cosd(φ) + convert(FT, 0.09) * half)
    set!(stale_c, (λ, φ, z) -> convert(FT, 0.4) + convert(FT, 0.2) * sind(λ) + convert(FT, 0.1) * cosd(φ))

    fill_halo_regions!((reference_u, reference_v))
    fill_halo_regions!((stale_u, stale_v))
    fill_halo_regions!(reference_c)
    fill_halo_regions!(stale_c)

    model.clock.time = half

    computed_timescale = Oceananigans.Models.NonhydrostaticModels.cell_advection_timescale(model)
    Oceananigans.TimeSteppers.compute_tendencies!(model, ())

    expected_total_velocities = Oceananigans.Utils.sum_of_velocities(model.velocities,
                                                                     (u = reference_u, v = reference_v, w = model.background_fields.velocities.w))
    stale_total_velocities = Oceananigans.Utils.sum_of_velocities(model.velocities,
                                                                  (u = stale_u, v = stale_v, w = model.background_fields.velocities.w))

    expected_advective_velocities =
        Oceananigans.Advection.spherical_shell_volume_flux_velocities(grid, expected_total_velocities)
    stale_advective_velocities =
        Oceananigans.Advection.spherical_shell_volume_flux_velocities(grid, stale_total_velocities)

    background_tracer_advection_velocities =
        Oceananigans.Models.NonhydrostaticModels.tracer_advection_velocities(grid, model.velocities)

    expected_timescale = Oceananigans.Advection.cell_advection_timescale(grid, expected_total_velocities)
    stale_timescale = Oceananigans.Advection.cell_advection_timescale(grid, stale_total_velocities)

    samples = ((N + 2, N + 2, 1),
               (2, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (N - 1, div(N, 2), 1))

    maximum_stale_u_difference = zero(FT)
    maximum_stale_v_difference = zero(FT)
    maximum_stale_c_difference = zero(FT)

    for (i, j, k) in samples
        expected_Gu = -(Oceananigans.Advection.div_𝐯u(i, j, k, grid, model.advection, expected_total_velocities, model.velocities.u) +
                        Oceananigans.Advection.div_𝐯u(i, j, k, grid, model.advection, model.velocities, reference_u) +
                        Oceananigans.Advection.U_dot_∇u_metric(i, j, k, grid, model.advection, expected_total_velocities, model.velocities) +
                        Oceananigans.Advection.U_dot_∇u_metric(i, j, k, grid, model.advection, model.velocities, (u = reference_u, v = reference_v, w = model.background_fields.velocities.w)))

        expected_Gv = -(Oceananigans.Advection.div_𝐯v(i, j, k, grid, model.advection, expected_total_velocities, model.velocities.v) +
                        Oceananigans.Advection.div_𝐯v(i, j, k, grid, model.advection, model.velocities, reference_v) +
                        Oceananigans.Advection.U_dot_∇v_metric(i, j, k, grid, model.advection, expected_total_velocities, model.velocities) +
                        Oceananigans.Advection.U_dot_∇v_metric(i, j, k, grid, model.advection, model.velocities, (u = reference_u, v = reference_v, w = model.background_fields.velocities.w)))

        expected_Gc = -(div_Uc(i, j, k, grid, model.advection, expected_advective_velocities, model.tracers.c) +
                        div_Uc(i, j, k, grid, model.advection, background_tracer_advection_velocities, reference_c))

        stale_Gu = -(Oceananigans.Advection.div_𝐯u(i, j, k, grid, model.advection, stale_total_velocities, model.velocities.u) +
                     Oceananigans.Advection.div_𝐯u(i, j, k, grid, model.advection, model.velocities, stale_u) +
                     Oceananigans.Advection.U_dot_∇u_metric(i, j, k, grid, model.advection, stale_total_velocities, model.velocities) +
                     Oceananigans.Advection.U_dot_∇u_metric(i, j, k, grid, model.advection, model.velocities, (u = stale_u, v = stale_v, w = model.background_fields.velocities.w)))

        stale_Gv = -(Oceananigans.Advection.div_𝐯v(i, j, k, grid, model.advection, stale_total_velocities, model.velocities.v) +
                     Oceananigans.Advection.div_𝐯v(i, j, k, grid, model.advection, model.velocities, stale_v) +
                     Oceananigans.Advection.U_dot_∇v_metric(i, j, k, grid, model.advection, stale_total_velocities, model.velocities) +
                     Oceananigans.Advection.U_dot_∇v_metric(i, j, k, grid, model.advection, model.velocities, (u = stale_u, v = stale_v, w = model.background_fields.velocities.w)))

        stale_Gc = -(div_Uc(i, j, k, grid, model.advection, stale_advective_velocities, model.tracers.c) +
                     div_Uc(i, j, k, grid, model.advection, background_tracer_advection_velocities, stale_c))

        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        computed_Gc = model.timestepper.Gⁿ.c[i, j, k]

        u_scale = max(one(FT), abs(expected_Gu), abs(computed_Gu))
        v_scale = max(one(FT), abs(expected_Gv), abs(computed_Gv))
        c_scale = max(one(FT), abs(expected_Gc), abs(computed_Gc))

        @test abs(computed_timescale - expected_timescale) ≤ 1000eps(FT) * max(one(FT), abs(expected_timescale))
        @test abs(computed_Gu - expected_Gu) ≤ 2000eps(FT) * u_scale
        @test abs(computed_Gv - expected_Gv) ≤ 2000eps(FT) * v_scale
        @test abs(computed_Gc - expected_Gc) ≤ 2000eps(FT) * c_scale

        maximum_stale_u_difference = max(maximum_stale_u_difference, abs(expected_Gu - stale_Gu))
        maximum_stale_v_difference = max(maximum_stale_v_difference, abs(expected_Gv - stale_Gv))
        maximum_stale_c_difference = max(maximum_stale_c_difference, abs(expected_Gc - stale_Gc))
    end

    @test abs(computed_timescale - stale_timescale) > 100eps(FT) * max(one(FT), abs(expected_timescale))
    @test maximum_stale_u_difference > 100eps(FT)
    @test maximum_stale_v_difference > 100eps(FT)
    @test maximum_stale_c_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_nonhydrostatic_model_step_closure_prognostics_refreshes_state_halos(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    closure = Oceananigans.TurbulenceClosures.CATKEVerticalDiffusivity(FT)

    function build_model()
        model = NonhydrostaticModel(grid;
                                    tracers = (:b, :e),
                                    buoyancy = BuoyancyTracer(),
                                    advection = Centered(FT),
                                    closure = closure)

        set!(model,
             u = (λ, φ, z) -> convert(FT, 0.17) * sind(λ) + convert(FT, 0.05) * cosd(φ) + convert(FT, 0.07) * z,
             v = (λ, φ, z) -> convert(FT, 0.12) * cosd(λ) - convert(FT, 0.04) * sind(φ) - convert(FT, 0.06) * z,
             w = (λ, φ, z) -> convert(FT, 0.03) * sind(λ / 2) * cosd(φ) + convert(FT, 0.02) * z,
             b = (λ, φ, z) -> convert(FT, 0.06) * sind(λ / 2) * cosd(φ) + convert(FT, 0.23) * z,
             e = (λ, φ, z) -> convert(FT, 2e-4) + convert(FT, 7e-5) * sind(λ) * cosd(φ) + convert(FT, 3e-5) * z)

        Oceananigans.TurbulenceClosures.initialize_closure_fields!(model.closure_fields, model.closure, model)
        model.clock.iteration = 3

        return model
    end

    function corrupt_nonhydrostatic_catke_step_state_halos!(model)
        u = model.velocities.u
        v = model.velocities.v
        w = model.velocities.w
        b = model.tracers.b
        e = model.tracers.e

        for k in 1:grid.Nz, j in 0:(size(u, 2) + 1), i in 0:(size(u, 1) + 1)
            (1 <= i <= size(u, 1) && 1 <= j <= size(u, 2)) && continue
            u[i, j, k] = convert(FT, 3i - 2j + k)
        end

        for k in 1:grid.Nz, j in 0:(size(v, 2) + 1), i in 0:(size(v, 1) + 1)
            (1 <= i <= size(v, 1) && 1 <= j <= size(v, 2)) && continue
            v[i, j, k] = convert(FT, -2i + 4j - k)
        end

        for k in 1:grid.Nz, j in 0:(size(w, 2) + 1), i in 0:(size(w, 1) + 1)
            (1 <= i <= size(w, 1) && 1 <= j <= size(w, 2)) && continue
            w[i, j, k] = convert(FT, 2i + j - 3k)
        end

        for k in 1:grid.Nz, j in 0:(size(b, 2) + 1), i in 0:(size(b, 1) + 1)
            (1 <= i <= size(b, 1) && 1 <= j <= size(b, 2)) && continue
            b[i, j, k] = convert(FT, i - 3j + 2k)
            e[i, j, k] = convert(FT, -4i + j - k)
        end

        return nothing
    end

    reference_model = build_model()
    Oceananigans.TimeSteppers.step_closure_prognostics!(reference_model, one(FT))
    Oceananigans.TurbulenceClosures.compute_closure_fields!(reference_model.closure_fields,
                                                            reference_model.closure,
                                                            reference_model)

    guarded_model = build_model()
    corrupt_nonhydrostatic_catke_step_state_halos!(guarded_model)
    Oceananigans.TimeSteppers.step_closure_prognostics!(guarded_model, one(FT))
    Oceananigans.TurbulenceClosures.compute_closure_fields!(guarded_model.closure_fields,
                                                            guarded_model.closure,
                                                            guarded_model)

    stale_model = build_model()
    corrupt_nonhydrostatic_catke_step_state_halos!(stale_model)
    Oceananigans.TurbulenceClosures.step_closure_prognostics!(stale_model.closure_fields,
                                                              stale_model.closure,
                                                              stale_model,
                                                              one(FT))
    Oceananigans.TurbulenceClosures.compute_closure_fields!(stale_model.closure_fields,
                                                            stale_model.closure,
                                                            stale_model)

    sampled_points = ((1, N + 1, 1),
                      (N + 1, 1, 2),
                      (2N, N + 1, 1),
                      (N + 1, 2N, 2),
                      (N + 2, N + 2, 1))

    maximum_reference_tke = zero(FT)
    maximum_reference_viscosity = zero(FT)
    maximum_guarded_tke_error = zero(FT)
    maximum_guarded_viscosity_error = zero(FT)
    maximum_stale_tke_difference = zero(FT)
    maximum_stale_viscosity_difference = zero(FT)

    for (i, j, k) in sampled_points
        e_reference = reference_model.tracers.e[i, j, k]
        κu_reference = reference_model.closure_fields.κu[i, j, k]

        e_guarded = guarded_model.tracers.e[i, j, k]
        κu_guarded = guarded_model.closure_fields.κu[i, j, k]

        e_stale = stale_model.tracers.e[i, j, k]
        κu_stale = stale_model.closure_fields.κu[i, j, k]

        maximum_reference_tke = max(maximum_reference_tke, abs(e_reference))
        maximum_reference_viscosity = max(maximum_reference_viscosity, abs(κu_reference))
        maximum_guarded_tke_error = max(maximum_guarded_tke_error, abs(e_reference - e_guarded))
        maximum_guarded_viscosity_error = max(maximum_guarded_viscosity_error, abs(κu_reference - κu_guarded))
        maximum_stale_tke_difference = max(maximum_stale_tke_difference, abs(e_reference - e_stale))
        maximum_stale_viscosity_difference = max(maximum_stale_viscosity_difference, abs(κu_reference - κu_stale))
    end

    @test maximum_reference_tke > sqrt(eps(FT))
    @test maximum_reference_viscosity > sqrt(eps(FT))
    @test maximum_guarded_tke_error ≤ 1000eps(FT) * max(one(FT), maximum_reference_tke)
    @test maximum_guarded_viscosity_error ≤ 1000eps(FT) * max(one(FT), maximum_reference_viscosity)
    @test maximum_stale_tke_difference > 100eps(FT) * max(one(FT), maximum_reference_tke)
    @test maximum_stale_viscosity_difference > 100eps(FT) * max(one(FT), maximum_reference_viscosity)

    return nothing
end

@testset "OctaHEALPix nonhydrostatic time-dependent background field refresh" begin
    for FT in (Float32, Float64)
        test_octahealpix_nonhydrostatic_time_series_background_fields_refresh_for_timescale_momentum_and_tracer(FT, 8)
    end
end

@testset "OctaHEALPix nonhydrostatic closure-step state refresh" begin
    for FT in (Float32, Float64)
        test_octahealpix_nonhydrostatic_model_step_closure_prognostics_refreshes_state_halos(FT, 8)
    end
end

function test_octahealpix_nonhydrostatic_time_series_momentum_advective_forcing_refreshes_state_for_timescale_and_tendencies(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))
    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    forcing_u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times)
    forcing_v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times)

    set!(forcing_u_fts, (λ, φ, z, t) -> convert(FT, 0.13) * sind(λ) +
                                         convert(FT, 0.04) * cosd(φ) +
                                         convert(FT, 0.11) * t)
    set!(forcing_v_fts, (λ, φ, z, t) -> convert(FT, 0.09) * cosd(λ) -
                                         convert(FT, 0.03) * sind(φ) -
                                         convert(FT, 0.07) * t)

    source_clock = Oceananigans.Clock(time = zero(FT))
    forcing_u = Oceananigans.OutputReaders.TimeSeriesInterpolation(forcing_u_fts, grid; clock = source_clock)
    forcing_v = Oceananigans.OutputReaders.TimeSeriesInterpolation(forcing_v_fts, grid; clock = source_clock)

    forcing = (u = AdvectiveForcing(u = forcing_u, v = forcing_v),
               v = AdvectiveForcing(u = forcing_u, v = forcing_v))

    reference_u = XFaceField(grid)
    reference_v = YFaceField(grid)
    stale_u = XFaceField(grid)
    stale_v = YFaceField(grid)

    set!((u = reference_u, v = reference_v);
         u = (λ, φ, z) -> convert(FT, 0.13) * sind(λ) +
                          convert(FT, 0.04) * cosd(φ) +
                          convert(FT, 0.11) * half,
         v = (λ, φ, z) -> convert(FT, 0.09) * cosd(λ) -
                          convert(FT, 0.03) * sind(φ) -
                          convert(FT, 0.07) * half)

    set!((u = stale_u, v = stale_v);
         u = (λ, φ, z) -> convert(FT, 0.13) * sind(λ) + convert(FT, 0.04) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.09) * cosd(λ) - convert(FT, 0.03) * sind(φ))

    fill_halo_regions!((reference_u, reference_v))
    fill_halo_regions!((stale_u, stale_v))

    model = NonhydrostaticModel(grid;
                                tracers = nothing,
                                buoyancy = nothing,
                                forcing,
                                advection = Centered(FT))

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.16) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.11) * cosd(λ) - convert(FT, 0.03) * sind(φ),
         w = (λ, φ, z) -> convert(FT, 0.02) * sind(λ / 2) * cosd(φ))

    model.clock.time = half

    computed_timescale = Oceananigans.Models.NonhydrostaticModels.cell_advection_timescale(model)
    Oceananigans.TimeSteppers.compute_tendencies!(model, ())

    reference_forcing = AdvectiveForcing(u = reference_u, v = reference_v)
    stale_forcing = AdvectiveForcing(u = stale_u, v = stale_v)

    expected_total_velocities = Oceananigans.Forcings.with_advective_forcing(reference_forcing, model.velocities)
    stale_total_velocities = Oceananigans.Forcings.with_advective_forcing(stale_forcing, model.velocities)

    base_timescale = Oceananigans.Advection.cell_advection_timescale(grid, model.velocities)
    expected_timescale = min(base_timescale,
                             Oceananigans.Advection.cell_advection_timescale(grid, expected_total_velocities))
    stale_timescale = min(base_timescale,
                          Oceananigans.Advection.cell_advection_timescale(grid, stale_total_velocities))

    samples = ((N + 2, N + 2, 1),
               (2, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (N - 1, div(N, 2), 1))

    maximum_stale_u_difference = zero(FT)
    maximum_stale_v_difference = zero(FT)

    for (i, j, k) in samples
        expected_Gu = -(Oceananigans.Advection.div_𝐯u(i, j, k, grid, model.advection, expected_total_velocities, model.velocities.u) +
                        Oceananigans.Advection.U_dot_∇u_metric(i, j, k, grid, model.advection, expected_total_velocities, model.velocities))

        expected_Gv = -(Oceananigans.Advection.div_𝐯v(i, j, k, grid, model.advection, expected_total_velocities, model.velocities.v) +
                        Oceananigans.Advection.U_dot_∇v_metric(i, j, k, grid, model.advection, expected_total_velocities, model.velocities))

        stale_Gu = -(Oceananigans.Advection.div_𝐯u(i, j, k, grid, model.advection, stale_total_velocities, model.velocities.u) +
                     Oceananigans.Advection.U_dot_∇u_metric(i, j, k, grid, model.advection, stale_total_velocities, model.velocities))

        stale_Gv = -(Oceananigans.Advection.div_𝐯v(i, j, k, grid, model.advection, stale_total_velocities, model.velocities.v) +
                     Oceananigans.Advection.U_dot_∇v_metric(i, j, k, grid, model.advection, stale_total_velocities, model.velocities))

        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]

        u_scale = max(one(FT), abs(expected_Gu), abs(computed_Gu))
        v_scale = max(one(FT), abs(expected_Gv), abs(computed_Gv))

        @test abs(computed_Gu - expected_Gu) ≤ 2000eps(FT) * u_scale
        @test abs(computed_Gv - expected_Gv) ≤ 2000eps(FT) * v_scale

        maximum_stale_u_difference = max(maximum_stale_u_difference, abs(expected_Gu - stale_Gu))
        maximum_stale_v_difference = max(maximum_stale_v_difference, abs(expected_Gv - stale_Gv))
    end

    timescale_scale = max(one(FT), abs(expected_timescale), abs(computed_timescale))

    @test abs(computed_timescale - expected_timescale) ≤ 1000eps(FT) * timescale_scale
    @test abs(expected_timescale - stale_timescale) > 100eps(FT)
    @test maximum_stale_u_difference > 100eps(FT)
    @test maximum_stale_v_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_nonhydrostatic_horizontal_biogeochemical_drift_refreshes_halos(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    drift_u = XFaceField(grid)
    drift_v = YFaceField(grid)
    reference_u = XFaceField(grid)
    reference_v = YFaceField(grid)
    stale_u = XFaceField(grid)
    stale_v = YFaceField(grid)

    set!((u = drift_u, v = drift_v);
         u = (λ, φ, z) -> convert(FT, 0.07) * sind(λ) + convert(FT, 0.02) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.05) * cosd(λ) - convert(FT, 0.015) * sind(φ))

    set!((u = reference_u, v = reference_v);
         u = (λ, φ, z) -> convert(FT, 0.07) * sind(λ) + convert(FT, 0.02) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.05) * cosd(λ) - convert(FT, 0.015) * sind(φ))

    set!((u = stale_u, v = stale_v);
         u = (λ, φ, z) -> convert(FT, 0.07) * sind(λ) + convert(FT, 0.02) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.05) * cosd(λ) - convert(FT, 0.015) * sind(φ))

    fill_halo_regions!((reference_u, reference_v))

    drift_velocity = (u = drift_u, v = drift_v, w = ZeroField())
    reference_drift_velocity = (u = reference_u, v = reference_v, w = ZeroField())
    stale_drift_velocity = (u = stale_u, v = stale_v, w = ZeroField())
    biogeochemistry = OctaHEALPixHorizontalDriftBiogeochemistry(drift_velocity)

    model = NonhydrostaticModel(grid;
                                tracers = :c,
                                buoyancy = nothing,
                                biogeochemistry,
                                advection = Centered(FT))

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ),
         w = (λ, φ, z) -> convert(FT, 0.02) * sind(λ / 2) * cosd(φ),
         c = (λ, φ, z) -> convert(FT, 0.4) + convert(FT, 0.2) * sind(λ) + convert(FT, 0.1) * cosd(φ))

    Oceananigans.TimeSteppers.update_state!(model)
    Oceananigans.TimeSteppers.compute_tendencies!(model, ())

    scheme = model.advection
    expected_total_velocities = Oceananigans.Utils.sum_of_velocities(model.velocities,
                                                                     model.background_fields.velocities,
                                                                     reference_drift_velocity)
    stale_total_velocities = Oceananigans.Utils.sum_of_velocities(model.velocities,
                                                                  model.background_fields.velocities,
                                                                  stale_drift_velocity)
    expected_advective_velocities = (u = OctaHEALPixConvertedTransportU(grid, expected_total_velocities.u, expected_total_velocities.v),
                                     v = OctaHEALPixConvertedTransportV(grid, expected_total_velocities.u, expected_total_velocities.v),
                                     w = expected_total_velocities.w)
    stale_advective_velocities = (u = OctaHEALPixConvertedTransportU(grid, stale_total_velocities.u, stale_total_velocities.v),
                                  v = OctaHEALPixConvertedTransportV(grid, stale_total_velocities.u, stale_total_velocities.v),
                                  w = stale_total_velocities.w)

    samples = ((N + 2, N + 2, 1),
               (2, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (N - 1, div(N, 2), 1))
    maximum_stale_difference = zero(FT)

    for (i, j, k) in samples
        expected_Gc = - div_Uc(i, j, k, grid, scheme, expected_advective_velocities, model.tracers.c)
        stale_Gc = - div_Uc(i, j, k, grid, scheme, stale_advective_velocities, model.tracers.c)
        computed_Gc = model.timestepper.Gⁿ.c[i, j, k]
        tendency_scale = max(one(FT), abs(expected_Gc), abs(computed_Gc))

        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale
        maximum_stale_difference = max(maximum_stale_difference, abs(expected_Gc - stale_Gc))
    end

    @test maximum_stale_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_nonhydrostatic_background_tracer_uses_horizontal_biogeochemical_drift(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    drift_u = XFaceField(grid)
    drift_v = YFaceField(grid)

    set!((u = drift_u, v = drift_v);
         u = (λ, φ, z) -> convert(FT, 0.07) * sind(λ) + convert(FT, 0.02) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.05) * cosd(λ) - convert(FT, 0.015) * sind(φ))

    fill_halo_regions!((drift_u, drift_v))

    drift_velocity = (u = drift_u, v = drift_v, w = ZeroField())
    biogeochemistry = OctaHEALPixHorizontalDriftBiogeochemistry(drift_velocity)

    background_fields = (
        c = (λ, φ, z, t) -> convert(FT, 0.4) + convert(FT, 0.2) * sind(λ) + convert(FT, 0.1) * cosd(φ)
    )

    model = NonhydrostaticModel(grid;
                                tracers = :c,
                                buoyancy = nothing,
                                biogeochemistry,
                                advection = Centered(FT),
                                background_fields)

    set!(model,
         u = zero(FT),
         v = zero(FT),
         w = zero(FT),
         c = zero(FT))

    Oceananigans.TimeSteppers.update_state!(model)
    Oceananigans.TimeSteppers.compute_tendencies!(model, ())

    scheme = model.advection
    expected_total_velocities = Oceananigans.Utils.sum_of_velocities(model.velocities, drift_velocity)
    expected_advective_velocities = (u = OctaHEALPixConvertedTransportU(grid, expected_total_velocities.u, expected_total_velocities.v),
                                     v = OctaHEALPixConvertedTransportV(grid, expected_total_velocities.u, expected_total_velocities.v),
                                     w = expected_total_velocities.w)
    zero_advective_velocities = (u = OctaHEALPixConvertedTransportU(grid, model.velocities.u, model.velocities.v),
                                 v = OctaHEALPixConvertedTransportV(grid, model.velocities.u, model.velocities.v),
                                 w = model.velocities.w)

    samples = ((N + 2, N + 2, 1),
               (2, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (N - 1, div(N, 2), 1))
    maximum_naive_difference = zero(FT)

    for (i, j, k) in samples
        expected_Gc = - div_Uc(i, j, k, grid, scheme, expected_advective_velocities, model.background_fields.tracers.c)
        naive_Gc = - div_Uc(i, j, k, grid, scheme, zero_advective_velocities, model.background_fields.tracers.c)
        computed_Gc = model.timestepper.Gⁿ.c[i, j, k]
        tendency_scale = max(one(FT), abs(expected_Gc), abs(computed_Gc))

        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale
        maximum_naive_difference = max(maximum_naive_difference, abs(expected_Gc - naive_Gc))
    end

    @test maximum_naive_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_nonhydrostatic_update_state_callback_variance_dissipation_refreshes_horizontal_drift_halos(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    drift_u = XFaceField(grid)
    drift_v = YFaceField(grid)
    reference_u = XFaceField(grid)
    reference_v = YFaceField(grid)
    stale_u = XFaceField(grid)
    stale_v = YFaceField(grid)

    set!((u = drift_u, v = drift_v);
         u = (λ, φ, z) -> convert(FT, 0.07) * sind(λ) + convert(FT, 0.02) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.05) * cosd(λ) - convert(FT, 0.015) * sind(φ))

    set!((u = reference_u, v = reference_v);
         u = (λ, φ, z) -> convert(FT, 0.07) * sind(λ) + convert(FT, 0.02) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.05) * cosd(λ) - convert(FT, 0.015) * sind(φ))

    set!((u = stale_u, v = stale_v);
         u = (λ, φ, z) -> convert(FT, 0.07) * sind(λ) + convert(FT, 0.02) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.05) * cosd(λ) - convert(FT, 0.015) * sind(φ))

    fill_halo_regions!((reference_u, reference_v))

    drift_velocity = (u = drift_u, v = drift_v, w = ZeroField())
    reference_drift_velocity = (u = reference_u, v = reference_v, w = ZeroField())
    stale_drift_velocity = (u = stale_u, v = stale_v, w = ZeroField())
    biogeochemistry = OctaHEALPixHorizontalDriftBiogeochemistry(drift_velocity)

    model = NonhydrostaticModel(grid;
                                timestepper = :QuasiAdamsBashforth2,
                                tracers = :c,
                                buoyancy = nothing,
                                biogeochemistry,
                                advection = Centered(FT))

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ),
         w = (λ, φ, z) -> convert(FT, 0.02) * sind(λ / 2) * cosd(φ),
         c = (λ, φ, z) -> convert(FT, 0.4) + convert(FT, 0.2) * sind(λ) + convert(FT, 0.1) * cosd(φ))

    for j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue
        drift_u[i, j, 1] = convert(FT, 111)
        drift_v[i, j, 1] = convert(FT, -222)
    end

    ϵ = Oceananigans.Models.VarianceDissipationComputations.VarianceDissipation(:c, grid)
    callback = Oceananigans.Models.VarianceDissipationComputations.Callback(ϵ)
    Oceananigans.TimeSteppers.update_state!(model, [callback])

    expected_total_velocities = Oceananigans.Utils.sum_of_velocities(model.velocities,
                                                                     model.background_fields.velocities,
                                                                     reference_drift_velocity)

    stale_total_velocities = Oceananigans.Utils.sum_of_velocities(model.velocities,
                                                                  model.background_fields.velocities,
                                                                  stale_drift_velocity)

    expected_advective_velocities = (u = OctaHEALPixConvertedTransportU(grid, expected_total_velocities.u, expected_total_velocities.v),
                                     v = OctaHEALPixConvertedTransportV(grid, expected_total_velocities.u, expected_total_velocities.v),
                                     w = expected_total_velocities.w)

    stale_advective_velocities = (u = OctaHEALPixConvertedTransportU(grid, stale_total_velocities.u, stale_total_velocities.v),
                                  v = OctaHEALPixConvertedTransportV(grid, stale_total_velocities.u, stale_total_velocities.v),
                                  w = stale_total_velocities.w)

    samples = ((N + 2, N + 2, 1),
               (2, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (N - 1, div(N, 2), 1))

    maximum_stale_transport_difference = zero(FT)
    maximum_stale_flux_difference = zero(FT)

    for (i, j, k) in samples
        expected_transport_u = expected_advective_velocities.u[i, j, k]
        expected_transport_v = expected_advective_velocities.v[i, j, k]
        stale_transport_u = stale_advective_velocities.u[i, j, k]
        stale_transport_v = stale_advective_velocities.v[i, j, k]

        expected_fx = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_x(i, j, k, grid, model.advection, expected_advective_velocities, model.tracers.c)
        expected_fy = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_y(i, j, k, grid, model.advection, expected_advective_velocities, model.tracers.c)
        stale_fx = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_x(i, j, k, grid, model.advection, stale_advective_velocities, model.tracers.c)
        stale_fy = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_y(i, j, k, grid, model.advection, stale_advective_velocities, model.tracers.c)

        computed_transport_u = ϵ.previous_state.Uⁿ.u[i, j, k]
        computed_transport_v = ϵ.previous_state.Uⁿ.v[i, j, k]
        computed_fx = ϵ.advective_fluxes.Fⁿ.x[i, j, k]
        computed_fy = ϵ.advective_fluxes.Fⁿ.y[i, j, k]

        transport_scale = max(one(FT), abs(expected_transport_u), abs(expected_transport_v),
                              abs(computed_transport_u), abs(computed_transport_v))
        flux_scale = max(one(FT), abs(expected_fx), abs(expected_fy), abs(computed_fx), abs(computed_fy))

        @test abs(computed_transport_u - expected_transport_u) ≤ 2000eps(FT) * transport_scale
        @test abs(computed_transport_v - expected_transport_v) ≤ 2000eps(FT) * transport_scale
        @test abs(computed_fx - expected_fx) ≤ 2000eps(FT) * flux_scale
        @test abs(computed_fy - expected_fy) ≤ 2000eps(FT) * flux_scale

        maximum_stale_transport_difference = max(maximum_stale_transport_difference,
                                                 abs(expected_transport_u - stale_transport_u),
                                                 abs(expected_transport_v - stale_transport_v))

        maximum_stale_flux_difference = max(maximum_stale_flux_difference,
                                            abs(expected_fx - stale_fx),
                                            abs(expected_fy - stale_fy))
    end

    @test maximum_stale_transport_difference > 100eps(FT)
    @test maximum_stale_flux_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_hydrostatic_update_state_callback_refreshes_horizontal_drift_halos(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    drift_u = XFaceField(grid)
    drift_v = YFaceField(grid)
    reference_u = XFaceField(grid)
    reference_v = YFaceField(grid)
    stale_u = XFaceField(grid)
    stale_v = YFaceField(grid)

    set!((u = drift_u, v = drift_v);
         u = (λ, φ, z) -> convert(FT, 0.07) * sind(λ) + convert(FT, 0.02) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.05) * cosd(λ) - convert(FT, 0.015) * sind(φ))

    set!((u = reference_u, v = reference_v);
         u = (λ, φ, z) -> convert(FT, 0.07) * sind(λ) + convert(FT, 0.02) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.05) * cosd(λ) - convert(FT, 0.015) * sind(φ))

    set!((u = stale_u, v = stale_v);
         u = (λ, φ, z) -> convert(FT, 0.07) * sind(λ) + convert(FT, 0.02) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.05) * cosd(λ) - convert(FT, 0.015) * sind(φ))

    fill_halo_regions!((reference_u, reference_v))

    drift_velocity = (u = drift_u, v = drift_v, w = ZeroField())
    reference_drift_velocity = (u = reference_u, v = reference_v, w = ZeroField())
    stale_drift_velocity = (u = stale_u, v = stale_v, w = ZeroField())
    biogeochemistry = OctaHEALPixHorizontalDriftBiogeochemistry(drift_velocity)

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        biogeochemistry,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ),
         c = (λ, φ, z) -> convert(FT, 0.4) + convert(FT, 0.2) * sind(λ) + convert(FT, 0.1) * cosd(φ))

    for j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue
        drift_u[i, j, 1] = convert(FT, 111)
        drift_v[i, j, 1] = convert(FT, -222)
    end

    samples = ((N + 2, N + 2, 1),
               (2, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (N - 1, div(N, 2), 1))

    captured_transport_u = zeros(FT, length(samples))
    captured_transport_v = zeros(FT, length(samples))

    function capture_transport_state(callback_model)
        drift = biogeochemical_drift_velocity(callback_model.biogeochemistry, Val(:c))
        auxiliary_velocities = Oceananigans.Models.HydrostaticFreeSurfaceModels.tracer_auxiliary_velocities(drift,
                                                                                                             nothing,
                                                                                                             callback_model.forcing.c)
        total_transport = Oceananigans.Models.HydrostaticFreeSurfaceModels.total_tracer_advection_velocities(callback_model.grid,
                                                                                                             callback_model.transport_velocities,
                                                                                                             auxiliary_velocities)

        for (n, (i, j, k)) in enumerate(samples)
            captured_transport_u[n] = total_transport.u[i, j, k]
            captured_transport_v[n] = total_transport.v[i, j, k]
        end

        return nothing
    end

    callback = Oceananigans.Simulations.Callback(capture_transport_state,
                                                 Oceananigans.Simulations.IterationInterval(1);
                                                 callsite = Oceananigans.UpdateStateCallsite())

    Oceananigans.TimeSteppers.update_state!(model, [callback])

    expected_auxiliary_velocities = Oceananigans.Models.HydrostaticFreeSurfaceModels.tracer_auxiliary_velocities(reference_drift_velocity,
                                                                                                                  nothing,
                                                                                                                  model.forcing.c)
    stale_auxiliary_velocities = Oceananigans.Models.HydrostaticFreeSurfaceModels.tracer_auxiliary_velocities(stale_drift_velocity,
                                                                                                               nothing,
                                                                                                               model.forcing.c)

    expected_transport = Oceananigans.Models.HydrostaticFreeSurfaceModels.total_tracer_advection_velocities(grid,
                                                                                                            model.transport_velocities,
                                                                                                            expected_auxiliary_velocities)

    stale_transport = Oceananigans.Models.HydrostaticFreeSurfaceModels.total_tracer_advection_velocities(grid,
                                                                                                         model.transport_velocities,
                                                                                                         stale_auxiliary_velocities)

    maximum_stale_difference = zero(FT)

    for (n, (i, j, k)) in enumerate(samples)
        computed_u = captured_transport_u[n]
        computed_v = captured_transport_v[n]
        expected_u = expected_transport.u[i, j, k]
        expected_v = expected_transport.v[i, j, k]
        stale_u_value = stale_transport.u[i, j, k]
        stale_v_value = stale_transport.v[i, j, k]

        scale = max(one(FT), abs(expected_u), abs(expected_v), abs(computed_u), abs(computed_v))

        @test abs(computed_u - expected_u) ≤ 2000eps(FT) * scale
        @test abs(computed_v - expected_v) ≤ 2000eps(FT) * scale

        maximum_stale_difference = max(maximum_stale_difference,
                                       abs(expected_u - stale_u_value),
                                       abs(expected_v - stale_v_value))
    end

    @test maximum_stale_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_nonhydrostatic_multistep_centered_momentum_and_tracer(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))

    model = NonhydrostaticModel(grid;
                                timestepper = :QuasiAdamsBashforth2,
                                tracers = :c,
                                buoyancy = nothing,
                                advection = Centered(FT))

    λ₀ = convert(FT, 45)
    φ₀ = convert(FT, 15)
    bell_radius = convert(FT, 30)
    bell_amplitude = convert(FT, 1//2)

    localized_tracer(λ, φ, z) = begin
        cos_distance = sind(φ₀) * sind(φ) +
                       cosd(φ₀) * cosd(φ) * cosd(λ - λ₀)
        γ = acosd(clamp(cos_distance, -one(FT), one(FT)))
        return ifelse(γ < bell_radius,
                      bell_amplitude * (one(FT) + cospi(γ / bell_radius)),
                      zero(FT))
    end

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.18) * sind(λ) + convert(FT, 0.07) * cosd(φ) + convert(FT, 0.04) * z,
         v = (λ, φ, z) -> convert(FT, 0.12) * cosd(λ) - convert(FT, 0.05) * sind(φ) + convert(FT, 0.03) * z,
         w = (λ, φ, z) -> convert(FT, 0.03) * sind(λ / 2) * cosd(φ) * (z - convert(FT, 1//2)),
         c = localized_tracer)

    initial_u = Array(interior(model.velocities.u))
    initial_v = Array(interior(model.velocities.v))
    initial_w = Array(interior(model.velocities.w))
    initial_tracer = Array(interior(model.tracers.c))
    initial_tracer_mass = sum(volume(i, j, k, grid, Center(), Center(), Center()) * model.tracers.c[i, j, k]
                              for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx)

    Δt = convert(FT, 1//20)
    maximum_velocity = zero(FT)

    for step in 1:10
        time_step!(model, Δt)

        for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx
            maximum_velocity = max(maximum_velocity,
                                   abs(model.velocities.u[i, j, k]),
                                   abs(model.velocities.v[i, j, k]),
                                   abs(model.velocities.w[i, j, k]))

            @test isfinite(model.velocities.u[i, j, k])
            @test isfinite(model.velocities.v[i, j, k])
            @test isfinite(model.velocities.w[i, j, k])
            @test isfinite(model.tracers.c[i, j, k])
        end
    end

    final_u = Array(interior(model.velocities.u))
    final_v = Array(interior(model.velocities.v))
    final_w = Array(interior(model.velocities.w))
    final_tracer = Array(interior(model.tracers.c))
    final_tracer_mass = sum(volume(i, j, k, grid, Center(), Center(), Center()) * model.tracers.c[i, j, k]
                            for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx)

    u_change = maximum(abs, final_u .- initial_u)
    v_change = maximum(abs, final_v .- initial_v)
    w_change = maximum(abs, final_w .- initial_w)
    tracer_change = maximum(abs, final_tracer .- initial_tracer)
    tracer_mass_scale = max(one(FT), abs(initial_tracer_mass))

    @test maximum_velocity > 100eps(FT)
    @test u_change > 100eps(FT)
    @test v_change > 100eps(FT)
    @test w_change > 100eps(FT)
    @test tracer_change > 100eps(FT)
    @test abs(final_tracer_mass - initial_tracer_mass) ≤ 100000eps(FT) * tracer_mass_scale
    @test !any(isnan, final_u)
    @test !any(isnan, final_v)
    @test !any(isnan, final_w)
    @test !any(isnan, final_tracer)

    return nothing
end

function test_octahealpix_nonhydrostatic_closure_auxiliary_transport_refreshes_halos(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    closure = Oceananigans.TurbulenceClosures.IsopycnalSkewSymmetricDiffusivity(FT;
                                                                                κ_skew = convert(FT, 10),
                                                                                κ_symmetric = convert(FT, 10),
                                                                                skew_flux_formulation = Oceananigans.TurbulenceClosures.AdvectiveFormulation())

    function build_model()
        buoyancy = BuoyancyForce(grid, BuoyancyTracer(); materialize_gradients = true)
        model = NonhydrostaticModel(grid;
                                    timestepper = :QuasiAdamsBashforth2,
                                    tracers = :b,
                                    buoyancy,
                                    closure,
                                    advection = Centered(FT))

        set!(model,
             u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
             v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ),
             w = (λ, φ, z) -> convert(FT, 0.02) * sind(λ / 2) * cosd(φ),
             b = (λ, φ, z) -> convert(FT, 0.2) * sind(λ) +
                              convert(FT, 0.1) * cosd(φ) +
                              convert(FT, 0.05) * z)

        Oceananigans.TimeSteppers.update_state!(model)
        return model
    end

    function corrupt_closure_auxiliary_velocity_halos!(closure_fields)
        for k in 1:grid.Nz, j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
            (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue
            closure_fields.u[i, j, k] = convert(FT, 111)
            closure_fields.v[i, j, k] = convert(FT, -222)
        end
        return nothing
    end

    reference_model = build_model()
    Oceananigans.TimeSteppers.compute_tendencies!(reference_model, ())

    stale_model = build_model()
    corrupt_closure_auxiliary_velocity_halos!(stale_model.closure_fields)

    model = build_model()
    corrupt_closure_auxiliary_velocity_halos!(model.closure_fields)
    Oceananigans.TimeSteppers.compute_tendencies!(model, ())

    closure_velocities = Oceananigans.TurbulenceClosures.closure_auxiliary_velocity(reference_model.closure,
                                                                                    reference_model.closure_fields,
                                                                                    Val(:b))
    stale_closure_velocities = Oceananigans.TurbulenceClosures.closure_auxiliary_velocity(stale_model.closure,
                                                                                          stale_model.closure_fields,
                                                                                          Val(:b))

    expected_total_velocities = Oceananigans.Utils.sum_of_velocities(reference_model.velocities,
                                                                     reference_model.background_fields.velocities,
                                                                     closure_velocities)
    stale_total_velocities = Oceananigans.Utils.sum_of_velocities(stale_model.velocities,
                                                                  stale_model.background_fields.velocities,
                                                                  stale_closure_velocities)

    expected_advective_velocities = (u = OctaHEALPixConvertedTransportU(grid, expected_total_velocities.u, expected_total_velocities.v),
                                     v = OctaHEALPixConvertedTransportV(grid, expected_total_velocities.u, expected_total_velocities.v),
                                     w = expected_total_velocities.w)
    stale_advective_velocities = (u = OctaHEALPixConvertedTransportU(grid, stale_total_velocities.u, stale_total_velocities.v),
                                  v = OctaHEALPixConvertedTransportV(grid, stale_total_velocities.u, stale_total_velocities.v),
                                  w = stale_total_velocities.w)

    scheme = model.advection
    samples = ((N + 2, N + 2, 1),
               (2, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (N - 1, div(N, 2), 1))
    maximum_stale_tendency_difference = zero(FT)
    maximum_stale_transport_difference = zero(FT)
    maximum_stale_flux_difference = zero(FT)

    ϵ = Oceananigans.Models.VarianceDissipationComputations.VarianceDissipation(:b, grid)
    Oceananigans.Models.VarianceDissipationComputations.cache_fluxes!(ϵ, model, :b)

    computed_timescale = Oceananigans.Models.NonhydrostaticModels.cell_advection_timescale(model)

    expected_timescale = minimum((k, j, i) for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx) do (k, j, i)
        inverse_timescale_x = abs(expected_advective_velocities.u[i, j, k]) * Oceananigans.Operators.V⁻¹ᶜᶜᶜ(i, j, k, grid)
        inverse_timescale_y = abs(expected_advective_velocities.v[i, j, k]) * Oceananigans.Operators.V⁻¹ᶜᶜᶜ(i, j, k, grid)
        inverse_timescale_z = abs(expected_advective_velocities.w[i, j, k]) * Oceananigans.Operators.Δz⁻¹ᶜᶜᶠ(i, j, k, grid)
        return one(FT) / (inverse_timescale_x + inverse_timescale_y + inverse_timescale_z)
    end

    stale_timescale = minimum((k, j, i) for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx) do (k, j, i)
        inverse_timescale_x = abs(stale_advective_velocities.u[i, j, k]) * Oceananigans.Operators.V⁻¹ᶜᶜᶜ(i, j, k, grid)
        inverse_timescale_y = abs(stale_advective_velocities.v[i, j, k]) * Oceananigans.Operators.V⁻¹ᶜᶜᶜ(i, j, k, grid)
        inverse_timescale_z = abs(stale_advective_velocities.w[i, j, k]) * Oceananigans.Operators.Δz⁻¹ᶜᶜᶠ(i, j, k, grid)
        return one(FT) / (inverse_timescale_x + inverse_timescale_y + inverse_timescale_z)
    end

    timescale_scale = max(one(FT), abs(expected_timescale), abs(computed_timescale))
    @test abs(computed_timescale - expected_timescale) ≤ 1000eps(FT) * timescale_scale
    @test abs(expected_timescale - stale_timescale) > 100eps(FT)

    for (i, j, k) in samples
        expected_Gb = - div_Uc(i, j, k, grid, scheme, expected_advective_velocities, model.tracers.b)
        stale_Gb = - div_Uc(i, j, k, grid, scheme, stale_advective_velocities, model.tracers.b)
        computed_Gb = model.timestepper.Gⁿ.b[i, j, k]
        tendency_scale = max(one(FT), abs(expected_Gb), abs(computed_Gb))

        @test abs(computed_Gb - expected_Gb) ≤ 1000eps(FT) * tendency_scale
        maximum_stale_tendency_difference = max(maximum_stale_tendency_difference, abs(expected_Gb - stale_Gb))

        expected_transport_u = expected_advective_velocities.u[i, j, k]
        expected_transport_v = expected_advective_velocities.v[i, j, k]
        computed_transport_u = ϵ.previous_state.Uⁿ.u[i, j, k]
        computed_transport_v = ϵ.previous_state.Uⁿ.v[i, j, k]
        transport_scale = max(one(FT), abs(expected_transport_u), abs(expected_transport_v),
                              abs(computed_transport_u), abs(computed_transport_v))

        @test abs(computed_transport_u - expected_transport_u) ≤ 1000eps(FT) * transport_scale
        @test abs(computed_transport_v - expected_transport_v) ≤ 1000eps(FT) * transport_scale
        maximum_stale_transport_difference = max(maximum_stale_transport_difference,
                                                 abs(expected_transport_u - stale_advective_velocities.u[i, j, k]),
                                                 abs(expected_transport_v - stale_advective_velocities.v[i, j, k]))

        expected_fx = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_x(i, j, k, grid, scheme,
                                                                                     expected_advective_velocities,
                                                                                     model.tracers.b)
        expected_fy = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_y(i, j, k, grid, scheme,
                                                                                     expected_advective_velocities,
                                                                                     model.tracers.b)
        stale_fx = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_x(i, j, k, grid, scheme,
                                                                                  stale_advective_velocities,
                                                                                  model.tracers.b)
        stale_fy = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_y(i, j, k, grid, scheme,
                                                                                  stale_advective_velocities,
                                                                                  model.tracers.b)
        computed_fx = ϵ.advective_fluxes.Fⁿ.x[i, j, k]
        computed_fy = ϵ.advective_fluxes.Fⁿ.y[i, j, k]
        flux_scale = max(one(FT), abs(expected_fx), abs(expected_fy), abs(computed_fx), abs(computed_fy))

        @test abs(computed_fx - expected_fx) ≤ 1000eps(FT) * flux_scale
        @test abs(computed_fy - expected_fy) ≤ 1000eps(FT) * flux_scale
        maximum_stale_flux_difference = max(maximum_stale_flux_difference,
                                            abs(expected_fx - stale_fx),
                                            abs(expected_fy - stale_fy))
    end

    @test maximum_stale_tendency_difference > 100eps(FT)
    @test maximum_stale_transport_difference > 100eps(FT)
    @test maximum_stale_flux_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_nonzero_transport_free_stream_preservation(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    constant_tracer_value = convert(FT, 3//4)
    set!(model,
         u = (λ, φ, z) -> cosd(φ),
         v = (λ, φ, z) -> zero(FT),
         c = constant_tracer_value)

    dt = convert(FT, 1//100)
    maximum_transport = zero(FT)
    maximum_tendency = zero(FT)

    for j in 1:grid.Ny, i in 1:grid.Nx
        maximum_transport = max(maximum_transport, abs(model.transport_velocities.u[i, j, 1]))
        maximum_transport = max(maximum_transport, abs(model.transport_velocities.v[i, j, 1]))
    end

    for _ in 1:10
        compute_tracer_tendencies!(model)

        for j in 1:grid.Ny, i in 1:grid.Nx
            maximum_tendency = max(maximum_tendency, abs(model.timestepper.Gⁿ.c[i, j, 1]))
            model.tracers.c[i, j, 1] += dt * model.timestepper.Gⁿ.c[i, j, 1]
        end

        fill_halo_regions!(model.tracers.c)
    end

    maximum_tracer_deviation = zero(FT)

    for j in 1:grid.Ny, i in 1:grid.Nx
        maximum_tracer_deviation = max(maximum_tracer_deviation,
                                       abs(model.tracers.c[i, j, 1] - constant_tracer_value))
    end

    tracer_scale = max(one(FT), abs(constant_tracer_value))

    @test maximum_transport > sqrt(eps(FT))
    @test maximum_tendency ≤ 1000eps(FT) * tracer_scale
    @test maximum_tracer_deviation ≤ 10000eps(FT) * tracer_scale

    return nothing
end

function test_octahealpix_nonzero_transport_localized_tracer_mass_conservation(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    λ₀ = convert(FT, 45)
    φ₀ = convert(FT, 15)
    bell_radius = convert(FT, 30)
    bell_amplitude = convert(FT, 1//2)

    function localized_bell(λ, φ)
        cos_distance =
            sind(φ₀) * sind(φ) +
            cosd(φ₀) * cosd(φ) * cosd(λ - λ₀)

        γ = acosd(clamp(cos_distance, -one(FT), one(FT)))

        if γ < bell_radius
            return bell_amplitude * (one(FT) + cospi(γ / bell_radius))
        else
            return zero(FT)
        end
    end

    tracer = Array{FT}(undef, grid.Nx, grid.Ny, 1)
    for j in 1:grid.Ny, i in 1:grid.Nx
        λ = λnode(i, j, 1, grid, Center(), Center(), Center())
        φ = φnode(i, j, 1, grid, Center(), Center(), Center())
        tracer[i, j, 1] = localized_bell(λ, φ)
    end

    set!(model,
         u = (λ, φ, z) -> cosd(φ),
         v = (λ, φ, z) -> zero(FT))
    set!(model.tracers.c, tracer)

    initial_tracer = Array(interior(model.tracers.c))
    initial_mass = sum(volume(i, j, 1, grid, Center(), Center(), Center()) * model.tracers.c[i, j, 1]
                       for j in 1:grid.Ny, i in 1:grid.Nx)

    dt = convert(FT, 1//100)
    maximum_transport = zero(FT)
    maximum_tendency = zero(FT)

    for j in 1:grid.Ny, i in 1:grid.Nx
        maximum_transport = max(maximum_transport, abs(model.transport_velocities.u[i, j, 1]))
        maximum_transport = max(maximum_transport, abs(model.transport_velocities.v[i, j, 1]))
    end

    for _ in 1:10
        compute_tracer_tendencies!(model)

        for j in 1:grid.Ny, i in 1:grid.Nx
            maximum_tendency = max(maximum_tendency, abs(model.timestepper.Gⁿ.c[i, j, 1]))
            model.tracers.c[i, j, 1] += dt * model.timestepper.Gⁿ.c[i, j, 1]
        end

        fill_halo_regions!(model.tracers.c)
    end

    final_tracer = Array(interior(model.tracers.c))
    final_mass = sum(volume(i, j, 1, grid, Center(), Center(), Center()) * model.tracers.c[i, j, 1]
                     for j in 1:grid.Ny, i in 1:grid.Nx)

    mass_scale = max(abs(initial_mass), one(FT))
    tracer_change = maximum(abs, final_tracer .- initial_tracer)

    @test maximum_transport > 100eps(FT)
    @test maximum_tendency > 100eps(FT)
    @test tracer_change > 100eps(FT)
    @test abs(final_mass - initial_mass) ≤ 10000eps(FT) * mass_scale
    @test !any(isnan, final_tracer)

    return nothing
end

function test_octahealpix_transport_velocity_conversion(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    set!(model,
         u = (λ, φ, z) -> sind(λ) * cosd(φ),
         v = (λ, φ, z) -> cosd(λ) * sind(φ))

    fill_halo_regions!(model.velocities)
    compute_transport_velocities!(model, model.free_surface)

    transport_u_error = maximum((k, j, i) for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx) do (k, j, i)
        expected = covariant_to_volume_flux_uᶠᶜᶜ(i, j, k, grid, model.velocities.u, model.velocities.v)
        return abs(model.transport_velocities.u[i, j, k] - expected)
    end

    transport_v_error = maximum((k, j, i) for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx) do (k, j, i)
        expected = covariant_to_volume_flux_vᶜᶠᶜ(i, j, k, grid, model.velocities.u, model.velocities.v)
        return abs(model.transport_velocities.v[i, j, k] - expected)
    end

    transport_scale = max(maximum(abs, Array(interior(model.transport_velocities.u))),
                          maximum(abs, Array(interior(model.transport_velocities.v))),
                          one(FT))

    transport_u_bottom_halo_error = maximum((j, i) for j in 1:grid.Ny, i in 1:grid.Nx) do (j, i)
        return abs(model.transport_velocities.u[i, j, 0] - model.transport_velocities.u[i, j, 1])
    end

    transport_u_top_halo_error = maximum((j, i) for j in 1:grid.Ny, i in 1:grid.Nx) do (j, i)
        return abs(model.transport_velocities.u[i, j, grid.Nz + 1] - model.transport_velocities.u[i, j, grid.Nz])
    end

    transport_v_bottom_halo_error = maximum((j, i) for j in 1:grid.Ny, i in 1:grid.Nx) do (j, i)
        return abs(model.transport_velocities.v[i, j, 0] - model.transport_velocities.v[i, j, 1])
    end

    transport_v_top_halo_error = maximum((j, i) for j in 1:grid.Ny, i in 1:grid.Nx) do (j, i)
        return abs(model.transport_velocities.v[i, j, grid.Nz + 1] - model.transport_velocities.v[i, j, grid.Nz])
    end

    @test transport_u_error ≤ 1000eps(FT) * transport_scale
    @test transport_v_error ≤ 1000eps(FT) * transport_scale
    @test transport_u_bottom_halo_error == zero(FT)
    @test transport_u_top_halo_error == zero(FT)
    @test transport_v_bottom_halo_error == zero(FT)
    @test transport_v_top_halo_error == zero(FT)

    return nothing
end

function test_octahealpix_transport_velocity_conversion_uses_fresh_covariant_halos(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    initial_u(λ, φ, z) = convert(FT, -0.17) * cosd(λ) + convert(FT, 0.11) * sind(φ) - convert(FT, 0.35) * z
    initial_v(λ, φ, z) = convert(FT, 0.19) * sind(λ) + convert(FT, 0.07) * cosd(φ) + convert(FT, 0.25) * z
    target_u(λ, φ, z) = convert(FT, 0.12) * sind(λ) + convert(FT, 0.03) * cosd(φ) + convert(FT, 0.2) * z
    target_v(λ, φ, z) = convert(FT, 0.08) * cosd(λ) - convert(FT, 0.02) * sind(φ) - convert(FT, 0.15) * z

    set!(model, u = initial_u, v = initial_v)
    fill_halo_regions!(model.velocities)

    for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:(grid.Nx + 1)
        λ = grid.λᶠᶜᵃ[i, j]
        φ = grid.φᶠᶜᵃ[i, j]
        z = znode(i, j, k, grid, Face(), Center(), Center())
        @inbounds model.velocities.u[i, j, k] = target_u(λ, φ, z)
    end

    for k in 1:grid.Nz, j in 1:(grid.Ny + 1), i in 1:grid.Nx
        λ = grid.λᶜᶠᵃ[i, j]
        φ = grid.φᶜᶠᵃ[i, j]
        z = znode(i, j, k, grid, Center(), Face(), Center())
        @inbounds model.velocities.v[i, j, k] = target_v(λ, φ, z)
    end

    expected_covariant_u = similar(model.velocities.u)
    expected_covariant_v = similar(model.velocities.v)
    copyto!(parent(expected_covariant_u), parent(model.velocities.u))
    copyto!(parent(expected_covariant_v), parent(model.velocities.v))
    fill_halo_regions!((expected_covariant_u, expected_covariant_v))

    expected_transport_u = XFaceField(grid;
                                      boundary_conditions = model.transport_velocities.u.boundary_conditions)
    expected_transport_v = YFaceField(grid;
                                      boundary_conditions = model.transport_velocities.v.boundary_conditions)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.convert_to_volume_flux_velocities!(expected_transport_u,
                                                                                        expected_transport_v,
                                                                                        grid,
                                                                                        expected_covariant_u,
                                                                                        expected_covariant_v)
    fill_halo_regions!((expected_transport_u, expected_transport_v))

    stale_transport_u = XFaceField(grid;
                                   boundary_conditions = model.transport_velocities.u.boundary_conditions)
    stale_transport_v = YFaceField(grid;
                                   boundary_conditions = model.transport_velocities.v.boundary_conditions)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.convert_to_volume_flux_velocities!(stale_transport_u,
                                                                                        stale_transport_v,
                                                                                        grid,
                                                                                        model.velocities.u,
                                                                                        model.velocities.v)
    fill_halo_regions!((stale_transport_u, stale_transport_v))

    compute_transport_velocities!(model, model.free_surface)

    transport_scale = max(max(maximum(abs, parent(expected_transport_u)),
                              maximum(abs, parent(expected_transport_v))),
                          one(FT))
    tolerance = convert(FT, 500) * eps(FT) * transport_scale

    u_error = maximum(abs, parent(model.transport_velocities.u) .- parent(expected_transport_u))
    v_error = maximum(abs, parent(model.transport_velocities.v) .- parent(expected_transport_v))
    stale_u_error = maximum(abs, parent(model.transport_velocities.u) .- parent(stale_transport_u))
    stale_v_error = maximum(abs, parent(model.transport_velocities.v) .- parent(stale_transport_v))

    @test u_error ≤ tolerance
    @test v_error ≤ tolerance
    @test stale_u_error > tolerance
    @test stale_v_error > tolerance

    return nothing
end

function test_octahealpix_implicit_transport_velocity_conversion_ignores_stale_transport_state(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = ImplicitFreeSurface(),
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.12) * sind(λ) + convert(FT, 0.03) * cosd(φ) + convert(FT, 0.2) * z,
         v = (λ, φ, z) -> convert(FT, 0.08) * cosd(λ) - convert(FT, 0.02) * sind(φ) - convert(FT, 0.15) * z,
         c = zero(FT))

    stale_u = XFaceField(grid)
    stale_v = YFaceField(grid)

    set!((u = stale_u, v = stale_v);
         u = (λ, φ, z) -> convert(FT, -0.17) * cosd(λ) + convert(FT, 0.11) * sind(φ) - convert(FT, 0.35) * z,
         v = (λ, φ, z) -> convert(FT, 0.19) * sind(λ) + convert(FT, 0.07) * cosd(φ) + convert(FT, 0.25) * z)
    fill_halo_regions!((stale_u, stale_v))

    set!(model.transport_velocities;
         u = (λ, φ, z) -> convert(FT, -0.17) * cosd(λ) + convert(FT, 0.11) * sind(φ) - convert(FT, 0.35) * z,
         v = (λ, φ, z) -> convert(FT, 0.19) * sind(λ) + convert(FT, 0.07) * cosd(φ) + convert(FT, 0.25) * z)
    fill_halo_regions!(model.transport_velocities)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.compute_transport_velocities!(model, model.free_surface)

    expected_transport = (u = OctaHEALPixConvertedTransportU(grid, model.velocities.u, model.velocities.v),
                          v = OctaHEALPixConvertedTransportV(grid, model.velocities.u, model.velocities.v))

    buggy_u = XFaceField(grid)
    buggy_v = YFaceField(grid)

    for j in 1:grid.Ny, i in 1:grid.Nx
        U_current = zero(FT)
        U_stale = zero(FT)
        V_current = zero(FT)
        V_stale = zero(FT)

        for k in 1:grid.Nz
            U_current += Oceananigans.Operators.Δzᶠᶜᶜ(i, j, k, grid) * model.velocities.u[i, j, k]
            U_stale += Oceananigans.Operators.Δzᶠᶜᶜ(i, j, k, grid) * stale_u[i, j, k]
            V_current += Oceananigans.Operators.Δzᶜᶠᶜ(i, j, k, grid) * model.velocities.v[i, j, k]
            V_stale += Oceananigans.Operators.Δzᶜᶠᶜ(i, j, k, grid) * stale_v[i, j, k]
        end

        Hᶠᶜ = Oceananigans.Operators.column_depthᶠᶜᵃ(i, j, grid)
        Hᶜᶠ = Oceananigans.Operators.column_depthᶜᶠᵃ(i, j, grid)

        u_correction = ifelse(Hᶠᶜ == zero(FT), zero(FT), (U_current - U_stale) / Hᶠᶜ)
        v_correction = ifelse(Hᶜᶠ == zero(FT), zero(FT), (V_current - V_stale) / Hᶜᶠ)

        for k in 1:grid.Nz
            buggy_u[i, j, k] = stale_u[i, j, k] + u_correction
            buggy_v[i, j, k] = stale_v[i, j, k] + v_correction
        end
    end

    fill_halo_regions!((buggy_u, buggy_v))

    buggy_transport = (u = OctaHEALPixConvertedTransportU(grid, buggy_u, buggy_v),
                       v = OctaHEALPixConvertedTransportV(grid, buggy_u, buggy_v))

    sampled_points = ((N + 2, N + 2, 1),
                      (N + 2, N + 2, 2),
                      (1, N + 1, 1),
                      (N + 1, 1, 2),
                      (2N, N + 1, 1),
                      (N + 1, 2N, 2))

    maximum_buggy_difference = zero(FT)

    for (i, j, k) in sampled_points
        expected_u = expected_transport.u[i, j, k]
        expected_v = expected_transport.v[i, j, k]
        computed_u = model.transport_velocities.u[i, j, k]
        computed_v = model.transport_velocities.v[i, j, k]

        u_scale = max(one(FT), abs(expected_u), abs(computed_u))
        v_scale = max(one(FT), abs(expected_v), abs(computed_v))

        @test abs(computed_u - expected_u) ≤ 1000eps(FT) * u_scale
        @test abs(computed_v - expected_v) ≤ 1000eps(FT) * v_scale

        maximum_buggy_difference = max(maximum_buggy_difference,
                                       abs(expected_u - buggy_transport.u[i, j, k]),
                                       abs(expected_v - buggy_transport.v[i, j, k]))
    end

    @test maximum_buggy_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_prescribed_transport_velocity_conversion(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))
    connectivity = grid.connectivity

    velocities = PrescribedVelocityFields(u = (λ, φ, z, t) -> sind(λ) * cosd(φ),
                                          v = (λ, φ, z, t) -> cosd(λ) * sind(φ))

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities,
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    @test model.transport_velocities !== model.velocities
    @test model.transport_velocities.u.boundary_conditions.south isa Oceananigans.BoundaryConditions.QConZBC
    @test model.transport_velocities.u.boundary_conditions.north isa Oceananigans.BoundaryConditions.QConZBC
    @test model.transport_velocities.v.boundary_conditions.west isa Oceananigans.BoundaryConditions.QConZBC
    @test model.transport_velocities.v.boundary_conditions.east isa Oceananigans.BoundaryConditions.QConZBC

    compute_transport_velocities!(model, model.free_surface)

    transport_u_error = maximum((j, i) for j in 1:grid.Ny, i in 1:grid.Nx) do (j, i)
        expected = covariant_to_volume_flux_uᶠᶜᶜ(i, j, 1, grid, model.velocities.u, model.velocities.v)
        return abs(model.transport_velocities.u[i, j, 1] - expected)
    end

    transport_v_error = maximum((j, i) for j in 1:grid.Ny, i in 1:grid.Nx) do (j, i)
        expected = covariant_to_volume_flux_vᶜᶠᶜ(i, j, 1, grid, model.velocities.u, model.velocities.v)
        return abs(model.transport_velocities.v[i, j, 1] - expected)
    end

    transport_scale = max(maximum(abs, Array(interior(model.transport_velocities.u))),
                          maximum(abs, Array(interior(model.transport_velocities.v))),
                          one(FT))

    transport_u_halo_max_error = zero(FT)
    transport_v_halo_max_error = zero(FT)

    for j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue

        source_field, source_i, source_j, sign =
            octahealpix_transport_face_halo_source(i, j, connectivity, grid.Nx, grid.Ny, N, :u)
        expected_u = source_field === :u ? sign * model.transport_velocities.u[source_i, source_j, 1] :
                                           sign * model.transport_velocities.v[source_i, source_j, 1]
        transport_u_halo_max_error = max(transport_u_halo_max_error,
                                         abs(model.transport_velocities.u[i, j, 1] - expected_u))

        source_field, source_i, source_j, sign =
            octahealpix_transport_face_halo_source(i, j, connectivity, grid.Nx, grid.Ny, N, :v)
        expected_v = source_field === :u ? sign * model.transport_velocities.u[source_i, source_j, 1] :
                                           sign * model.transport_velocities.v[source_i, source_j, 1]
        transport_v_halo_max_error = max(transport_v_halo_max_error,
                                         abs(model.transport_velocities.v[i, j, 1] - expected_v))
    end

    @test transport_u_error ≤ 1000eps(FT) * transport_scale
    @test transport_v_error ≤ 1000eps(FT) * transport_scale
    @test transport_u_halo_max_error == zero(FT)
    @test transport_v_halo_max_error == zero(FT)

    return nothing
end

function test_octahealpix_prescribed_transport_state_drives_tracer_tendency(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    velocities = PrescribedVelocityFields(u = (λ, φ, z, t) -> sind(λ) * cosd(φ),
                                          v = (λ, φ, z, t) -> cosd(λ) * sind(φ))

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities,
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model, c = (λ, φ, z) -> sind(2 * λ) + cosd(φ))

    compute_transport_velocities!(model, model.free_surface)
    compute_tracer_tendencies!(model)

    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    for (i, j) in sampled_points
        expected_Gc = -div_Uc(i, j, 1, grid, model.advection.c, model.transport_velocities, model.tracers.c)
        computed_Gc = model.timestepper.Gⁿ.c[i, j, 1]
        tendency_scale = max(abs(expected_Gc), one(FT))
        @test abs(expected_Gc) > 100eps(FT)
        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale
    end

    forward = Array(interior(model.timestepper.Gⁿ.c))

    set!(model.transport_velocities.u, -model.transport_velocities.u)
    set!(model.transport_velocities.v, -model.transport_velocities.v)
    fill_halo_regions!(model.transport_velocities)
    compute_tracer_tendencies!(model)
    reverse = Array(interior(model.timestepper.Gⁿ.c))

    tolerance = 200 * eps(FT) * max(one(FT), max(maximum(abs, forward), maximum(abs, reverse)))

    @test forward ≈ -reverse atol = tolerance
    @test !any(isnan, forward)
    @test !any(isnan, reverse)

    return nothing
end

