function test_octahealpix_explicit_ab2_step_refreshes_transport_before_tracer_tendency(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model,
         u = zero(FT),
         v = zero(FT),
         c = (λ, φ, z) -> sind(2 * λ) + convert(FT, 0.3) * cosd(φ))

    c_before = CenterField(grid)
    set!(c_before, model.tracers.c)
    fill_halo_regions!(c_before)

    set!(model.timestepper.Gⁿ.u, (λ, φ, z) -> convert(FT, 0.2) * sind(λ) + convert(FT, 0.05) * cosd(φ))
    set!(model.timestepper.Gⁿ.v, (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.04) * sind(φ))
    set!(model.timestepper.G⁻.u, zero(FT))
    set!(model.timestepper.G⁻.v, zero(FT))

    Δt = convert(FT, 1//2)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.hydrostatic_ab2_step!(model,
                                                                           model.free_surface,
                                                                           grid,
                                                                           Δt,
                                                                           ())

    expected_transport = (u = OctaHEALPixConvertedTransportU(grid, model.velocities.u, model.velocities.v),
                          v = OctaHEALPixConvertedTransportV(grid, model.velocities.u, model.velocities.v),
                          w = model.transport_velocities.w)

    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    for (i, j) in sampled_points
        expected_Gc = -div_Uc(i, j, 1, grid, model.advection.c, expected_transport, c_before)
        computed_Gc = model.timestepper.Gⁿ.c[i, j, 1]
        tendency_scale = max(abs(expected_Gc), one(FT))
        @test abs(expected_Gc) > 100eps(FT)
        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale
    end

    return nothing
end

function test_octahealpix_explicit_ab2_step_updates_momentum_from_nonorthogonal_tendencies(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant(),
                                        tracer_advection = nothing)

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.04) * sind(φ))

    u_before = XFaceField(grid)
    v_before = YFaceField(grid)
    set!(u_before, model.velocities.u)
    set!(v_before, model.velocities.v)
    fill_halo_regions!((u_before, v_before))

    compute_momentum_tendencies!(model, ())

    Gⁿ_u = XFaceField(grid)
    Gⁿ_v = YFaceField(grid)
    set!(Gⁿ_u, model.timestepper.Gⁿ.u)
    set!(Gⁿ_v, model.timestepper.Gⁿ.v)
    fill_halo_regions!((Gⁿ_u, Gⁿ_v))

    set!(model.timestepper.G⁻.u, zero(FT))
    set!(model.timestepper.G⁻.v, zero(FT))

    Δt = convert(FT, 1//2)
    χ = convert(FT, model.timestepper.χ)
    coefficient = Δt * (convert(FT, 3//2) + χ)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.hydrostatic_ab2_step!(model,
                                                                           model.free_surface,
                                                                           grid,
                                                                           Δt,
                                                                           ())

    expected_u = XFaceField(grid)
    expected_v = YFaceField(grid)

    for j in 1:grid.Ny, i in 1:grid.Nx
        expected_u[i, j, 1] = u_before[i, j, 1] + coefficient * Gⁿ_u[i, j, 1]
        expected_v[i, j, 1] = v_before[i, j, 1] + coefficient * Gⁿ_v[i, j, 1]
    end

    fill_halo_regions!((expected_u, expected_v))

    u_interior_error = zero(FT)
    v_interior_error = zero(FT)
    u_halo_error = zero(FT)
    v_halo_error = zero(FT)
    maximum_velocity_update = zero(FT)

    for j in 1:grid.Ny, i in 1:grid.Nx
        u_interior_error = max(u_interior_error, abs(model.velocities.u[i, j, 1] - expected_u[i, j, 1]))
        v_interior_error = max(v_interior_error, abs(model.velocities.v[i, j, 1] - expected_v[i, j, 1]))
        maximum_velocity_update = max(maximum_velocity_update,
                                      abs(model.velocities.u[i, j, 1] - u_before[i, j, 1]),
                                      abs(model.velocities.v[i, j, 1] - v_before[i, j, 1]))
    end

    for j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue
        u_halo_error = max(u_halo_error, abs(model.velocities.u[i, j, 1] - expected_u[i, j, 1]))
        v_halo_error = max(v_halo_error, abs(model.velocities.v[i, j, 1] - expected_v[i, j, 1]))
    end

    @test maximum_velocity_update > 100eps(FT)
    @test u_interior_error ≤ 1000eps(FT) * max(one(FT), maximum(abs, Array(interior(expected_u))))
    @test v_interior_error ≤ 1000eps(FT) * max(one(FT), maximum(abs, Array(interior(expected_v))))
    @test u_halo_error == zero(FT)
    @test v_halo_error == zero(FT)

    return nothing
end

function test_octahealpix_explicit_ab2_step_updates_weno_vector_invariant_momentum_and_tracer(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (5, 5, 3))

    scheme = WENOVectorInvariant(FT; order = 5,
                                 upwinding = OnlySelfUpwinding(cross_scheme = Centered()))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = scheme,
                                        tracer_advection = Centered(FT),
                                        timestepper = :QuasiAdamsBashforth2)

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.14) * sind(λ) + convert(FT, 0.09) * z + convert(FT, 0.03) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.07) * cosd(λ) - convert(FT, 0.05) * z + convert(FT, 0.02) * sind(φ),
         c = (λ, φ, z) -> convert(FT, 0.3) * sind(2 * λ) + convert(FT, 0.2) * cosd(φ) + convert(FT, 0.1) * z)

    u_before = XFaceField(grid)
    v_before = YFaceField(grid)
    c_before = CenterField(grid)
    set!(u_before, model.velocities.u)
    set!(v_before, model.velocities.v)
    set!(c_before, model.tracers.c)
    fill_halo_regions!((u_before, v_before, c_before))

    Oceananigans.TimeSteppers.compute_tendencies!(model, ())

    Gⁿ_u = XFaceField(grid)
    Gⁿ_v = YFaceField(grid)
    Gⁿ_c = CenterField(grid)
    set!(Gⁿ_u, model.timestepper.Gⁿ.u)
    set!(Gⁿ_v, model.timestepper.Gⁿ.v)
    set!(Gⁿ_c, model.timestepper.Gⁿ.c)
    fill_halo_regions!((Gⁿ_u, Gⁿ_v, Gⁿ_c))

    set!(model.timestepper.G⁻.u, zero(FT))
    set!(model.timestepper.G⁻.v, zero(FT))
    set!(model.timestepper.G⁻.c, zero(FT))

    Δt = convert(FT, 1//2)
    χ = convert(FT, model.timestepper.χ)
    coefficient = Δt * (convert(FT, 3//2) + χ)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.hydrostatic_ab2_step!(model,
                                                                           model.free_surface,
                                                                           grid,
                                                                           Δt,
                                                                           ())

    expected_u = XFaceField(grid)
    expected_v = YFaceField(grid)
    expected_c = CenterField(grid)

    for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx
        expected_u[i, j, k] = u_before[i, j, k] + coefficient * Gⁿ_u[i, j, k]
        expected_v[i, j, k] = v_before[i, j, k] + coefficient * Gⁿ_v[i, j, k]
        expected_c[i, j, k] = c_before[i, j, k] + coefficient * Gⁿ_c[i, j, k]
    end

    fill_halo_regions!((expected_u, expected_v, expected_c))

    u_interior_error = zero(FT)
    v_interior_error = zero(FT)
    c_interior_error = zero(FT)
    u_halo_error = zero(FT)
    v_halo_error = zero(FT)
    c_halo_error = zero(FT)
    maximum_update = zero(FT)

    for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx
        u_interior_error = max(u_interior_error, abs(model.velocities.u[i, j, k] - expected_u[i, j, k]))
        v_interior_error = max(v_interior_error, abs(model.velocities.v[i, j, k] - expected_v[i, j, k]))
        c_interior_error = max(c_interior_error, abs(model.tracers.c[i, j, k] - expected_c[i, j, k]))
        maximum_update = max(maximum_update,
                             abs(model.velocities.u[i, j, k] - u_before[i, j, k]),
                             abs(model.velocities.v[i, j, k] - v_before[i, j, k]),
                             abs(model.tracers.c[i, j, k] - c_before[i, j, k]))
    end

    for k in 1:grid.Nz, j in -grid.Hy:(grid.Ny + grid.Hy), i in -grid.Hx:(grid.Nx + grid.Hx)
        (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue
        u_halo_error = max(u_halo_error, abs(model.velocities.u[i, j, k] - expected_u[i, j, k]))
        v_halo_error = max(v_halo_error, abs(model.velocities.v[i, j, k] - expected_v[i, j, k]))
        c_halo_error = max(c_halo_error, abs(model.tracers.c[i, j, k] - expected_c[i, j, k]))
    end

    @test maximum_update > 100eps(FT)
    @test u_interior_error ≤ 1000eps(FT) * max(one(FT), maximum(abs, Array(interior(expected_u))))
    @test v_interior_error ≤ 1000eps(FT) * max(one(FT), maximum(abs, Array(interior(expected_v))))
    @test c_interior_error ≤ 1000eps(FT) * max(one(FT), maximum(abs, Array(interior(expected_c))))
    @test u_halo_error == zero(FT)
    @test v_halo_error == zero(FT)
    @test c_halo_error == zero(FT)

