function test_octahealpix_explicit_rk_substep_updates_momentum_from_nonorthogonal_tendencies(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant(),
                                        tracer_advection = nothing)

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.04) * sind(φ))

    u_before = XFaceField(grid)
    v_before = YFaceField(grid)
    set!(u_before, model.velocities.u)
    set!(v_before, model.velocities.v)
    fill_halo_regions!((u_before, v_before))

    compute_momentum_tendencies!(model, ())

    Gⁿ_u = XFaceField(grid)
    Gⁿ_v = YFaceField(grid)
    set!(Gⁿ_u, model.timestepper.Gⁿ.u)
    set!(Gⁿ_v, model.timestepper.Gⁿ.v)
    fill_halo_regions!((Gⁿ_u, Gⁿ_v))

    set!(model.timestepper.Ψ⁻.u, u_before)
    set!(model.timestepper.Ψ⁻.v, v_before)

    Δτ = convert(FT, 1//2)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.rk_substep!(model,
                                                                 model.free_surface,
                                                                 grid,
                                                                 Δτ,
                                                                 ())

    expected_u = XFaceField(grid)
    expected_v = YFaceField(grid)

    for j in 1:grid.Ny, i in 1:grid.Nx
        expected_u[i, j, 1] = u_before[i, j, 1] + Δτ * Gⁿ_u[i, j, 1]
        expected_v[i, j, 1] = v_before[i, j, 1] + Δτ * Gⁿ_v[i, j, 1]
    end

    fill_halo_regions!((expected_u, expected_v))

    u_interior_error = zero(FT)
    v_interior_error = zero(FT)
    u_halo_error = zero(FT)
    v_halo_error = zero(FT)
    maximum_velocity_update = zero(FT)

    for j in 1:grid.Ny, i in 1:grid.Nx
        u_interior_error = max(u_interior_error, abs(model.velocities.u[i, j, 1] - expected_u[i, j, 1]))
        v_interior_error = max(v_interior_error, abs(model.velocities.v[i, j, 1] - expected_v[i, j, 1]))
        maximum_velocity_update = max(maximum_velocity_update,
                                      abs(model.velocities.u[i, j, 1] - u_before[i, j, 1]),
                                      abs(model.velocities.v[i, j, 1] - v_before[i, j, 1]))
    end

    for j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue
        u_halo_error = max(u_halo_error, abs(model.velocities.u[i, j, 1] - expected_u[i, j, 1]))
        v_halo_error = max(v_halo_error, abs(model.velocities.v[i, j, 1] - expected_v[i, j, 1]))
    end

    @test maximum_velocity_update > 100eps(FT)
    @test u_interior_error ≤ 1000eps(FT) * max(one(FT), maximum(abs, Array(interior(expected_u))))
    @test v_interior_error ≤ 1000eps(FT) * max(one(FT), maximum(abs, Array(interior(expected_v))))
    @test u_halo_error == zero(FT)
    @test v_halo_error == zero(FT)

    return nothing
end

function test_octahealpix_explicit_free_surface_time_step_updates_momentum_from_covariant_surface_gradient(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = ExplicitFreeSurface(),
                                        momentum_advection = VectorInvariant(),
                                        tracer_advection = nothing)

    set!(model,
         u = (λ, φ, z) -> zero(FT),
         v = (λ, φ, z) -> zero(FT))

    set!(model.free_surface.η,
         (λ, φ, z) -> convert(FT, 0.03) * sind(λ) + convert(FT, 0.02) * cosd(φ))

    η_before = CenterField(grid)
    u_before = XFaceField(grid)
    v_before = YFaceField(grid)

    set!(η_before, model.free_surface.η)
    set!(u_before, model.velocities.u)
    set!(v_before, model.velocities.v)

    fill_halo_regions!(η_before)
    fill_halo_regions!((u_before, v_before))

    Δt = convert(FT, 1//5)
    g = model.free_surface.gravitational_acceleration

    time_step!(model, Δt)

    expected_u = XFaceField(grid)
    expected_v = YFaceField(grid)

    for j in 1:grid.Ny, i in 1:grid.Nx
        expected_u[i, j, 1] = u_before[i, j, 1] - Δt * g * covariant_gradient_xᶠᶜᶜ(i, j, 1, grid, η_before)
        expected_v[i, j, 1] = v_before[i, j, 1] - Δt * g * covariant_gradient_yᶜᶠᶜ(i, j, 1, grid, η_before)
    end

    fill_halo_regions!((expected_u, expected_v))

    u_interior_error = zero(FT)
    v_interior_error = zero(FT)
    u_halo_error = zero(FT)
    v_halo_error = zero(FT)
    maximum_velocity_update = zero(FT)

    for j in 1:grid.Ny, i in 1:grid.Nx
        u_interior_error = max(u_interior_error, abs(model.velocities.u[i, j, 1] - expected_u[i, j, 1]))
        v_interior_error = max(v_interior_error, abs(model.velocities.v[i, j, 1] - expected_v[i, j, 1]))
        maximum_velocity_update = max(maximum_velocity_update,
                                      abs(model.velocities.u[i, j, 1] - u_before[i, j, 1]),
                                      abs(model.velocities.v[i, j, 1] - v_before[i, j, 1]))
    end

    for j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue
        u_halo_error = max(u_halo_error, abs(model.velocities.u[i, j, 1] - expected_u[i, j, 1]))
        v_halo_error = max(v_halo_error, abs(model.velocities.v[i, j, 1] - expected_v[i, j, 1]))
    end

    @test maximum_velocity_update > 100eps(FT)
    @test u_interior_error ≤ 1000eps(FT) * max(one(FT), maximum(abs, Array(interior(expected_u))))
    @test v_interior_error ≤ 1000eps(FT) * max(one(FT), maximum(abs, Array(interior(expected_v))))
    @test u_halo_error == zero(FT)
    @test v_halo_error == zero(FT)

    return nothing
end

function test_octahealpix_explicit_free_surface_multistep_updates_momentum_from_covariant_surface_gradient(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = ExplicitFreeSurface(),
                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    set!(model,
         u = (λ, φ, z) -> zero(FT),
         v = (λ, φ, z) -> zero(FT))

    set!(model.free_surface.η,
         (λ, φ, z) -> convert(FT, 0.03) * sind(λ) + convert(FT, 0.02) * cosd(φ))

    η_before = CenterField(grid)
    u_before = XFaceField(grid)
    v_before = YFaceField(grid)
    expected_u = XFaceField(grid)
    expected_v = YFaceField(grid)
    naive_u = XFaceField(grid)
    naive_v = YFaceField(grid)

    Δt = convert(FT, 1//10)
    g = model.free_surface.gravitational_acceleration

    maximum_surface_displacement = zero(FT)
    maximum_velocity_update = zero(FT)
    maximum_difference_from_naive = zero(FT)
    maximum_u_error = zero(FT)
    maximum_v_error = zero(FT)
    maximum_u_halo_error = zero(FT)
    maximum_v_halo_error = zero(FT)
    maximum_expected_u_scale = one(FT)
    maximum_expected_v_scale = one(FT)

    for step in 1:5
        set!(η_before, model.free_surface.η)
        set!(u_before, model.velocities.u)
        set!(v_before, model.velocities.v)

        fill_halo_regions!(η_before)
        fill_halo_regions!((u_before, v_before))

        time_step!(model, Δt)

        for j in 1:grid.Ny, i in 1:grid.Nx
            covariant_gradient_u = Oceananigans.Operators.covariant_gradient_xᶠᶜᶜ(i, j, grid.Nz + 1, grid, η_before)
            covariant_gradient_v = Oceananigans.Operators.covariant_gradient_yᶜᶠᶜ(i, j, grid.Nz + 1, grid, η_before)
            naive_gradient_u = Oceananigans.Operators.δxᶠᶜᶠ(i, j, grid.Nz + 1, grid, η_before) *
                               Oceananigans.Operators.Δx⁻¹ᶠᶜᶠ(i, j, 1, grid)
            naive_gradient_v = Oceananigans.Operators.δyᶜᶠᶠ(i, j, grid.Nz + 1, grid, η_before) *
                               Oceananigans.Operators.Δy⁻¹ᶜᶠᶠ(i, j, 1, grid)

            expected_u[i, j, 1] = u_before[i, j, 1] - Δt * g * covariant_gradient_u
            expected_v[i, j, 1] = v_before[i, j, 1] - Δt * g * covariant_gradient_v
            naive_u[i, j, 1] = u_before[i, j, 1] - Δt * g * naive_gradient_u
            naive_v[i, j, 1] = v_before[i, j, 1] - Δt * g * naive_gradient_v
        end

        fill_halo_regions!((expected_u, expected_v))
        fill_halo_regions!((naive_u, naive_v))

        maximum_expected_u_scale = max(maximum_expected_u_scale, maximum(abs, Array(interior(expected_u))))
        maximum_expected_v_scale = max(maximum_expected_v_scale, maximum(abs, Array(interior(expected_v))))

        for j in 1:grid.Ny, i in 1:grid.Nx
            maximum_surface_displacement = max(maximum_surface_displacement,
                                               abs(model.free_surface.η[i, j, grid.Nz + 1]))
            maximum_velocity_update = max(maximum_velocity_update,
                                          abs(model.velocities.u[i, j, 1] - u_before[i, j, 1]),
                                          abs(model.velocities.v[i, j, 1] - v_before[i, j, 1]))
            maximum_difference_from_naive = max(maximum_difference_from_naive,
                                                abs(model.velocities.u[i, j, 1] - naive_u[i, j, 1]),
                                                abs(model.velocities.v[i, j, 1] - naive_v[i, j, 1]))
            maximum_u_error = max(maximum_u_error, abs(model.velocities.u[i, j, 1] - expected_u[i, j, 1]))
            maximum_v_error = max(maximum_v_error, abs(model.velocities.v[i, j, 1] - expected_v[i, j, 1]))

            @test isfinite(model.velocities.u[i, j, 1])
            @test isfinite(model.velocities.v[i, j, 1])
            @test isfinite(model.free_surface.η[i, j, grid.Nz + 1])
        end

        for j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
            (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue
            maximum_u_halo_error = max(maximum_u_halo_error, abs(model.velocities.u[i, j, 1] - expected_u[i, j, 1]))
            maximum_v_halo_error = max(maximum_v_halo_error, abs(model.velocities.v[i, j, 1] - expected_v[i, j, 1]))
        end
    end

    @test maximum_surface_displacement > 100eps(FT)
    @test maximum_velocity_update > 100eps(FT)
    @test maximum_difference_from_naive > 100eps(FT)
    @test maximum_u_error ≤ 1000eps(FT) * maximum_expected_u_scale
    @test maximum_v_error ≤ 1000eps(FT) * maximum_expected_v_scale
    @test maximum_u_halo_error == zero(FT)
    @test maximum_v_halo_error == zero(FT)

    return nothing
end

