        covariant_gradient_u = Oceananigans.Operators.covariant_gradient_xᶠᶜᶜ(i, j, grid.Nz + 1, grid, η_after)
        covariant_gradient_v = Oceananigans.Operators.covariant_gradient_yᶜᶠᶜ(i, j, grid.Nz + 1, grid, η_after)
        naive_gradient_u = Oceananigans.Operators.δxᶠᶜᶠ(i, j, grid.Nz + 1, grid, η_after) *
                           Oceananigans.Operators.Δx⁻¹ᶠᶜᶠ(i, j, 1, grid)
        naive_gradient_v = Oceananigans.Operators.δyᶜᶠᶠ(i, j, grid.Nz + 1, grid, η_after) *
                           Oceananigans.Operators.Δy⁻¹ᶜᶠᶠ(i, j, 1, grid)

        expected_u[i, j, 1] = u_before[i, j, 1] - Δt * g * covariant_gradient_u
        expected_v[i, j, 1] = v_before[i, j, 1] - Δt * g * covariant_gradient_v
        naive_u[i, j, 1] = u_before[i, j, 1] - Δt * g * naive_gradient_u
        naive_v[i, j, 1] = v_before[i, j, 1] - Δt * g * naive_gradient_v
    end

    fill_halo_regions!((expected_u, expected_v))
    fill_halo_regions!((naive_u, naive_v))

    u_interior_error = zero(FT)
    v_interior_error = zero(FT)
