    set!(model,
         u = (λ, φ, z) -> zero(FT),
         v = (λ, φ, z) -> zero(FT))

    set!(model.free_surface.η,
         (λ, φ, z) -> convert(FT, 0.02) * sind(λ) + convert(FT, 0.01) * cosd(φ))

    Δt = convert(FT, 1//5)

    time_step!(model, Δt)

    expected_u = XFaceField(grid)
    expected_v = YFaceField(grid)

    U = model.free_surface.barotropic_velocities.U
    V = model.free_surface.barotropic_velocities.V

    for j in 1:grid.Ny, i in 1:grid.Nx
        Hᶠᶜ = Oceananigans.Operators.column_depthᶠᶜᵃ(i, j, grid)
        Hᶜᶠ = Oceananigans.Operators.column_depthᶜᶠᵃ(i, j, grid)

        expected_u[i, j, 1] = ifelse(Hᶠᶜ == 0, zero(FT), U[i, j, 1] / Hᶠᶜ)
        expected_v[i, j, 1] = ifelse(Hᶜᶠ == 0, zero(FT), V[i, j, 1] / Hᶜᶠ)
    end

    fill_halo_regions!((expected_u, expected_v))

    u_interior_error = zero(FT)
    v_interior_error = zero(FT)
    u_halo_error = zero(FT)
    v_halo_error = zero(FT)
    maximum_velocity_update = zero(FT)
    maximum_barotropic_mode = zero(FT)

    for j in 1:grid.Ny, i in 1:grid.Nx
        u_interior_error = max(u_interior_error, abs(model.velocities.u[i, j, 1] - expected_u[i, j, 1]))
        v_interior_error = max(v_interior_error, abs(model.velocities.v[i, j, 1] - expected_v[i, j, 1]))
        maximum_velocity_update = max(maximum_velocity_update,
                                      abs(model.velocities.u[i, j, 1]),
                                      abs(model.velocities.v[i, j, 1]))
        maximum_barotropic_mode = max(maximum_barotropic_mode,
                                      abs(U[i, j, 1]),
                                      abs(V[i, j, 1]))
    end

    for j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue
        u_halo_error = max(u_halo_error, abs(model.velocities.u[i, j, 1] - expected_u[i, j, 1]))
        v_halo_error = max(v_halo_error, abs(model.velocities.v[i, j, 1] - expected_v[i, j, 1]))
    end

    @test maximum_barotropic_mode > 100eps(FT)
    @test maximum_velocity_update > 100eps(FT)
    @test u_interior_error ≤ 1000eps(FT) * max(one(FT), maximum(abs, Array(interior(expected_u))))
    @test v_interior_error ≤ 1000eps(FT) * max(one(FT), maximum(abs, Array(interior(expected_v))))
    @test u_halo_error == zero(FT)
    @test v_halo_error == zero(FT)

    return nothing
end

function test_octahealpix_split_explicit_free_surface_multistep_reconciles_barotropic_mode(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = SplitExplicitFreeSurface(substeps = 8),
                                        momentum_advection = VectorInvariant(),
                                        tracer_advection = nothing)

    set!(model,
         u = (λ, φ, z) -> zero(FT),
         v = (λ, φ, z) -> zero(FT))

    set!(model.free_surface.η,
         (λ, φ, z) -> convert(FT, 0.02) * sind(λ) + convert(FT, 0.01) * cosd(φ))

    Δt = convert(FT, 1//10)
    k_top = grid.Nz + 1

    initial_surface = [model.free_surface.η[i, j, k_top] for j in 1:grid.Ny, i in 1:grid.Nx]
    initial_surface_volume = sum(Oceananigans.Operators.Azᶜᶜᵃ(i, j, 1, grid) * model.free_surface.η[i, j, k_top]
                                 for j in 1:grid.Ny, i in 1:grid.Nx)

    maximum_relative_barotropic_mismatch = zero(FT)
    maximum_velocity = zero(FT)
    maximum_barotropic_mode = zero(FT)
    maximum_surface_displacement = zero(FT)

    for step in 1:50
        time_step!(model, Δt)

        for j in 1:grid.Ny, i in 1:grid.Nx
            integrated_u = zero(FT)
            integrated_v = zero(FT)

            for k in 1:grid.Nz
                integrated_u += Oceananigans.Operators.Δzᶠᶜᶜ(i, j, k, grid) * model.velocities.u[i, j, k]
                integrated_v += Oceananigans.Operators.Δzᶜᶠᶜ(i, j, k, grid) * model.velocities.v[i, j, k]

                maximum_velocity = max(maximum_velocity,
                                       abs(model.velocities.u[i, j, k]),
                                       abs(model.velocities.v[i, j, k]))

                @test isfinite(model.velocities.u[i, j, k])
                @test isfinite(model.velocities.v[i, j, k])
            end

            barotropic_u = model.free_surface.barotropic_velocities.U[i, j, 1]
            barotropic_v = model.free_surface.barotropic_velocities.V[i, j, 1]
            u_scale = max(one(FT), abs(barotropic_u), abs(integrated_u))
            v_scale = max(one(FT), abs(barotropic_v), abs(integrated_v))

            maximum_relative_barotropic_mismatch = max(maximum_relative_barotropic_mismatch,
                                                       abs(integrated_u - barotropic_u) / u_scale,
                                                       abs(integrated_v - barotropic_v) / v_scale)

            maximum_barotropic_mode = max(maximum_barotropic_mode,
                                          abs(barotropic_u),
                                          abs(barotropic_v))

            maximum_surface_displacement = max(maximum_surface_displacement,
                                               abs(model.free_surface.η[i, j, k_top]))

            @test isfinite(model.free_surface.η[i, j, k_top])
        end
    end

    final_surface = [model.free_surface.η[i, j, k_top] for j in 1:grid.Ny, i in 1:grid.Nx]
    final_surface_volume = sum(Oceananigans.Operators.Azᶜᶜᵃ(i, j, 1, grid) * model.free_surface.η[i, j, k_top]
                               for j in 1:grid.Ny, i in 1:grid.Nx)
    surface_change = maximum(abs, final_surface .- initial_surface)
    surface_volume_scale = max(one(FT), abs(initial_surface_volume), abs(final_surface_volume))

    @test maximum_barotropic_mode > 100eps(FT)
    @test maximum_velocity > 100eps(FT)
    @test maximum_surface_displacement > 100eps(FT)
    @test surface_change > 100eps(FT)
    @test abs(final_surface_volume - initial_surface_volume) ≤ 100000eps(FT) * surface_volume_scale
    @test maximum_relative_barotropic_mismatch ≤ 1000eps(FT)

    return nothing
end

function test_octahealpix_split_explicit_free_surface_multistep_advects_weno_momentum_and_tracer(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (5, 5, 3))

    momentum_scheme = WENOVectorInvariant(FT; order = 5,
                                          upwinding = OnlySelfUpwinding(cross_scheme = Centered()))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = SplitExplicitFreeSurface(substeps = 8),
                                        momentum_advection = momentum_scheme,
                                        tracer_advection = Centered(FT))

    λ₀ = convert(FT, 45)
    φ₀ = convert(FT, 15)
    bell_radius = convert(FT, 30)
    bell_amplitude = convert(FT, 1//2)

    localized_tracer(λ, φ, z) = begin
        cos_distance = sind(φ₀) * sind(φ) +
                       cosd(φ₀) * cosd(φ) * cosd(λ - λ₀)
        γ = acosd(clamp(cos_distance, -one(FT), one(FT)))
        return ifelse(γ < bell_radius,
                      bell_amplitude * (one(FT) + cospi(γ / bell_radius)),
                      zero(FT))
    end

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.14) * sind(λ) + convert(FT, 0.09) * z + convert(FT, 0.03) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.07) * cosd(λ) - convert(FT, 0.05) * z + convert(FT, 0.02) * sind(φ),
         c = localized_tracer)

    set!(model.free_surface.η,
         (λ, φ, z) -> convert(FT, 0.02) * sind(λ) + convert(FT, 0.01) * cosd(φ))

    initial_u = Array(interior(model.velocities.u))
    initial_v = Array(interior(model.velocities.v))
    initial_tracer = Array(interior(model.tracers.c))
    initial_tracer_mass = sum(volume(i, j, k, grid, Center(), Center(), Center()) * model.tracers.c[i, j, k]
                              for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx)

    Δt = convert(FT, 1//10)
    maximum_velocity = zero(FT)
    maximum_surface_displacement = zero(FT)

    for step in 1:10
        time_step!(model, Δt)

        for j in 1:grid.Ny, i in 1:grid.Nx
            maximum_surface_displacement = max(maximum_surface_displacement,
                                               abs(model.free_surface.η[i, j, grid.Nz + 1]))

            for k in 1:grid.Nz
                maximum_velocity = max(maximum_velocity,
                                       abs(model.velocities.u[i, j, k]),
                                       abs(model.velocities.v[i, j, k]))

                @test isfinite(model.velocities.u[i, j, k])
                @test isfinite(model.velocities.v[i, j, k])
                @test isfinite(model.tracers.c[i, j, k])
            end
        end
    end

    final_u = Array(interior(model.velocities.u))
    final_v = Array(interior(model.velocities.v))
    final_tracer = Array(interior(model.tracers.c))
    final_tracer_mass = sum(volume(i, j, k, grid, Center(), Center(), Center()) * model.tracers.c[i, j, k]
                            for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx)

    u_change = maximum(abs, final_u .- initial_u)
    v_change = maximum(abs, final_v .- initial_v)
    tracer_change = maximum(abs, final_tracer .- initial_tracer)
    tracer_mass_scale = max(one(FT), abs(initial_tracer_mass))

    @test maximum_surface_displacement > 100eps(FT)
    @test maximum_velocity > 100eps(FT)
    @test u_change > 100eps(FT)
    @test v_change > 100eps(FT)
    @test tracer_change > 100eps(FT)
    @test abs(final_tracer_mass - initial_tracer_mass) ≤ 100000eps(FT) * tracer_mass_scale
    @test !any(isnan, final_u)
    @test !any(isnan, final_v)
    @test !any(isnan, final_tracer)

    return nothing
end

