function test_octahealpix_split_explicit_transport_velocities_match_filtered_barotropic_mode(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = SplitExplicitFreeSurface(substeps = 8),
                                        momentum_advection = nothing)

    set!(model,
         u = (λ, φ, z) -> zero(FT),
         v = (λ, φ, z) -> zero(FT),
         c = (λ, φ, z) -> zero(FT))

    set!(model.free_surface.η,
         (λ, φ, z) -> convert(FT, 0.02) * sind(λ) + convert(FT, 0.01) * cosd(φ))

    fill_halo_regions!(model.free_surface.η)

    Δt = convert(FT, 1//10)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.compute_free_surface_tendency!(grid, model, model.free_surface)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.step_free_surface!(model.free_surface, model, model.timestepper, Δt)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.compute_transport_velocities!(model, model.free_surface)

    u_reference_covariant = XFaceField(grid)
    v_reference_covariant = YFaceField(grid)
    set!(u_reference_covariant, model.velocities.u)
    set!(v_reference_covariant, model.velocities.v)

    parent(model.free_surface.barotropic_velocities.U) .= parent(model.free_surface.filtered_state.Ũ)
    parent(model.free_surface.barotropic_velocities.V) .= parent(model.free_surface.filtered_state.Ṽ)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.SplitExplicitFreeSurfaces.barotropic_split_explicit_corrector!(
        u_reference_covariant, v_reference_covariant, model.free_surface, grid)

    fill_halo_regions!((u_reference_covariant, v_reference_covariant))

    u_reference_transport = XFaceField(grid;
                                       boundary_conditions = model.transport_velocities.u.boundary_conditions)
    v_reference_transport = YFaceField(grid;
                                       boundary_conditions = model.transport_velocities.v.boundary_conditions)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.convert_to_volume_flux_velocities!(
        u_reference_transport, v_reference_transport, grid, u_reference_covariant, v_reference_covariant)
    fill_halo_regions!((u_reference_transport, v_reference_transport))

    u_naive_transport = XFaceField(grid;
                                   boundary_conditions = model.transport_velocities.u.boundary_conditions)
    v_naive_transport = YFaceField(grid;
                                   boundary_conditions = model.transport_velocities.v.boundary_conditions)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.convert_to_volume_flux_velocities!(
        u_naive_transport, v_naive_transport, grid, model.velocities.u, model.velocities.v)
    fill_halo_regions!((u_naive_transport, v_naive_transport))

    reference_scale = max(max(maximum(abs, parent(u_reference_transport)),
                              maximum(abs, parent(v_reference_transport))),
                          one(FT))
    tolerance = convert(FT, 500) * eps(FT) * reference_scale

    u_error = maximum(abs, parent(model.transport_velocities.u) .- parent(u_reference_transport))
    v_error = maximum(abs, parent(model.transport_velocities.v) .- parent(v_reference_transport))

    u_naive_error = maximum(abs, parent(model.transport_velocities.u) .- parent(u_naive_transport))
    v_naive_error = maximum(abs, parent(model.transport_velocities.v) .- parent(v_naive_transport))

    @test u_error ≤ tolerance
    @test v_error ≤ tolerance
    @test u_naive_error > tolerance
    @test v_naive_error > tolerance

    return nothing
end

function test_octahealpix_implicit_free_surface_time_step_refreshes_transport_state_after_pressure_correction(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = ImplicitFreeSurface(),
                                        momentum_advection = nothing)

    set!(model,
         u = (λ, φ, z) -> zero(FT),
         v = (λ, φ, z) -> zero(FT),
         c = (λ, φ, z) -> zero(FT))

    set!(model.free_surface.η,
         (λ, φ, z) -> convert(FT, 0.02) * sind(λ) + convert(FT, 0.01) * cosd(φ))

    fill_halo_regions!(model.free_surface.η)

    Δt = convert(FT, 1//10)
    time_step!(model, Δt)

    expected_covariant_u = similar(model.velocities.u)
    expected_covariant_v = similar(model.velocities.v)
    copyto!(parent(expected_covariant_u), parent(model.velocities.u))
    copyto!(parent(expected_covariant_v), parent(model.velocities.v))
    fill_halo_regions!((expected_covariant_u, expected_covariant_v))

    expected_u = XFaceField(grid;
                            boundary_conditions = model.transport_velocities.u.boundary_conditions)
    expected_v = YFaceField(grid;
                            boundary_conditions = model.transport_velocities.v.boundary_conditions)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.convert_to_volume_flux_velocities!(
        expected_u, expected_v, grid, expected_covariant_u, expected_covariant_v)
    fill_halo_regions!((expected_u, expected_v))

    stale_covariant_u = similar(model.velocities.u)
    stale_covariant_v = similar(model.velocities.v)
    parent(stale_covariant_u) .= zero(FT)
    parent(stale_covariant_v) .= zero(FT)

    for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:(grid.Nx + 1)
        @inbounds stale_covariant_u[i, j, k] = model.velocities.u[i, j, k]
    end

    for k in 1:grid.Nz, j in 1:(grid.Ny + 1), i in 1:grid.Nx
        @inbounds stale_covariant_v[i, j, k] = model.velocities.v[i, j, k]
    end

    stale_u = XFaceField(grid;
                         boundary_conditions = model.transport_velocities.u.boundary_conditions)
    stale_v = YFaceField(grid;
                         boundary_conditions = model.transport_velocities.v.boundary_conditions)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.convert_to_volume_flux_velocities!(
        stale_u, stale_v, grid, stale_covariant_u, stale_covariant_v)
    fill_halo_regions!((stale_u, stale_v))

    transport_scale = max(max(maximum(abs, parent(expected_u)),
                              maximum(abs, parent(expected_v))),
                          one(FT))
    tolerance = convert(FT, 500) * eps(FT) * transport_scale

    u_error = maximum(abs, parent(model.transport_velocities.u) .- parent(expected_u))
    v_error = maximum(abs, parent(model.transport_velocities.v) .- parent(expected_v))

    stale_u_error = maximum(abs, parent(model.transport_velocities.u) .- parent(stale_u))
    stale_v_error = maximum(abs, parent(model.transport_velocities.v) .- parent(stale_v))

    @test u_error ≤ tolerance
    @test v_error ≤ tolerance
    @test stale_u_error > tolerance
    @test stale_v_error > tolerance

    return nothing
end

function test_octahealpix_split_explicit_free_surface_time_step_preserves_constant_tracer(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = SplitExplicitFreeSurface(substeps = 8),
                                        momentum_advection = nothing)

    c₀ = convert(FT, 0.37)

    set!(model,
         u = (λ, φ, z) -> zero(FT),
         v = (λ, φ, z) -> zero(FT),
         c = (λ, φ, z) -> c₀)

    set!(model.free_surface.η,
         (λ, φ, z) -> convert(FT, 0.02) * sind(λ) + convert(FT, 0.01) * cosd(φ))

    Δt = convert(FT, 1//10)
    maximum_velocity = zero(FT)
    maximum_tracer_error = zero(FT)
    maximum_surface_displacement = zero(FT)

    for step in 1:5
        time_step!(model, Δt)

        for j in 1:grid.Ny, i in 1:grid.Nx
            maximum_surface_displacement = max(maximum_surface_displacement,
                                               abs(model.free_surface.η[i, j, grid.Nz + 1]))

            for k in 1:grid.Nz
                maximum_velocity = max(maximum_velocity,
                                       abs(model.velocities.u[i, j, k]),
                                       abs(model.velocities.v[i, j, k]))
                maximum_tracer_error = max(maximum_tracer_error, abs(model.tracers.c[i, j, k] - c₀))

                @test isfinite(model.velocities.u[i, j, k])
                @test isfinite(model.velocities.v[i, j, k])
                @test isfinite(model.tracers.c[i, j, k])
            end
        end
    end

    @test maximum_surface_displacement > 100eps(FT)
    @test maximum_velocity > 100eps(FT)
    @test maximum_tracer_error ≤ 1000eps(FT) * max(one(FT), abs(c₀))

    return nothing
end

function test_octahealpix_split_explicit_free_surface_localized_tracer_time_step_mass_conservation(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = SplitExplicitFreeSurface(substeps = 8),
                                        momentum_advection = nothing)

    λ₀ = convert(FT, 45)
    φ₀ = convert(FT, 15)
    bell_radius = convert(FT, 30)
    bell_amplitude = convert(FT, 1//2)

    localized_tracer(λ, φ, z) = begin
        cos_distance = sind(φ₀) * sind(φ) +
                       cosd(φ₀) * cosd(φ) * cosd(λ - λ₀)
        γ = acosd(clamp(cos_distance, -one(FT), one(FT)))
        return ifelse(γ < bell_radius,
                      bell_amplitude * (one(FT) + cospi(γ / bell_radius)),
                      zero(FT))
    end

    set!(model,
         u = (λ, φ, z) -> zero(FT),
         v = (λ, φ, z) -> zero(FT),
         c = localized_tracer)

    set!(model.free_surface.η,
         (λ, φ, z) -> convert(FT, 0.02) * sind(λ) + convert(FT, 0.01) * cosd(φ))

    initial_tracer = Array(interior(model.tracers.c))
    initial_mass = sum(volume(i, j, k, grid, Center(), Center(), Center()) * model.tracers.c[i, j, k]
                       for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx)

    Δt = convert(FT, 1//10)
    maximum_velocity = zero(FT)
    maximum_surface_displacement = zero(FT)

    for step in 1:5
        time_step!(model, Δt)

        for j in 1:grid.Ny, i in 1:grid.Nx
            maximum_surface_displacement = max(maximum_surface_displacement,
                                               abs(model.free_surface.η[i, j, grid.Nz + 1]))

            for k in 1:grid.Nz
                maximum_velocity = max(maximum_velocity,
                                       abs(model.velocities.u[i, j, k]),
                                       abs(model.velocities.v[i, j, k]))

                @test isfinite(model.velocities.u[i, j, k])
                @test isfinite(model.velocities.v[i, j, k])
                @test isfinite(model.tracers.c[i, j, k])
            end
        end
    end

    final_tracer = Array(interior(model.tracers.c))
    final_mass = sum(volume(i, j, k, grid, Center(), Center(), Center()) * model.tracers.c[i, j, k]
                     for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx)

    tracer_change = maximum(abs, final_tracer .- initial_tracer)
    mass_scale = max(one(FT), abs(initial_mass))

    @test maximum_surface_displacement > 100eps(FT)
    @test maximum_velocity > 100eps(FT)
    @test tracer_change > 100eps(FT)
    @test abs(final_mass - initial_mass) ≤ 100000eps(FT) * mass_scale
    @test !any(isnan, final_tracer)

    return nothing
end

