    source_u_bcs = FieldBoundaryConditions(source_grid, (Face(), Center(), Center());
                                           south = qcov,
                                           north = qcov)
    source_v_bcs = FieldBoundaryConditions(source_grid, (Center(), Face(), Center());
                                           west = qcov,
                                           east = qcov)

    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    source_u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(source_grid, times;
                                                                      boundary_conditions = source_u_bcs)
    source_v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(source_grid, times;
                                                                      boundary_conditions = source_v_bcs)

    set!(source_u_fts, (λ, φ, z, t) -> convert(FT, 2) * sind(λ) + cosd(φ) + t)
    set!(source_v_fts, (λ, φ, z, t) -> cosd(λ) - convert(FT, 3) * sind(φ) + convert(FT, 2) * t)

    velocities = PrescribedVelocityFields(u = source_u_fts, v = source_v_fts)

    model = HydrostaticFreeSurfaceModel(destination_grid;
                                        velocities,
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    time_step!(model, half)

    expected_u = XFaceField(destination_grid; boundary_conditions = source_u_fts.boundary_conditions)
    expected_v = YFaceField(destination_grid; boundary_conditions = source_v_fts.boundary_conditions)
    source_u_half = source_u_fts[Oceananigans.Units.Time(half)]
    source_v_half = source_v_fts[Oceananigans.Units.Time(half)]

    Oceananigans.Fields.set_paired_quadfolded_vector_fields!(expected_u, expected_v, source_u_half, source_v_half)
    fill_halo_regions!((expected_u, expected_v))

    u_interior_error = zero(FT)
    v_interior_error = zero(FT)
    u_halo_error = zero(FT)
    v_halo_error = zero(FT)

    for j in 1:destination_grid.Ny, i in 1:destination_grid.Nx
        u_interior_error = max(u_interior_error, abs(model.velocities.u[i, j, 1] - expected_u[i, j, 1]))
        v_interior_error = max(v_interior_error, abs(model.velocities.v[i, j, 1] - expected_v[i, j, 1]))
    end

    for j in 0:(destination_grid.Ny + 1), i in 0:(destination_grid.Nx + 1)
        (1 <= i <= destination_grid.Nx && 1 <= j <= destination_grid.Ny) && continue
        u_halo_error = max(u_halo_error, abs(model.velocities.u[i, j, 1] - expected_u[i, j, 1]))
        v_halo_error = max(v_halo_error, abs(model.velocities.v[i, j, 1] - expected_v[i, j, 1]))
    end

    @test u_interior_error == zero(FT)
    @test v_interior_error == zero(FT)
    @test u_halo_error == zero(FT)
    @test v_halo_error == zero(FT)

    return nothing
end

