        u_interior_error = max(u_interior_error, abs(model.velocities.u[i, j, 1] - expected_u[i, j, 1]))
        v_interior_error = max(v_interior_error, abs(model.velocities.v[i, j, 1] - expected_v[i, j, 1]))
    end

    for j in 0:(destination_grid.Ny + 1), i in 0:(destination_grid.Nx + 1)
        (1 <= i <= destination_grid.Nx && 1 <= j <= destination_grid.Ny) && continue
        u_halo_error = max(u_halo_error, abs(model.velocities.u[i, j, 1] - expected_u[i, j, 1]))
        v_halo_error = max(v_halo_error, abs(model.velocities.v[i, j, 1] - expected_v[i, j, 1]))
    end

    @test u_interior_error == zero(FT)
    @test v_interior_error == zero(FT)
    @test u_halo_error == zero(FT)
    @test v_halo_error == zero(FT)

    return nothing
end

function test_octahealpix_prescribed_field_time_series_velocity_materialization_incompatible_halo_error(FT, N)
    radius = convert(FT, 3)
    source_mapping = OctaHEALPixMapping(N)
    source_u_grid = SphericalShellGrid(CPU(), FT; mapping = source_mapping,
                                       z = (zero(FT), one(FT)),
                                       radius,
                                       halo = (1, 1, 1))
    source_v_grid = SphericalShellGrid(CPU(), FT; mapping = source_mapping,
                                       z = (zero(FT), one(FT)),
                                       radius,
                                       halo = (2, 2, 1))

    destination_mapping = OctaHEALPixMapping(N)
    destination_grid = SphericalShellGrid(CPU(), FT; mapping = destination_mapping,
                                          z = (zero(FT), one(FT)),
                                          radius,
                                          halo = (1, 1, 1))

    qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(one(FT))
    source_u_bcs = FieldBoundaryConditions(source_u_grid, (Face(), Center(), Center());
                                           south = qcov,
                                           north = qcov)
    source_v_bcs = FieldBoundaryConditions(source_v_grid, (Center(), Face(), Center());
                                           west = qcov,
                                           east = qcov)

    times = [zero(FT), one(FT)]
    source_u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(source_u_grid, times;
                                                                      boundary_conditions = source_u_bcs)
    source_v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(source_v_grid, times;
                                                                      boundary_conditions = source_v_bcs)

    set!(source_u_fts, (λ, φ, z, t) -> convert(FT, 2) * sind(λ) + cosd(φ) + t)
    set!(source_v_fts, (λ, φ, z, t) -> cosd(λ) - convert(FT, 3) * sind(φ) + convert(FT, 2) * t)

    velocities = PrescribedVelocityFields(u = source_u_fts, v = source_v_fts)

    @test_throws ArgumentError HydrostaticFreeSurfaceModel(destination_grid;
                                                           velocities,
                                                           tracers = nothing,
                                                           buoyancy = nothing,
                                                           free_surface = nothing,
                                                           momentum_advection = nothing,
                                                           tracer_advection = nothing)

    return nothing
end

function test_octahealpix_prescribed_vertical_field_time_series_velocity_materialization(FT, N)
    radius = convert(FT, 3)
    source_mapping = OctaHEALPixMapping(div(N, 2))
    source_grid = SphericalShellGrid(CPU(), FT; mapping = source_mapping,
                                     z = (zero(FT), one(FT)),
                                     radius,
                                     halo = (1, 1, 1))

    destination_mapping = OctaHEALPixMapping(N)
    destination_grid = SphericalShellGrid(CPU(), FT; mapping = destination_mapping,
                                          z = (zero(FT), one(FT)),
                                          radius,
                                          halo = (1, 1, 1))

    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    source_w_fts = Oceananigans.FieldTimeSeries{Center, Center, Face}(source_grid, times)
    set!(source_w_fts, (λ, φ, z, t) -> sind(λ) - cosd(φ) + t)

    velocities = PrescribedVelocityFields(u = (λ, φ, z, t) -> sind(λ) * cosd(φ),
                                          v = (λ, φ, z, t) -> cosd(λ) * sind(φ),
                                          w = source_w_fts)

    model = HydrostaticFreeSurfaceModel(destination_grid;
                                        velocities,
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant(),
                                        tracer_advection = nothing)

    time_step!(model, half)

    @test model.velocities.w isa Oceananigans.OutputReaders.TimeSeriesInterpolation
    @test model.velocities.w.grid === destination_grid

    expected_w = ZFaceField(destination_grid; boundary_conditions = source_w_fts.boundary_conditions)
    source_w_half = source_w_fts[Oceananigans.Units.Time(half)]
    set!(expected_w, source_w_half)
    fill_halo_regions!(expected_w)

    w_interior_error = zero(FT)
    w_halo_error = zero(FT)

    for k in 1:(destination_grid.Nz + 1), j in 1:destination_grid.Ny, i in 1:destination_grid.Nx
        w_interior_error = max(w_interior_error, abs(model.velocities.w[i, j, k] - expected_w[i, j, k]))
    end

    for k in 1:(destination_grid.Nz + 1), j in 0:(destination_grid.Ny + 1), i in 0:(destination_grid.Nx + 1)
        (1 <= i <= destination_grid.Nx && 1 <= j <= destination_grid.Ny) && continue
        w_halo_error = max(w_halo_error, abs(model.velocities.w[i, j, k] - expected_w[i, j, k]))
    end

    @test w_interior_error == zero(FT)
    @test w_halo_error == zero(FT)

    momentum = model.advection.momentum
    U = (u = model.velocities.u, v = model.velocities.v, w = model.velocities.w)
    k = 1

    compute_momentum_tendencies!(model, ())
    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    for (i, j) in sampled_points
        expected_Gu = -U_dot_∇u(i, j, k, destination_grid, momentum, U)
        expected_Gv = -U_dot_∇v(i, j, k, destination_grid, momentum, U)
        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        magnitude_scale = max(abs(expected_Gu), abs(expected_Gv), one(FT))

        @test abs(expected_Gu) > 100eps(FT)
        @test abs(expected_Gv) > 100eps(FT)
        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * magnitude_scale
        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * magnitude_scale
    end

    return nothing
end

