                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    expected_u = XFaceField(destination_grid; boundary_conditions = source_u.boundary_conditions)
    source_v_zero = YFaceField(source_grid)
    set!(source_v_zero, zero(eltype(source_v_zero)))
    expected_v = YFaceField(destination_grid; boundary_conditions = source_v_zero.boundary_conditions)

    Oceananigans.Fields.set_paired_quadfolded_vector_fields!(expected_u, expected_v, source_u, source_v_zero)
    fill_halo_regions!((expected_u, expected_v))

    u_interior_error = zero(FT)
