    @test inferred_transport_velocities.w.grid === grid

    return nothing
end

function test_octahealpix_same_grid_prescribed_operation_velocity_materialization(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT;
                              size = (2N, 2N, 2),
                              mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    source_u = XFaceField(grid)
    source_v = YFaceField(grid)
    source_w = ZFaceField(grid)

    set!(source_u, (λ, φ, z) -> convert(FT, 2) * sind(λ) + cosd(φ) + convert(FT, 0.1) * z)
    set!(source_v, (λ, φ, z) -> cosd(λ) - convert(FT, 3) * sind(φ) + convert(FT, 0.2) * z)
    set!(source_w, (λ, φ, z) -> convert(FT, 0.25) * (one(FT) + z) * (sind(λ / 2) + cosd(φ)))
    fill_halo_regions!((source_u, source_v, source_w))

    velocities = PrescribedVelocityFields(u = source_u + zero(FT),
                                          v = source_v - zero(FT),
                                          w = source_w + zero(FT))

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities,
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant(),
                                        tracer_advection = nothing)

    u_error = zero(FT)
    v_error = zero(FT)
    w_error = zero(FT)

    for k in 1:grid.Nz, j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        u_error = max(u_error, abs(model.velocities.u[i, j, k] - source_u[i, j, k]))
        v_error = max(v_error, abs(model.velocities.v[i, j, k] - source_v[i, j, k]))
    end

    for k in 1:(grid.Nz + 1), j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        w_error = max(w_error, abs(model.velocities.w[i, j, k] - source_w[i, j, k]))
    end

    @test u_error == zero(FT)
    @test v_error == zero(FT)
    @test w_error == zero(FT)

    momentum = model.advection.momentum
    U = (u = model.velocities.u, v = model.velocities.v, w = model.velocities.w)

    compute_momentum_tendencies!(model, ())

    sampled_points = ((N + 2, N + 2, 1),
                      (N + 1, N + 1, 2),
                      (2N - 1, N + 1, 1),
                      (N + 1, 2N - 1, 2))

    for (i, j, k) in sampled_points
        expected_Gu = -U_dot_∇u(i, j, k, grid, momentum, U)
        expected_Gv = -U_dot_∇v(i, j, k, grid, momentum, U)
        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        magnitude_scale = max(abs(expected_Gu), abs(expected_Gv), one(FT))

        @test abs(expected_Gu) > 100eps(FT)
        @test abs(expected_Gv) > 100eps(FT)
        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * magnitude_scale
        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * magnitude_scale
    end

    return nothing
end

function test_octahealpix_same_grid_horizontal_computed_field_construction(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT;
                              size = (2N, 2N, 2),
                              mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    source_u = XFaceField(grid)
    source_v = YFaceField(grid)
    source_w = ZFaceField(grid)

    set!(source_u, (λ, φ, z) -> convert(FT, 2) * sind(λ) + cosd(φ) + convert(FT, 0.1) * z)
    set!(source_v, (λ, φ, z) -> cosd(λ) - convert(FT, 3) * sind(φ) + convert(FT, 0.2) * z)
    set!(source_w, (λ, φ, z) -> convert(FT, 0.25) * (one(FT) + z) * (sind(λ / 2) + cosd(φ)))
    fill_halo_regions!((source_u, source_v, source_w))

    computed_u = Field(source_u + zero(FT); boundary_conditions = source_u.boundary_conditions)
    computed_v = Field(source_v - zero(FT); boundary_conditions = source_v.boundary_conditions)
    fill_halo_regions!((computed_u, computed_v))

    u_error = zero(FT)
    v_error = zero(FT)

    for k in 1:grid.Nz, j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        u_error = max(u_error, abs(computed_u[i, j, k] - source_u[i, j, k]))
        v_error = max(v_error, abs(computed_v[i, j, k] - source_v[i, j, k]))
    end

    @test u_error == zero(FT)
    @test v_error == zero(FT)

    staged_u = Field(source_u + zero(FT);
                     boundary_conditions = source_u.boundary_conditions,
                     compute = false)
    staged_v = Field(source_v - zero(FT);
                     boundary_conditions = source_v.boundary_conditions,
                     compute = false)
    staged_w = Field(source_w + zero(FT);
                     boundary_conditions = source_w.boundary_conditions,
                     compute = false)

    Oceananigans.Fields.compute!((; u = staged_u, v = staged_v, w = staged_w))

    staged_u_error = zero(FT)
    staged_v_error = zero(FT)
    staged_w_error = zero(FT)

    for k in 1:grid.Nz, j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        staged_u_error = max(staged_u_error, abs(staged_u[i, j, k] - source_u[i, j, k]))
        staged_v_error = max(staged_v_error, abs(staged_v[i, j, k] - source_v[i, j, k]))
    end

    for k in 1:(grid.Nz + 1), j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        staged_w_error = max(staged_w_error, abs(staged_w[i, j, k] - source_w[i, j, k]))
    end

    @test staged_u_error == zero(FT)
    @test staged_v_error == zero(FT)
    @test staged_w_error == zero(FT)

    tuple_u = Field(source_u + zero(FT);
                    boundary_conditions = source_u.boundary_conditions,
                    compute = false)
    tuple_v = Field(source_v - zero(FT);
                    boundary_conditions = source_v.boundary_conditions,
                    compute = false)
    tuple_w = Field(source_w + zero(FT);
                    boundary_conditions = source_w.boundary_conditions,
                    compute = false)

    Oceananigans.Fields.compute!((tuple_u, tuple_v, tuple_w))

    tuple_u_error = zero(FT)
    tuple_v_error = zero(FT)
    tuple_w_error = zero(FT)

    for k in 1:grid.Nz, j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        tuple_u_error = max(tuple_u_error, abs(tuple_u[i, j, k] - source_u[i, j, k]))
        tuple_v_error = max(tuple_v_error, abs(tuple_v[i, j, k] - source_v[i, j, k]))
    end

    for k in 1:(grid.Nz + 1), j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        tuple_w_error = max(tuple_w_error, abs(tuple_w[i, j, k] - source_w[i, j, k]))
    end

    @test tuple_u_error == zero(FT)
    @test tuple_v_error == zero(FT)
    @test tuple_w_error == zero(FT)

    helper_u = Field(source_u + zero(FT);
                     boundary_conditions = source_u.boundary_conditions,
                     compute = false)
    helper_v = Field(source_v - zero(FT);
                     boundary_conditions = source_v.boundary_conditions,
                     compute = false)
    helper_w = Field(source_w + zero(FT);
                     boundary_conditions = source_w.boundary_conditions,
                     compute = false)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.compute_auxiliary_fields!((; u = helper_u,
                                                                                 v = helper_v,
                                                                                 w = helper_w))

    helper_u_error = zero(FT)
    helper_v_error = zero(FT)
    helper_w_error = zero(FT)

    for k in 1:grid.Nz, j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        helper_u_error = max(helper_u_error, abs(helper_u[i, j, k] - source_u[i, j, k]))
        helper_v_error = max(helper_v_error, abs(helper_v[i, j, k] - source_v[i, j, k]))
    end

    for k in 1:(grid.Nz + 1), j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        helper_w_error = max(helper_w_error, abs(helper_w[i, j, k] - source_w[i, j, k]))
    end

    @test helper_u_error == zero(FT)
    @test helper_v_error == zero(FT)
    @test helper_w_error == zero(FT)

    alias_u = Field(source_u + zero(FT);
                    boundary_conditions = source_u.boundary_conditions,
                    compute = false)
    alias_v = Field(source_v - zero(FT);
                    boundary_conditions = source_v.boundary_conditions,
                    compute = false)
    alias_w = Field(source_w + zero(FT);
                    boundary_conditions = source_w.boundary_conditions,
                    compute = false)

    Oceananigans.Fields.compute!((; xface = alias_u, yface = alias_v, zface = alias_w))

    alias_u_error = zero(FT)
    alias_v_error = zero(FT)
    alias_w_error = zero(FT)

    for k in 1:grid.Nz, j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        alias_u_error = max(alias_u_error, abs(alias_u[i, j, k] - source_u[i, j, k]))
        alias_v_error = max(alias_v_error, abs(alias_v[i, j, k] - source_v[i, j, k]))
    end

    for k in 1:(grid.Nz + 1), j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        alias_w_error = max(alias_w_error, abs(alias_w[i, j, k] - source_w[i, j, k]))
    end

    @test alias_u_error == zero(FT)
    @test alias_v_error == zero(FT)
    @test alias_w_error == zero(FT)

    source_U = XFaceField(grid)
    source_V = YFaceField(grid)

    set!(source_U, (λ, φ, z) -> convert(FT, 0.75) * cosd(λ / 2) + convert(FT, 0.15) * z)
    set!(source_V, (λ, φ, z) -> convert(FT, -0.5) * sind(φ / 2) - convert(FT, 0.05) * z)
    fill_halo_regions!((source_U, source_V))

    paired_u = Field(source_u + zero(FT);
                     boundary_conditions = source_u.boundary_conditions,
                     compute = false)
    paired_v = Field(source_v - zero(FT);
                     boundary_conditions = source_v.boundary_conditions,
                     compute = false)
    paired_U = Field(source_U + zero(FT);
                     boundary_conditions = source_U.boundary_conditions,
                     compute = false)
    paired_V = Field(source_V - zero(FT);
                     boundary_conditions = source_V.boundary_conditions,
                     compute = false)
    paired_w = Field(source_w + zero(FT);
                     boundary_conditions = source_w.boundary_conditions,
                     compute = false)

    Oceananigans.Fields.compute!((; u = paired_u,
                                    v = paired_v,
                                    U = paired_U,
                                    V = paired_V,
                                    w = paired_w))

    paired_u_error = zero(FT)
    paired_v_error = zero(FT)
    paired_U_error = zero(FT)
    paired_V_error = zero(FT)
    paired_w_error = zero(FT)

    for k in 1:grid.Nz, j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        paired_u_error = max(paired_u_error, abs(paired_u[i, j, k] - source_u[i, j, k]))
        paired_v_error = max(paired_v_error, abs(paired_v[i, j, k] - source_v[i, j, k]))
        paired_U_error = max(paired_U_error, abs(paired_U[i, j, k] - source_U[i, j, k]))
        paired_V_error = max(paired_V_error, abs(paired_V[i, j, k] - source_V[i, j, k]))
    end

    for k in 1:(grid.Nz + 1), j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        paired_w_error = max(paired_w_error, abs(paired_w[i, j, k] - source_w[i, j, k]))
    end

    @test paired_u_error == zero(FT)
    @test paired_v_error == zero(FT)
    @test paired_U_error == zero(FT)
    @test paired_V_error == zero(FT)
    @test paired_w_error == zero(FT)

    tuple_pair_u = Field(source_u + zero(FT);
                         boundary_conditions = source_u.boundary_conditions,
                         compute = false)
    tuple_pair_v = Field(source_v - zero(FT);
                         boundary_conditions = source_v.boundary_conditions,
                         compute = false)
    tuple_pair_U = Field(source_U + zero(FT);
                         boundary_conditions = source_U.boundary_conditions,
                         compute = false)
    tuple_pair_V = Field(source_V - zero(FT);
                         boundary_conditions = source_V.boundary_conditions,
                         compute = false)
    tuple_pair_w = Field(source_w + zero(FT);
                         boundary_conditions = source_w.boundary_conditions,
                         compute = false)

    Oceananigans.Fields.compute!((tuple_pair_u,
                                  tuple_pair_v,
                                  tuple_pair_w,
                                  tuple_pair_U,
                                  tuple_pair_V))

    tuple_pair_u_error = zero(FT)
    tuple_pair_v_error = zero(FT)
    tuple_pair_U_error = zero(FT)
    tuple_pair_V_error = zero(FT)
    tuple_pair_w_error = zero(FT)

    for k in 1:grid.Nz, j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        tuple_pair_u_error = max(tuple_pair_u_error, abs(tuple_pair_u[i, j, k] - source_u[i, j, k]))
        tuple_pair_v_error = max(tuple_pair_v_error, abs(tuple_pair_v[i, j, k] - source_v[i, j, k]))
        tuple_pair_U_error = max(tuple_pair_U_error, abs(tuple_pair_U[i, j, k] - source_U[i, j, k]))
        tuple_pair_V_error = max(tuple_pair_V_error, abs(tuple_pair_V[i, j, k] - source_V[i, j, k]))
    end

    for k in 1:(grid.Nz + 1), j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        tuple_pair_w_error = max(tuple_pair_w_error, abs(tuple_pair_w[i, j, k] - source_w[i, j, k]))
