function test_octahealpix_prescribed_velocity_operation_updates_horizontal_computed_halos(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT;
                              size = (2N, 2N, 2),
                              mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    source_u = XFaceField(grid)
    source_v = YFaceField(grid)
    source_w = ZFaceField(grid)

    set!(source_u, (λ, φ, z) -> sind(λ) + cosd(φ) + convert(FT, 0.1) * z)
    set!(source_v, (λ, φ, z) -> cosd(λ) - sind(φ) + convert(FT, 0.2) * z)
    set!(source_w, (λ, φ, z) -> convert(FT, 0.5) * (sind(λ / 2) + cosd(φ) + z))
    fill_halo_regions!((source_u, source_v, source_w))

    velocities =
        Oceananigans.Models.HydrostaticFreeSurfaceModels.hydrostatic_velocity_fields(
            PrescribedVelocityFields(u = source_u + zero(FT),
                                     v = source_v - zero(FT),
                                     w = source_w + zero(FT)),
            grid,
            Oceananigans.Clock(time = zero(FT)),
            (;))

    u_only_velocities =
        Oceananigans.Models.HydrostaticFreeSurfaceModels.hydrostatic_velocity_fields(
            PrescribedVelocityFields(u = source_u + zero(FT),
                                     v = source_v,
                                     w = source_w + zero(FT)),
            grid,
            Oceananigans.Clock(time = zero(FT)),
            (;))

    v_only_velocities =
        Oceananigans.Models.HydrostaticFreeSurfaceModels.hydrostatic_velocity_fields(
            PrescribedVelocityFields(u = source_u,
                                     v = source_v - zero(FT),
                                     w = source_w + zero(FT)),
            grid,
            Oceananigans.Clock(time = zero(FT)),
            (;))

    constant_v = Oceananigans.Fields.ConstantField(convert(FT, 3//2))
    u_with_constant_partner_velocities =
        Oceananigans.Models.HydrostaticFreeSurfaceModels.hydrostatic_velocity_fields(
            PrescribedVelocityFields(u = source_u + zero(FT),
                                     v = constant_v,
                                     w = source_w + zero(FT)),
            grid,
            Oceananigans.Clock(time = zero(FT)),
            (;))

    zero_u = ZeroField()
    v_with_zero_partner_velocities =
        Oceananigans.Models.HydrostaticFreeSurfaceModels.hydrostatic_velocity_fields(
            PrescribedVelocityFields(u = zero_u,
                                     v = source_v - zero(FT),
                                     w = source_w + zero(FT)),
            grid,
            Oceananigans.Clock(time = zero(FT)),
            (;))

    set!(source_u, (λ, φ, z) -> convert(FT, 2) * sind(λ) - cosd(φ) + convert(FT, 0.3) * z)
    set!(source_v, (λ, φ, z) -> convert(FT, 3) * cosd(λ) + sind(φ) - convert(FT, 0.1) * z)
    set!(source_w, (λ, φ, z) -> convert(FT, 0.25) * (sind(λ) - cosd(φ / 2) + z))
    fill_halo_regions!((source_u, source_v, source_w))

    function check_prescribed_velocity_update(velocities, expected_u_source, expected_v_source, expected_w_source)
        Oceananigans.Models.HydrostaticFreeSurfaceModels.update_prescribed_velocity_field_operations!(velocities)

        expected_u = XFaceField(grid; boundary_conditions = velocities.u.boundary_conditions)
        expected_v = YFaceField(grid; boundary_conditions = velocities.v.boundary_conditions)
        expected_w = ZFaceField(grid; boundary_conditions = velocities.w.boundary_conditions)

        set!((u = expected_u, v = expected_v),
             u = expected_u_source,
             v = expected_v_source)
        set!(expected_w, expected_w_source)
        fill_halo_regions!((expected_u, expected_v, expected_w))

        u_error = zero(FT)
        v_error = zero(FT)
        w_error = zero(FT)

        for k in 1:grid.Nz, j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
            u_error = max(u_error, abs(velocities.u[i, j, k] - expected_u[i, j, k]))
            v_error = max(v_error, abs(velocities.v[i, j, k] - expected_v[i, j, k]))
        end

        for k in 0:(grid.Nz + 1), j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
            w_error = max(w_error, abs(velocities.w[i, j, k] - expected_w[i, j, k]))
        end

        @test u_error == zero(FT)
        @test v_error == zero(FT)
        @test w_error == zero(FT)
    end

    check_prescribed_velocity_update(velocities,
                                     source_u + zero(FT),
                                     source_v - zero(FT),
                                     source_w + zero(FT))

    check_prescribed_velocity_update(u_only_velocities,
                                     source_u + zero(FT),
                                     source_v,
                                     source_w + zero(FT))

    check_prescribed_velocity_update(v_only_velocities,
                                     source_u,
                                     source_v - zero(FT),
                                     source_w + zero(FT))

    check_prescribed_velocity_update(u_with_constant_partner_velocities,
                                     source_u + zero(FT),
                                     constant_v,
                                     source_w + zero(FT))

    check_prescribed_velocity_update(v_with_zero_partner_velocities,
                                     zero_u,
                                     source_v - zero(FT),
                                     source_w + zero(FT))

    return nothing
end

function test_octahealpix_tuple_velocity_halo_fill_with_extra_field(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT;
                              size = (2N, 2N, 2),
                              mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    u = XFaceField(grid)
    v = YFaceField(grid)
    w = ZFaceField(grid)

    set!(u, (λ, φ, z) -> convert(FT, 2) * sind(λ) + cosd(φ) + convert(FT, 0.1) * z)
    set!(v, (λ, φ, z) -> cosd(λ) - convert(FT, 3) * sind(φ) + convert(FT, 0.2) * z)
    set!(w, (λ, φ, z) -> convert(FT, 0.25) * (one(FT) + z) * (sind(λ / 2) + cosd(φ)))

    expected_u = XFaceField(grid; boundary_conditions = u.boundary_conditions)
    expected_v = YFaceField(grid; boundary_conditions = v.boundary_conditions)
    expected_w = ZFaceField(grid; boundary_conditions = w.boundary_conditions)

    set!(expected_u, (λ, φ, z) -> convert(FT, 2) * sind(λ) + cosd(φ) + convert(FT, 0.1) * z)
    set!(expected_v, (λ, φ, z) -> cosd(λ) - convert(FT, 3) * sind(φ) + convert(FT, 0.2) * z)
    set!(expected_w, (λ, φ, z) -> convert(FT, 0.25) * (one(FT) + z) * (sind(λ / 2) + cosd(φ)))

    fill_halo_regions!((expected_u, expected_v))
    fill_halo_regions!(expected_w)
    fill_halo_regions!((u, v, w))

    u_error = zero(FT)
    v_error = zero(FT)
    w_error = zero(FT)

    for k in 1:grid.Nz, j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        u_error = max(u_error, abs(u[i, j, k] - expected_u[i, j, k]))
        v_error = max(v_error, abs(v[i, j, k] - expected_v[i, j, k]))
    end

    for k in 1:(grid.Nz + 1), j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        w_error = max(w_error, abs(w[i, j, k] - expected_w[i, j, k]))
    end

    @test u_error == zero(FT)
    @test v_error == zero(FT)
    @test w_error == zero(FT)

    return nothing
end

