function test_octahealpix_same_grid_prescribed_time_series_interpolation_operation_velocity_materialization(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT;
                              size = (2N, 2N, 2),
                              mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(one(FT))
    u_bcs = FieldBoundaryConditions(grid, (Face(), Center(), Center());
                                    south = qcov,
                                    north = qcov)
    v_bcs = FieldBoundaryConditions(grid, (Center(), Face(), Center());
                                    west = qcov,
                                    east = qcov)

    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times;
                                                               boundary_conditions = u_bcs)
    v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times;
                                                               boundary_conditions = v_bcs)
    w_fts = Oceananigans.FieldTimeSeries{Center, Center, Face}(grid, times)

    set!(u_fts, (λ, φ, z, t) -> convert(FT, 2) * sind(λ) + cosd(φ) + t + convert(FT, 0.1) * z)
    set!(v_fts, (λ, φ, z, t) -> cosd(λ) - convert(FT, 3) * sind(φ) + convert(FT, 2) * t + convert(FT, 0.2) * z)
    set!(w_fts, (λ, φ, z, t) -> convert(FT, 0.25) * (one(FT) + z) * (sind(λ / 2) + cosd(φ)) + t)

    shared_clock = Oceananigans.Clock(time = zero(FT))

    velocities = PrescribedVelocityFields(u = Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, grid; clock = shared_clock) + zero(FT),
                                          v = Oceananigans.OutputReaders.TimeSeriesInterpolation(v_fts, grid; clock = shared_clock) - zero(FT),
                                          w = Oceananigans.OutputReaders.TimeSeriesInterpolation(w_fts, grid; clock = shared_clock) + zero(FT))

    model = HydrostaticFreeSurfaceModel(grid;
                                        clock = shared_clock,
                                        velocities,
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant(),
                                        tracer_advection = nothing)

    @test !isnothing(model.velocities.u.operand)
    @test !isnothing(model.velocities.v.operand)
    @test !isnothing(model.velocities.w.operand)

    time_step!(model, half)

    expected_u = u_fts[Oceananigans.Units.Time(half)]
    expected_v = v_fts[Oceananigans.Units.Time(half)]
    expected_w = w_fts[Oceananigans.Units.Time(half)]
    fill_halo_regions!((expected_u, expected_v, expected_w))

    u_error = zero(FT)
    v_error = zero(FT)
    w_error = zero(FT)

    for k in 1:grid.Nz, j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        u_error = max(u_error, abs(model.velocities.u[i, j, k] - expected_u[i, j, k]))
        v_error = max(v_error, abs(model.velocities.v[i, j, k] - expected_v[i, j, k]))
    end

    for k in 1:(grid.Nz + 1), j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        w_error = max(w_error, abs(model.velocities.w[i, j, k] - expected_w[i, j, k]))
    end

    @test u_error == zero(FT)
    @test v_error == zero(FT)
    @test w_error == zero(FT)

    momentum = model.advection.momentum
    U = (u = model.velocities.u, v = model.velocities.v, w = model.velocities.w)

    compute_momentum_tendencies!(model, ())

    sampled_points = ((N + 2, N + 2, 1),
                      (N + 1, N + 1, 2),
                      (2N - 1, N + 1, 1),
                      (N + 1, 2N - 1, 2))

    for (i, j, k) in sampled_points
        expected_Gu = -U_dot_∇u(i, j, k, grid, momentum, U)
        expected_Gv = -U_dot_∇v(i, j, k, grid, momentum, U)
        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        magnitude_scale = max(abs(expected_Gu), abs(expected_Gv), one(FT))

        @test abs(expected_Gu) > 100eps(FT)
        @test abs(expected_Gv) > 100eps(FT)
        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * magnitude_scale
        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * magnitude_scale
    end

    return nothing
end

