    set!(v_fts, (λ, φ, z, t) -> cosd(λ) - convert(FT, 3) * sind(φ) + convert(FT, 2) * t + convert(FT, 0.2) * z)
    set!(w_fts, (λ, φ, z, t) -> convert(FT, 0.25) * (one(FT) + z) * (sind(λ / 2) + cosd(φ)) + t)

    source_clock = Oceananigans.Clock(time = zero(FT))

    velocities = PrescribedVelocityFields(u = Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, source_grid; clock = source_clock) + zero(FT),
                                          v = Oceananigans.OutputReaders.TimeSeriesInterpolation(v_fts, source_grid; clock = source_clock) - zero(FT),
                                          w = Oceananigans.OutputReaders.TimeSeriesInterpolation(w_fts, source_grid; clock = source_clock) + zero(FT))

    model = HydrostaticFreeSurfaceModel(destination_grid;
                                        velocities,
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant(),
                                        tracer_advection = nothing)

    time_step!(model, half)

    source_u_half = u_fts[Oceananigans.Units.Time(half)]
    source_v_half = v_fts[Oceananigans.Units.Time(half)]
    source_w_half = w_fts[Oceananigans.Units.Time(half)]

    expected_u = XFaceField(destination_grid; boundary_conditions = source_u_half.boundary_conditions)
    expected_v = YFaceField(destination_grid; boundary_conditions = source_v_half.boundary_conditions)
    expected_w = ZFaceField(destination_grid; boundary_conditions = source_w_half.boundary_conditions)

    Oceananigans.Fields.set_paired_quadfolded_vector_fields!(expected_u, expected_v, source_u_half, source_v_half)
    set!(expected_w, source_w_half)
    fill_halo_regions!((expected_u, expected_v, expected_w))

    u_error = zero(FT)
    v_error = zero(FT)
    w_error = zero(FT)

    for k in 1:destination_grid.Nz, j in 0:(destination_grid.Ny + 1), i in 0:(destination_grid.Nx + 1)
        u_error = max(u_error, abs(model.velocities.u[i, j, k] - expected_u[i, j, k]))
        v_error = max(v_error, abs(model.velocities.v[i, j, k] - expected_v[i, j, k]))
    end

    for k in 1:(destination_grid.Nz + 1), j in 0:(destination_grid.Ny + 1), i in 0:(destination_grid.Nx + 1)
        w_error = max(w_error, abs(model.velocities.w[i, j, k] - expected_w[i, j, k]))
    end

    @test u_error == zero(FT)
    @test v_error == zero(FT)
    @test w_error == zero(FT)

    momentum = model.advection.momentum
    U = (u = model.velocities.u, v = model.velocities.v, w = model.velocities.w)

    compute_momentum_tendencies!(model, ())

    sampled_points = ((N + 2, N + 2, 1),
                      (N + 1, N + 1, 2),
                      (2N - 1, N + 1, 1),
                      (N + 1, 2N - 1, 2))

    for (i, j, k) in sampled_points
        expected_Gu = -U_dot_∇u(i, j, k, destination_grid, momentum, U)
        expected_Gv = -U_dot_∇v(i, j, k, destination_grid, momentum, U)
        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        magnitude_scale = max(abs(expected_Gu), abs(expected_Gv), one(FT))

        @test abs(expected_Gu) > 100eps(FT)
        @test abs(expected_Gv) > 100eps(FT)
        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * magnitude_scale
        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * magnitude_scale
    end

    return nothing
end

function test_octahealpix_adapted_prescribed_velocity_fields_preserve_parameters(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    parameters = (; α = convert(FT, 2), β = convert(FT, 3))
    velocities = PrescribedVelocityFields(u = (λ, φ, z, t, p) -> p.α * sind(λ) + cosd(φ),
                                          v = (λ, φ, z, t, p) -> cosd(λ) - p.β * sind(φ),
                                          parameters = parameters)

    adapted_velocities = Adapt.adapt_structure(Val(:noop), velocities)

    @test adapted_velocities.parameters == parameters

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities = adapted_velocities,
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model, c = (λ, φ, z) -> sind(λ / 2) * cosd(φ))

    compute_transport_velocities!(model, model.free_surface)
    compute_tracer_tendencies!(model)

    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    for (i, j) in sampled_points
        expected_Gc = -div_Uc(i, j, 1, grid, model.advection.c, model.transport_velocities, model.tracers.c)
        computed_Gc = model.timestepper.Gⁿ.c[i, j, 1]
        tendency_scale = max(abs(expected_Gc), one(FT))
        @test abs(expected_Gc) > 100eps(FT)
        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale
    end

    return nothing
end

function test_octahealpix_prescribed_field_time_series_transport_boundary_condition_sign_propagation(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))
    connectivity = grid.connectivity
    halo_sign = -one(FT)

    qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(halo_sign)
    u_bcs = FieldBoundaryConditions(grid, (Face(), Center(), Center());
                                    south = qcov,
                                    north = qcov)
    v_bcs = FieldBoundaryConditions(grid, (Center(), Face(), Center());
                                    west = qcov,
                                    east = qcov)

    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times;
                                                               boundary_conditions = u_bcs)
    v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times;
                                                               boundary_conditions = v_bcs)

    set!(u_fts, (λ, φ, z, t) -> sind(λ) + t)
    set!(v_fts, (λ, φ, z, t) -> cosd(φ) + convert(FT, 2) * t)

    velocities = PrescribedVelocityFields(u = u_fts, v = v_fts)

    inferred_transport_velocities =
        Oceananigans.Models.HydrostaticFreeSurfaceModels.transport_velocity_fields(velocities)

    @test inferred_transport_velocities.u.boundary_conditions.south isa Oceananigans.BoundaryConditions.QConZBC
    @test inferred_transport_velocities.u.boundary_conditions.north isa Oceananigans.BoundaryConditions.QConZBC
    @test inferred_transport_velocities.v.boundary_conditions.west isa Oceananigans.BoundaryConditions.QConZBC
    @test inferred_transport_velocities.v.boundary_conditions.east isa Oceananigans.BoundaryConditions.QConZBC
    @test inferred_transport_velocities.u.boundary_conditions.south.condition == halo_sign
    @test inferred_transport_velocities.u.boundary_conditions.north.condition == halo_sign
    @test inferred_transport_velocities.v.boundary_conditions.west.condition == halo_sign
    @test inferred_transport_velocities.v.boundary_conditions.east.condition == halo_sign

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities,
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    @test model.transport_velocities.u.boundary_conditions.south isa Oceananigans.BoundaryConditions.QConZBC
    @test model.transport_velocities.u.boundary_conditions.north isa Oceananigans.BoundaryConditions.QConZBC
    @test model.transport_velocities.v.boundary_conditions.west isa Oceananigans.BoundaryConditions.QConZBC
    @test model.transport_velocities.v.boundary_conditions.east isa Oceananigans.BoundaryConditions.QConZBC
    @test model.transport_velocities.u.boundary_conditions.south.condition == halo_sign
    @test model.transport_velocities.u.boundary_conditions.north.condition == halo_sign
    @test model.transport_velocities.v.boundary_conditions.west.condition == halo_sign
    @test model.transport_velocities.v.boundary_conditions.east.condition == halo_sign

    time_step!(model, half)
    compute_transport_velocities!(model, model.free_surface)

    transport_u_halo_max_error = zero(FT)
    transport_v_halo_max_error = zero(FT)

    for j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue

        source_field, source_i, source_j, sign =
            octahealpix_transport_face_halo_source(i, j, connectivity, grid.Nx, grid.Ny, N, :u)
        expected_u = source_field === :u ? halo_sign * sign * model.transport_velocities.u[source_i, source_j, 1] :
                                           halo_sign * sign * model.transport_velocities.v[source_i, source_j, 1]
        transport_u_halo_max_error = max(transport_u_halo_max_error,
                                         abs(model.transport_velocities.u[i, j, 1] - expected_u))

        source_field, source_i, source_j, sign =
            octahealpix_transport_face_halo_source(i, j, connectivity, grid.Nx, grid.Ny, N, :v)
        expected_v = source_field === :u ? halo_sign * sign * model.transport_velocities.u[source_i, source_j, 1] :
                                           halo_sign * sign * model.transport_velocities.v[source_i, source_j, 1]
        transport_v_halo_max_error = max(transport_v_halo_max_error,
                                         abs(model.transport_velocities.v[i, j, 1] - expected_v))
    end

    @test transport_u_halo_max_error == zero(FT)
    @test transport_v_halo_max_error == zero(FT)

    return nothing
end

function test_octahealpix_prescribed_time_series_interpolation_velocity_materialization(FT, N)
    radius = convert(FT, 3)
    source_mapping = OctaHEALPixMapping(div(N, 2))
    source_grid = SphericalShellGrid(CPU(), FT; mapping = source_mapping,
                                     z = (zero(FT), one(FT)),
                                     radius,
                                     halo = (1, 1, 1))

    destination_mapping = OctaHEALPixMapping(N)
    destination_grid = SphericalShellGrid(CPU(), FT; mapping = destination_mapping,
                                          z = (zero(FT), one(FT)),
                                          radius,
                                          halo = (1, 1, 1))

    qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(one(FT))
    source_u_bcs = FieldBoundaryConditions(source_grid, (Face(), Center(), Center());
                                           south = qcov,
                                           north = qcov)
    source_v_bcs = FieldBoundaryConditions(source_grid, (Center(), Face(), Center());
                                           west = qcov,
                                           east = qcov)

    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    source_u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(source_grid, times;
                                                                      boundary_conditions = source_u_bcs)
    source_v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(source_grid, times;
                                                                      boundary_conditions = source_v_bcs)

    set!(source_u_fts, (λ, φ, z, t) -> convert(FT, 2) * sind(λ) + cosd(φ) + t)
    set!(source_v_fts, (λ, φ, z, t) -> cosd(λ) - convert(FT, 3) * sind(φ) + convert(FT, 2) * t)

    source_clock = Oceananigans.Clock(time = zero(FT))
    source_u = Oceananigans.OutputReaders.TimeSeriesInterpolation(source_u_fts, source_grid; clock = source_clock)
    source_v = Oceananigans.OutputReaders.TimeSeriesInterpolation(source_v_fts, source_grid; clock = source_clock)
    velocities = PrescribedVelocityFields(u = source_u, v = source_v)

    model = HydrostaticFreeSurfaceModel(destination_grid;
                                        velocities,
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    @test model.velocities.u isa Oceananigans.OutputReaders.TimeSeriesInterpolation
    @test model.velocities.v isa Oceananigans.OutputReaders.TimeSeriesInterpolation
    @test model.velocities.u.grid === destination_grid
    @test model.velocities.v.grid === destination_grid

    time_step!(model, half)

    expected_u = XFaceField(destination_grid; boundary_conditions = source_u_fts.boundary_conditions)
    expected_v = YFaceField(destination_grid; boundary_conditions = source_v_fts.boundary_conditions)
    source_u_half = source_u_fts[Oceananigans.Units.Time(half)]
    source_v_half = source_v_fts[Oceananigans.Units.Time(half)]

    Oceananigans.Fields.set_paired_quadfolded_vector_fields!(expected_u, expected_v, source_u_half, source_v_half)
    fill_halo_regions!((expected_u, expected_v))

    u_interior_error = zero(FT)
    v_interior_error = zero(FT)
    u_halo_error = zero(FT)
    v_halo_error = zero(FT)

    for j in 1:destination_grid.Ny, i in 1:destination_grid.Nx
        u_interior_error = max(u_interior_error, abs(model.velocities.u[i, j, 1] - expected_u[i, j, 1]))
        v_interior_error = max(v_interior_error, abs(model.velocities.v[i, j, 1] - expected_v[i, j, 1]))
    end

    for j in 0:(destination_grid.Ny + 1), i in 0:(destination_grid.Nx + 1)
        (1 <= i <= destination_grid.Nx && 1 <= j <= destination_grid.Ny) && continue
        u_halo_error = max(u_halo_error, abs(model.velocities.u[i, j, 1] - expected_u[i, j, 1]))
        v_halo_error = max(v_halo_error, abs(model.velocities.v[i, j, 1] - expected_v[i, j, 1]))
    end

    @test u_interior_error == zero(FT)
    @test v_interior_error == zero(FT)
    @test u_halo_error == zero(FT)
    @test v_halo_error == zero(FT)

    return nothing
end

function test_octahealpix_cross_grid_static_mixed_prescribed_operation_velocity_materialization(FT, N)
    radius = convert(FT, 3)
    source_mapping = OctaHEALPixMapping(div(N, 2))
    source_grid = SphericalShellGrid(CPU(), FT;
                                     size = (N, N, 2),
                                     mapping = source_mapping,
                                     z = (zero(FT), one(FT)),
                                     radius,
                                     halo = (1, 1, 1))

    destination_mapping = OctaHEALPixMapping(N)
    destination_grid = SphericalShellGrid(CPU(), FT;
                                          size = (2N, 2N, 2),
                                          mapping = destination_mapping,
                                          z = (zero(FT), one(FT)),
                                          radius,
                                          halo = (1, 1, 1))

    qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(one(FT))
    u_bcs = FieldBoundaryConditions(source_grid, (Face(), Center(), Center());
                                    south = qcov,
                                    north = qcov)
    v_bcs = FieldBoundaryConditions(source_grid, (Center(), Face(), Center());
                                    west = qcov,
                                    east = qcov)

    source_u = XFaceField(source_grid; boundary_conditions = u_bcs)
    source_v = YFaceField(source_grid; boundary_conditions = v_bcs)
    source_w = ZFaceField(source_grid)

    set!(source_u, (λ, φ, z) -> convert(FT, 2) * sind(λ) + cosd(φ) + convert(FT, 0.1) * z)
    set!(source_v, (λ, φ, z) -> cosd(λ) - convert(FT, 3) * sind(φ) + convert(FT, 0.2) * z)
    set!(source_w, (λ, φ, z) -> convert(FT, 0.25) * (one(FT) + z) * (sind(λ / 2) + cosd(φ)))
    fill_halo_regions!((source_u, source_v, source_w))

    velocities = PrescribedVelocityFields(u = source_u + zero(FT),
                                          v = source_v,
                                          w = source_w + zero(FT))

    model = HydrostaticFreeSurfaceModel(destination_grid;
                                        velocities,
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant(),
                                        tracer_advection = nothing)

    expected_u = XFaceField(destination_grid; boundary_conditions = source_u.boundary_conditions)
    expected_v = YFaceField(destination_grid; boundary_conditions = source_v.boundary_conditions)
    expected_w = ZFaceField(destination_grid; boundary_conditions = source_w.boundary_conditions)

    Oceananigans.Fields.set_paired_quadfolded_vector_fields!(expected_u, expected_v, source_u, source_v)
    set!(expected_w, source_w)
    fill_halo_regions!((expected_u, expected_v, expected_w))

    u_error = zero(FT)
    v_error = zero(FT)
    w_error = zero(FT)

    for k in 1:destination_grid.Nz, j in 0:(destination_grid.Ny + 1), i in 0:(destination_grid.Nx + 1)
        u_error = max(u_error, abs(model.velocities.u[i, j, k] - expected_u[i, j, k]))
        v_error = max(v_error, abs(model.velocities.v[i, j, k] - expected_v[i, j, k]))
    end

    for k in 1:(destination_grid.Nz + 1), j in 0:(destination_grid.Ny + 1), i in 0:(destination_grid.Nx + 1)
        w_error = max(w_error, abs(model.velocities.w[i, j, k] - expected_w[i, j, k]))
    end

    @test u_error == zero(FT)
    @test v_error == zero(FT)
    @test w_error == zero(FT)

    momentum = model.advection.momentum
    U = (u = model.velocities.u, v = model.velocities.v, w = model.velocities.w)

    compute_momentum_tendencies!(model, ())

    sampled_points = ((N + 2, N + 2, 1),
                      (N + 1, N + 1, 2),
                      (2N - 1, N + 1, 1),
                      (N + 1, 2N - 1, 2))

    for (i, j, k) in sampled_points
        expected_Gu = -U_dot_∇u(i, j, k, destination_grid, momentum, U)
        expected_Gv = -U_dot_∇v(i, j, k, destination_grid, momentum, U)
        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        magnitude_scale = max(abs(expected_Gu), abs(expected_Gv), one(FT))

        @test abs(expected_Gu) > 100eps(FT)
        @test abs(expected_Gv) > 100eps(FT)
        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * magnitude_scale
        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * magnitude_scale
    end

    return nothing
end

