                                          mapping = destination_mapping,
                                          z = (zero(FT), one(FT)),
                                          radius,
                                          halo = (1, 1, 1))

    qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(one(FT))
    u_bcs = FieldBoundaryConditions(source_grid, (Face(), Center(), Center());
                                    south = qcov,
                                    north = qcov)
    v_bcs = FieldBoundaryConditions(source_grid, (Center(), Face(), Center());
                                    west = qcov,
                                    east = qcov)

    source_u = XFaceField(source_grid; boundary_conditions = u_bcs)
    source_v = YFaceField(source_grid; boundary_conditions = v_bcs)
    source_w = ZFaceField(source_grid)

    set!(source_u, (λ, φ, z) -> convert(FT, 2) * sind(λ) + cosd(φ) + convert(FT, 0.1) * z)
    set!(source_v, (λ, φ, z) -> cosd(λ) - convert(FT, 3) * sind(φ) + convert(FT, 0.2) * z)
    set!(source_w, (λ, φ, z) -> convert(FT, 0.25) * (one(FT) + z) * (sind(λ / 2) + cosd(φ)))
    fill_halo_regions!((source_u, source_v, source_w))

    velocities = PrescribedVelocityFields(u = source_u,
                                          v = source_v - zero(FT),
                                          w = source_w + zero(FT))

    model = HydrostaticFreeSurfaceModel(destination_grid;
                                        velocities,
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant(),
                                        tracer_advection = nothing)

    expected_u = XFaceField(destination_grid; boundary_conditions = source_u.boundary_conditions)
    expected_v = YFaceField(destination_grid; boundary_conditions = source_v.boundary_conditions)
    expected_w = ZFaceField(destination_grid; boundary_conditions = source_w.boundary_conditions)

    Oceananigans.Fields.set_paired_quadfolded_vector_fields!(expected_u, expected_v, source_u, source_v)
    set!(expected_w, source_w)
    fill_halo_regions!((expected_u, expected_v, expected_w))

    u_error = zero(FT)
    v_error = zero(FT)
    w_error = zero(FT)

    for k in 1:destination_grid.Nz, j in 0:(destination_grid.Ny + 1), i in 0:(destination_grid.Nx + 1)
        u_error = max(u_error, abs(model.velocities.u[i, j, k] - expected_u[i, j, k]))
        v_error = max(v_error, abs(model.velocities.v[i, j, k] - expected_v[i, j, k]))
    end

    for k in 1:(destination_grid.Nz + 1), j in 0:(destination_grid.Ny + 1), i in 0:(destination_grid.Nx + 1)
        w_error = max(w_error, abs(model.velocities.w[i, j, k] - expected_w[i, j, k]))
    end

    @test u_error == zero(FT)
    @test v_error == zero(FT)
    @test w_error == zero(FT)

    momentum = model.advection.momentum
    U = (u = model.velocities.u, v = model.velocities.v, w = model.velocities.w)

    compute_momentum_tendencies!(model, ())

    sampled_points = ((N + 2, N + 2, 1),
                      (N + 1, N + 1, 2),
                      (2N - 1, N + 1, 1),
                      (N + 1, 2N - 1, 2))

    for (i, j, k) in sampled_points
        expected_Gu = -U_dot_∇u(i, j, k, destination_grid, momentum, U)
        expected_Gv = -U_dot_∇v(i, j, k, destination_grid, momentum, U)
        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        magnitude_scale = max(abs(expected_Gu), abs(expected_Gv), one(FT))

        @test abs(expected_Gu) > 100eps(FT)
        @test abs(expected_Gv) > 100eps(FT)
        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * magnitude_scale
        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * magnitude_scale
    end

    return nothing
end

function test_octahealpix_cross_grid_dynamic_mixed_prescribed_v_operation_velocity_materialization(FT, N)
    radius = convert(FT, 3)
    source_mapping = OctaHEALPixMapping(div(N, 2))
    source_grid = SphericalShellGrid(CPU(), FT;
                                     size = (N, N, 2),
                                     mapping = source_mapping,
                                     z = (zero(FT), one(FT)),
                                     radius,
                                     halo = (1, 1, 1))

    destination_mapping = OctaHEALPixMapping(N)
    destination_grid = SphericalShellGrid(CPU(), FT;
                                          size = (2N, 2N, 2),
                                          mapping = destination_mapping,
                                          z = (zero(FT), one(FT)),
                                          radius,
                                          halo = (1, 1, 1))

    qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(one(FT))
    u_bcs = FieldBoundaryConditions(source_grid, (Face(), Center(), Center());
                                    south = qcov,
                                    north = qcov)
    v_bcs = FieldBoundaryConditions(source_grid, (Center(), Face(), Center());
                                    west = qcov,
                                    east = qcov)

    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    source_u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(source_grid, times;
                                                                      boundary_conditions = u_bcs)
    source_v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(source_grid, times;
                                                                      boundary_conditions = v_bcs)
    source_w_fts = Oceananigans.FieldTimeSeries{Center, Center, Face}(source_grid, times)

    set!(source_u_fts, (λ, φ, z, t) -> convert(FT, 2) * sind(λ) + cosd(φ) + t + convert(FT, 0.1) * z)
    set!(source_v_fts, (λ, φ, z, t) -> cosd(λ) - convert(FT, 3) * sind(φ) + convert(FT, 2) * t + convert(FT, 0.2) * z)
    set!(source_w_fts, (λ, φ, z, t) -> convert(FT, 0.25) * (one(FT) + z) * (sind(λ / 2) + cosd(φ)) + t)

    source_clock = Oceananigans.Clock(time = zero(FT))
    source_u = Oceananigans.OutputReaders.TimeSeriesInterpolation(source_u_fts, source_grid; clock = source_clock)

    velocities = PrescribedVelocityFields(u = source_u,
                                          v = Oceananigans.OutputReaders.TimeSeriesInterpolation(source_v_fts, source_grid; clock = source_clock) - zero(FT),
                                          w = Oceananigans.OutputReaders.TimeSeriesInterpolation(source_w_fts, source_grid; clock = source_clock) + zero(FT))

    model = HydrostaticFreeSurfaceModel(destination_grid;
                                        velocities,
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    @test model.velocities.u isa Oceananigans.OutputReaders.TimeSeriesInterpolation
    @test model.velocities.v isa Oceananigans.OutputReaders.TimeSeriesInterpolation
    @test model.velocities.u.grid === destination_grid
    @test model.velocities.v.grid === destination_grid

    time_step!(model, half)

    expected_u = XFaceField(destination_grid; boundary_conditions = source_u_fts.boundary_conditions)
    expected_v = YFaceField(destination_grid; boundary_conditions = source_v_fts.boundary_conditions)
    source_u_half = source_u_fts[Oceananigans.Units.Time(half)]
    source_v_half = source_v_fts[Oceananigans.Units.Time(half)]

    Oceananigans.Fields.set_paired_quadfolded_vector_fields!(expected_u, expected_v, source_u_half, source_v_half)
    fill_halo_regions!((expected_u, expected_v))

    u_interior_error = zero(FT)
    v_interior_error = zero(FT)
    u_halo_error = zero(FT)
    v_halo_error = zero(FT)

    for j in 1:destination_grid.Ny, i in 1:destination_grid.Nx
        u_interior_error = max(u_interior_error, abs(model.velocities.u[i, j, 1] - expected_u[i, j, 1]))
        v_interior_error = max(v_interior_error, abs(model.velocities.v[i, j, 1] - expected_v[i, j, 1]))
    end

    for j in 0:(destination_grid.Ny + 1), i in 0:(destination_grid.Nx + 1)
        (1 <= i <= destination_grid.Nx && 1 <= j <= destination_grid.Ny) && continue
        u_halo_error = max(u_halo_error, abs(model.velocities.u[i, j, 1] - expected_u[i, j, 1]))
        v_halo_error = max(v_halo_error, abs(model.velocities.v[i, j, 1] - expected_v[i, j, 1]))
    end

    @test u_interior_error == zero(FT)
    @test v_interior_error == zero(FT)
    @test u_halo_error == zero(FT)
    @test v_halo_error == zero(FT)

    return nothing
end

