function test_octahealpix_prescribed_time_series_interpolation_transport_boundary_condition_sign_propagation(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))
    connectivity = grid.connectivity
    halo_sign = -one(FT)

    qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(halo_sign)
    u_bcs = FieldBoundaryConditions(grid, (Face(), Center(), Center());
                                    south = qcov,
                                    north = qcov)
    v_bcs = FieldBoundaryConditions(grid, (Center(), Face(), Center());
                                    west = qcov,
                                    east = qcov)

    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times;
                                                               boundary_conditions = u_bcs)
    v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times;
                                                               boundary_conditions = v_bcs)

    set!(u_fts, (λ, φ, z, t) -> sind(λ) + t)
    set!(v_fts, (λ, φ, z, t) -> cosd(φ) + convert(FT, 2) * t)

    source_clock = Oceananigans.Clock(time = zero(FT))
    u = Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, grid; clock = source_clock)
    v = Oceananigans.OutputReaders.TimeSeriesInterpolation(v_fts, grid; clock = source_clock)
    velocities = PrescribedVelocityFields(u = u, v = v)

    inferred_transport_velocities =
        Oceananigans.Models.HydrostaticFreeSurfaceModels.transport_velocity_fields(velocities)

    @test inferred_transport_velocities.u.boundary_conditions.south isa Oceananigans.BoundaryConditions.QConZBC
    @test inferred_transport_velocities.u.boundary_conditions.north isa Oceananigans.BoundaryConditions.QConZBC
    @test inferred_transport_velocities.v.boundary_conditions.west isa Oceananigans.BoundaryConditions.QConZBC
    @test inferred_transport_velocities.v.boundary_conditions.east isa Oceananigans.BoundaryConditions.QConZBC
    @test inferred_transport_velocities.u.boundary_conditions.south.condition == halo_sign
    @test inferred_transport_velocities.u.boundary_conditions.north.condition == halo_sign
    @test inferred_transport_velocities.v.boundary_conditions.west.condition == halo_sign
    @test inferred_transport_velocities.v.boundary_conditions.east.condition == halo_sign

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities,
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    @test model.transport_velocities.u.boundary_conditions.south isa Oceananigans.BoundaryConditions.QConZBC
    @test model.transport_velocities.u.boundary_conditions.north isa Oceananigans.BoundaryConditions.QConZBC
    @test model.transport_velocities.v.boundary_conditions.west isa Oceananigans.BoundaryConditions.QConZBC
    @test model.transport_velocities.v.boundary_conditions.east isa Oceananigans.BoundaryConditions.QConZBC
    @test model.transport_velocities.u.boundary_conditions.south.condition == halo_sign
    @test model.transport_velocities.u.boundary_conditions.north.condition == halo_sign
    @test model.transport_velocities.v.boundary_conditions.west.condition == halo_sign
    @test model.transport_velocities.v.boundary_conditions.east.condition == halo_sign

    time_step!(model, half)
    compute_transport_velocities!(model, model.free_surface)

    transport_u_halo_max_error = zero(FT)
    transport_v_halo_max_error = zero(FT)

    for j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue

        source_field, source_i, source_j, sign =
            octahealpix_transport_face_halo_source(i, j, connectivity, grid.Nx, grid.Ny, N, :u)
        expected_u = source_field === :u ? halo_sign * sign * model.transport_velocities.u[source_i, source_j, 1] :
                                           halo_sign * sign * model.transport_velocities.v[source_i, source_j, 1]
        transport_u_halo_max_error = max(transport_u_halo_max_error,
                                         abs(model.transport_velocities.u[i, j, 1] - expected_u))

        source_field, source_i, source_j, sign =
            octahealpix_transport_face_halo_source(i, j, connectivity, grid.Nx, grid.Ny, N, :v)
        expected_v = source_field === :u ? halo_sign * sign * model.transport_velocities.u[source_i, source_j, 1] :
                                           halo_sign * sign * model.transport_velocities.v[source_i, source_j, 1]
        transport_v_halo_max_error = max(transport_v_halo_max_error,
                                         abs(model.transport_velocities.v[i, j, 1] - expected_v))
    end

    @test transport_u_halo_max_error == zero(FT)
    @test transport_v_halo_max_error == zero(FT)

    return nothing
end

function test_octahealpix_prescribed_time_series_interpolation_transport_state_drives_tracer_tendency(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))
    connectivity = grid.connectivity
    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times)
    v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times)

    set!(u_fts, (λ, φ, z, t) -> t)
    set!(v_fts, (λ, φ, z, t) -> convert(FT, 2) * t)

    source_clock = Oceananigans.Clock(time = zero(FT))
    u = Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, grid; clock = source_clock)
    v = Oceananigans.OutputReaders.TimeSeriesInterpolation(v_fts, grid; clock = source_clock)
    velocities = PrescribedVelocityFields(u = u, v = v)

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities,
                                        tracers = :c,
                                        buoyancy = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    time_step!(model, half)

    @test model.velocities.u[1, 1, 1] ≈ half
    @test model.velocities.v[1, 1, 1] ≈ convert(FT, 2) * half

    set!(model, c = (λ, φ, z) -> sind(λ / 2) * cosd(φ))

    compute_transport_velocities!(model, model.free_surface)

    source_field, source_i, source_j, sign =
        octahealpix_transport_face_halo_source(0, N + 1, connectivity, grid.Nx, grid.Ny, N, :u)
    expected_u_halo = source_field === :u ? sign * model.transport_velocities.u[source_i, source_j, 1] :
                                            sign * model.transport_velocities.v[source_i, source_j, 1]

    source_field, source_i, source_j, sign =
        octahealpix_transport_face_halo_source(N + 1, 0, connectivity, grid.Nx, grid.Ny, N, :v)
    expected_v_halo = source_field === :u ? sign * model.transport_velocities.u[source_i, source_j, 1] :
                                            sign * model.transport_velocities.v[source_i, source_j, 1]

    @test model.transport_velocities.u[0, N + 1, 1] == expected_u_halo
    @test model.transport_velocities.v[N + 1, 0, 1] == expected_v_halo

    compute_tracer_tendencies!(model)

    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    for (i, j) in sampled_points
        expected_Gc = -div_Uc(i, j, 1, grid, model.advection.c, model.transport_velocities, model.tracers.c)
        computed_Gc = model.timestepper.Gⁿ.c[i, j, 1]
        tendency_scale = max(abs(expected_Gc), one(FT))
        @test abs(expected_Gc) > 100eps(FT)
        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale
    end

    forward = Array(interior(model.timestepper.Gⁿ.c))

    set!(model.transport_velocities.u, -model.transport_velocities.u)
    set!(model.transport_velocities.v, -model.transport_velocities.v)
    fill_halo_regions!(model.transport_velocities)
    compute_tracer_tendencies!(model)
    reverse = Array(interior(model.timestepper.Gⁿ.c))

    tolerance = 200 * eps(FT) * max(one(FT), max(maximum(abs, forward), maximum(abs, reverse)))

    @test forward ≈ -reverse atol = tolerance
    @test !any(isnan, forward)
    @test !any(isnan, reverse)

    return nothing
end

function test_octahealpix_prescribed_time_series_interpolation_momentum_tendencies(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))
    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times)
    v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times)

    set!(u_fts, (λ, φ, z, t) -> sind(λ) * cosd(φ) + t)
    set!(v_fts, (λ, φ, z, t) -> cosd(λ) * sind(φ) - t)

    source_clock = Oceananigans.Clock(time = zero(FT))
    u = Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, grid; clock = source_clock)
    v = Oceananigans.OutputReaders.TimeSeriesInterpolation(v_fts, grid; clock = source_clock)
    velocities = PrescribedVelocityFields(u = u, v = v)

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities,
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant())

    time_step!(model, half)

    momentum = model.advection.momentum
    U = (u = model.velocities.u, v = model.velocities.v, w = model.velocities.w)
    k = 1

    compute_momentum_tendencies!(model, ())
    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    for (i, j) in sampled_points
        expected_Gu = -U_dot_∇u(i, j, k, grid, momentum, U)
        expected_Gv = -U_dot_∇v(i, j, k, grid, momentum, U)
        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        magnitude_scale = max(abs(expected_Gu), abs(expected_Gv), one(FT))

        @test abs(expected_Gu) > 100eps(FT)
        @test abs(expected_Gv) > 100eps(FT)
        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * magnitude_scale
        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * magnitude_scale
    end

    @test !any(isnan, Array(interior(model.timestepper.Gⁿ.u)))
    @test !any(isnan, Array(interior(model.timestepper.Gⁿ.v)))

    return nothing
end

function test_octahealpix_prescribed_time_series_interpolation_cell_advection_timescale_refreshes_transport_state(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))
    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times)
    v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times)

    set!(u_fts, (λ, φ, z, t) -> t)
    set!(v_fts, (λ, φ, z, t) -> convert(FT, 2) * t)

    source_clock = Oceananigans.Clock(time = zero(FT))
    u = Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, grid; clock = source_clock)
    v = Oceananigans.OutputReaders.TimeSeriesInterpolation(v_fts, grid; clock = source_clock)
    velocities = PrescribedVelocityFields(u = u, v = v)

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities,
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    compute_transport_velocities!(model, model.free_surface)
    @test isinf(Oceananigans.Advection.cell_advection_timescale(model.grid, model.transport_velocities))

    model.clock.time = half

    stale_timescale = Oceananigans.Advection.cell_advection_timescale(model.grid, model.transport_velocities)
    computed_timescale = Oceananigans.Advection.cell_advection_timescale(model)
    refreshed_timescale = Oceananigans.Advection.cell_advection_timescale(model.grid, model.transport_velocities)

    @test model.velocities.u[1, 1, 1] ≈ half
    @test model.velocities.v[1, 1, 1] ≈ one(FT)

    transport_u_scale = zero(FT)
    transport_v_scale = zero(FT)
    transport_u_error = zero(FT)
    transport_v_error = zero(FT)

    for j in 1:grid.Ny, i in 1:grid.Nx
        expected_u = covariant_to_volume_flux_uᶠᶜᶜ(i, j, 1, grid, half, one(FT))
        expected_v = covariant_to_volume_flux_vᶜᶠᶜ(i, j, 1, grid, half, one(FT))

        computed_u = model.transport_velocities.u[i, j, 1]
        computed_v = model.transport_velocities.v[i, j, 1]

        transport_u_scale = max(transport_u_scale, abs(expected_u), abs(computed_u))
        transport_v_scale = max(transport_v_scale, abs(expected_v), abs(computed_v))
        transport_u_error = max(transport_u_error, abs(computed_u - expected_u))
        transport_v_error = max(transport_v_error, abs(computed_v - expected_v))
    end

    @test abs(computed_timescale - refreshed_timescale) ≤ 1000eps(FT) * max(one(FT), abs(computed_timescale), abs(refreshed_timescale))
    @test isinf(stale_timescale)
    @test isfinite(computed_timescale)
    @test transport_u_error ≤ 1000eps(FT) * max(one(FT), transport_u_scale)
    @test transport_v_error ≤ 1000eps(FT) * max(one(FT), transport_v_scale)

    return nothing
end

function test_octahealpix_prescribed_time_series_interpolation_compute_tracer_tendencies_refreshes_transport_state(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))
    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times)
    v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times)

    set!(u_fts, (λ, φ, z, t) -> t)
    set!(v_fts, (λ, φ, z, t) -> convert(FT, 2) * t)

    source_clock = Oceananigans.Clock(time = zero(FT))
    u = Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, grid; clock = source_clock)
    v = Oceananigans.OutputReaders.TimeSeriesInterpolation(v_fts, grid; clock = source_clock)
    velocities = PrescribedVelocityFields(u = u, v = v)

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities,
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model, c = (λ, φ, z) -> sind(λ / 2) * cosd(φ))
    compute_transport_velocities!(model, model.free_surface)

    stale_transport_u = deepcopy(model.transport_velocities.u)
    stale_transport_v = deepcopy(model.transport_velocities.v)
    model.clock.time = half

    compute_tracer_tendencies!(model)

    @test model.velocities.u[1, 1, 1] ≈ half
    @test model.velocities.v[1, 1, 1] ≈ one(FT)

    transport_u_scale = zero(FT)
    transport_v_scale = zero(FT)
    transport_u_error = zero(FT)
    transport_v_error = zero(FT)

    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    stale_halo_transport_u = deepcopy(model.transport_velocities.u)
    stale_halo_transport_v = deepcopy(model.transport_velocities.v)

    for k in 1:grid.Nz, j in (1 - grid.Hy):(grid.Ny + grid.Hy), i in (1 - grid.Hx):(grid.Nx + grid.Hx)
        (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue

        stale_halo_transport_u[i, j, k] = stale_transport_u[i, j, k]
        stale_halo_transport_v[i, j, k] = stale_transport_v[i, j, k]
    end

    stale_halo_transport = (u = stale_halo_transport_u,
                            v = stale_halo_transport_v,
                            w = model.transport_velocities.w)
    maximum_stale_difference = zero(FT)

    for j in 1:grid.Ny, i in 1:grid.Nx
        expected_u = covariant_to_volume_flux_uᶠᶜᶜ(i, j, 1, grid, half, one(FT))
        expected_v = covariant_to_volume_flux_vᶜᶠᶜ(i, j, 1, grid, half, one(FT))

        computed_u = model.transport_velocities.u[i, j, 1]
        computed_v = model.transport_velocities.v[i, j, 1]

        transport_u_scale = max(transport_u_scale, abs(expected_u), abs(computed_u))
        transport_v_scale = max(transport_v_scale, abs(expected_v), abs(computed_v))
        transport_u_error = max(transport_u_error, abs(computed_u - expected_u))
        transport_v_error = max(transport_v_error, abs(computed_v - expected_v))
    end

    for (i, j) in sampled_points
        expected_Gc = -div_Uc(i, j, 1, grid, model.advection.c, model.transport_velocities, model.tracers.c)
        stale_Gc = -div_Uc(i, j, 1, grid, model.advection.c, stale_halo_transport, model.tracers.c)
        computed_Gc = model.timestepper.Gⁿ.c[i, j, 1]
        tendency_scale = max(abs(expected_Gc), one(FT))
        @test abs(expected_Gc) > 100eps(FT)
        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale
        maximum_stale_difference = max(maximum_stale_difference, abs(expected_Gc - stale_Gc))
    end

    @test transport_u_error ≤ 1000eps(FT) * max(one(FT), transport_u_scale)
    @test transport_v_error ≤ 1000eps(FT) * max(one(FT), transport_v_scale)
    @test maximum_stale_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_prescribed_time_series_interpolation_compute_transport_velocities_refreshes_velocity_state(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))
    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times)
    v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times)

    set!(u_fts, (λ, φ, z, t) -> sind(λ) * cosd(φ) + t)
    set!(v_fts, (λ, φ, z, t) -> cosd(λ) * sind(φ) - t)

    source_clock = Oceananigans.Clock(time = zero(FT))
    u = Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, grid; clock = source_clock)
    v = Oceananigans.OutputReaders.TimeSeriesInterpolation(v_fts, grid; clock = source_clock)
    velocities = PrescribedVelocityFields(u = u, v = v)

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities,
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    fill_halo_regions!(model.velocities, model.clock, fields(model))
    compute_transport_velocities!(model, model.free_surface)

    stale_u = deepcopy(model.velocities.u)
    stale_v = deepcopy(model.velocities.v)
    model.clock.time = half

    compute_transport_velocities!(model, model.free_surface)

    expected_u = sind(grid.λᶠᶜᵃ[1, 1]) * cosd(grid.φᶠᶜᵃ[1, 1]) + half
    expected_v = cosd(grid.λᶜᶠᵃ[1, 1]) * sind(grid.φᶜᶠᵃ[1, 1]) - half

    @test model.velocities.u[1, 1, 1] ≈ expected_u
    @test model.velocities.v[1, 1, 1] ≈ expected_v

    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    transport_u_error = zero(FT)
    transport_v_error = zero(FT)
    transport_scale = zero(FT)
    stale_transport_difference = zero(FT)

    for (i, j) in sampled_points
        current_u = covariant_to_volume_flux_uᶠᶜᶜ(i, j, 1, grid, model.velocities.u, model.velocities.v)
        current_v = covariant_to_volume_flux_vᶜᶠᶜ(i, j, 1, grid, model.velocities.u, model.velocities.v)
        stale_u_transport = covariant_to_volume_flux_uᶠᶜᶜ(i, j, 1, grid, stale_u, stale_v)
        stale_v_transport = covariant_to_volume_flux_vᶜᶠᶜ(i, j, 1, grid, stale_u, stale_v)

        computed_u = model.transport_velocities.u[i, j, 1]
        computed_v = model.transport_velocities.v[i, j, 1]

        transport_scale = max(transport_scale,
                              abs(current_u), abs(current_v),
                              abs(computed_u), abs(computed_v))
        transport_u_error = max(transport_u_error, abs(computed_u - current_u))
        transport_v_error = max(transport_v_error, abs(computed_v - current_v))
        stale_transport_difference = max(stale_transport_difference,
                                         abs(computed_u - stale_u_transport),
                                         abs(computed_v - stale_v_transport))
    end

    @test transport_u_error ≤ 1000eps(FT) * max(one(FT), transport_scale)
    @test transport_v_error ≤ 1000eps(FT) * max(one(FT), transport_scale)
    @test stale_transport_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_prescribed_time_series_interpolation_compute_transport_velocities_refreshes_velocity_state(FT,
                                                                                                                    N,
                                                                                                                    free_surface::ImplicitFreeSurface)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))
    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times)
    v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times)

    set!(u_fts, (λ, φ, z, t) -> convert(FT, 0.17) * sind(λ) +
                                 convert(FT, 0.05) * cosd(φ) +
                                 convert(FT, 0.11) * t)
    set!(v_fts, (λ, φ, z, t) -> convert(FT, 0.12) * cosd(λ) -
                                 convert(FT, 0.04) * sind(φ) -
                                 convert(FT, 0.09) * t)

    function build_model()
        source_clock = Oceananigans.Clock(time = zero(FT))
        u = Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, grid; clock = source_clock)
        v = Oceananigans.OutputReaders.TimeSeriesInterpolation(v_fts, grid; clock = source_clock)
        velocities = PrescribedVelocityFields(u = u, v = v)

        model = HydrostaticFreeSurfaceModel(grid;
                                            velocities,
                                            tracers = nothing,
                                            buoyancy = nothing,
                                            free_surface = ImplicitFreeSurface(),
                                            momentum_advection = nothing,
                                            tracer_advection = nothing)

        return model
    end

    reference_model = build_model()
    reference_model.clock.time = half
    Oceananigans.Models.HydrostaticFreeSurfaceModels.refresh_prescribed_velocity_state!(reference_model,
                                                                                        reference_model.velocities)
    compute_transport_velocities!(reference_model, reference_model.free_surface)

    guarded_model = build_model()
    guarded_model.clock.time = half
    compute_transport_velocities!(guarded_model, guarded_model.free_surface)

    stale_model = build_model()
    stale_model.clock.time = half
    Oceananigans.Models.HydrostaticFreeSurfaceModels.convert_to_volume_flux_velocities!(stale_model.transport_velocities.u,
                                                                                        stale_model.transport_velocities.v,
                                                                                        grid,
                                                                                        stale_model.velocities.u,
                                                                                        stale_model.velocities.v)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.fill_horizontal_transport_velocity_halos!(stale_model.transport_velocities, grid)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.update_vertical_transport_velocities!(stale_model.transport_velocities, grid, stale_model)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.fill_vertical_transport_velocity_halos!(stale_model.transport_velocities, grid)

    velocity_scale = max(abs(reference_model.velocities.u[1, 1, 1]),
                         abs(reference_model.velocities.v[1, 1, 1]),
                         one(FT))

    @test abs(guarded_model.velocities.u[1, 1, 1] - reference_model.velocities.u[1, 1, 1]) ≤ 1000eps(FT) * velocity_scale
    @test abs(guarded_model.velocities.v[1, 1, 1] - reference_model.velocities.v[1, 1, 1]) ≤ 1000eps(FT) * velocity_scale

    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    transport_scale = zero(FT)
    maximum_guarded_error = zero(FT)
    maximum_stale_difference = zero(FT)

    for (i, j) in sampled_points
        reference_u = reference_model.transport_velocities.u[i, j, 1]
        reference_v = reference_model.transport_velocities.v[i, j, 1]
        guarded_u = guarded_model.transport_velocities.u[i, j, 1]
        guarded_v = guarded_model.transport_velocities.v[i, j, 1]
        stale_u = stale_model.transport_velocities.u[i, j, 1]
        stale_v = stale_model.transport_velocities.v[i, j, 1]

        transport_scale = max(transport_scale,
                              abs(reference_u), abs(reference_v),
                              abs(guarded_u), abs(guarded_v))
        maximum_guarded_error = max(maximum_guarded_error,
                                    abs(reference_u - guarded_u),
                                    abs(reference_v - guarded_v))
        maximum_stale_difference = max(maximum_stale_difference,
                                       abs(reference_u - stale_u),
                                       abs(reference_v - stale_v))
    end

    @test maximum_guarded_error ≤ 1000eps(FT) * max(one(FT), transport_scale)
    @test maximum_stale_difference > 100eps(FT) * max(one(FT), transport_scale)

    return nothing
end

function test_octahealpix_prescribed_time_series_interpolation_compute_transport_velocities_refreshes_velocity_state(FT,
                                                                                                                    N,
                                                                                                                    free_surface::SplitExplicitFreeSurface)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))
    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times)
    v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times)

    set!(u_fts, (λ, φ, z, t) -> convert(FT, 0.17) * sind(λ) +
                                 convert(FT, 0.05) * cosd(φ) +
                                 convert(FT, 0.11) * t)
    set!(v_fts, (λ, φ, z, t) -> convert(FT, 0.12) * cosd(λ) -
                                 convert(FT, 0.04) * sind(φ) -
                                 convert(FT, 0.09) * t)

    function build_model()
        source_clock = Oceananigans.Clock(time = zero(FT))
        u = Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, grid; clock = source_clock)
        v = Oceananigans.OutputReaders.TimeSeriesInterpolation(v_fts, grid; clock = source_clock)
        velocities = PrescribedVelocityFields(u = u, v = v)

        model = HydrostaticFreeSurfaceModel(grid;
                                            velocities,
                                            tracers = nothing,
                                            buoyancy = nothing,
                                            free_surface = SplitExplicitFreeSurface(substeps = 8),
                                            momentum_advection = nothing,
                                            tracer_advection = nothing)

        return model
    end

    reference_model = build_model()
    reference_model.clock.time = half
    Oceananigans.Models.HydrostaticFreeSurfaceModels.refresh_prescribed_velocity_state!(reference_model,
                                                                                        reference_model.velocities)
    compute_transport_velocities!(reference_model, reference_model.free_surface)

    guarded_model = build_model()
    guarded_model.clock.time = half
    compute_transport_velocities!(guarded_model, guarded_model.free_surface)

    stale_model = build_model()
    stale_model.clock.time = half

    split_explicit_free_surface = stale_model.free_surface
    stale_grid = stale_model.grid
    stale_u, stale_v, stale_w = stale_model.velocities
    stale_ũ, stale_ṽ, stale_w̃ = stale_model.transport_velocities
    stale_Ũ = split_explicit_free_surface.filtered_state.Ũ
    stale_Ṽ = split_explicit_free_surface.filtered_state.Ṽ
    stale_U̅ = split_explicit_free_surface.filtered_state.U̅
    stale_V̅ = split_explicit_free_surface.filtered_state.V̅

    Oceananigans.DistributedComputations.synchronize_communication!(split_explicit_free_surface)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.SplitExplicitFreeSurfaces.compute_barotropic_mode!(stale_U̅,
                                                                                                       stale_V̅,
                                                                                                       stale_grid,
                                                                                                       stale_u,
                                                                                                       stale_v)
    launch!(architecture(stale_grid), stale_grid, Oceananigans.Models.volume_kernel_parameters(stale_grid),
            Oceananigans.Models.HydrostaticFreeSurfaceModels.SplitExplicitFreeSurfaces._compute_split_explicit_transport_velocities!,
            stale_ũ, stale_ṽ, stale_grid, stale_Ũ, stale_Ṽ, stale_u, stale_v, stale_U̅, stale_V̅)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.convert_to_volume_flux_velocities!(stale_ũ, stale_ṽ, stale_grid, stale_ũ, stale_ṽ)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.fill_horizontal_transport_velocity_halos!(stale_model.transport_velocities, stale_grid)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.update_vertical_transport_velocities!(stale_model.transport_velocities, stale_grid, stale_model)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.fill_vertical_transport_velocity_halos!(stale_model.transport_velocities, stale_grid)

    velocity_scale = max(abs(reference_model.velocities.u[1, 1, 1]),
                         abs(reference_model.velocities.v[1, 1, 1]),
                         one(FT))

    @test abs(guarded_model.velocities.u[1, 1, 1] - reference_model.velocities.u[1, 1, 1]) ≤ 1000eps(FT) * velocity_scale
    @test abs(guarded_model.velocities.v[1, 1, 1] - reference_model.velocities.v[1, 1, 1]) ≤ 1000eps(FT) * velocity_scale

    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    transport_scale = zero(FT)
    maximum_guarded_error = zero(FT)
    maximum_stale_difference = zero(FT)

    for (i, j) in sampled_points
        reference_u = reference_model.transport_velocities.u[i, j, 1]
        reference_v = reference_model.transport_velocities.v[i, j, 1]
        guarded_u = guarded_model.transport_velocities.u[i, j, 1]
        guarded_v = guarded_model.transport_velocities.v[i, j, 1]
        stale_u_value = stale_model.transport_velocities.u[i, j, 1]
        stale_v_value = stale_model.transport_velocities.v[i, j, 1]

        transport_scale = max(transport_scale,
                              abs(reference_u), abs(reference_v),
                              abs(guarded_u), abs(guarded_v))
        maximum_guarded_error = max(maximum_guarded_error,
                                    abs(reference_u - guarded_u),
                                    abs(reference_v - guarded_v))
        maximum_stale_difference = max(maximum_stale_difference,
                                       abs(reference_u - stale_u_value),
                                       abs(reference_v - stale_v_value))
    end

    @test maximum_guarded_error ≤ 1000eps(FT) * max(one(FT), transport_scale)
    @test maximum_stale_difference > 100eps(FT) * max(one(FT), transport_scale)

    return nothing
end

