    stale_halo_u = deepcopy(model.velocities.u)
    stale_halo_v = deepcopy(model.velocities.v)

    for k in 1:grid.Nz, j in (1 - grid.Hy):(grid.Ny + grid.Hy), i in (1 - grid.Hx):(grid.Nx + grid.Hx)
        (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue

        stale_halo_u[i, j, k] = stale_u[i, j, k]
        stale_halo_v[i, j, k] = stale_v[i, j, k]
    end

    stale_halo_U = (u = stale_halo_u, v = stale_halo_v, w = model.velocities.w)
    maximum_stale_difference = zero(FT)

    for (i, j) in sampled_points
        expected_Gu = -U_dot_∇u(i, j, k, grid, momentum, U)
        expected_Gv = -U_dot_∇v(i, j, k, grid, momentum, U)

        stale_Gu = -U_dot_∇u(i, j, k, grid, momentum, stale_halo_U)
        stale_Gv = -U_dot_∇v(i, j, k, grid, momentum, stale_halo_U)

        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        magnitude_scale = max(abs(expected_Gu), abs(expected_Gv), one(FT))

        @test abs(expected_Gu) > 100eps(FT)
        @test abs(expected_Gv) > 100eps(FT)
        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * magnitude_scale
        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * magnitude_scale

        maximum_stale_difference = max(maximum_stale_difference,
                                       abs(expected_Gu - stale_Gu),
                                       abs(expected_Gv - stale_Gv))
    end

    @test maximum_stale_difference > 100eps(FT)
    @test !any(isnan, Array(interior(model.timestepper.Gⁿ.u)))
    @test !any(isnan, Array(interior(model.timestepper.Gⁿ.v)))

    return nothing
end

function test_octahealpix_prescribed_time_series_interpolation_model_step_closure_prognostics_refreshes_velocity_state(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))
    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)
    closure = Oceananigans.TurbulenceClosures.CATKEVerticalDiffusivity(FT)

    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times)
    v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times)

    set!(u_fts, (λ, φ, z, t) -> convert(FT, 0.17) * sind(λ) +
                                 convert(FT, 0.05) * cosd(φ) +
                                 convert(FT, 0.07) * z +
                                 convert(FT, 0.11) * t)
    set!(v_fts, (λ, φ, z, t) -> convert(FT, 0.12) * cosd(λ) -
                                 convert(FT, 0.04) * sind(φ) -
                                 convert(FT, 0.06) * z -
                                 convert(FT, 0.09) * t)

    function build_model()
        source_clock = Oceananigans.Clock(time = zero(FT))
        u = Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, grid; clock = source_clock)
        v = Oceananigans.OutputReaders.TimeSeriesInterpolation(v_fts, grid; clock = source_clock)
        velocities = PrescribedVelocityFields(u = u, v = v)

        model = HydrostaticFreeSurfaceModel(grid;
                                            velocities,
                                            tracers = (:b, :e),
                                            buoyancy = BuoyancyTracer(),
                                            free_surface = nothing,
                                            momentum_advection = nothing,
                                            tracer_advection = Centered(FT),
                                            closure = closure)

        set!(model,
             b = (λ, φ, z) -> convert(FT, 0.06) * sind(λ / 2) * cosd(φ) + convert(FT, 0.23) * z,
             e = (λ, φ, z) -> convert(FT, 2e-4) + convert(FT, 7e-5) * sind(λ) * cosd(φ) + convert(FT, 3e-5) * z)

        Oceananigans.TurbulenceClosures.initialize_closure_fields!(model.closure_fields, model.closure, model)
        model.clock.iteration = 3

        return model
    end

    reference_model = build_model()
    reference_model.clock.time = half
    Oceananigans.Models.HydrostaticFreeSurfaceModels.refresh_prescribed_velocity_state!(reference_model,
                                                                                        reference_model.velocities)
    fill_halo_regions!(reference_model.tracers, reference_model.clock, fields(reference_model))
    Oceananigans.TurbulenceClosures.step_closure_prognostics!(reference_model.closure_fields,
                                                              reference_model.closure,
                                                              reference_model,
                                                              one(FT))
    Oceananigans.TurbulenceClosures.compute_closure_fields!(reference_model.closure_fields,
                                                            reference_model.closure,
                                                            reference_model)

    guarded_model = build_model()
    guarded_model.clock.time = half
    Oceananigans.TimeSteppers.step_closure_prognostics!(guarded_model, one(FT))
    Oceananigans.TurbulenceClosures.compute_closure_fields!(guarded_model.closure_fields,
                                                            guarded_model.closure,
                                                            guarded_model)

    stale_model = build_model()
    stale_model.clock.time = half
    fill_halo_regions!(stale_model.velocities, stale_model.clock, fields(stale_model))
    fill_halo_regions!(stale_model.tracers, stale_model.clock, fields(stale_model))
    Oceananigans.TurbulenceClosures.step_closure_prognostics!(stale_model.closure_fields,
                                                              stale_model.closure,
                                                              stale_model,
                                                              one(FT))
    Oceananigans.TurbulenceClosures.compute_closure_fields!(stale_model.closure_fields,
                                                            stale_model.closure,
                                                            stale_model)

    velocity_scale = max(abs(reference_model.velocities.u[1, 1, 1]),
                         abs(reference_model.velocities.v[1, 1, 1]),
                         one(FT))

    @test abs(guarded_model.velocities.u[1, 1, 1] - reference_model.velocities.u[1, 1, 1]) ≤ 1000eps(FT) * velocity_scale
    @test abs(guarded_model.velocities.v[1, 1, 1] - reference_model.velocities.v[1, 1, 1]) ≤ 1000eps(FT) * velocity_scale
    @test max(abs(reference_model.velocities.u[1, 1, 1] - stale_model.velocities.u[1, 1, 1]),
              abs(reference_model.velocities.v[1, 1, 1] - stale_model.velocities.v[1, 1, 1])) > 100eps(FT) * velocity_scale

    sampled_points = ((1, N + 1, 1),
                      (N + 1, 1, 2),
                      (2N, N + 1, 1),
                      (N + 1, 2N, 2),
                      (N + 2, N + 2, 1))

    maximum_reference_tke = zero(FT)
    maximum_reference_viscosity = zero(FT)
    maximum_guarded_tke_error = zero(FT)
    maximum_guarded_viscosity_error = zero(FT)
    maximum_stale_tke_difference = zero(FT)
    maximum_stale_viscosity_difference = zero(FT)

    for (i, j, k) in sampled_points
        e_reference = reference_model.tracers.e[i, j, k]
        κu_reference = reference_model.closure_fields.κu[i, j, k]

        e_guarded = guarded_model.tracers.e[i, j, k]
        κu_guarded = guarded_model.closure_fields.κu[i, j, k]

        e_stale = stale_model.tracers.e[i, j, k]
        κu_stale = stale_model.closure_fields.κu[i, j, k]

        maximum_reference_tke = max(maximum_reference_tke, abs(e_reference))
        maximum_reference_viscosity = max(maximum_reference_viscosity, abs(κu_reference))
        maximum_guarded_tke_error = max(maximum_guarded_tke_error, abs(e_reference - e_guarded))
        maximum_guarded_viscosity_error = max(maximum_guarded_viscosity_error, abs(κu_reference - κu_guarded))
        maximum_stale_tke_difference = max(maximum_stale_tke_difference, abs(e_reference - e_stale))
        maximum_stale_viscosity_difference = max(maximum_stale_viscosity_difference, abs(κu_reference - κu_stale))
    end

    @test maximum_reference_tke > sqrt(eps(FT))
    @test maximum_reference_viscosity > sqrt(eps(FT))
    @test maximum_guarded_tke_error ≤ 1000eps(FT) * max(one(FT), maximum_reference_tke)
    @test maximum_guarded_viscosity_error ≤ 1000eps(FT) * max(one(FT), maximum_reference_viscosity)
    @test maximum_stale_tke_difference > 100eps(FT) * max(one(FT), maximum_reference_tke)
    @test maximum_stale_viscosity_difference > 100eps(FT) * max(one(FT), maximum_reference_viscosity)

    return nothing
end

function test_octahealpix_prescribed_time_series_interpolation_compute_explicit_free_surface_tendency_refreshes_velocity_state(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))
    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)
    k_top = grid.Nz + 1

    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times)
    v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times)

    set!(u_fts, (λ, φ, z, t) -> convert(FT, 0.17) * sind(λ) +
                                 convert(FT, 0.05) * cosd(φ) +
                                 convert(FT, 0.11) * t)
    set!(v_fts, (λ, φ, z, t) -> convert(FT, 0.12) * cosd(λ) -
                                 convert(FT, 0.04) * sind(φ) -
                                 convert(FT, 0.09) * t)

    function build_model()
        source_clock = Oceananigans.Clock(time = zero(FT))
        u = Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, grid; clock = source_clock)
        v = Oceananigans.OutputReaders.TimeSeriesInterpolation(v_fts, grid; clock = source_clock)
        velocities = PrescribedVelocityFields(u = u, v = v)

        model = HydrostaticFreeSurfaceModel(grid;
                                            velocities,
                                            tracers = nothing,
                                            buoyancy = nothing,
                                            free_surface = ExplicitFreeSurface(),
                                            momentum_advection = nothing,
                                            tracer_advection = nothing)

        set!(model.free_surface.displacement,
             (λ, φ, z) -> convert(FT, 0.02) * sind(λ / 2) * cosd(φ))
        fill_halo_regions!(model.free_surface.displacement)

        return model
    end

    reference_model = build_model()
    reference_model.clock.time = half
    Oceananigans.Models.HydrostaticFreeSurfaceModels.refresh_prescribed_velocity_state!(reference_model,
                                                                                        reference_model.velocities)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.compute_free_surface_tendency!(grid,
                                                                                    reference_model,
                                                                                    reference_model.free_surface)

    guarded_model = build_model()
    guarded_model.clock.time = half
    Oceananigans.Models.HydrostaticFreeSurfaceModels.compute_free_surface_tendency!(grid,
                                                                                    guarded_model,
                                                                                    guarded_model.free_surface)

    stale_model = build_model()
    stale_model.clock.time = half

    velocity_scale = max(abs(reference_model.velocities.u[1, 1, 1]),
                         abs(reference_model.velocities.v[1, 1, 1]),
                         one(FT))

    @test abs(guarded_model.velocities.u[1, 1, 1] - reference_model.velocities.u[1, 1, 1]) ≤ 1000eps(FT) * velocity_scale
    @test abs(guarded_model.velocities.v[1, 1, 1] - reference_model.velocities.v[1, 1, 1]) ≤ 1000eps(FT) * velocity_scale

    sampled_points = ((1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N),
                      (N + 2, N + 2))

    maximum_reference_tendency = zero(FT)
    maximum_guarded_error = zero(FT)
    maximum_stale_difference = zero(FT)

    for (i, j) in sampled_points
        reference_Gη = reference_model.timestepper.Gⁿ.η[i, j, k_top]
        guarded_Gη = guarded_model.timestepper.Gⁿ.η[i, j, k_top]
        stale_Gη = Oceananigans.Models.HydrostaticFreeSurfaceModels.free_surface_tendency(i, j, grid,
                                                                                           stale_model.vertical_coordinate,
                                                                                           stale_model.velocities,
                                                                                           stale_model.free_surface,
                                                                                           stale_model.tracers,
                                                                                           stale_model.auxiliary_fields,
                                                                                           stale_model.forcing,
                                                                                           stale_model.clock)

        maximum_reference_tendency = max(maximum_reference_tendency, abs(reference_Gη))
        maximum_guarded_error = max(maximum_guarded_error, abs(reference_Gη - guarded_Gη))
        maximum_stale_difference = max(maximum_stale_difference, abs(reference_Gη - stale_Gη))
    end

    @test maximum_reference_tendency > sqrt(eps(FT))
    @test maximum_guarded_error ≤ 1000eps(FT) * max(one(FT), maximum_reference_tendency)
    @test maximum_stale_difference > 100eps(FT) * max(one(FT), maximum_reference_tendency)

    return nothing
end

function test_octahealpix_prescribed_time_series_interpolation_step_implicit_free_surface_refreshes_velocity_state(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))
    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)
    Δt = convert(FT, 1//10)
    k_top = grid.Nz + 1

    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times)
    v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times)

    set!(u_fts, (λ, φ, z, t) -> convert(FT, 0.17) * sind(λ) +
                                 convert(FT, 0.05) * cosd(φ) +
                                 convert(FT, 0.11) * t)
    set!(v_fts, (λ, φ, z, t) -> convert(FT, 0.12) * cosd(λ) -
                                 convert(FT, 0.04) * sind(φ) -
                                 convert(FT, 0.09) * t)

    function build_model()
        source_clock = Oceananigans.Clock(time = zero(FT))
        u = Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, grid; clock = source_clock)
        v = Oceananigans.OutputReaders.TimeSeriesInterpolation(v_fts, grid; clock = source_clock)
        velocities = PrescribedVelocityFields(u = u, v = v)

        model = HydrostaticFreeSurfaceModel(grid;
                                            velocities,
                                            tracers = nothing,
                                            buoyancy = nothing,
                                            free_surface = ImplicitFreeSurface(),
                                            momentum_advection = nothing,
                                            tracer_advection = nothing)

        set!(model.free_surface.displacement,
             (λ, φ, z) -> convert(FT, 0.02) * sind(λ / 2) * cosd(φ))
        fill_halo_regions!(model.free_surface.displacement)

        return model
    end

    reference_model = build_model()
    reference_model.clock.time = half
    Oceananigans.Models.HydrostaticFreeSurfaceModels.refresh_prescribed_velocity_state!(reference_model,
                                                                                        reference_model.velocities)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.step_free_surface!(reference_model.free_surface,
                                                                        reference_model,
                                                                        reference_model.timestepper,
                                                                        Δt)

    guarded_model = build_model()
    guarded_model.clock.time = half
    Oceananigans.Models.HydrostaticFreeSurfaceModels.step_free_surface!(guarded_model.free_surface,
                                                                        guarded_model,
                                                                        guarded_model.timestepper,
                                                                        Δt)

    stale_model = build_model()
    stale_model.clock.time = half

    η = stale_model.free_surface.displacement
    rhs = stale_model.free_surface.implicit_step_solver.right_hand_side
    solver = stale_model.free_surface.implicit_step_solver
    g = stale_model.free_surface.gravitational_acceleration
    u, v, _ = stale_model.velocities

    fill_halo_regions!((u, v), stale_model.clock, fields(stale_model))
    Oceananigans.Models.HydrostaticFreeSurfaceModels.compute_implicit_free_surface_right_hand_side!(rhs,
                                                                                                    solver,
                                                                                                    g,
                                                                                                    Δt,
                                                                                                    stale_model.velocities,
                                                                                                    η)
    Oceananigans.Solvers.solve!(η, solver, rhs, g, Δt)
    fill_halo_regions!(η)

    velocity_scale = max(abs(reference_model.velocities.u[1, 1, 1]),
                         abs(reference_model.velocities.v[1, 1, 1]),
                         one(FT))

    @test abs(guarded_model.velocities.u[1, 1, 1] - reference_model.velocities.u[1, 1, 1]) ≤ 1000eps(FT) * velocity_scale
    @test abs(guarded_model.velocities.v[1, 1, 1] - reference_model.velocities.v[1, 1, 1]) ≤ 1000eps(FT) * velocity_scale

    sampled_points = ((1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N),
                      (N + 2, N + 2))

    maximum_reference_displacement = zero(FT)
    maximum_guarded_error = zero(FT)
    maximum_stale_difference = zero(FT)

    for (i, j) in sampled_points
        reference_η = reference_model.free_surface.displacement[i, j, k_top]
        guarded_η = guarded_model.free_surface.displacement[i, j, k_top]
        stale_η = stale_model.free_surface.displacement[i, j, k_top]

        maximum_reference_displacement = max(maximum_reference_displacement, abs(reference_η))
        maximum_guarded_error = max(maximum_guarded_error, abs(reference_η - guarded_η))
        maximum_stale_difference = max(maximum_stale_difference, abs(reference_η - stale_η))
    end

    @test maximum_reference_displacement > sqrt(eps(FT))
    @test maximum_guarded_error ≤ 1000eps(FT) * max(one(FT), maximum_reference_displacement)
    @test maximum_stale_difference > 100eps(FT) * max(one(FT), maximum_reference_displacement)

    return nothing
end

function test_octahealpix_time_series_free_surface_forcing_refreshes_split_explicit_step(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))
    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)
    Δt = convert(FT, 1//10)
    k_top = grid.Nz + 1

    η_fts = Oceananigans.FieldTimeSeries{Center, Center, Face}(grid, times)
    set!(η_fts, (λ, φ, z, t) -> convert(FT, 0.03) * sind(λ / 2) * cosd(φ) +
                                 convert(FT, 0.08) * t)

    function build_model()
        source_clock = Oceananigans.Clock(time = zero(FT))
        η_tsi = Oceananigans.OutputReaders.TimeSeriesInterpolation(η_fts, grid; clock = source_clock)

        model = HydrostaticFreeSurfaceModel(grid;
                                            tracers = nothing,
                                            buoyancy = nothing,
                                            free_surface = SplitExplicitFreeSurface(substeps = 8),
                                            momentum_advection = nothing,
                                            tracer_advection = nothing,
                                            forcing = (η = η_tsi,))

        set!(model.free_surface.displacement, zero(FT))
        fill_halo_regions!(model.free_surface.displacement)

        return model
    end

    reference_model = build_model()
    reference_model.clock.time = half
    Oceananigans.Models.update_model_field_time_series!(reference_model, reference_model.clock)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.step_free_surface!(reference_model.free_surface,
                                                                        reference_model,
                                                                        reference_model.timestepper,
                                                                        Δt)

    guarded_model = build_model()
    guarded_model.clock.time = half
    Oceananigans.Models.HydrostaticFreeSurfaceModels.step_free_surface!(guarded_model.free_surface,
                                                                        guarded_model,
                                                                        guarded_model.timestepper,
                                                                        Δt)

    stale_model = build_model()
    stale_model.clock.time = half

    free_surface = stale_model.free_surface
    free_surface_grid = free_surface.displacement.grid
    filtered_state = free_surface.filtered_state
    substepping = free_surface.substepping
    barotropic_velocities = free_surface.barotropic_velocities
    barotropic_timestepper = free_surface.timestepper
    baroclinic_timestepper = stale_model.timestepper

    Nsubsteps = Oceananigans.Models.HydrostaticFreeSurfaceModels.calculate_substeps(substepping, Δt)
    fractional_Δt, weights, transport_weights = Oceananigans.Models.HydrostaticFreeSurfaceModels.calculate_adaptive_settings(substepping, Nsubsteps)
    Nsubsteps = length(weights)
    Δτᴮ = fractional_Δt * Δt

    GUⁿ = stale_model.timestepper.Gⁿ.U
    GVⁿ = stale_model.timestepper.Gⁿ.V

    η = free_surface.displacement
    U = barotropic_velocities.U
    V = barotropic_velocities.V
    F = stale_model.forcing.η

    Oceananigans.Models.HydrostaticFreeSurfaceModels.wait_free_surface_communication!(free_surface,
                                                                                      stale_model,
                                                                                      architecture(free_surface_grid))
    Oceananigans.Models.HydrostaticFreeSurfaceModels.initialize_free_surface_state!(free_surface,
                                                                                    baroclinic_timestepper,
                                                                                    barotropic_timestepper)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.SplitExplicitFreeSurfaces.iterate_split_explicit!(
        free_surface, free_surface_grid, GUⁿ, GVⁿ, Δτᴮ, F, stale_model.clock, weights, transport_weights, Val(Nsubsteps))

    launch!(architecture(free_surface_grid), free_surface_grid, :xy,
            Oceananigans.Models.HydrostaticFreeSurfaceModels.SplitExplicitFreeSurfaces._update_split_explicit_state!,
            η, U, V, free_surface_grid, filtered_state)

    fill_halo_regions!((filtered_state.Ũ, filtered_state.Ṽ))
    fill_halo_regions!((U, V))
    fill_halo_regions!(η)

    sampled_points = ((1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N),
                      (N + 2, N + 2))

    maximum_reference_displacement = zero(FT)
    maximum_guarded_error = zero(FT)
    maximum_stale_difference = zero(FT)

    for (i, j) in sampled_points
        reference_η = reference_model.free_surface.displacement[i, j, k_top]
        guarded_η = guarded_model.free_surface.displacement[i, j, k_top]
        stale_η = stale_model.free_surface.displacement[i, j, k_top]

        maximum_reference_displacement = max(maximum_reference_displacement, abs(reference_η))
        maximum_guarded_error = max(maximum_guarded_error, abs(reference_η - guarded_η))
        maximum_stale_difference = max(maximum_stale_difference, abs(reference_η - stale_η))
    end

    @test maximum_reference_displacement > sqrt(eps(FT))
    @test maximum_guarded_error ≤ 1000eps(FT) * max(one(FT), maximum_reference_displacement)
    @test maximum_stale_difference > 100eps(FT) * max(one(FT), maximum_reference_displacement)

    return nothing
end

