        u = Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, grid; clock = source_clock)
        v = Oceananigans.OutputReaders.TimeSeriesInterpolation(v_fts, grid; clock = source_clock)
        velocities = PrescribedVelocityFields(u = u, v = v)

        model = HydrostaticFreeSurfaceModel(grid;
                                            velocities,
                                            tracers = nothing,
                                            buoyancy = nothing,
                                            free_surface = SplitExplicitFreeSurface(substeps = 8),
                                            momentum_advection = nothing,
                                            tracer_advection = nothing)

        parent(model.free_surface.barotropic_velocities.U) .= convert(FT, 0.03)
        parent(model.free_surface.barotropic_velocities.V) .= convert(FT, -0.02)
        fill_halo_regions!((model.free_surface.barotropic_velocities.U,
                            model.free_surface.barotropic_velocities.V))

        return model
    end

    reference_model = build_model()
    reference_model.clock.time = half
    Oceananigans.Models.HydrostaticFreeSurfaceModels.refresh_prescribed_velocity_state!(reference_model,
                                                                                        reference_model.velocities)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.correct_barotropic_mode!(reference_model,
                                                                              reference_model.free_surface,
                                                                              Δt)

    guarded_model = build_model()
    guarded_model.clock.time = half
    Oceananigans.Models.HydrostaticFreeSurfaceModels.correct_barotropic_mode!(guarded_model,
                                                                              guarded_model.free_surface,
                                                                              Δt)

    stale_model = build_model()
    stale_model.clock.time = half
    Oceananigans.Models.HydrostaticFreeSurfaceModels.SplitExplicitFreeSurfaces.barotropic_split_explicit_corrector!(
        stale_model.velocities.u,
        stale_model.velocities.v,
        stale_model.free_surface,
        stale_model.grid)

    velocity_scale = max(abs(reference_model.velocities.u[1, 1, 1]),
                         abs(reference_model.velocities.v[1, 1, 1]),
                         one(FT))

    @test abs(guarded_model.velocities.u[1, 1, 1] - reference_model.velocities.u[1, 1, 1]) ≤ 1000eps(FT) * velocity_scale
    @test abs(guarded_model.velocities.v[1, 1, 1] - reference_model.velocities.v[1, 1, 1]) ≤ 1000eps(FT) * velocity_scale

    sampled_points = ((1, N + 1, 1),
                      (N + 1, 1, 1),
                      (2N, N + 1, 1),
                      (N + 1, 2N, 1),
                      (N + 2, N + 2, 1))

    maximum_reference_velocity = zero(FT)
    maximum_guarded_error = zero(FT)
    maximum_stale_difference = zero(FT)

    for (i, j, k) in sampled_points
        reference_u = reference_model.velocities.u[i, j, k]
        reference_v = reference_model.velocities.v[i, j, k]
        guarded_u = guarded_model.velocities.u[i, j, k]
        guarded_v = guarded_model.velocities.v[i, j, k]
        stale_u = stale_model.velocities.u[i, j, k]
        stale_v = stale_model.velocities.v[i, j, k]

        maximum_reference_velocity = max(maximum_reference_velocity, abs(reference_u), abs(reference_v))
        maximum_guarded_error = max(maximum_guarded_error,
                                    abs(reference_u - guarded_u),
                                    abs(reference_v - guarded_v))
        maximum_stale_difference = max(maximum_stale_difference,
                                       abs(reference_u - stale_u),
                                       abs(reference_v - stale_v))
    end

    @test maximum_reference_velocity > sqrt(eps(FT))
    @test maximum_guarded_error ≤ 1000eps(FT) * max(one(FT), maximum_reference_velocity)
    @test maximum_stale_difference > 100eps(FT) * max(one(FT), maximum_reference_velocity)

    return nothing
end

function test_octahealpix_prescribed_time_series_interpolation_correct_implicit_barotropic_mode_refreshes_velocity_state(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))
    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)
    Δt = convert(FT, 1//10)

    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times)
    v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times)

    set!(u_fts, (λ, φ, z, t) -> convert(FT, 0.17) * sind(λ) +
                                 convert(FT, 0.05) * cosd(φ) +
                                 convert(FT, 0.11) * t)
    set!(v_fts, (λ, φ, z, t) -> convert(FT, 0.12) * cosd(λ) -
                                 convert(FT, 0.04) * sind(φ) -
                                 convert(FT, 0.09) * t)

    function build_model()
        source_clock = Oceananigans.Clock(time = zero(FT))
        u = Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, grid; clock = source_clock)
        v = Oceananigans.OutputReaders.TimeSeriesInterpolation(v_fts, grid; clock = source_clock)
        velocities = PrescribedVelocityFields(u = u, v = v)

        model = HydrostaticFreeSurfaceModel(grid;
                                            velocities,
                                            tracers = nothing,
                                            buoyancy = nothing,
                                            free_surface = ImplicitFreeSurface(),
                                            momentum_advection = nothing,
                                            tracer_advection = nothing)

        set!(model.free_surface.displacement,
             (λ, φ, z) -> convert(FT, 0.02) * sind(λ / 2) * cosd(φ))
        fill_halo_regions!(model.free_surface.displacement)

        return model
    end

    reference_model = build_model()
    reference_model.clock.time = half
    Oceananigans.Models.HydrostaticFreeSurfaceModels.refresh_prescribed_velocity_state!(reference_model,
                                                                                        reference_model.velocities)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.correct_barotropic_mode!(reference_model,
                                                                              reference_model.free_surface,
                                                                              Δt)

    guarded_model = build_model()
    guarded_model.clock.time = half
    Oceananigans.Models.HydrostaticFreeSurfaceModels.correct_barotropic_mode!(guarded_model,
                                                                              guarded_model.free_surface,
                                                                              Δt)

    stale_model = build_model()
    stale_model.clock.time = half
    launch!(stale_model.architecture,
            stale_model.grid,
            Oceananigans.Models.volume_kernel_parameters(stale_model.grid),
            Oceananigans.Models.HydrostaticFreeSurfaceModels._barotropic_pressure_correction!,
            stale_model.velocities,
            stale_model.grid,
            Δt,
            stale_model.free_surface.gravitational_acceleration,
            stale_model.free_surface.displacement)

    velocity_scale = max(abs(reference_model.velocities.u[1, 1, 1]),
                         abs(reference_model.velocities.v[1, 1, 1]),
                         one(FT))

    @test abs(guarded_model.velocities.u[1, 1, 1] - reference_model.velocities.u[1, 1, 1]) ≤ 1000eps(FT) * velocity_scale
    @test abs(guarded_model.velocities.v[1, 1, 1] - reference_model.velocities.v[1, 1, 1]) ≤ 1000eps(FT) * velocity_scale

    sampled_points = ((1, N + 1, 1),
                      (N + 1, 1, 1),
                      (2N, N + 1, 1),
                      (N + 1, 2N, 1),
                      (N + 2, N + 2, 1))

    maximum_reference_velocity = zero(FT)
    maximum_guarded_error = zero(FT)
    maximum_stale_difference = zero(FT)

    for (i, j, k) in sampled_points
        reference_u = reference_model.velocities.u[i, j, k]
        reference_v = reference_model.velocities.v[i, j, k]
        guarded_u = guarded_model.velocities.u[i, j, k]
        guarded_v = guarded_model.velocities.v[i, j, k]
        stale_u = stale_model.velocities.u[i, j, k]
        stale_v = stale_model.velocities.v[i, j, k]

        maximum_reference_velocity = max(maximum_reference_velocity, abs(reference_u), abs(reference_v))
        maximum_guarded_error = max(maximum_guarded_error,
                                    abs(reference_u - guarded_u),
                                    abs(reference_v - guarded_v))
        maximum_stale_difference = max(maximum_stale_difference,
                                       abs(reference_u - stale_u),
                                       abs(reference_v - stale_v))
    end

    @test maximum_reference_velocity > sqrt(eps(FT))
    @test maximum_guarded_error ≤ 1000eps(FT) * max(one(FT), maximum_reference_velocity)
    @test maximum_stale_difference > 100eps(FT) * max(one(FT), maximum_reference_velocity)

    return nothing
end

function test_octahealpix_prescribed_mixed_time_series_interpolation_momentum_tendencies(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))
    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    source_u_bcs = FieldBoundaryConditions(grid, (Face(), Center(), Center());
                                           south = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(one(FT)),
                                           north = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(one(FT)))
    source_v_bcs = FieldBoundaryConditions(grid, (Center(), Face(), Center());
                                           west = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(one(FT)),
                                           east = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(one(FT)))

    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times;
                                                               boundary_conditions = source_u_bcs)
    v = YFaceField(grid; boundary_conditions = source_v_bcs)

    set!(u_fts, (λ, φ, z, t) -> sind(λ) * cosd(φ) + t)
    set!(v, (λ, φ, z) -> cosd(λ) * sind(φ))

    source_clock = Oceananigans.Clock(time = zero(FT))
    u = Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, grid; clock = source_clock)
    velocities = PrescribedVelocityFields(u = u, v = v)

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities,
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant())

    time_step!(model, half)

    momentum = model.advection.momentum
    U = (u = model.velocities.u, v = model.velocities.v, w = model.velocities.w)
    k = 1

    compute_momentum_tendencies!(model, ())
    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    for (i, j) in sampled_points
        expected_Gu = -U_dot_∇u(i, j, k, grid, momentum, U)
        expected_Gv = -U_dot_∇v(i, j, k, grid, momentum, U)
        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        magnitude_scale = max(abs(expected_Gu), abs(expected_Gv), one(FT))

        @test abs(expected_Gu) > 100eps(FT)
        @test abs(expected_Gv) > 100eps(FT)
        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * magnitude_scale
        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * magnitude_scale
    end

    @test !any(isnan, Array(interior(model.timestepper.Gⁿ.u)))
    @test !any(isnan, Array(interior(model.timestepper.Gⁿ.v)))

    return nothing
end

function test_octahealpix_prescribed_mixed_time_series_interpolation_transport_state_drives_tracer_tendency(FT, N)
    radius = convert(FT, 3)
    source_mapping = OctaHEALPixMapping(div(N, 2))
    source_grid = SphericalShellGrid(CPU(), FT; mapping = source_mapping,
                                     z = (zero(FT), one(FT)),
                                     radius,
                                     halo = (3, 3, 3))

    destination_mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping = destination_mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))
    connectivity = grid.connectivity
    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(one(FT))
    source_u_bcs = FieldBoundaryConditions(source_grid, (Face(), Center(), Center());
                                           south = qcov,
                                           north = qcov)
    source_v_bcs = FieldBoundaryConditions(source_grid, (Center(), Face(), Center());
                                           west = qcov,
                                           east = qcov)

    source_u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(source_grid, times;
                                                                      boundary_conditions = source_u_bcs)
    source_v = YFaceField(source_grid; boundary_conditions = source_v_bcs)

    set!(source_u_fts, (λ, φ, z, t) -> convert(FT, 2) * sind(λ) + cosd(φ) + t)
    set!(source_v, (λ, φ, z) -> cosd(λ) - convert(FT, 3) * sind(φ))

    source_clock = Oceananigans.Clock(time = zero(FT))
    source_u = Oceananigans.OutputReaders.TimeSeriesInterpolation(source_u_fts, source_grid; clock = source_clock)
    velocities = PrescribedVelocityFields(u = source_u, v = source_v)

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities,
                                        tracers = :c,
                                        buoyancy = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    time_step!(model, half)

    set!(model, c = (λ, φ, z) -> sind(λ / 2) * cosd(φ))

    compute_transport_velocities!(model, model.free_surface)

    source_field, source_i, source_j, sign =
        octahealpix_transport_face_halo_source(0, N + 1, connectivity, grid.Nx, grid.Ny, N, :u)
    expected_u_halo = source_field === :u ? sign * model.transport_velocities.u[source_i, source_j, 1] :
                                            sign * model.transport_velocities.v[source_i, source_j, 1]

    source_field, source_i, source_j, sign =
        octahealpix_transport_face_halo_source(N + 1, 0, connectivity, grid.Nx, grid.Ny, N, :v)
    expected_v_halo = source_field === :u ? sign * model.transport_velocities.u[source_i, source_j, 1] :
                                            sign * model.transport_velocities.v[source_i, source_j, 1]

    @test model.transport_velocities.u[0, N + 1, 1] == expected_u_halo
    @test model.transport_velocities.v[N + 1, 0, 1] == expected_v_halo

    compute_tracer_tendencies!(model)

    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    for (i, j) in sampled_points
        expected_Gc = -div_Uc(i, j, 1, grid, model.advection.c, model.transport_velocities, model.tracers.c)
        computed_Gc = model.timestepper.Gⁿ.c[i, j, 1]
        tendency_scale = max(abs(expected_Gc), one(FT))
        @test abs(expected_Gc) > 100eps(FT)
        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale
    end

    forward = Array(interior(model.timestepper.Gⁿ.c))

    set!(model.transport_velocities.u, -model.transport_velocities.u)
    set!(model.transport_velocities.v, -model.transport_velocities.v)
    fill_halo_regions!(model.transport_velocities)
    compute_tracer_tendencies!(model)
    reverse = Array(interior(model.timestepper.Gⁿ.c))

    tolerance = 200 * eps(FT) * max(one(FT), max(maximum(abs, forward), maximum(abs, reverse)))

    @test forward ≈ -reverse atol = tolerance
    @test !any(isnan, forward)
    @test !any(isnan, reverse)

    return nothing
end

function test_octahealpix_prescribed_operation_velocity_materialization_rebinds_model_clock(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(one(FT))
    u_bcs = FieldBoundaryConditions(grid, (Face(), Center(), Center());
                                    south = qcov,
                                    north = qcov)
    v_bcs = FieldBoundaryConditions(grid, (Center(), Face(), Center());
                                    west = qcov,
                                    east = qcov)

    times = [zero(FT), one(FT)]
    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times;
                                                               boundary_conditions = u_bcs)
    v = YFaceField(grid; boundary_conditions = v_bcs)

    set!(u_fts, (λ, φ, z, t) -> sind(λ) + t)
    set!(v, (λ, φ, z) -> cosd(φ))

    source_clock = Oceananigans.Clock(time = zero(FT))
    u = Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, grid; clock = source_clock) + zero(FT)

    velocities = PrescribedVelocityFields(u = u, v = v)

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities,
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    half = convert(FT, 1//2)
    time_step!(model, half)

    expected_u = u_fts[Oceananigans.Units.Time(half)]
    expected_v = YFaceField(grid; boundary_conditions = v.boundary_conditions)
    set!(expected_v, v)
    fill_halo_regions!((expected_u, expected_v))

    u_error = zero(FT)
    v_error = zero(FT)

    for j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        u_error = max(u_error, abs(model.velocities.u[i, j, 1] - expected_u[i, j, 1]))
        v_error = max(v_error, abs(model.velocities.v[i, j, 1] - expected_v[i, j, 1]))
    end

    @test u_error == zero(FT)
    @test v_error == zero(FT)

    return nothing
end

function test_octahealpix_prescribed_vertical_operation_velocity_materialization_rebinds_model_clock(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    times = [zero(FT), one(FT)]
    w_fts = Oceananigans.FieldTimeSeries{Center, Center, Face}(grid, times)
    set!(w_fts, (λ, φ, z, t) -> sind(λ) + t)

    source_clock = Oceananigans.Clock(time = zero(FT))
    w = Oceananigans.OutputReaders.TimeSeriesInterpolation(w_fts, grid; clock = source_clock) + zero(FT)

    velocities = PrescribedVelocityFields(u = (λ, φ, z, t) -> sind(λ) * cosd(φ),
                                          v = (λ, φ, z, t) -> cosd(λ) * sind(φ),
                                          w = w)

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities,
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    half = convert(FT, 1//2)
    time_step!(model, half)

    expected_w = w_fts[Oceananigans.Units.Time(half)]
    fill_halo_regions!(expected_w)

    w_error = zero(FT)

    for k in 1:(grid.Nz + 1), j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        w_error = max(w_error, abs(model.velocities.w[i, j, k] - expected_w[i, j, k]))
    end

    @test w_error == zero(FT)

    return nothing
end

function test_octahealpix_mislocated_single_component_prescribed_horizontal_velocity_error(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

