    v_bcs = FieldBoundaryConditions(grid, (Center(), Face(), Center());
                                    west = qcov,
                                    east = qcov)

    mislocated_v = YFaceField(grid; boundary_conditions = v_bcs)
    set!(mislocated_v, (λ, φ, z) -> cosd(λ) + sind(φ))

    @test_throws ArgumentError HydrostaticFreeSurfaceModel(grid;
                                                           velocities = PrescribedVelocityFields(u = mislocated_v),
