                                                                          boundary_conditions = v_bcs)
    set!(mislocated_v_fts, (λ, φ, z, t) -> cosd(λ) + sind(φ) + t)

    source_clock = Oceananigans.Clock(time = zero(FT))
    mislocated_v_tsi = Oceananigans.OutputReaders.TimeSeriesInterpolation(mislocated_v_fts, grid; clock = source_clock)

