                                                           tracer_advection = nothing)

    return nothing
end

function test_octahealpix_adapted_time_series_velocity_materialization_error(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(one(FT))
    u_bcs = FieldBoundaryConditions(grid, (Face(), Center(), Center());
                                    south = qcov,
                                    north = qcov)
    v_bcs = FieldBoundaryConditions(grid, (Center(), Face(), Center());
                                    west = qcov,
                                    east = qcov)

    times = [zero(FT), one(FT)]
    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times;
                                                               boundary_conditions = u_bcs)
    v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times;
                                                               boundary_conditions = v_bcs)
    w_fts = Oceananigans.FieldTimeSeries{Center, Center, Face}(grid, times)

    set!(u_fts, (λ, φ, z, t) -> sind(λ) + t)
    set!(v_fts, (λ, φ, z, t) -> cosd(φ) + t)
    set!(w_fts, (λ, φ, z, t) -> sind(λ / 2) + t)

    adapted_u_fts = Adapt.adapt_structure(Val(:noop), u_fts)
    adapted_v_fts = Adapt.adapt_structure(Val(:noop), v_fts)
    adapted_w_fts = Adapt.adapt_structure(Val(:noop), w_fts)

    @test_throws ArgumentError HydrostaticFreeSurfaceModel(grid;
                                                           velocities = PrescribedVelocityFields(u = adapted_u_fts, v = adapted_v_fts),
                                                           tracers = nothing,
                                                           buoyancy = nothing,
                                                           free_surface = nothing,
                                                           momentum_advection = nothing,
                                                           tracer_advection = nothing)

    source_clock = Oceananigans.Clock(time = zero(FT))
    u_tsi = Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, grid; clock = source_clock)
    v_tsi = Oceananigans.OutputReaders.TimeSeriesInterpolation(v_fts, grid; clock = source_clock)
    adapted_u_tsi = Adapt.adapt_structure(Val(:noop), u_tsi)
    adapted_v_tsi = Adapt.adapt_structure(Val(:noop), v_tsi)

    @test_throws ArgumentError HydrostaticFreeSurfaceModel(grid;
                                                           velocities = PrescribedVelocityFields(u = adapted_u_tsi, v = adapted_v_tsi),
                                                           tracers = nothing,
                                                           buoyancy = nothing,
                                                           free_surface = nothing,
                                                           momentum_advection = nothing,
                                                           tracer_advection = nothing)

    @test_throws ArgumentError HydrostaticFreeSurfaceModel(grid;
                                                           velocities = PrescribedVelocityFields(u = (λ, φ, z, t) -> sind(λ) * cosd(φ),
                                                                                                v = (λ, φ, z, t) -> cosd(λ) * sind(φ),
                                                                                                w = adapted_w_fts),
                                                           tracers = nothing,
                                                           buoyancy = nothing,
                                                           free_surface = nothing,
                                                           momentum_advection = nothing,
                                                           tracer_advection = nothing)

    return nothing
end

function test_octahealpix_adapted_prescribed_time_series_sources_preserve_materialization(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(one(FT))
    u_bcs = FieldBoundaryConditions(grid, (Face(), Center(), Center());
                                    south = qcov,
                                    north = qcov)
    v_bcs = FieldBoundaryConditions(grid, (Center(), Face(), Center());
                                    west = qcov,
                                    east = qcov)

    times = [zero(FT), one(FT)]
    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times;
                                                               boundary_conditions = u_bcs)
    v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times;
                                                               boundary_conditions = v_bcs)

    set!(u_fts, (λ, φ, z, t) -> sind(λ) + t)
    set!(v_fts, (λ, φ, z, t) -> cosd(φ) + convert(FT, 2) * t)

    source_clock = Oceananigans.Clock(time = zero(FT))
    u_tsi = Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, grid; clock = source_clock)
    v_tsi = Oceananigans.OutputReaders.TimeSeriesInterpolation(v_fts, grid; clock = source_clock)

    velocities = PrescribedVelocityFields(u = u_tsi, v = v_tsi, parameters = (; α = convert(FT, 2)))
    adapted_velocities = Adapt.adapt_structure(Val(:noop), velocities)

    @test adapted_velocities.u isa Oceananigans.OutputReaders.TimeSeriesInterpolation
    @test adapted_velocities.v isa Oceananigans.OutputReaders.TimeSeriesInterpolation
    @test adapted_velocities.parameters == velocities.parameters

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities = adapted_velocities,
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    @test model.velocities.u isa Oceananigans.OutputReaders.TimeSeriesInterpolation
    @test model.velocities.v isa Oceananigans.OutputReaders.TimeSeriesInterpolation

    return nothing
end

function test_octahealpix_transport_velocity_fields_support_operation_sources(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(one(FT))
    u_bcs = FieldBoundaryConditions(grid, (Face(), Center(), Center());
                                    south = qcov,
                                    north = qcov)
    v_bcs = FieldBoundaryConditions(grid, (Center(), Face(), Center());
                                    west = qcov,
                                    east = qcov)

    times = [zero(FT), one(FT)]
    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times;
                                                               boundary_conditions = u_bcs)
    v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times;
                                                               boundary_conditions = v_bcs)

    set!(u_fts, (λ, φ, z, t) -> sind(λ) + t)
    set!(v_fts, (λ, φ, z, t) -> cosd(φ) + t)

    source_clock = Oceananigans.Clock(time = zero(FT))
    operation_u = Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, grid; clock = source_clock) + zero(FT)
    operation_v = v_fts - zero(FT)
    operation_w = Oceananigans.FieldTimeSeries{Center, Center, Face}(grid, times)
    set!(operation_w, (λ, φ, z, t) -> sind(λ / 2) + t)

    transport_velocities =
        Oceananigans.Models.HydrostaticFreeSurfaceModels.transport_velocity_fields(
            PrescribedVelocityFields(u = operation_u, v = operation_v, w = operation_w + zero(FT)), grid)

    @test transport_velocities.u isa Oceananigans.Fields.Field
    @test transport_velocities.v isa Oceananigans.Fields.Field
    @test transport_velocities.w isa Oceananigans.Fields.Field
    @test transport_velocities.u.grid === grid
    @test transport_velocities.v.grid === grid
    @test transport_velocities.w.grid === grid
    @test transport_velocities.u.boundary_conditions.south isa Oceananigans.BoundaryConditions.QConZBC
    @test transport_velocities.u.boundary_conditions.north isa Oceananigans.BoundaryConditions.QConZBC
    @test transport_velocities.v.boundary_conditions.west isa Oceananigans.BoundaryConditions.QConZBC
    @test transport_velocities.v.boundary_conditions.east isa Oceananigans.BoundaryConditions.QConZBC
    @test transport_velocities.u.boundary_conditions.south.condition == one(FT)
    @test transport_velocities.u.boundary_conditions.north.condition == one(FT)
    @test transport_velocities.v.boundary_conditions.west.condition == one(FT)
    @test transport_velocities.v.boundary_conditions.east.condition == one(FT)

    inferred_transport_velocities =
        Oceananigans.Models.HydrostaticFreeSurfaceModels.transport_velocity_fields(
            PrescribedVelocityFields(u = operation_u, v = operation_v, w = operation_w + zero(FT)))

    @test inferred_transport_velocities.u isa Oceananigans.Fields.Field
    @test inferred_transport_velocities.v isa Oceananigans.Fields.Field
    @test inferred_transport_velocities.w isa Oceananigans.Fields.Field
    @test inferred_transport_velocities.u.grid === grid
    @test inferred_transport_velocities.v.grid === grid
    @test inferred_transport_velocities.w.grid === grid
    @test inferred_transport_velocities.u.boundary_conditions.south isa Oceananigans.BoundaryConditions.QConZBC
    @test inferred_transport_velocities.u.boundary_conditions.north isa Oceananigans.BoundaryConditions.QConZBC
    @test inferred_transport_velocities.v.boundary_conditions.west isa Oceananigans.BoundaryConditions.QConZBC
    @test inferred_transport_velocities.v.boundary_conditions.east isa Oceananigans.BoundaryConditions.QConZBC
    @test inferred_transport_velocities.u.boundary_conditions.south.condition == one(FT)
    @test inferred_transport_velocities.u.boundary_conditions.north.condition == one(FT)
    @test inferred_transport_velocities.v.boundary_conditions.west.condition == one(FT)
    @test inferred_transport_velocities.v.boundary_conditions.east.condition == one(FT)

    adapted_u_tsi = Adapt.adapt_structure(Val(:noop), Oceananigans.OutputReaders.TimeSeriesInterpolation(u_fts, grid; clock = source_clock))
    adapted_v_tsi = Adapt.adapt_structure(Val(:noop), Oceananigans.OutputReaders.TimeSeriesInterpolation(v_fts, grid; clock = source_clock))

    @test_throws ArgumentError Oceananigans.Models.HydrostaticFreeSurfaceModels.transport_velocity_fields(
        PrescribedVelocityFields(u = adapted_u_tsi, v = adapted_v_tsi), grid)

    return nothing
end

