@inline function centered_transport_flux_x(i, j, k, grid, scheme, U, c)
    volume_flux = @inbounds U.u[i, j, k]
    cᶠᶜᶜ = Oceananigans.Advection._symmetric_interpolate_xᶠᵃᵃ(i, j, k, grid, scheme, c)
    return volume_flux * cᶠᶜᶜ
end

@inline function centered_transport_flux_y(i, j, k, grid, scheme, U, c)
    volume_flux = @inbounds U.v[i, j, k]
    cᶜᶠᶜ = Oceananigans.Advection._symmetric_interpolate_yᵃᶠᵃ(i, j, k, grid, scheme, c)
    return volume_flux * cᶜᶠᶜ
end

@inline function bounded_transport_flux_divergence_x(i, j, k, grid, advection, U, c)
    c_min = @inbounds advection.bounds[1]
    c_max = @inbounds advection.bounds[2]

    c₊ᴸ = Oceananigans.Advection._biased_interpolate_xᶠᵃᵃ(i+1, j, k, grid, advection, Oceananigans.Advection.LeftBias,  c)
    c₊ᴿ = Oceananigans.Advection._biased_interpolate_xᶠᵃᵃ(i+1, j, k, grid, advection, Oceananigans.Advection.RightBias, c)
    c₋ᴸ = Oceananigans.Advection._biased_interpolate_xᶠᵃᵃ(i,   j, k, grid, advection, Oceananigans.Advection.LeftBias,  c)
    c₋ᴿ = Oceananigans.Advection._biased_interpolate_xᶠᵃᵃ(i,   j, k, grid, advection, Oceananigans.Advection.RightBias, c)

    FT = eltype(c)
    ω̂₁ = convert(FT, 5//18)
    ω̂ₙ = convert(FT, 5//18)
    ε₂ = convert(FT, 1e-20)

    cᵢⱼ = @inbounds c[i, j, k]
    p̃ = (cᵢⱼ - ω̂₁ * c₋ᴿ - ω̂ₙ * c₊ᴸ) / (1 - 2ω̂₁)
    M = max(p̃, c₊ᴸ, c₋ᴿ)
    m = min(p̃, c₊ᴸ, c₋ᴿ)

    θ_max = abs((c_max - cᵢⱼ) / (M - cᵢⱼ + ε₂))
    θ_min = abs((c_min - cᵢⱼ) / (m - cᵢⱼ + ε₂))
    θ = min(θ_max, θ_min, one(FT))

    c₊ᴸ = θ * (c₊ᴸ - cᵢⱼ) + cᵢⱼ
    c₋ᴿ = θ * (c₋ᴿ - cᵢⱼ) + cᵢⱼ

    u⁺ = @inbounds U.u[i+1, j, k]
    u⁻ = @inbounds U.u[i,   j, k]
    ρuc⁺ = Oceananigans.Operators.ℑxᶠᵃᵃ(i+1, j, k, grid, one(FT)) *
           Oceananigans.Advection.upwind_biased_product(u⁺, c₊ᴸ, c₊ᴿ)
    ρuc⁻ = Oceananigans.Operators.ℑxᶠᵃᵃ(i,   j, k, grid, one(FT)) *
           Oceananigans.Advection.upwind_biased_product(u⁻, c₋ᴸ, c₋ᴿ)

    return ρuc⁺ - ρuc⁻
end

@inline function bounded_transport_flux_divergence_y(i, j, k, grid, advection, U, c)
    c_min = @inbounds advection.bounds[1]
    c_max = @inbounds advection.bounds[2]

    c₊ᴸ = Oceananigans.Advection._biased_interpolate_yᵃᶠᵃ(i, j+1, k, grid, advection, Oceananigans.Advection.LeftBias,  c)
    c₊ᴿ = Oceananigans.Advection._biased_interpolate_yᵃᶠᵃ(i, j+1, k, grid, advection, Oceananigans.Advection.RightBias, c)
    c₋ᴸ = Oceananigans.Advection._biased_interpolate_yᵃᶠᵃ(i, j,   k, grid, advection, Oceananigans.Advection.LeftBias,  c)
    c₋ᴿ = Oceananigans.Advection._biased_interpolate_yᵃᶠᵃ(i, j,   k, grid, advection, Oceananigans.Advection.RightBias, c)

    FT = eltype(c)
    ω̂₁ = convert(FT, 5//18)
    ω̂ₙ = convert(FT, 5//18)
    ε₂ = convert(FT, 1e-20)

    cᵢⱼ = @inbounds c[i, j, k]
    p̃ = (cᵢⱼ - ω̂₁ * c₋ᴿ - ω̂ₙ * c₊ᴸ) / (1 - 2ω̂₁)
    M = max(p̃, c₊ᴸ, c₋ᴿ)
    m = min(p̃, c₊ᴸ, c₋ᴿ)

    θ_max = abs((c_max - cᵢⱼ) / (M - cᵢⱼ + ε₂))
    θ_min = abs((c_min - cᵢⱼ) / (m - cᵢⱼ + ε₂))
    θ = min(θ_max, θ_min, one(FT))

    c₊ᴸ = θ * (c₊ᴸ - cᵢⱼ) + cᵢⱼ
    c₋ᴿ = θ * (c₋ᴿ - cᵢⱼ) + cᵢⱼ

    v⁺ = @inbounds U.v[i, j+1, k]
    v⁻ = @inbounds U.v[i, j,   k]
    ρvc⁺ = Oceananigans.Operators.ℑyᵃᶠᵃ(i, j+1, k, grid, one(FT)) *
           Oceananigans.Advection.upwind_biased_product(v⁺, c₊ᴸ, c₊ᴿ)
    ρvc⁻ = Oceananigans.Operators.ℑyᵃᶠᵃ(i, j,   k, grid, one(FT)) *
           Oceananigans.Advection.upwind_biased_product(v⁻, c₋ᴸ, c₋ᴿ)

    return ρvc⁺ - ρvc⁻
end

@inline function naive_bounded_transport_flux_divergence_x(i, j, k, grid, advection, U, c)
    c_min = @inbounds advection.bounds[1]
