function test_octahealpix_tracer_operator_uses_transport_fluxes_directly(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities = PrescribedVelocityFields(),
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model, c = (λ, φ, z) -> sind(λ / 2) + convert(FT, 0.2) * cosd(φ))
    set!(model.transport_velocities.u, (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ))
    set!(model.transport_velocities.v, (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ))
    set!(model.transport_velocities.w, zero(FT))

    fill_halo_regions!((model.transport_velocities.u, model.transport_velocities.v))
    fill_halo_regions!(model.transport_velocities.w)

    compute_tracer_tendencies!(model)

    scheme = Centered(FT)
    samples = ((2, div(N, 2), 1),
               (N - 1, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (div(N, 2), N - 1, 1))

    for (i, j, k) in samples
        expected_divergence =
            Oceananigans.Operators.V⁻¹ᶜᶜᶜ(i, j, k, grid) *
            (Oceananigans.Operators.δxᶜᵃᵃ(i, j, k, grid, centered_transport_flux_x, scheme, model.transport_velocities, model.tracers.c) +
             Oceananigans.Operators.δyᵃᶜᵃ(i, j, k, grid, centered_transport_flux_y, scheme, model.transport_velocities, model.tracers.c))

        computed_Gc = model.timestepper.Gⁿ.c[i, j, k]
        expected_Gc = -expected_divergence
        tendency_scale = max(one(FT), abs(expected_Gc), abs(computed_Gc))
        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale
    end

    return nothing
end

function test_octahealpix_interior_tracer_advection_operator(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))
    u₁ = Array{FT}(undef, 2N + 1, 2N, 1)
    u₂ = Array{FT}(undef, 2N, 2N + 1, 1)
    c₀ = convert(FT, 5//2)
    c = fill(c₀, 2N, 2N, 1)
    U = (u = u₁, v = u₂, w = ZeroField())
    scheme = Centered(FT)

    for j in 1:(2N), i in 1:(2N + 1)
        u₁[i, j, 1] = convert(FT, i) / convert(FT, 2N + 1) +
                      convert(FT, 1//3) * convert(FT, j) / convert(FT, 2N)
    end

    for j in 1:(2N + 1), i in 1:(2N)
        u₂[i, j, 1] = convert(FT, 2//3) * convert(FT, i) / convert(FT, 2N) -
                      convert(FT, j) / convert(FT, 2N + 1)
    end

    interior_i_ranges = (2:(N - 1), (N + 2):(2N - 1))
    interior_j_ranges = (2:(N - 1), (N + 2):(2N - 1))

    divergence_formula_error = zero(FT)
    integrated_divergence_error = zero(FT)
    scale = one(FT)

    for j_range in interior_j_ranges, i_range in interior_i_ranges
        integrated_divergence = zero(FT)
        boundary_flux = zero(FT)

        for j in j_range, i in i_range
            expected_divergence =
                Oceananigans.Operators.V⁻¹ᶜᶜᶜ(i, j, 1, grid) *
                (Oceananigans.Operators.δxᶜᵃᵃ(i, j, 1, grid, centered_transport_flux_x, scheme, U, c) +
                 Oceananigans.Operators.δyᵃᶜᵃ(i, j, 1, grid, centered_transport_flux_y, scheme, U, c))
            computed_divergence = div_Uc(i, j, 1, grid, scheme, U, c)

            divergence_formula_error = max(divergence_formula_error,
                                           abs(computed_divergence - expected_divergence))
            scale = max(scale, abs(expected_divergence), abs(computed_divergence))

            integrated_divergence +=
                volume(i, j, 1, grid, Center(), Center(), Center()) * computed_divergence
        end

        west_i = first(i_range)
        east_i = last(i_range) + 1
        south_j = first(j_range)
        north_j = last(j_range) + 1

        for j in j_range
            boundary_flux += centered_transport_flux_x(east_i, j, 1, grid, scheme, U, c) -
                             centered_transport_flux_x(west_i, j, 1, grid, scheme, U, c)
        end

        for i in i_range
            boundary_flux += centered_transport_flux_y(i, north_j, 1, grid, scheme, U, c) -
                             centered_transport_flux_y(i, south_j, 1, grid, scheme, U, c)
        end

        integrated_divergence_error = max(integrated_divergence_error,
                                          abs(integrated_divergence - boundary_flux))
        scale = max(scale, abs(boundary_flux), abs(integrated_divergence))
    end

    @test divergence_formula_error ≤ 1000eps(FT) * scale
    @test integrated_divergence_error ≤ 1000eps(FT) * scale

    return nothing
end

function test_octahealpix_tracer_tendency_with_affine_fields(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    u₁_field = Array{FT}(undef, 2N + 1, 2N, 1)
    u₂_field = Array{FT}(undef, 2N, 2N + 1, 1)
    c_field = Array{FT}(undef, 2N, 2N, 1)

    for j in 1:(2N), i in 1:(2N + 1)
        u₁_field[i, j, 1] = convert(FT, i) / convert(FT, 2N + 1) +
                            convert(FT, 1//3) * convert(FT, j) / convert(FT, 2N)
    end

    for j in 1:(2N + 1), i in 1:(2N)
        u₂_field[i, j, 1] = convert(FT, 2//3) * convert(FT, i) / convert(FT, 2N) -
                            convert(FT, j) / convert(FT, 2N + 1)
    end

    for j in 1:(2N), i in 1:(2N)
        c_field[i, j, 1] = convert(FT, 5//2) +
                           convert(FT, 2//5) * convert(FT, i) / convert(FT, 2N) -
                           convert(FT, 1//4) * convert(FT, j) / convert(FT, 2N)
    end

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model, u = u₁_field, v = u₂_field, c = c_field)
    compute_transport_velocities!(model, model.free_surface)
    compute_tracer_tendencies!(model)

    interior_indices = vcat(collect(2:(N - 1)),
                            collect((N + 2):(2N - 1)))

    tracer_tendency_error = zero(FT)
    tracer_tendency_scale = one(FT)
    maximum_naive_difference = zero(FT)

    for j in interior_indices, i in interior_indices
        expected_Gc = -div_Uc(i, j, 1, grid, model.advection.c, model.transport_velocities, model.tracers.c)
        naive_Gc = -div_Uc(i, j, 1, grid, model.advection.c, model.velocities, model.tracers.c)
        computed_Gc = model.timestepper.Gⁿ.c[i, j, 1]

        tracer_tendency_error = max(tracer_tendency_error, abs(computed_Gc - expected_Gc))
        tracer_tendency_scale = max(tracer_tendency_scale, abs(expected_Gc), abs(computed_Gc))
        maximum_naive_difference = max(maximum_naive_difference, abs(expected_Gc - naive_Gc))
    end

    @test tracer_tendency_error ≤ 1000eps(FT) * tracer_tendency_scale
    @test maximum_naive_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_bounds_preserving_weno_uses_transport_fluxes_directly(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (2, 2, 2))

    scheme = Oceananigans.Advection.WENO(FT; order = 3, bounds = (zero(FT), one(FT)))
    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = scheme)

    u₁_field = Array{FT}(undef, 2N + 1, 2N, 1)
    u₂_field = Array{FT}(undef, 2N, 2N + 1, 1)
    c_field = Array{FT}(undef, 2N, 2N, 1)

    for j in 1:(2N), i in 1:(2N + 1)
        u₁_field[i, j, 1] = convert(FT, i) / convert(FT, 10 * (2N + 1)) +
                            convert(FT, 1//30) * convert(FT, j) / convert(FT, 2N)
    end

    for j in 1:(2N + 1), i in 1:(2N)
        u₂_field[i, j, 1] = convert(FT, 1//15) * convert(FT, i) / convert(FT, 2N) -
                            convert(FT, j) / convert(FT, 20 * (2N + 1))
    end

    for j in 1:(2N), i in 1:(2N)
        c_field[i, j, 1] = convert(FT, 1//2) +
                           convert(FT, 1//10) * convert(FT, i) / convert(FT, 2N) -
                           convert(FT, 1//20) * convert(FT, j) / convert(FT, 2N)
    end

    set!(model, u = u₁_field, v = u₂_field, c = c_field)

    compute_tracer_tendencies!(model)

    samples = ((2, div(N, 2), 1),
               (N - 1, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (div(N, 2), N - 1, 1))

    maximum_naive_difference = zero(FT)

    for (i, j, k) in samples
        expected_divergence =
            Oceananigans.Operators.V⁻¹ᶜᶜᶜ(i, j, k, grid) *
            (bounded_transport_flux_divergence_x(i, j, k, grid, scheme, model.transport_velocities, model.tracers.c) +
             bounded_transport_flux_divergence_y(i, j, k, grid, scheme, model.transport_velocities, model.tracers.c))

        naive_divergence =
            Oceananigans.Operators.V⁻¹ᶜᶜᶜ(i, j, k, grid) *
            (naive_bounded_transport_flux_divergence_x(i, j, k, grid, scheme, model.transport_velocities, model.tracers.c) +
             naive_bounded_transport_flux_divergence_y(i, j, k, grid, scheme, model.transport_velocities, model.tracers.c))

        computed_Gc = model.timestepper.Gⁿ.c[i, j, k]
        expected_Gc = -expected_divergence
        naive_Gc = -naive_divergence
        tendency_scale = max(one(FT), abs(expected_Gc), abs(computed_Gc))

        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale
        maximum_naive_difference = max(maximum_naive_difference, abs(expected_Gc - naive_Gc))
    end

    @test maximum_naive_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_horizontal_advective_forcing_uses_transport_fluxes(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    forcing_u = XFaceField(grid)
    forcing_v = YFaceField(grid)
    reference_u = XFaceField(grid)
    reference_v = YFaceField(grid)

    u_velocity(λ, φ, z) = convert(FT, 0.11) * sind(λ) + convert(FT, 0.04) * cosd(φ)
    v_velocity(λ, φ, z) = convert(FT, 0.07) * cosd(λ) - convert(FT, 0.03) * sind(φ)

    set!((u = forcing_u, v = forcing_v); u = u_velocity, v = v_velocity)
    set!((u = reference_u, v = reference_v); u = u_velocity, v = v_velocity)

    forcing = (c = AdvectiveForcing(u = forcing_u, v = forcing_v),)

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        forcing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model, c = (λ, φ, z) -> convert(FT, 0.5) + convert(FT, 0.2) * sind(λ) + convert(FT, 0.1) * cosd(φ))
    fill_halo_regions!((forcing_u, forcing_v))
    fill_halo_regions!((reference_u, reference_v))

    for j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue
        forcing_u[i, j, 1] = convert(FT, 111)
        forcing_v[i, j, 1] = convert(FT, -222)
    end

    expected_transport = (u = OctaHEALPixConvertedTransportU(grid, reference_u, reference_v),
                          v = OctaHEALPixConvertedTransportV(grid, reference_u, reference_v),
                          w = model.transport_velocities.w)

    naive_transport = (u = reference_u,
                       v = reference_v,
                       w = model.transport_velocities.w)

    corrupted_transport = (u = OctaHEALPixConvertedTransportU(grid, forcing_u, forcing_v),
                           v = OctaHEALPixConvertedTransportV(grid, forcing_u, forcing_v),
                           w = model.transport_velocities.w)

    samples = ((2, div(N, 2), 1),
               (N - 1, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (div(N, 2), N - 1, 1))

    corrupted_Gcs = map(samples) do (i, j, k)
        -div_Uc(i, j, k, grid, model.advection.c, corrupted_transport, model.tracers.c)
    end

    Oceananigans.Models.HydrostaticFreeSurfaceModels.compute_transport_velocities!(model, model.free_surface)
    compute_tracer_tendencies!(model)

    maximum_transformed_difference = zero(FT)
    maximum_corrupted_difference = zero(FT)

    for (n, (i, j, k)) in enumerate(samples)
        expected_Gc = -div_Uc(i, j, k, grid, model.advection.c, expected_transport, model.tracers.c)
        naive_Gc = -div_Uc(i, j, k, grid, model.advection.c, naive_transport, model.tracers.c)
        corrupted_Gc = corrupted_Gcs[n]
        computed_Gc = model.timestepper.Gⁿ.c[i, j, k]
        tendency_scale = max(one(FT), abs(expected_Gc), abs(computed_Gc))

        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale
        maximum_transformed_difference = max(maximum_transformed_difference, abs(expected_Gc - naive_Gc))
        maximum_corrupted_difference = max(maximum_corrupted_difference, abs(expected_Gc - corrupted_Gc))
    end

    @test maximum_transformed_difference > 100eps(FT)
    @test maximum_corrupted_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_single_component_horizontal_advective_forcing_preserves_signed_seam_bcs(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(-one(FT))
    u_bcs = FieldBoundaryConditions(grid, (Face(), Center(), Center());
                                    south = qcov,
                                    north = qcov)
    v_bcs = FieldBoundaryConditions(grid, (Center(), Face(), Center());
                                    west = qcov,
                                    east = qcov)

    forcing_u = XFaceField(grid; boundary_conditions = u_bcs)
    staging_v = YFaceField(grid; boundary_conditions = v_bcs)
    reference_u = XFaceField(grid; boundary_conditions = u_bcs)
    reference_v = YFaceField(grid; boundary_conditions = v_bcs)

    u_velocity(λ, φ, z) = convert(FT, 0.12) * sind(λ) + convert(FT, 0.05) * cosd(φ)

    set!((u = forcing_u, v = staging_v); u = u_velocity, v = zero(FT))
    set!((u = reference_u, v = reference_v); u = u_velocity, v = zero(FT))

    forcing = (c = AdvectiveForcing(u = forcing_u),)

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        forcing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model, c = (λ, φ, z) -> convert(FT, 0.45) + convert(FT, 0.18) * sind(λ) + convert(FT, 0.07) * cosd(φ))
    fill_halo_regions!((reference_u, reference_v))

    for j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue
        forcing_u[i, j, 1] = convert(FT, 333)
    end

    expected_transport = (u = OctaHEALPixConvertedTransportU(grid, reference_u, reference_v),
                          v = OctaHEALPixConvertedTransportV(grid, reference_u, reference_v),
                          w = model.transport_velocities.w)

    naive_transport = (u = reference_u,
                       v = reference_v,
                       w = model.transport_velocities.w)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.compute_transport_velocities!(model, model.free_surface)
    compute_tracer_tendencies!(model)

    samples = ((2, div(N, 2), 1),
               (N - 1, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (div(N, 2), N - 1, 1))

    maximum_transformed_difference = zero(FT)

    for (i, j, k) in samples
        expected_Gc = -div_Uc(i, j, k, grid, model.advection.c, expected_transport, model.tracers.c)
        naive_Gc = -div_Uc(i, j, k, grid, model.advection.c, naive_transport, model.tracers.c)
        computed_Gc = model.timestepper.Gⁿ.c[i, j, k]
        tendency_scale = max(one(FT), abs(expected_Gc), abs(computed_Gc))

        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale
        maximum_transformed_difference = max(maximum_transformed_difference, abs(expected_Gc - naive_Gc))
    end

    @test maximum_transformed_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_horizontal_biogeochemical_drift_uses_transport_fluxes(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    drift_u = XFaceField(grid)
    drift_v = YFaceField(grid)
    reference_u = XFaceField(grid)
    reference_v = YFaceField(grid)

    u_velocity(λ, φ, z) = convert(FT, 0.09) * sind(λ) + convert(FT, 0.03) * cosd(φ)
    v_velocity(λ, φ, z) = convert(FT, 0.06) * cosd(λ) - convert(FT, 0.02) * sind(φ)

    set!((u = drift_u, v = drift_v); u = u_velocity, v = v_velocity)
    set!((u = reference_u, v = reference_v); u = u_velocity, v = v_velocity)

    drift_velocity = (u = drift_u, v = drift_v, w = ZeroField())
    biogeochemistry = OctaHEALPixHorizontalDriftBiogeochemistry(drift_velocity)

    model = HydrostaticFreeSurfaceModel(grid;
                                        buoyancy = nothing,
                                        biogeochemistry,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

