        drift_u[i, j, 1] = convert(FT, 123)
        drift_v[i, j, 1] = convert(FT, -321)
    end

    expected_transport = (u = OctaHEALPixConvertedTransportU(grid, reference_u, reference_v),
                          v = OctaHEALPixConvertedTransportV(grid, reference_u, reference_v),
