                           v = OctaHEALPixConvertedTransportV(grid, drift_u, drift_v),
                           w = model.transport_velocities.w)

    samples = ((2, div(N, 2), 1),
               (N - 1, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (div(N, 2), N - 1, 1))

    corrupted_Gcs = map(samples) do (i, j, k)
        -div_Uc(i, j, k, grid, model.advection.c, corrupted_transport, model.tracers.c)
    end

    Oceananigans.Models.HydrostaticFreeSurfaceModels.compute_transport_velocities!(model, model.free_surface)
    compute_tracer_tendencies!(model)

    maximum_transformed_difference = zero(FT)
    maximum_corrupted_difference = zero(FT)

    for (n, (i, j, k)) in enumerate(samples)
        expected_Gc = -div_Uc(i, j, k, grid, model.advection.c, expected_transport, model.tracers.c)
        naive_Gc = -div_Uc(i, j, k, grid, model.advection.c, naive_transport, model.tracers.c)
        corrupted_Gc = corrupted_Gcs[n]
        computed_Gc = model.timestepper.Gⁿ.c[i, j, k]
        tendency_scale = max(one(FT), abs(expected_Gc), abs(computed_Gc))

        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale
        maximum_transformed_difference = max(maximum_transformed_difference, abs(expected_Gc - naive_Gc))
        maximum_corrupted_difference = max(maximum_corrupted_difference, abs(expected_Gc - corrupted_Gc))
    end

    @test maximum_transformed_difference > 100eps(FT)
    @test maximum_corrupted_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_tracer_forcing_uses_physical_velocities(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    velocity_source(i, j, k, grid, clock, model_fields) =
        @inbounds model_fields.u[i, j, k] + convert(FT, 2) * model_fields.v[i, j, k]

    forcing = (c = Oceananigans.Forcings.Forcing(velocity_source, discrete_form = true),)

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        forcing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.13) * sind(λ) + convert(FT, 0.02) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.09) * cosd(λ) - convert(FT, 0.05) * sind(φ),
         c = zero(FT))

    fill_halo_regions!(model.velocities)
    set!(model.transport_velocities.u, zero(FT))
    set!(model.transport_velocities.v, zero(FT))
    set!(model.transport_velocities.w, zero(FT))
    fill_halo_regions!((model.transport_velocities.u, model.transport_velocities.v))
    fill_halo_regions!(model.transport_velocities.w)

    compute_tracer_tendencies!(model)

    samples = ((2, div(N, 2), 1),
               (N - 1, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (div(N, 2), N - 1, 1))

    maximum_transport_difference = zero(FT)

    for (i, j, k) in samples
        expected_Gc = model.velocities.u[i, j, k] + convert(FT, 2) * model.velocities.v[i, j, k]
        naive_Gc = model.transport_velocities.u[i, j, k] + convert(FT, 2) * model.transport_velocities.v[i, j, k]
        computed_Gc = model.timestepper.Gⁿ.c[i, j, k]
        tendency_scale = max(one(FT), abs(expected_Gc), abs(computed_Gc))

        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale
        maximum_transport_difference = max(maximum_transport_difference, abs(expected_Gc - naive_Gc))
    end

    @test maximum_transport_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_time_series_horizontal_advective_forcing_refreshes_transport_state_for_cfl_and_tracer_tendencies(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))
    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    forcing_u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times)
    forcing_v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times)

    set!(forcing_u_fts, (λ, φ, z, t) -> convert(FT, 0.11) * sind(λ) +
                                         convert(FT, 0.04) * cosd(φ) +
                                         convert(FT, 0.09) * t)
    set!(forcing_v_fts, (λ, φ, z, t) -> convert(FT, 0.07) * cosd(λ) -
                                         convert(FT, 0.03) * sind(φ) -
                                         convert(FT, 0.05) * t)

    source_clock = Oceananigans.Clock(time = zero(FT))
    forcing_u = Oceananigans.OutputReaders.TimeSeriesInterpolation(forcing_u_fts, grid; clock = source_clock)
    forcing_v = Oceananigans.OutputReaders.TimeSeriesInterpolation(forcing_v_fts, grid; clock = source_clock)

    forcing = (c = AdvectiveForcing(u = forcing_u, v = forcing_v),)

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        forcing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.13) * sind(λ) + convert(FT, 0.02) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.09) * cosd(λ) - convert(FT, 0.05) * sind(φ),
         c = (λ, φ, z) -> convert(FT, 0.5) + convert(FT, 0.2) * sind(λ) + convert(FT, 0.1) * cosd(φ))

    Oceananigans.Models.HydrostaticFreeSurfaceModels.compute_transport_velocities!(model, model.free_surface)
    model.clock.time = half

    reference_u = XFaceField(grid)
    reference_v = YFaceField(grid)
    stale_u = XFaceField(grid)
    stale_v = YFaceField(grid)

    set!((u = reference_u, v = reference_v);
         u = (λ, φ, z) -> convert(FT, 0.11) * sind(λ) +
                          convert(FT, 0.04) * cosd(φ) +
                          convert(FT, 0.09) * half,
         v = (λ, φ, z) -> convert(FT, 0.07) * cosd(λ) -
                          convert(FT, 0.03) * sind(φ) -
                          convert(FT, 0.05) * half)

    set!((u = stale_u, v = stale_v);
         u = (λ, φ, z) -> convert(FT, 0.11) * sind(λ) + convert(FT, 0.04) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.07) * cosd(λ) - convert(FT, 0.03) * sind(φ))

    fill_halo_regions!((reference_u, reference_v))
    fill_halo_regions!((stale_u, stale_v))

    computed_timescale = Oceananigans.Advection.cell_advection_timescale(model)
    compute_tracer_tendencies!(model)

    reference_forcing = AdvectiveForcing(u = reference_u, v = reference_v)
    stale_forcing = AdvectiveForcing(u = stale_u, v = stale_v)

    expected_auxiliary_velocities =
        Oceananigans.Models.HydrostaticFreeSurfaceModels.tracer_auxiliary_velocities(nothing, nothing, reference_forcing)
    stale_auxiliary_velocities =
        Oceananigans.Models.HydrostaticFreeSurfaceModels.tracer_auxiliary_velocities(nothing, nothing, stale_forcing)

    expected_total_transport =
        Oceananigans.Models.HydrostaticFreeSurfaceModels.total_tracer_advection_velocities(grid,
                                                                                           model.transport_velocities,
                                                                                           expected_auxiliary_velocities)
    stale_total_transport =
        Oceananigans.Models.HydrostaticFreeSurfaceModels.total_tracer_advection_velocities(grid,
                                                                                           model.transport_velocities,
                                                                                           stale_auxiliary_velocities)

    base_timescale = Oceananigans.Advection.cell_advection_timescale(model.grid, model.transport_velocities)
    expected_timescale = min(base_timescale, Oceananigans.Advection.cell_advection_timescale(grid, expected_total_transport))
    stale_timescale = min(base_timescale, Oceananigans.Advection.cell_advection_timescale(grid, stale_total_transport))

    samples = ((2, div(N, 2), 1),
               (N - 1, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (div(N, 2), N - 1, 1))

    maximum_stale_difference = zero(FT)

    for (i, j, k) in samples
        expected_Gc = -div_Uc(i, j, k, grid, model.advection.c, expected_total_transport, model.tracers.c)
        stale_Gc = -div_Uc(i, j, k, grid, model.advection.c, stale_total_transport, model.tracers.c)
        computed_Gc = model.timestepper.Gⁿ.c[i, j, k]
        tendency_scale = max(one(FT), abs(expected_Gc), abs(computed_Gc))

        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale
        maximum_stale_difference = max(maximum_stale_difference, abs(expected_Gc - stale_Gc))
    end

    timescale_scale = max(one(FT), abs(expected_timescale), abs(computed_timescale))
    @test abs(computed_timescale - expected_timescale) ≤ 1000eps(FT) * timescale_scale
    @test abs(expected_timescale - stale_timescale) > 100eps(FT)
    @test maximum_stale_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_time_series_horizontal_momentum_advective_forcing_refreshes_state_for_momentum_tendencies(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))
    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    forcing_u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times)
    forcing_v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times)

    set!(forcing_u_fts, (λ, φ, z, t) -> convert(FT, 0.13) * sind(λ) +
                                         convert(FT, 0.04) * cosd(φ) +
                                         convert(FT, 0.11) * t)
    set!(forcing_v_fts, (λ, φ, z, t) -> convert(FT, 0.09) * cosd(λ) -
                                         convert(FT, 0.03) * sind(φ) -
                                         convert(FT, 0.07) * t)

    source_clock = Oceananigans.Clock(time = zero(FT))
    forcing_u = Oceananigans.OutputReaders.TimeSeriesInterpolation(forcing_u_fts, grid; clock = source_clock)
    forcing_v = Oceananigans.OutputReaders.TimeSeriesInterpolation(forcing_v_fts, grid; clock = source_clock)

    forcing = (u = AdvectiveForcing(u = forcing_u, v = forcing_v),
               v = AdvectiveForcing(u = forcing_u, v = forcing_v))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        forcing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant())

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.16) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.12) * cosd(λ) - convert(FT, 0.04) * sind(φ))

    model.clock.time = half

    reference_u = XFaceField(grid)
    reference_v = YFaceField(grid)
    stale_u = XFaceField(grid)
    stale_v = YFaceField(grid)

    set!((u = reference_u, v = reference_v);
         u = (λ, φ, z) -> convert(FT, 0.13) * sind(λ) +
                          convert(FT, 0.04) * cosd(φ) +
                          convert(FT, 0.11) * half,
         v = (λ, φ, z) -> convert(FT, 0.09) * cosd(λ) -
                          convert(FT, 0.03) * sind(φ) -
                          convert(FT, 0.07) * half)

    set!((u = stale_u, v = stale_v);
         u = (λ, φ, z) -> convert(FT, 0.13) * sind(λ) + convert(FT, 0.04) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.09) * cosd(λ) - convert(FT, 0.03) * sind(φ))

    fill_halo_regions!((reference_u, reference_v))
    fill_halo_regions!((stale_u, stale_v))

    compute_momentum_tendencies!(model, ())

    momentum = model.advection.momentum
    expected_U = Oceananigans.Forcings.with_advective_forcing(AdvectiveForcing(u = reference_u, v = reference_v), model.velocities)
    stale_U = Oceananigans.Forcings.with_advective_forcing(AdvectiveForcing(u = stale_u, v = stale_v), model.velocities)
    k = 1

    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    maximum_stale_u_difference = zero(FT)
    maximum_stale_v_difference = zero(FT)

    for (i, j) in sampled_points
        expected_Gu = -U_dot_∇u(i, j, k, grid, momentum, expected_U)
        expected_Gv = -U_dot_∇v(i, j, k, grid, momentum, expected_U)
        stale_Gu = -U_dot_∇u(i, j, k, grid, momentum, stale_U)
        stale_Gv = -U_dot_∇v(i, j, k, grid, momentum, stale_U)
        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        magnitude_scale = max(abs(expected_Gu), abs(expected_Gv), one(FT))

        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * magnitude_scale
        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * magnitude_scale

        maximum_stale_u_difference = max(maximum_stale_u_difference, abs(expected_Gu - stale_Gu))
        maximum_stale_v_difference = max(maximum_stale_v_difference, abs(expected_Gv - stale_Gv))
    end

    @test maximum_stale_u_difference > 100eps(FT)
    @test maximum_stale_v_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_hydrostatic_pressure_halos_drive_momentum_tendencies(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :b,
                                        buoyancy = BuoyancyTracer(),
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    set!(model, b = (λ, φ, z) -> convert(FT, 0.2) * sind(λ) + convert(FT, 0.1) * cosd(φ) + convert(FT, 0.05) * z)

    reference_pressure = CenterField(grid)
    stale_pressure = CenterField(grid)

    Oceananigans.Models.NonhydrostaticModels.update_hydrostatic_pressure!(reference_pressure,
                                                                          model.architecture,
                                                                          grid,
                                                                          model.buoyancy,
                                                                          model.tracers)
    fill_halo_regions!(reference_pressure)
    set!(stale_pressure, reference_pressure)

    for j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue
        model.pressure.pHY′[i, j, 1] = convert(FT, 777)
        stale_pressure[i, j, 1] = convert(FT, 777)
    end

    Oceananigans.TimeSteppers.update_state!(model)

    u_samples = ((1, div(grid.Ny, 4), 1),
                 (grid.Nx + 1, div(grid.Ny, 4), 1),
                 (1, div(3 * grid.Ny, 4), 1),
                 (grid.Nx + 1, div(3 * grid.Ny, 4), 1))

    v_samples = ((div(grid.Nx, 4), 1, 1),
                 (div(grid.Nx, 4), grid.Ny + 1, 1),
                 (div(3 * grid.Nx, 4), 1, 1),
                 (div(3 * grid.Nx, 4), grid.Ny + 1, 1))

    maximum_stale_u_difference = zero(FT)
    maximum_stale_v_difference = zero(FT)
    maximum_naive_u_difference = zero(FT)
    maximum_naive_v_difference = zero(FT)

    for (i, j, k) in u_samples
        expected_Gu = -Oceananigans.Operators.covariant_gradient_xᶠᶜᶜ(i, j, k, grid, reference_pressure)
        stale_Gu = -Oceananigans.Operators.covariant_gradient_xᶠᶜᶜ(i, j, k, grid, stale_pressure)
        naive_Gu = -Oceananigans.Operators.δxᶠᶜᶜ(i, j, k, grid, reference_pressure) *
                    Oceananigans.Operators.Δx⁻¹ᶠᶜᶜ(i, j, k, grid)
        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        tendency_scale = max(one(FT), abs(expected_Gu), abs(computed_Gu))

        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * tendency_scale
        maximum_stale_u_difference = max(maximum_stale_u_difference, abs(expected_Gu - stale_Gu))
        maximum_naive_u_difference = max(maximum_naive_u_difference, abs(expected_Gu - naive_Gu))
    end

    for (i, j, k) in v_samples
        expected_Gv = -Oceananigans.Operators.covariant_gradient_yᶜᶠᶜ(i, j, k, grid, reference_pressure)
        stale_Gv = -Oceananigans.Operators.covariant_gradient_yᶜᶠᶜ(i, j, k, grid, stale_pressure)
        naive_Gv = -Oceananigans.Operators.δyᶜᶠᶜ(i, j, k, grid, reference_pressure) *
                    Oceananigans.Operators.Δy⁻¹ᶜᶠᶜ(i, j, k, grid)
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        tendency_scale = max(one(FT), abs(expected_Gv), abs(computed_Gv))

        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * tendency_scale
        maximum_stale_v_difference = max(maximum_stale_v_difference, abs(expected_Gv - stale_Gv))
        maximum_naive_v_difference = max(maximum_naive_v_difference, abs(expected_Gv - naive_Gv))
    end

    @test maximum_stale_u_difference > 100eps(FT)
    @test maximum_stale_v_difference > 100eps(FT)
    @test maximum_naive_u_difference > 100eps(FT)
    @test maximum_naive_v_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_materialized_buoyancy_gradient_halos_drive_closure_auxiliary_velocity(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    closure = Oceananigans.TurbulenceClosures.IsopycnalSkewSymmetricDiffusivity(FT;
                                                                                κ_skew = convert(FT, 10),
                                                                                κ_symmetric = convert(FT, 10),
                                                                                skew_flux_formulation = Oceananigans.TurbulenceClosures.AdvectiveFormulation())

    function build_model()
        buoyancy = BuoyancyForce(grid, BuoyancyTracer(); materialize_gradients = true)
        model = HydrostaticFreeSurfaceModel(grid;
                                            tracers = :b,
                                            buoyancy,
                                            closure,
                                            free_surface = nothing,
                                            momentum_advection = nothing,
                                            tracer_advection = Centered(FT))

        set!(model, b = (λ, φ, z) -> convert(FT, 0.2) * sind(λ) +
                                   convert(FT, 0.1) * cosd(φ) +
                                   convert(FT, 0.05) * z)
        return model
    end

    function corrupt_materialized_buoyancy_gradient_halos!(gradients)
        for k in 1:grid.Nz, j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
            (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue
            gradients.∂xᵣ_b[i, j, k] = convert(FT, 111)
            gradients.∂yᵣ_b[i, j, k] = convert(FT, -222)
        end
        return nothing
    end

    reference_model = build_model()
    Oceananigans.TimeSteppers.update_state!(reference_model)

    stale_model = build_model()
    Oceananigans.TimeSteppers.update_state!(stale_model)
    corrupt_materialized_buoyancy_gradient_halos!(stale_model.buoyancy.gradients)
    κ_params = Oceananigans.Models.HydrostaticFreeSurfaceModels.diffusivity_kernel_parameters(grid)
    Oceananigans.TurbulenceClosures.compute_closure_fields!(stale_model.closure_fields,
                                                            stale_model.closure,
                                                            stale_model;
                                                            parameters = κ_params)

    model = build_model()
    corrupt_materialized_buoyancy_gradient_halos!(model.buoyancy.gradients)
    Oceananigans.TimeSteppers.update_state!(model)

    u_samples = ((div(grid.Nx, 4), 1, 1),
                 (div(grid.Nx, 4), grid.Ny, 1),
                 (div(3 * grid.Nx, 4), 1, 1),
                 (div(3 * grid.Nx, 4), grid.Ny, 1))

    v_samples = ((1, div(grid.Ny, 4), 1),
                 (grid.Nx, div(grid.Ny, 4), 1),
                 (1, div(3 * grid.Ny, 4), 1),
                 (grid.Nx, div(3 * grid.Ny, 4), 1))

    maximum_stale_u_difference = zero(FT)
    maximum_stale_v_difference = zero(FT)

    for (i, j, k) in u_samples
        expected_u = reference_model.closure_fields.u[i, j, k]
        stale_u = stale_model.closure_fields.u[i, j, k]
        computed_u = model.closure_fields.u[i, j, k]
        value_scale = max(one(FT), abs(expected_u), abs(computed_u))

        @test abs(computed_u - expected_u) ≤ 1000eps(FT) * value_scale
        maximum_stale_u_difference = max(maximum_stale_u_difference, abs(expected_u - stale_u))
    end

    for (i, j, k) in v_samples
        expected_v = reference_model.closure_fields.v[i, j, k]
        stale_v = stale_model.closure_fields.v[i, j, k]
        computed_v = model.closure_fields.v[i, j, k]
        value_scale = max(one(FT), abs(expected_v), abs(computed_v))

        @test abs(computed_v - expected_v) ≤ 1000eps(FT) * value_scale
        maximum_stale_v_difference = max(maximum_stale_v_difference, abs(expected_v - stale_v))
    end

    @test maximum_stale_u_difference > 100eps(FT)
    @test maximum_stale_v_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_materialized_buoyancy_gradient_halo_fill_is_paired(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    actual = BuoyancyForce(grid, BuoyancyTracer(); materialize_gradients = true).gradients
    expected = BuoyancyForce(grid, BuoyancyTracer(); materialize_gradients = true).gradients
    generic = BuoyancyForce(grid, BuoyancyTracer(); materialize_gradients = true).gradients

    function seed_materialized_buoyancy_gradients!(gradients)
        for k in 1:grid.Nz, j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
            interior = 1 <= i <= grid.Nx && 1 <= j <= grid.Ny

            if interior
                gradients.∂xᵣ_b[i, j, k] = convert(FT, 11i - 3j + k)
                gradients.∂yᵣ_b[i, j, k] = convert(FT, -5i + 7j + 2k)
                gradients.∂z_b[i, j, k] = convert(FT, 3i + 2j - k)
            else
                gradients.∂xᵣ_b[i, j, k] = convert(FT, 111)
                gradients.∂yᵣ_b[i, j, k] = convert(FT, -222)
                gradients.∂z_b[i, j, k] = convert(FT, 333)
            end
        end

        return nothing
    end

    seed_materialized_buoyancy_gradients!(actual)
    seed_materialized_buoyancy_gradients!(expected)
    seed_materialized_buoyancy_gradients!(generic)

    Oceananigans.BuoyancyFormulations.fill_buoyancy_gradient_halos!(actual, grid)
    fill_halo_regions!((expected.∂xᵣ_b, expected.∂yᵣ_b))
    fill_halo_regions!(expected.∂z_b)
    fill_halo_regions!(generic)

    for k in 1:grid.Nz, j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        @test actual.∂xᵣ_b[i, j, k] == expected.∂xᵣ_b[i, j, k]
        @test actual.∂yᵣ_b[i, j, k] == expected.∂yᵣ_b[i, j, k]
        @test actual.∂z_b[i, j, k] == expected.∂z_b[i, j, k]
        @test generic.∂xᵣ_b[i, j, k] == expected.∂xᵣ_b[i, j, k]
        @test generic.∂yᵣ_b[i, j, k] == expected.∂yᵣ_b[i, j, k]
        @test generic.∂z_b[i, j, k] == expected.∂z_b[i, j, k]
    end

    return nothing
end

function test_octahealpix_dynamic_smagorinsky_filter_halos_drive_viscosity(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    closure = Oceananigans.TurbulenceClosures.DynamicSmagorinsky(FT; averaging = (1, 2))

    function build_model()
        model = HydrostaticFreeSurfaceModel(grid;
                                            tracers = :c,
                                            buoyancy = nothing,
                                            free_surface = nothing,
                                            momentum_advection = nothing,
                                            tracer_advection = Centered(FT),
                                            closure = closure)

        set!(model,
             u = (λ, φ, z) -> convert(FT, 0.25) * sind(λ) + convert(FT, 0.08) * cosd(φ) + convert(FT, 0.15) * z,
             v = (λ, φ, z) -> convert(FT, 0.18) * cosd(λ) - convert(FT, 0.06) * sind(φ) - convert(FT, 0.12) * z,
             c = zero(FT))

        return model
    end

    function corrupt_dynamic_smagorinsky_filter_halos!(closure_fields)
        Σ = closure_fields.Σ
        Σ̄ = closure_fields.Σ̄

        for k in 1:grid.Nz, j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
            (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue

            Σ[i, j, k] = convert(FT, 4i - 3j + 2k)
            Σ̄[i, j, k] = convert(FT, -2i + 5j + k)
        end

        return nothing
    end

    reference_model = build_model()
    Oceananigans.TurbulenceClosures.compute_closure_fields!(reference_model.closure_fields,
                                                            reference_model.closure,
                                                            reference_model)

    stale_model = build_model()
    arch = CPU()
    u, v, w = stale_model.velocities
    Σ = stale_model.closure_fields.Σ
    Σ̄ = stale_model.closure_fields.Σ̄
    LM = stale_model.closure_fields.LM
    MM = stale_model.closure_fields.MM

    Oceananigans.Utils.launch!(arch, grid, :xyz,
                               Oceananigans.TurbulenceClosures.Smagorinskys._compute_Σ!,
                               Σ, grid, u, v, w)
    Oceananigans.Utils.launch!(arch, grid, :xyz,
                               Oceananigans.TurbulenceClosures.Smagorinskys._compute_Σ̄!,
                               Σ̄, grid, u, v, w)

    fill_halo_regions!(Σ; only_local_halos=true)
    fill_halo_regions!(Σ̄; only_local_halos=true)
    corrupt_dynamic_smagorinsky_filter_halos!(stale_model.closure_fields)

    Oceananigans.Utils.launch!(arch, grid, :xyz,
                               Oceananigans.TurbulenceClosures.Smagorinskys._compute_LM_MM!,
                               LM, MM, Σ, Σ̄, grid, u, v, w)
    Oceananigans.Fields.compute!(stale_model.closure_fields.𝒥ᴸᴹ)
    Oceananigans.Fields.compute!(stale_model.closure_fields.𝒥ᴹᴹ)

    Oceananigans.Utils.launch!(arch, grid, :xyz,
                               Oceananigans.TurbulenceClosures.Smagorinskys._compute_smagorinsky_viscosity!,
                               stale_model.closure_fields,
                               grid,
                               stale_model.closure,
                               stale_model.buoyancy,
                               stale_model.velocities,
                               stale_model.tracers)

    sampled_points = ((1, N + 1, 1),
                      (N + 1, 1, 2),
                      (2N, N + 1, 1),
                      (N + 1, 2N, 2),
                      (N + 2, N + 2, 1))

    maximum_stale_difference = zero(FT)
    maximum_reference_viscosity = zero(FT)

    for (i, j, k) in sampled_points
        ν_reference = reference_model.closure_fields.νₑ[i, j, k]
        ν_stale = stale_model.closure_fields.νₑ[i, j, k]

        maximum_reference_viscosity = max(maximum_reference_viscosity, abs(ν_reference))
        maximum_stale_difference = max(maximum_stale_difference, abs(ν_reference - ν_stale))
    end

    @test maximum_reference_viscosity > sqrt(eps(FT))
    @test maximum_stale_difference > 100eps(FT) * max(one(FT), maximum_reference_viscosity)

    return nothing
end

function test_octahealpix_lagrangian_dynamic_smagorinsky_state_halos_drive_viscosity(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    closure = Oceananigans.TurbulenceClosures.DynamicSmagorinsky(FT)

    function build_model()
        model = HydrostaticFreeSurfaceModel(grid;
                                            tracers = :c,
                                            buoyancy = nothing,
                                            free_surface = nothing,
                                            momentum_advection = nothing,
                                            tracer_advection = Centered(FT),
                                            closure = closure)

        set!(model,
             u = (λ, φ, z) -> convert(FT, 0.23) * sind(λ) + convert(FT, 0.07) * cosd(φ) + convert(FT, 0.11) * z,
             v = (λ, φ, z) -> convert(FT, 0.17) * cosd(λ) - convert(FT, 0.05) * sind(φ) - convert(FT, 0.09) * z,
             c = zero(FT))

        return model
    end

    function corrupt_lagrangian_dynamic_smagorinsky_state_halos!(closure_fields)
        𝒥ᴸᴹ = closure_fields.𝒥ᴸᴹ
        𝒥ᴹᴹ = closure_fields.𝒥ᴹᴹ

        for k in 1:grid.Nz, j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
            (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue

            𝒥ᴸᴹ[i, j, k] = convert(FT, 4i - 3j + k)
            𝒥ᴹᴹ[i, j, k] = convert(FT, -2i + 5j + 2k)
        end

        return nothing
    end

    reference_model = build_model()
    Oceananigans.TurbulenceClosures.initialize_closure_fields!(reference_model.closure_fields,
                                                               reference_model.closure,
                                                               reference_model)
    reference_model.clock.time = one(FT)
    Oceananigans.TurbulenceClosures.step_closure_prognostics!(reference_model.closure_fields,
                                                              reference_model.closure,
                                                              reference_model,
                                                              one(FT))
    corrupt_lagrangian_dynamic_smagorinsky_state_halos!(reference_model.closure_fields)
    reference_model.clock.time = convert(FT, 2)
    Oceananigans.TurbulenceClosures.step_closure_prognostics!(reference_model.closure_fields,
                                                              reference_model.closure,
                                                              reference_model,
                                                              one(FT))
    Oceananigans.TurbulenceClosures.compute_closure_fields!(reference_model.closure_fields,
                                                            reference_model.closure,
                                                            reference_model)

    stale_model = build_model()
    Oceananigans.TurbulenceClosures.initialize_closure_fields!(stale_model.closure_fields,
                                                               stale_model.closure,
                                                               stale_model)
    stale_model.clock.time = one(FT)
    Oceananigans.TurbulenceClosures.step_closure_prognostics!(stale_model.closure_fields,
                                                              stale_model.closure,
                                                              stale_model,
                                                              one(FT))
    corrupt_lagrangian_dynamic_smagorinsky_state_halos!(stale_model.closure_fields)

    arch = CPU()
    u, v, w = stale_model.velocities
    Σ = stale_model.closure_fields.Σ
    Σ̄ = stale_model.closure_fields.Σ̄
    𝒥ᴸᴹ⁻ = stale_model.closure_fields.𝒥ᴸᴹ⁻
    𝒥ᴹᴹ⁻ = stale_model.closure_fields.𝒥ᴹᴹ⁻
    𝒥ᴸᴹ = stale_model.closure_fields.𝒥ᴸᴹ
    𝒥ᴹᴹ = stale_model.closure_fields.𝒥ᴹᴹ
    𝒥ᴸᴹ_min = stale_model.closure.coefficient.minimum_numerator

    Oceananigans.Utils.launch!(arch, grid, :xyz,
                               Oceananigans.TurbulenceClosures.Smagorinskys._compute_Σ!,
                               Σ, grid, u, v, w)
    Oceananigans.Utils.launch!(arch, grid, :xyz,
                               Oceananigans.TurbulenceClosures.Smagorinskys._compute_Σ̄!,
                               Σ̄, grid, u, v, w)
    fill_halo_regions!(Σ)
    fill_halo_regions!(Σ̄)

    parent(𝒥ᴸᴹ⁻) .= parent(𝒥ᴸᴹ)
    parent(𝒥ᴹᴹ⁻) .= parent(𝒥ᴹᴹ)

    stale_model.clock.time = convert(FT, 2)
    Δt_lagrangian = stale_model.clock.time - stale_model.closure_fields.previous_compute_time[]
    stale_model.closure_fields.previous_compute_time[] = stale_model.clock.time

    Oceananigans.Utils.launch!(arch, grid, :xyz,
                               Oceananigans.TurbulenceClosures.Smagorinskys._lagrangian_average_LM_MM!,
                               𝒥ᴸᴹ, 𝒥ᴹᴹ, 𝒥ᴸᴹ⁻, 𝒥ᴹᴹ⁻, 𝒥ᴸᴹ_min, Σ, Σ̄, grid, Δt_lagrangian, u, v, w)
    Oceananigans.TurbulenceClosures.compute_closure_fields!(stale_model.closure_fields,
                                                            stale_model.closure,
                                                            stale_model)

    sampled_points = ((1, N + 1, 1),
                      (N + 1, 1, 2),
                      (2N, N + 1, 1),
                      (N + 1, 2N, 2),
                      (N + 2, N + 2, 1))

    maximum_reference_viscosity = zero(FT)
    maximum_stale_difference = zero(FT)

    for (i, j, k) in sampled_points
        ν_reference = reference_model.closure_fields.νₑ[i, j, k]
        ν_stale = stale_model.closure_fields.νₑ[i, j, k]

        maximum_reference_viscosity = max(maximum_reference_viscosity, abs(ν_reference))
        maximum_stale_difference = max(maximum_stale_difference, abs(ν_reference - ν_stale))
    end

    @test maximum_reference_viscosity > sqrt(eps(FT))
    @test maximum_stale_difference > 100eps(FT) * max(one(FT), maximum_reference_viscosity)

    return nothing
end

function test_octahealpix_catke_previous_velocity_halos_drive_tke_step(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    closure = Oceananigans.TurbulenceClosures.CATKEVerticalDiffusivity(FT)

    function build_model()
        model = HydrostaticFreeSurfaceModel(grid;
                                            tracers = (:b, :e),
                                            buoyancy = BuoyancyTracer(),
                                            free_surface = nothing,
                                            momentum_advection = nothing,
                                            tracer_advection = Centered(FT),
                                            closure = closure)

        set!(model,
             u = (λ, φ, z) -> convert(FT, 0.19) * sind(λ) + convert(FT, 0.06) * cosd(φ) + convert(FT, 0.08) * z,
             v = (λ, φ, z) -> convert(FT, 0.14) * cosd(λ) - convert(FT, 0.05) * sind(φ) - convert(FT, 0.07) * z,
             b = (λ, φ, z) -> convert(FT, 0.07) * sind(λ / 2) * cosd(φ) + convert(FT, 0.28) * z,
             e = (λ, φ, z) -> convert(FT, 2e-4) + convert(FT, 8e-5) * sind(λ) * cosd(φ) + convert(FT, 3e-5) * z)

        return model
    end

    function corrupt_catke_previous_velocity_halos!(previous_velocities)
        u⁻ = previous_velocities.u
        v⁻ = previous_velocities.v

        for k in 1:grid.Nz, j in 0:(size(u⁻, 2) + 1), i in 0:(size(u⁻, 1) + 1)
            (1 <= i <= size(u⁻, 1) && 1 <= j <= size(u⁻, 2)) && continue
            u⁻[i, j, k] = convert(FT, 3i - 2j + k)
        end

        for k in 1:grid.Nz, j in 0:(size(v⁻, 2) + 1), i in 0:(size(v⁻, 1) + 1)
            (1 <= i <= size(v⁻, 1) && 1 <= j <= size(v⁻, 2)) && continue
            v⁻[i, j, k] = convert(FT, -2i + 4j - k)
        end

        return nothing
    end

    reference_model = build_model()
    Oceananigans.TurbulenceClosures.initialize_closure_fields!(reference_model.closure_fields,
                                                               reference_model.closure,
                                                               reference_model)
    Oceananigans.TurbulenceClosures.step_closure_prognostics!(reference_model.closure_fields,
                                                              reference_model.closure,
                                                              reference_model,
                                                              one(FT))
    Oceananigans.TurbulenceClosures.compute_closure_fields!(reference_model.closure_fields,
                                                            reference_model.closure,
                                                            reference_model)

    stale_model = build_model()
    Oceananigans.TurbulenceClosures.initialize_closure_fields!(stale_model.closure_fields,
                                                               stale_model.closure,
                                                               stale_model)
    corrupt_catke_previous_velocity_halos!(stale_model.closure_fields.previous_velocities)
    Oceananigans.TurbulenceClosures.step_closure_prognostics!(stale_model.closure_fields,
                                                              stale_model.closure,
                                                              stale_model,
                                                              one(FT))
    Oceananigans.TurbulenceClosures.compute_closure_fields!(stale_model.closure_fields,
                                                            stale_model.closure,
                                                            stale_model)

    sampled_points = ((1, N + 1, 1),
                      (N + 1, 1, 2),
                      (2N, N + 1, 1),
                      (N + 1, 2N, 2),
                      (N + 2, N + 2, 1))

    maximum_reference_tke = zero(FT)
    maximum_reference_viscosity = zero(FT)
    maximum_stale_tke_difference = zero(FT)
    maximum_stale_viscosity_difference = zero(FT)

    for (i, j, k) in sampled_points
        e_reference = reference_model.tracers.e[i, j, k]
        e_stale = stale_model.tracers.e[i, j, k]
        κu_reference = reference_model.closure_fields.κu[i, j, k]
        κu_stale = stale_model.closure_fields.κu[i, j, k]

        maximum_reference_tke = max(maximum_reference_tke, abs(e_reference))
        maximum_reference_viscosity = max(maximum_reference_viscosity, abs(κu_reference))
        maximum_stale_tke_difference = max(maximum_stale_tke_difference, abs(e_reference - e_stale))
        maximum_stale_viscosity_difference = max(maximum_stale_viscosity_difference, abs(κu_reference - κu_stale))
    end

    @test maximum_reference_tke > sqrt(eps(FT))
    @test maximum_reference_viscosity > sqrt(eps(FT))
    @test maximum_stale_tke_difference > 100eps(FT) * max(one(FT), maximum_reference_tke)
    @test maximum_stale_viscosity_difference > 100eps(FT) * max(one(FT), maximum_reference_viscosity)

    return nothing
end

