                                                              one(FT))
    stale_model.clock.iteration = 1
    corrupt_tke_dissipation_previous_velocity_halos!(stale_model.closure_fields.previous_velocities)
    Oceananigans.TurbulenceClosures.step_closure_prognostics!(stale_model.closure_fields,
                                                              stale_model.closure,
                                                              stale_model,
                                                              one(FT))
    Oceananigans.TurbulenceClosures.compute_closure_fields!(stale_model.closure_fields,
                                                            stale_model.closure,
                                                            stale_model)

    sampled_points = ((1, N + 1, 1),
                      (N + 1, 1, 2),
                      (2N, N + 1, 1),
                      (N + 1, 2N, 2),
                      (N + 2, N + 2, 1))

    maximum_reference_tke = zero(FT)
    maximum_reference_dissipation = zero(FT)
    maximum_reference_viscosity = zero(FT)
    maximum_stale_tke_difference = zero(FT)
    maximum_stale_dissipation_difference = zero(FT)
    maximum_stale_viscosity_difference = zero(FT)

    for (i, j, k) in sampled_points
        e_reference = reference_model.tracers.e[i, j, k]
        ϵ_reference = reference_model.tracers.ϵ[i, j, k]
        κu_reference = reference_model.closure_fields.κu[i, j, k]

        e_stale = stale_model.tracers.e[i, j, k]
        ϵ_stale = stale_model.tracers.ϵ[i, j, k]
        κu_stale = stale_model.closure_fields.κu[i, j, k]

        maximum_reference_tke = max(maximum_reference_tke, abs(e_reference))
        maximum_reference_dissipation = max(maximum_reference_dissipation, abs(ϵ_reference))
        maximum_reference_viscosity = max(maximum_reference_viscosity, abs(κu_reference))

        maximum_stale_tke_difference = max(maximum_stale_tke_difference, abs(e_reference - e_stale))
        maximum_stale_dissipation_difference = max(maximum_stale_dissipation_difference, abs(ϵ_reference - ϵ_stale))
        maximum_stale_viscosity_difference = max(maximum_stale_viscosity_difference, abs(κu_reference - κu_stale))
    end

    @test maximum_reference_tke > sqrt(eps(FT))
    @test maximum_reference_dissipation > sqrt(eps(FT))
    @test maximum_reference_viscosity > sqrt(eps(FT))
    @test maximum_stale_tke_difference > 100eps(FT) * max(one(FT), maximum_reference_tke)
    @test maximum_stale_dissipation_difference > 100eps(FT) * max(one(FT), maximum_reference_dissipation)
    @test maximum_stale_viscosity_difference > 100eps(FT) * max(one(FT), maximum_reference_viscosity)

    return nothing
end

function test_octahealpix_tke_dissipation_first_step_uses_current_velocities(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    closure = Oceananigans.TurbulenceClosures.TKEDissipationVerticalDiffusivity(FT)

    function build_model()
        model = HydrostaticFreeSurfaceModel(grid;
                                            tracers = (:b, :e, :ϵ),
                                            buoyancy = BuoyancyTracer(),
                                            free_surface = nothing,
                                            momentum_advection = nothing,
                                            tracer_advection = Centered(FT),
                                            closure = closure)

        set!(model,
             u = (λ, φ, z) -> convert(FT, 0.18) * sind(λ) + convert(FT, 0.05) * cosd(φ) + convert(FT, 0.07) * z,
             v = (λ, φ, z) -> convert(FT, 0.13) * cosd(λ) - convert(FT, 0.04) * sind(φ) - convert(FT, 0.06) * z,
             b = (λ, φ, z) -> convert(FT, 0.06) * sind(λ / 2) * cosd(φ) + convert(FT, 0.24) * z,
             e = (λ, φ, z) -> convert(FT, 3e-4) + convert(FT, 9e-5) * sind(λ) * cosd(φ) + convert(FT, 4e-5) * z,
             ϵ = (λ, φ, z) -> convert(FT, 4e-4) + convert(FT, 7e-5) * cosd(λ) * sind(φ) + convert(FT, 3e-5) * z)

        return model
    end

    function zero_tke_dissipation_previous_velocities!(previous_velocities)
        parent(previous_velocities.u) .= zero(FT)
        parent(previous_velocities.v) .= zero(FT)
        return nothing
    end

    reference_model = build_model()
    Oceananigans.TurbulenceClosures.initialize_closure_fields!(reference_model.closure_fields,
                                                               reference_model.closure,
                                                               reference_model)
    Oceananigans.TurbulenceClosures.step_closure_prognostics!(reference_model.closure_fields,
                                                              reference_model.closure,
                                                              reference_model,
                                                              one(FT))
    Oceananigans.TurbulenceClosures.compute_closure_fields!(reference_model.closure_fields,
                                                            reference_model.closure,
                                                            reference_model)

    guarded_model = build_model()
    zero_tke_dissipation_previous_velocities!(guarded_model.closure_fields.previous_velocities)
    Oceananigans.TurbulenceClosures.step_closure_prognostics!(guarded_model.closure_fields,
                                                              guarded_model.closure,
                                                              guarded_model,
                                                              one(FT))
    Oceananigans.TurbulenceClosures.compute_closure_fields!(guarded_model.closure_fields,
                                                            guarded_model.closure,
                                                            guarded_model)

    stale_model = build_model()
    zero_tke_dissipation_previous_velocities!(stale_model.closure_fields.previous_velocities)
    stale_model.clock.iteration = 1
    Oceananigans.TurbulenceClosures.step_closure_prognostics!(stale_model.closure_fields,
                                                              stale_model.closure,
                                                              stale_model,
                                                              one(FT))
    Oceananigans.TurbulenceClosures.compute_closure_fields!(stale_model.closure_fields,
                                                            stale_model.closure,
                                                            stale_model)

    sampled_points = ((1, N + 1, 1),
                      (N + 1, 1, 2),
                      (2N, N + 1, 1),
                      (N + 1, 2N, 2),
                      (N + 2, N + 2, 1))

    maximum_reference_tke = zero(FT)
    maximum_reference_dissipation = zero(FT)
    maximum_reference_viscosity = zero(FT)
    maximum_guarded_tke_error = zero(FT)
    maximum_guarded_dissipation_error = zero(FT)
    maximum_guarded_viscosity_error = zero(FT)
    maximum_stale_tke_difference = zero(FT)
    maximum_stale_dissipation_difference = zero(FT)
    maximum_stale_viscosity_difference = zero(FT)

    for (i, j, k) in sampled_points
        e_reference = reference_model.tracers.e[i, j, k]
        ϵ_reference = reference_model.tracers.ϵ[i, j, k]
        κu_reference = reference_model.closure_fields.κu[i, j, k]

        e_guarded = guarded_model.tracers.e[i, j, k]
        ϵ_guarded = guarded_model.tracers.ϵ[i, j, k]
        κu_guarded = guarded_model.closure_fields.κu[i, j, k]

        e_stale = stale_model.tracers.e[i, j, k]
        ϵ_stale = stale_model.tracers.ϵ[i, j, k]
        κu_stale = stale_model.closure_fields.κu[i, j, k]

        maximum_reference_tke = max(maximum_reference_tke, abs(e_reference))
        maximum_reference_dissipation = max(maximum_reference_dissipation, abs(ϵ_reference))
        maximum_reference_viscosity = max(maximum_reference_viscosity, abs(κu_reference))

        maximum_guarded_tke_error = max(maximum_guarded_tke_error, abs(e_reference - e_guarded))
        maximum_guarded_dissipation_error = max(maximum_guarded_dissipation_error, abs(ϵ_reference - ϵ_guarded))
        maximum_guarded_viscosity_error = max(maximum_guarded_viscosity_error, abs(κu_reference - κu_guarded))

        maximum_stale_tke_difference = max(maximum_stale_tke_difference, abs(e_reference - e_stale))
        maximum_stale_dissipation_difference = max(maximum_stale_dissipation_difference, abs(ϵ_reference - ϵ_stale))
        maximum_stale_viscosity_difference = max(maximum_stale_viscosity_difference, abs(κu_reference - κu_stale))
    end

    @test maximum_reference_tke > sqrt(eps(FT))
    @test maximum_reference_dissipation > sqrt(eps(FT))
    @test maximum_reference_viscosity > sqrt(eps(FT))
    @test maximum_guarded_tke_error ≤ 1000eps(FT) * max(one(FT), maximum_reference_tke)
    @test maximum_guarded_dissipation_error ≤ 1000eps(FT) * max(one(FT), maximum_reference_dissipation)
    @test maximum_guarded_viscosity_error ≤ 1000eps(FT) * max(one(FT), maximum_reference_viscosity)
    @test maximum_stale_tke_difference > 100eps(FT) * max(one(FT), maximum_reference_tke)
    @test maximum_stale_dissipation_difference > 100eps(FT) * max(one(FT), maximum_reference_dissipation)
    @test maximum_stale_viscosity_difference > 100eps(FT) * max(one(FT), maximum_reference_viscosity)

    return nothing
end

function test_octahealpix_tke_dissipation_rk_substep_skips_closure_tracers(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    closure = Oceananigans.TurbulenceClosures.TKEDissipationVerticalDiffusivity(FT)

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = (:b, :e, :ϵ, :c),
                                        buoyancy = BuoyancyTracer(),
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT),
                                        closure = closure)

    set!(model,
         b = (λ, φ, z) -> convert(FT, 0.04) * sind(λ / 2) * cosd(φ) + convert(FT, 0.18) * z,
         e = (λ, φ, z) -> convert(FT, 3e-4) + convert(FT, 8e-5) * sind(λ) * cosd(φ) + convert(FT, 3e-5) * z,
         ϵ = (λ, φ, z) -> convert(FT, 4e-4) + convert(FT, 7e-5) * cosd(λ) * sind(φ) + convert(FT, 2e-5) * z,
         c = (λ, φ, z) -> convert(FT, 0.02) * sind(λ) - convert(FT, 0.01) * cosd(φ) + convert(FT, 0.03) * z)

    fill_halo_regions!(model.tracers, model.clock, fields(model))
    Oceananigans.TimeSteppers.cache_current_fields!(model)

    for tracer_name in (:e, :ϵ, :c)
        parent(model.timestepper.Gⁿ[tracer_name]) .= zero(FT)
    end

    parent(model.timestepper.Gⁿ.e) .= convert(FT, 2)
    parent(model.timestepper.Gⁿ.ϵ) .= convert(FT, -3)
    parent(model.timestepper.Gⁿ.c) .= convert(FT, 5)

    e_before = deepcopy(parent(model.tracers.e))
    ϵ_before = deepcopy(parent(model.tracers.ϵ))
    c_before = deepcopy(parent(model.tracers.c))

    Oceananigans.Models.HydrostaticFreeSurfaceModels.rk_substep_tracers!(model.tracers, model, convert(FT, 0.1))

    maximum_e_change = maximum(abs, parent(model.tracers.e) .- e_before)
    maximum_ϵ_change = maximum(abs, parent(model.tracers.ϵ) .- ϵ_before)
    maximum_c_change = maximum(abs, parent(model.tracers.c) .- c_before)

    @test maximum_e_change == zero(FT)
    @test maximum_ϵ_change == zero(FT)
    @test maximum_c_change > 100eps(FT)

    return nothing
end

function test_octahealpix_model_step_closure_prognostics_refreshes_state_halos(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    closure = Oceananigans.TurbulenceClosures.CATKEVerticalDiffusivity(FT)

    function build_model()
        model = HydrostaticFreeSurfaceModel(grid;
                                            tracers = (:b, :e),
                                            buoyancy = BuoyancyTracer(),
                                            free_surface = nothing,
                                            momentum_advection = nothing,
                                            tracer_advection = Centered(FT),
                                            closure = closure)

        set!(model,
             u = (λ, φ, z) -> convert(FT, 0.17) * sind(λ) + convert(FT, 0.05) * cosd(φ) + convert(FT, 0.07) * z,
             v = (λ, φ, z) -> convert(FT, 0.12) * cosd(λ) - convert(FT, 0.04) * sind(φ) - convert(FT, 0.06) * z,
             b = (λ, φ, z) -> convert(FT, 0.06) * sind(λ / 2) * cosd(φ) + convert(FT, 0.23) * z,
             e = (λ, φ, z) -> convert(FT, 2e-4) + convert(FT, 7e-5) * sind(λ) * cosd(φ) + convert(FT, 3e-5) * z)

        Oceananigans.TurbulenceClosures.initialize_closure_fields!(model.closure_fields, model.closure, model)
        model.clock.iteration = 3

        return model
    end

    function corrupt_catke_step_state_halos!(model)
        u = model.velocities.u
        v = model.velocities.v
        b = model.tracers.b
        e = model.tracers.e

        for k in 1:grid.Nz, j in 0:(size(u, 2) + 1), i in 0:(size(u, 1) + 1)
            (1 <= i <= size(u, 1) && 1 <= j <= size(u, 2)) && continue
            u[i, j, k] = convert(FT, 3i - 2j + k)
        end

        for k in 1:grid.Nz, j in 0:(size(v, 2) + 1), i in 0:(size(v, 1) + 1)
            (1 <= i <= size(v, 1) && 1 <= j <= size(v, 2)) && continue
            v[i, j, k] = convert(FT, -2i + 4j - k)
        end

        for k in 1:grid.Nz, j in 0:(size(b, 2) + 1), i in 0:(size(b, 1) + 1)
            (1 <= i <= size(b, 1) && 1 <= j <= size(b, 2)) && continue
            b[i, j, k] = convert(FT, i - 3j + 2k)
            e[i, j, k] = convert(FT, -4i + j - k)
        end

        return nothing
    end

    reference_model = build_model()
    Oceananigans.TimeSteppers.step_closure_prognostics!(reference_model, one(FT))
    Oceananigans.TurbulenceClosures.compute_closure_fields!(reference_model.closure_fields,
                                                            reference_model.closure,
                                                            reference_model)

    guarded_model = build_model()
    corrupt_catke_step_state_halos!(guarded_model)
    Oceananigans.TimeSteppers.step_closure_prognostics!(guarded_model, one(FT))
    Oceananigans.TurbulenceClosures.compute_closure_fields!(guarded_model.closure_fields,
                                                            guarded_model.closure,
                                                            guarded_model)

    stale_model = build_model()
    corrupt_catke_step_state_halos!(stale_model)
    Oceananigans.TurbulenceClosures.step_closure_prognostics!(stale_model.closure_fields,
                                                              stale_model.closure,
                                                              stale_model,
                                                              one(FT))
    Oceananigans.TurbulenceClosures.compute_closure_fields!(stale_model.closure_fields,
                                                            stale_model.closure,
                                                            stale_model)

    sampled_points = ((1, N + 1, 1),
                      (N + 1, 1, 2),
                      (2N, N + 1, 1),
                      (N + 1, 2N, 2),
                      (N + 2, N + 2, 1))

    maximum_reference_tke = zero(FT)
    maximum_reference_viscosity = zero(FT)
    maximum_guarded_tke_error = zero(FT)
    maximum_guarded_viscosity_error = zero(FT)
    maximum_stale_tke_difference = zero(FT)
    maximum_stale_viscosity_difference = zero(FT)

    for (i, j, k) in sampled_points
        e_reference = reference_model.tracers.e[i, j, k]
        κu_reference = reference_model.closure_fields.κu[i, j, k]

        e_guarded = guarded_model.tracers.e[i, j, k]
        κu_guarded = guarded_model.closure_fields.κu[i, j, k]

        e_stale = stale_model.tracers.e[i, j, k]
        κu_stale = stale_model.closure_fields.κu[i, j, k]

        maximum_reference_tke = max(maximum_reference_tke, abs(e_reference))
        maximum_reference_viscosity = max(maximum_reference_viscosity, abs(κu_reference))
        maximum_guarded_tke_error = max(maximum_guarded_tke_error, abs(e_reference - e_guarded))
        maximum_guarded_viscosity_error = max(maximum_guarded_viscosity_error, abs(κu_reference - κu_guarded))
        maximum_stale_tke_difference = max(maximum_stale_tke_difference, abs(e_reference - e_stale))
        maximum_stale_viscosity_difference = max(maximum_stale_viscosity_difference, abs(κu_reference - κu_stale))
    end

    @test maximum_reference_tke > sqrt(eps(FT))
    @test maximum_reference_viscosity > sqrt(eps(FT))
    @test maximum_guarded_tke_error ≤ 1000eps(FT) * max(one(FT), maximum_reference_tke)
    @test maximum_guarded_viscosity_error ≤ 1000eps(FT) * max(one(FT), maximum_reference_viscosity)
    @test maximum_stale_tke_difference > 100eps(FT) * max(one(FT), maximum_reference_tke)
    @test maximum_stale_viscosity_difference > 100eps(FT) * max(one(FT), maximum_reference_viscosity)

    return nothing
end

