    @test maximum_guarded_viscosity_error ≤ 1000eps(FT) * max(one(FT), maximum_reference_viscosity)
    @test maximum_stale_tke_difference > 100eps(FT) * max(one(FT), maximum_reference_tke)
    @test maximum_stale_dissipation_difference > 100eps(FT) * max(one(FT), maximum_reference_dissipation)
    @test maximum_stale_viscosity_difference > 100eps(FT) * max(one(FT), maximum_reference_viscosity)

    return nothing
end

function test_octahealpix_model_set_velocity_refreshes_catke_previous_velocities(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    closure = Oceananigans.TurbulenceClosures.CATKEVerticalDiffusivity(FT)

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = (:b, :e),
                                        buoyancy = BuoyancyTracer(),
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT),
                                        closure = closure)

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.11) * sind(λ) + convert(FT, 0.03) * cosd(φ) + convert(FT, 0.04) * z,
         v = (λ, φ, z) -> convert(FT, 0.09) * cosd(λ) - convert(FT, 0.02) * sind(φ) - convert(FT, 0.05) * z,
         b = (λ, φ, z) -> convert(FT, 0.05) * sind(λ / 2) * cosd(φ) + convert(FT, 0.21) * z,
         e = (λ, φ, z) -> convert(FT, 2e-4) + convert(FT, 6e-5) * sind(λ) * cosd(φ) + convert(FT, 2e-5) * z)

    model.clock.iteration = 3

    previous_u = model.closure_fields.previous_velocities.u
    previous_v = model.closure_fields.previous_velocities.v

    parent(previous_u) .= convert(FT, -7)
    parent(previous_v) .= convert(FT, 9)

    current_u = model.velocities.u
    current_v = model.velocities.v

    poisoned_u_difference = maximum(abs, parent(previous_u) .- parent(current_u))
    poisoned_v_difference = maximum(abs, parent(previous_v) .- parent(current_v))

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.19) * sind(λ) + convert(FT, 0.06) * cosd(φ) + convert(FT, 0.08) * z,
         v = (λ, φ, z) -> convert(FT, 0.14) * cosd(λ) - convert(FT, 0.05) * sind(φ) - convert(FT, 0.07) * z,
         reconcile_state = false)

    refreshed_u_difference = maximum(abs, parent(previous_u) .- parent(current_u))
    refreshed_v_difference = maximum(abs, parent(previous_v) .- parent(current_v))
    velocity_scale = max(one(FT),
                         maximum(abs, parent(current_u)),
                         maximum(abs, parent(current_v)))

    @test poisoned_u_difference > 100eps(FT) * velocity_scale
    @test poisoned_v_difference > 100eps(FT) * velocity_scale
    @test refreshed_u_difference ≤ 1000eps(FT) * velocity_scale
    @test refreshed_v_difference ≤ 1000eps(FT) * velocity_scale

    return nothing
end

function test_octahealpix_ri_filter_halos_drive_vertical_diffusivity(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    closure = Oceananigans.TurbulenceClosures.RiBasedVerticalDiffusivity(FT;
                                                                         horizontal_Ri_filter = Oceananigans.TurbulenceClosures.FivePointHorizontalFilter())

    function build_model()
        model = HydrostaticFreeSurfaceModel(grid;
                                            tracers = :b,
                                            buoyancy = BuoyancyTracer(),
                                            free_surface = nothing,
                                            momentum_advection = nothing,
                                            tracer_advection = Centered(FT),
                                            closure = closure)

        set!(model,
             u = (λ, φ, z) -> convert(FT, 0.22) * sind(λ) + convert(FT, 0.05) * cosd(φ) + convert(FT, 0.12) * z,
             v = (λ, φ, z) -> convert(FT, 0.16) * cosd(λ) - convert(FT, 0.04) * sind(φ) - convert(FT, 0.11) * z,
             b = (λ, φ, z) -> convert(FT, 0.09) * sind(λ / 2) * cosd(φ) + convert(FT, 0.35) * z)

        model.clock.time = one(FT)

        return model
    end

    function corrupt_ri_halos!(Ri)
        for k in 1:(grid.Nz + 1), j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
            (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue
            Ri[i, j, k] = convert(FT, 3i - 2j + k)
        end

        return nothing
    end

    reference_model = build_model()
    Oceananigans.TurbulenceClosures.compute_closure_fields!(reference_model.closure_fields,
                                                            reference_model.closure,
                                                            reference_model)

    stale_model = build_model()
    arch = CPU()
    tracers = Oceananigans.TurbulenceClosures.buoyancy_tracers(stale_model)
    buoyancy = Oceananigans.TurbulenceClosures.buoyancy_force(stale_model)
    top_tracer_bcs = NamedTuple(c => tracers[c].boundary_conditions.top for c in propertynames(tracers))

    Oceananigans.Utils.launch!(arch, grid, :xyz,
                               Oceananigans.TurbulenceClosures.compute_ri_number!,
                               stale_model.closure_fields,
                               grid,
                               stale_model.closure,
                               stale_model.velocities,
                               tracers,
                               buoyancy,
                               top_tracer_bcs,
                               stale_model.clock)

    fill_halo_regions!(stale_model.closure_fields.Ri; only_local_halos=true)
    corrupt_ri_halos!(stale_model.closure_fields.Ri)

    Oceananigans.Utils.launch!(arch, grid, :xyz,
                               Oceananigans.TurbulenceClosures.compute_ri_based_diffusivities!,
                               stale_model.closure_fields,
                               grid,
                               stale_model.closure,
                               stale_model.velocities,
                               tracers,
                               buoyancy,
                               top_tracer_bcs,
                               stale_model.clock)

    sampled_points = ((1, N + 1, 2),
                      (N + 1, 1, 2),
                      (2N, N + 1, 2),
                      (N + 1, 2N, 2),
                      (N + 2, N + 2, 2))

    maximum_reference_scale = zero(FT)
    maximum_stale_difference = zero(FT)

    for (i, j, k) in sampled_points
        κu_reference = reference_model.closure_fields.κu[i, j, k]
        κc_reference = reference_model.closure_fields.κc[i, j, k]
        κu_stale = stale_model.closure_fields.κu[i, j, k]
        κc_stale = stale_model.closure_fields.κc[i, j, k]

        maximum_reference_scale = max(maximum_reference_scale, abs(κu_reference), abs(κc_reference))
        maximum_stale_difference = max(maximum_stale_difference,
                                       abs(κu_reference - κu_stale),
                                       abs(κc_reference - κc_stale))
    end

    @test maximum_reference_scale > sqrt(eps(FT))
    @test maximum_stale_difference > 100eps(FT) * max(one(FT), maximum_reference_scale)

    return nothing
end

function test_octahealpix_variance_dissipation_uses_transport_fluxes_directly(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model, u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
                v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ),
                c = (λ, φ, z) -> sind(λ / 2) + convert(FT, 0.2) * cosd(φ) + convert(FT, 0.1) * z)

    compute_transport_velocities!(model, model.free_surface)

    ϵ = Oceananigans.Models.VarianceDissipationComputations.VarianceDissipation(:c, grid)
    Oceananigans.Models.VarianceDissipationComputations.cache_fluxes!(ϵ, model, :c)

    scheme = model.advection.c
    samples = ((N + 2, N + 2, 1),
               (2, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (N - 1, div(N, 2), 1))
    maximum_transformed_difference = zero(FT)

    for (i, j, k) in samples
        expected_transport_u = model.transport_velocities.u[i, j, k]
        expected_transport_v = model.transport_velocities.v[i, j, k]
        computed_transport_u = ϵ.previous_state.Uⁿ.u[i, j, k]
        computed_transport_v = ϵ.previous_state.Uⁿ.v[i, j, k]
        transport_scale = max(one(FT), abs(expected_transport_u), abs(expected_transport_v),
                              abs(computed_transport_u), abs(computed_transport_v))

        @test abs(computed_transport_u - expected_transport_u) ≤ 1000eps(FT) * transport_scale
        @test abs(computed_transport_v - expected_transport_v) ≤ 1000eps(FT) * transport_scale

        expected_fx = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_x(i, j, k, grid, scheme,
                                                                                     model.transport_velocities,
                                                                                     model.tracers.c)
        expected_fy = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_y(i, j, k, grid, scheme,
                                                                                     model.transport_velocities,
                                                                                     model.tracers.c)
        naive_fx = Oceananigans.Advection._advective_tracer_flux_x(i, j, k, grid, scheme,
                                                                   model.transport_velocities.u,
                                                                   model.tracers.c)
        naive_fy = Oceananigans.Advection._advective_tracer_flux_y(i, j, k, grid, scheme,
                                                                   model.transport_velocities.v,
                                                                   model.tracers.c)
        computed_fx = ϵ.advective_fluxes.Fⁿ.x[i, j, k]
        computed_fy = ϵ.advective_fluxes.Fⁿ.y[i, j, k]
        flux_scale = max(one(FT), abs(expected_fx), abs(expected_fy), abs(computed_fx), abs(computed_fy))

        @test abs(computed_fx - expected_fx) ≤ 1000eps(FT) * flux_scale
        @test abs(computed_fy - expected_fy) ≤ 1000eps(FT) * flux_scale

        maximum_transformed_difference = max(maximum_transformed_difference,
                                             abs(expected_fx - naive_fx),
                                             abs(expected_fy - naive_fy))
    end

    @test maximum_transformed_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_bounds_preserving_variance_dissipation_uses_limited_transport_fluxes(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    scheme = Oceananigans.Advection.WENO(FT; order = 1, bounds = (zero(FT), one(FT)))
    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = scheme)

    set!(model, u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
                v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ),
                c = (λ, φ, z) -> convert(FT, 0.5) + convert(FT, 0.1) * sind(λ / 2) + convert(FT, 0.05) * cosd(φ))

    compute_transport_velocities!(model, model.free_surface)

    ϵ = Oceananigans.Models.VarianceDissipationComputations.VarianceDissipation(:c, grid)
    Oceananigans.Models.VarianceDissipationComputations.cache_fluxes!(ϵ, model, :c)

    function limited_transport_flux_x(i, j, k, U, c)
        c_min = scheme.bounds[1]
        c_max = scheme.bounds[2]
        ω̂₁ = convert(FT, 5//18)
        ω̂ₙ = convert(FT, 5//18)
        ε₂ = convert(FT, 1e-20)

        volume_flux = @inbounds U.u[i, j, k]
        positive_flux = volume_flux > zero(FT)

        cᵢⱼ = @inbounds c[i, j, k]
        cᵢ₋₁ⱼ = @inbounds c[i-1, j, k]

        c₊ᴸ = Oceananigans.Advection._biased_interpolate_xᶠᵃᵃ(i,   j, k, grid, scheme, Oceananigans.Advection.LeftBias,  c)
        c₋ᴿ = Oceananigans.Advection._biased_interpolate_xᶠᵃᵃ(i-1, j, k, grid, scheme, Oceananigans.Advection.RightBias, c)
        p̃₊ = (cᵢ₋₁ⱼ - ω̂₁ * c₋ᴿ - ω̂ₙ * c₊ᴸ) / (1 - 2ω̂₁)
        M₊ = max(p̃₊, c₊ᴸ, c₋ᴿ)
        m₊ = min(p̃₊, c₊ᴸ, c₋ᴿ)
        θ₊ = min(abs((c_max - cᵢ₋₁ⱼ) / (M₊ - cᵢ₋₁ⱼ + ε₂)),
                 abs((c_min - cᵢ₋₁ⱼ) / (m₊ - cᵢ₋₁ⱼ + ε₂)),
                 one(FT))
        limited_positive_state = θ₊ * (c₊ᴸ - cᵢ₋₁ⱼ) + cᵢ₋₁ⱼ

        c₊ᴸ₂ = Oceananigans.Advection._biased_interpolate_xᶠᵃᵃ(i+1, j, k, grid, scheme, Oceananigans.Advection.LeftBias,  c)
        c₋ᴿ₂ = Oceananigans.Advection._biased_interpolate_xᶠᵃᵃ(i,   j, k, grid, scheme, Oceananigans.Advection.RightBias, c)
        p̃₋ = (cᵢⱼ - ω̂₁ * c₋ᴿ₂ - ω̂ₙ * c₊ᴸ₂) / (1 - 2ω̂₁)
        M₋ = max(p̃₋, c₊ᴸ₂, c₋ᴿ₂)
        m₋ = min(p̃₋, c₊ᴸ₂, c₋ᴿ₂)
        θ₋ = min(abs((c_max - cᵢⱼ) / (M₋ - cᵢⱼ + ε₂)),
                 abs((c_min - cᵢⱼ) / (m₋ - cᵢⱼ + ε₂)),
                 one(FT))
        limited_negative_state = θ₋ * (c₋ᴿ₂ - cᵢⱼ) + cᵢⱼ

        return ifelse(positive_flux,
                      volume_flux * limited_positive_state,
                      volume_flux * limited_negative_state)
    end

    function limited_transport_flux_y(i, j, k, U, c)
        c_min = scheme.bounds[1]
        c_max = scheme.bounds[2]
        ω̂₁ = convert(FT, 5//18)
        ω̂ₙ = convert(FT, 5//18)
        ε₂ = convert(FT, 1e-20)

        volume_flux = @inbounds U.v[i, j, k]
        positive_flux = volume_flux > zero(FT)

        cᵢⱼ = @inbounds c[i, j, k]
        cᵢⱼ₋₁ = @inbounds c[i, j-1, k]

        c₊ᴸ = Oceananigans.Advection._biased_interpolate_yᵃᶠᵃ(i, j,   k, grid, scheme, Oceananigans.Advection.LeftBias,  c)
        c₋ᴿ = Oceananigans.Advection._biased_interpolate_yᵃᶠᵃ(i, j-1, k, grid, scheme, Oceananigans.Advection.RightBias, c)
        p̃₊ = (cᵢⱼ₋₁ - ω̂₁ * c₋ᴿ - ω̂ₙ * c₊ᴸ) / (1 - 2ω̂₁)
        M₊ = max(p̃₊, c₊ᴸ, c₋ᴿ)
        m₊ = min(p̃₊, c₊ᴸ, c₋ᴿ)
        θ₊ = min(abs((c_max - cᵢⱼ₋₁) / (M₊ - cᵢⱼ₋₁ + ε₂)),
                 abs((c_min - cᵢⱼ₋₁) / (m₊ - cᵢⱼ₋₁ + ε₂)),
                 one(FT))
        limited_positive_state = θ₊ * (c₊ᴸ - cᵢⱼ₋₁) + cᵢⱼ₋₁

        c₊ᴸ₂ = Oceananigans.Advection._biased_interpolate_yᵃᶠᵃ(i, j+1, k, grid, scheme, Oceananigans.Advection.LeftBias,  c)
        c₋ᴿ₂ = Oceananigans.Advection._biased_interpolate_yᵃᶠᵃ(i, j,   k, grid, scheme, Oceananigans.Advection.RightBias, c)
        p̃₋ = (cᵢⱼ - ω̂₁ * c₋ᴿ₂ - ω̂ₙ * c₊ᴸ₂) / (1 - 2ω̂₁)
        M₋ = max(p̃₋, c₊ᴸ₂, c₋ᴿ₂)
        m₋ = min(p̃₋, c₊ᴸ₂, c₋ᴿ₂)
        θ₋ = min(abs((c_max - cᵢⱼ) / (M₋ - cᵢⱼ + ε₂)),
                 abs((c_min - cᵢⱼ) / (m₋ - cᵢⱼ + ε₂)),
                 one(FT))
        limited_negative_state = θ₋ * (c₋ᴿ₂ - cᵢⱼ) + cᵢⱼ

        return ifelse(positive_flux,
                      volume_flux * limited_positive_state,
                      volume_flux * limited_negative_state)
    end

    samples = ((N + 2, N + 2, 1),
               (2, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (N - 1, div(N, 2), 1))
    maximum_limiter_difference = zero(FT)

    for (i, j, k) in samples
        expected_fx = limited_transport_flux_x(i, j, k, model.transport_velocities, model.tracers.c)
        expected_fy = limited_transport_flux_y(i, j, k, model.transport_velocities, model.tracers.c)
        naive_fx = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_x(i, j, k, grid,
                                                                                  Oceananigans.Advection.WENO(FT; order = 1),
                                                                                  model.transport_velocities,
                                                                                  model.tracers.c)
        naive_fy = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_y(i, j, k, grid,
                                                                                  Oceananigans.Advection.WENO(FT; order = 1),
                                                                                  model.transport_velocities,
                                                                                  model.tracers.c)
        computed_fx = ϵ.advective_fluxes.Fⁿ.x[i, j, k]
        computed_fy = ϵ.advective_fluxes.Fⁿ.y[i, j, k]
        flux_scale = max(one(FT), abs(expected_fx), abs(expected_fy), abs(computed_fx), abs(computed_fy))

        @test abs(computed_fx - expected_fx) ≤ 1000eps(FT) * flux_scale
        @test abs(computed_fy - expected_fy) ≤ 1000eps(FT) * flux_scale

        maximum_limiter_difference = max(maximum_limiter_difference,
                                         abs(expected_fx - naive_fx),
                                         abs(expected_fy - naive_fy))
    end

    @test maximum_limiter_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_variance_dissipation_vertical_transport_cache_uses_flux_form(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities = PrescribedVelocityFields(),
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model, c = (λ, φ, z) -> convert(FT, 0.1) * z + convert(FT, 0.02) * sind(λ))
    set!(model.transport_velocities.u, zero(FT))
    set!(model.transport_velocities.v, zero(FT))
    set!(model.transport_velocities.w, (λ, φ, z) -> convert(FT, 0.2) * z + convert(FT, 0.03) * cosd(φ))

    fill_halo_regions!((model.transport_velocities.u, model.transport_velocities.v))
    fill_halo_regions!(model.transport_velocities.w)

    ϵ = Oceananigans.Models.VarianceDissipationComputations.VarianceDissipation(:c, grid)
    Oceananigans.Models.VarianceDissipationComputations.cache_fluxes!(ϵ, model, :c)

    samples = ((2, div(N, 2), 1),
               (N - 1, div(N, 2), 1),
               (div(N, 2), 2, 2),
               (div(N, 2), N - 1, 2))

    for (i, j, k) in samples
        expected_flux = model.transport_velocities.w[i, j, k] *
                        Oceananigans.Operators.Azᶜᶜᶠ(i, j, k, grid)
        cached_flux = ϵ.previous_state.Uⁿ.w[i, j, k]
        flux_scale = max(one(FT), abs(expected_flux), abs(cached_flux))
        @test abs(cached_flux - expected_flux) ≤ 1000eps(FT) * flux_scale
    end

    return nothing
end

function test_octahealpix_nonhydrostatic_variance_dissipation_uses_transport_fluxes(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = NonhydrostaticModel(grid;
                                tracers = :c,
                                buoyancy = nothing,
                                advection = Centered(FT))

    set!(model, u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
                v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ),
                w = (λ, φ, z) -> convert(FT, 0.02) * sind(λ / 2) * cosd(φ),
                c = (λ, φ, z) -> sind(λ / 2) + convert(FT, 0.2) * cosd(φ) + convert(FT, 0.1) * z)

    ϵ = Oceananigans.Models.VarianceDissipationComputations.VarianceDissipation(:c, grid)
    Oceananigans.Models.VarianceDissipationComputations.cache_fluxes!(ϵ, model, :c)

    scheme = model.advection
    converted_transport = (u = OctaHEALPixConvertedTransportU(grid, model.velocities.u, model.velocities.v),
                           v = OctaHEALPixConvertedTransportV(grid, model.velocities.u, model.velocities.v),
                           w = model.velocities.w)

    samples = ((N + 2, N + 2, 1),
               (2, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (N - 1, div(N, 2), 1))
    maximum_transformed_difference = zero(FT)

    for (i, j, k) in samples
        expected_transport_u = converted_transport.u[i, j, k]
        expected_transport_v = converted_transport.v[i, j, k]
        computed_transport_u = ϵ.previous_state.Uⁿ.u[i, j, k]
        computed_transport_v = ϵ.previous_state.Uⁿ.v[i, j, k]
        transport_scale = max(one(FT), abs(expected_transport_u), abs(expected_transport_v),
                              abs(computed_transport_u), abs(computed_transport_v))

        @test abs(computed_transport_u - expected_transport_u) ≤ 1000eps(FT) * transport_scale
        @test abs(computed_transport_v - expected_transport_v) ≤ 1000eps(FT) * transport_scale

        expected_fx = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_x(i, j, k, grid, scheme,
                                                                                     converted_transport,
                                                                                     model.tracers.c)
        expected_fy = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_y(i, j, k, grid, scheme,
                                                                                     converted_transport,
                                                                                     model.tracers.c)
        naive_fx = Oceananigans.Advection._advective_tracer_flux_x(i, j, k, grid, scheme,
                                                                   model.velocities.u,
                                                                   model.tracers.c)
        naive_fy = Oceananigans.Advection._advective_tracer_flux_y(i, j, k, grid, scheme,
                                                                   model.velocities.v,
                                                                   model.tracers.c)
        computed_fx = ϵ.advective_fluxes.Fⁿ.x[i, j, k]
        computed_fy = ϵ.advective_fluxes.Fⁿ.y[i, j, k]
        flux_scale = max(one(FT), abs(expected_fx), abs(expected_fy), abs(computed_fx), abs(computed_fy))

        @test abs(computed_fx - expected_fx) ≤ 1000eps(FT) * flux_scale
        @test abs(computed_fy - expected_fy) ≤ 1000eps(FT) * flux_scale

        maximum_transformed_difference = max(maximum_transformed_difference,
                                             abs(expected_fx - naive_fx),
                                             abs(expected_fy - naive_fy))
    end

    @test maximum_transformed_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_variance_dissipation_includes_horizontal_biogeochemical_drift(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    drift_u = XFaceField(grid)
    drift_v = YFaceField(grid)

    set!((u = drift_u, v = drift_v);
         u = (λ, φ, z) -> convert(FT, 0.07) * sind(λ) + convert(FT, 0.02) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.05) * cosd(λ) - convert(FT, 0.015) * sind(φ))

    fill_halo_regions!((drift_u, drift_v))

    drift_velocity = (u = drift_u, v = drift_v, w = ZeroField())
    biogeochemistry = OctaHEALPixHorizontalDriftBiogeochemistry(drift_velocity)

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        biogeochemistry,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model, u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
                v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ),
                c = (λ, φ, z) -> sind(λ / 2) + convert(FT, 0.2) * cosd(φ) + convert(FT, 0.1) * z)

    compute_transport_velocities!(model, model.free_surface)

    ϵ = Oceananigans.Models.VarianceDissipationComputations.VarianceDissipation(:c, grid)
    Oceananigans.Models.VarianceDissipationComputations.cache_fluxes!(ϵ, model, :c)

    scheme = model.advection.c
    drift_transport = (u = OctaHEALPixConvertedTransportU(grid, drift_velocity.u, drift_velocity.v),
                       v = OctaHEALPixConvertedTransportV(grid, drift_velocity.u, drift_velocity.v),
                       w = ZeroField())
    total_transport = Oceananigans.Utils.sum_of_velocities(model.transport_velocities, drift_transport)

    samples = ((N + 2, N + 2, 1),
               (2, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (N - 1, div(N, 2), 1))
    maximum_auxiliary_difference = zero(FT)

    for (i, j, k) in samples
        expected_transport_u = total_transport.u[i, j, k]
        expected_transport_v = total_transport.v[i, j, k]
        computed_transport_u = ϵ.previous_state.Uⁿ.u[i, j, k]
        computed_transport_v = ϵ.previous_state.Uⁿ.v[i, j, k]
        transport_scale = max(one(FT), abs(expected_transport_u), abs(expected_transport_v),
                              abs(computed_transport_u), abs(computed_transport_v))

        @test abs(computed_transport_u - expected_transport_u) ≤ 1000eps(FT) * transport_scale
        @test abs(computed_transport_v - expected_transport_v) ≤ 1000eps(FT) * transport_scale

        expected_fx = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_x(i, j, k, grid, scheme,
                                                                                     total_transport,
                                                                                     model.tracers.c)
        expected_fy = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_y(i, j, k, grid, scheme,
                                                                                     total_transport,
                                                                                     model.tracers.c)
        naive_fx = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_x(i, j, k, grid, scheme,
                                                                                  model.transport_velocities,
                                                                                  model.tracers.c)
        naive_fy = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_y(i, j, k, grid, scheme,
                                                                                  model.transport_velocities,
                                                                                  model.tracers.c)
        computed_fx = ϵ.advective_fluxes.Fⁿ.x[i, j, k]
        computed_fy = ϵ.advective_fluxes.Fⁿ.y[i, j, k]
        flux_scale = max(one(FT), abs(expected_fx), abs(expected_fy), abs(computed_fx), abs(computed_fy))

        @test abs(computed_fx - expected_fx) ≤ 1000eps(FT) * flux_scale
        @test abs(computed_fy - expected_fy) ≤ 1000eps(FT) * flux_scale

        maximum_auxiliary_difference = max(maximum_auxiliary_difference,
                                           abs(expected_transport_u - model.transport_velocities.u[i, j, k]),
                                           abs(expected_transport_v - model.transport_velocities.v[i, j, k]),
                                           abs(expected_fx - naive_fx),
                                           abs(expected_fy - naive_fy))
    end

    @test maximum_auxiliary_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_nonhydrostatic_variance_dissipation_includes_background_transport(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    background_fields = (
        u = (λ, φ, z, t) -> convert(FT, 0.08) * cosd(λ) + convert(FT, 0.03) * sind(φ),
        v = (λ, φ, z, t) -> convert(FT, 0.06) * sind(λ / 2) - convert(FT, 0.02) * cosd(φ),
        w = (λ, φ, z, t) -> zero(FT)
    )

    model = NonhydrostaticModel(grid;
                                timestepper = :QuasiAdamsBashforth2,
                                tracers = :c,
                                buoyancy = nothing,
                                advection = Centered(FT),
                                background_fields)

    set!(model, u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
                v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ),
                w = (λ, φ, z) -> convert(FT, 0.02) * sind(λ / 2) * cosd(φ),
                c = (λ, φ, z) -> sind(λ / 2) + convert(FT, 0.2) * cosd(φ) + convert(FT, 0.1) * z)

    ϵ = Oceananigans.Models.VarianceDissipationComputations.VarianceDissipation(:c, grid)
    Oceananigans.Models.VarianceDissipationComputations.cache_fluxes!(ϵ, model, :c)

    scheme = model.advection
    total_velocities = Oceananigans.Utils.sum_of_velocities(model.velocities, model.background_fields.velocities)
    converted_transport = (u = OctaHEALPixConvertedTransportU(grid, total_velocities.u, total_velocities.v),
                           v = OctaHEALPixConvertedTransportV(grid, total_velocities.u, total_velocities.v),
                           w = total_velocities.w)
    naive_transport = (u = OctaHEALPixConvertedTransportU(grid, model.velocities.u, model.velocities.v),
                       v = OctaHEALPixConvertedTransportV(grid, model.velocities.u, model.velocities.v),
                       w = model.velocities.w)

    samples = ((N + 2, N + 2, 1),
               (2, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (N - 1, div(N, 2), 1))
    maximum_background_difference = zero(FT)

    for (i, j, k) in samples
        expected_transport_u = converted_transport.u[i, j, k]
        expected_transport_v = converted_transport.v[i, j, k]
        computed_transport_u = ϵ.previous_state.Uⁿ.u[i, j, k]
        computed_transport_v = ϵ.previous_state.Uⁿ.v[i, j, k]
        transport_scale = max(one(FT), abs(expected_transport_u), abs(expected_transport_v),
                              abs(computed_transport_u), abs(computed_transport_v))

        @test abs(computed_transport_u - expected_transport_u) ≤ 1000eps(FT) * transport_scale
        @test abs(computed_transport_v - expected_transport_v) ≤ 1000eps(FT) * transport_scale

        expected_fx = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_x(i, j, k, grid, scheme,
                                                                                     converted_transport,
                                                                                     model.tracers.c)
        expected_fy = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_y(i, j, k, grid, scheme,
                                                                                     converted_transport,
                                                                                     model.tracers.c)
        naive_fx = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_x(i, j, k, grid, scheme,
                                                                                  naive_transport,
                                                                                  model.tracers.c)
        naive_fy = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_y(i, j, k, grid, scheme,
                                                                                  naive_transport,
                                                                                  model.tracers.c)
        computed_fx = ϵ.advective_fluxes.Fⁿ.x[i, j, k]
        computed_fy = ϵ.advective_fluxes.Fⁿ.y[i, j, k]
        flux_scale = max(one(FT), abs(expected_fx), abs(expected_fy), abs(computed_fx), abs(computed_fy))

        @test abs(computed_fx - expected_fx) ≤ 1000eps(FT) * flux_scale
        @test abs(computed_fy - expected_fy) ≤ 1000eps(FT) * flux_scale

        maximum_background_difference = max(maximum_background_difference,
                                            abs(expected_transport_u - naive_transport.u[i, j, k]),
                                            abs(expected_transport_v - naive_transport.v[i, j, k]),
                                            abs(expected_fx - naive_fx),
                                            abs(expected_fy - naive_fy))
    end

    @test maximum_background_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_nonhydrostatic_variance_dissipation_refreshes_background_field_halos(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    background_u = XFaceField(grid)
    background_v = YFaceField(grid)
    reference_u = XFaceField(grid)
    reference_v = YFaceField(grid)

    set!((u = background_u, v = background_v);
         u = (λ, φ, z) -> convert(FT, 0.08) * cosd(λ) + convert(FT, 0.03) * sind(φ),
         v = (λ, φ, z) -> convert(FT, 0.06) * sind(λ / 2) - convert(FT, 0.02) * cosd(φ))

    set!((u = reference_u, v = reference_v);
         u = (λ, φ, z) -> convert(FT, 0.08) * cosd(λ) + convert(FT, 0.03) * sind(φ),
         v = (λ, φ, z) -> convert(FT, 0.06) * sind(λ / 2) - convert(FT, 0.02) * cosd(φ))

    fill_halo_regions!((reference_u, reference_v))

    background_fields = BackgroundFields(u = background_u, v = background_v)

    model = NonhydrostaticModel(grid;
                                timestepper = :QuasiAdamsBashforth2,
                                tracers = :c,
                                buoyancy = nothing,
                                advection = Centered(FT),
                                background_fields)

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ),
         w = (λ, φ, z) -> convert(FT, 0.02) * sind(λ / 2) * cosd(φ),
         c = (λ, φ, z) -> sind(λ / 2) + convert(FT, 0.2) * cosd(φ) + convert(FT, 0.1) * z)

    for j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue
        background_u[i, j, 1] = convert(FT, 111)
        background_v[i, j, 1] = convert(FT, -222)
    end

    ϵ = Oceananigans.Models.VarianceDissipationComputations.VarianceDissipation(:c, grid)
    Oceananigans.Models.VarianceDissipationComputations.cache_fluxes!(ϵ, model, :c)

    expected_total_velocities = Oceananigans.Utils.sum_of_velocities(model.velocities,
                                                                     (u = reference_u, v = reference_v, w = model.background_fields.velocities.w))
    stale_total_velocities = Oceananigans.Utils.sum_of_velocities(model.velocities,
                                                                  (u = background_u, v = background_v, w = model.background_fields.velocities.w))

    expected_transport = Oceananigans.Advection.spherical_shell_volume_flux_velocities(grid, expected_total_velocities)
    stale_transport = Oceananigans.Advection.spherical_shell_volume_flux_velocities(grid, stale_total_velocities)
    scheme = model.advection

    samples = ((N + 2, N + 2, 1),
               (2, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (N - 1, div(N, 2), 1))

    maximum_stale_difference = zero(FT)

    for (i, j, k) in samples
        expected_transport_u = expected_transport.u[i, j, k]
        expected_transport_v = expected_transport.v[i, j, k]
        computed_transport_u = ϵ.previous_state.Uⁿ.u[i, j, k]
        computed_transport_v = ϵ.previous_state.Uⁿ.v[i, j, k]
        stale_transport_u = stale_transport.u[i, j, k]
        stale_transport_v = stale_transport.v[i, j, k]

        transport_scale = max(one(FT), abs(expected_transport_u), abs(expected_transport_v),
                              abs(computed_transport_u), abs(computed_transport_v))

        @test abs(computed_transport_u - expected_transport_u) ≤ 1000eps(FT) * transport_scale
        @test abs(computed_transport_v - expected_transport_v) ≤ 1000eps(FT) * transport_scale

        expected_fx = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_x(i, j, k, grid, scheme,
                                                                                     expected_transport,
                                                                                     model.tracers.c)
        expected_fy = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_y(i, j, k, grid, scheme,
                                                                                     expected_transport,
                                                                                     model.tracers.c)
        stale_fx = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_x(i, j, k, grid, scheme,
                                                                                  stale_transport,
                                                                                  model.tracers.c)
        stale_fy = Oceananigans.Advection._nonorthogonal_advective_tracer_flux_y(i, j, k, grid, scheme,
                                                                                  stale_transport,
                                                                                  model.tracers.c)
        computed_fx = ϵ.advective_fluxes.Fⁿ.x[i, j, k]
        computed_fy = ϵ.advective_fluxes.Fⁿ.y[i, j, k]
        flux_scale = max(one(FT), abs(expected_fx), abs(expected_fy), abs(computed_fx), abs(computed_fy))

        @test abs(computed_fx - expected_fx) ≤ 1000eps(FT) * flux_scale
        @test abs(computed_fy - expected_fy) ≤ 1000eps(FT) * flux_scale

        maximum_stale_difference = max(maximum_stale_difference,
                                       abs(expected_transport_u - stale_transport_u),
                                       abs(expected_transport_v - stale_transport_v),
                                       abs(expected_fx - stale_fx),
                                       abs(expected_fy - stale_fy))
    end

    @test maximum_stale_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_cell_advection_timescale_uses_transport_fluxes_directly(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model, u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
                v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ))

    compute_transport_velocities!(model, model.free_surface)

    expected_timescale = typemax(FT)
    for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx
        inverse_timescale =
            abs(model.transport_velocities.u[i, j, k]) * Oceananigans.Operators.V⁻¹ᶜᶜᶜ(i, j, k, grid) +
            abs(model.transport_velocities.v[i, j, k]) * Oceananigans.Operators.V⁻¹ᶜᶜᶜ(i, j, k, grid) +
            abs(model.transport_velocities.w[i, j, k]) * Oceananigans.Operators.Δz⁻¹ᶜᶜᶠ(i, j, k, grid)

        expected_timescale = min(expected_timescale, one(FT) / inverse_timescale)
    end

    computed_timescale = Oceananigans.Advection.cell_advection_timescale(model)
    naive_timescale = Oceananigans.Advection.cell_advection_timescale(model.grid, model.velocities)
    timescale_scale = max(one(FT), abs(expected_timescale), abs(computed_timescale))

    @test abs(computed_timescale - expected_timescale) ≤ 1000eps(FT) * timescale_scale
    @test abs(expected_timescale - naive_timescale) > 100eps(FT)

    return nothing
end

