function test_octahealpix_cell_advection_timescale_includes_horizontal_momentum_advective_forcing(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    forcing_u = XFaceField(grid)
    forcing_v = YFaceField(grid)

    set!((u = forcing_u, v = forcing_v);
         u = (λ, φ, z) -> convert(FT, 0.18) * sind(λ) + convert(FT, 0.06) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.11) * cosd(λ) - convert(FT, 0.04) * sind(φ))

    fill_halo_regions!((forcing_u, forcing_v))

    forcing = (u = AdvectiveForcing(u = forcing_u, v = forcing_v),)

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        forcing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant(),
                                        tracer_advection = nothing)

    set!(model, u = zero(FT), v = zero(FT))
    compute_transport_velocities!(model, model.free_surface)

    auxiliary_velocities = Oceananigans.Models.HydrostaticFreeSurfaceModels.tracer_auxiliary_velocities(nothing, nothing, model.forcing.u)
    total_transport = Oceananigans.Models.HydrostaticFreeSurfaceModels.total_tracer_advection_velocities(grid,
                                                                                                          model.transport_velocities,
                                                                                                          auxiliary_velocities)

    expected_timescale = typemax(FT)
    for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx
        inverse_timescale =
            abs(total_transport.u[i, j, k]) * Oceananigans.Operators.V⁻¹ᶜᶜᶜ(i, j, k, grid) +
            abs(total_transport.v[i, j, k]) * Oceananigans.Operators.V⁻¹ᶜᶜᶜ(i, j, k, grid) +
            abs(total_transport.w[i, j, k]) * Oceananigans.Operators.Δz⁻¹ᶜᶜᶠ(i, j, k, grid)

        expected_timescale = min(expected_timescale, one(FT) / inverse_timescale)
    end

    computed_timescale = Oceananigans.Advection.cell_advection_timescale(model)
    naive_timescale = Oceananigans.Advection.cell_advection_timescale(model.grid, model.transport_velocities)
    timescale_scale = max(one(FT), abs(expected_timescale), abs(computed_timescale))

    @test abs(computed_timescale - expected_timescale) ≤ 1000eps(FT) * timescale_scale
    @test isfinite(expected_timescale)
    @test isinf(naive_timescale)

    return nothing
end

