function test_octahealpix_physical_velocity_multilayer_constant_tracer_conservation(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    Nz = 4
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, Nz),
                              z = (-one(FT), zero(FT)),
                              radius,
                              halo = (3, 3, 3))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    vertical_shear(z) = one(FT) + convert(FT, 1//2) * z
    set!(model,
         u = (λ, φ, z) -> vertical_shear(z) *
                          (convert(FT, 3//20) * sind(λ) +
                           convert(FT, 1//20) * cosd(φ)),
         v = (λ, φ, z) -> vertical_shear(z) *
                          (convert(FT, 1//10) * cosd(λ) -
                           convert(FT, 3//100) * sind(φ)),
         c = one(FT))

    compute_transport_velocities!(model, model.free_surface)
    compute_tracer_tendencies!(model)

    bottom_w = maximum(abs(model.transport_velocities.w[i, j, 1])
                       for j in 1:grid.Ny, i in 1:grid.Nx)

    top_w = maximum(abs(model.transport_velocities.w[i, j, grid.Nz + 1])
                    for j in 1:grid.Ny, i in 1:grid.Nx)

    interior_w = maximum(abs(model.transport_velocities.w[i, j, k])
                         for k in 2:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx)

    mass_tendency = sum(volume(i, j, k, grid, Center(), Center(), Center()) *
                        model.timestepper.Gⁿ.c[i, j, k]
                        for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx)

    mass_scale = sum(volume(i, j, k, grid, Center(), Center(), Center())
                     for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx)

    velocity_scale = max(one(FT), interior_w)

    @test bottom_w ≤ 1000eps(FT) * velocity_scale
    @test top_w ≤ 1000eps(FT) * velocity_scale
    @test interior_w > sqrt(eps(FT))
    @test abs(mass_tendency) ≤ 100eps(FT) * mass_scale

    return nothing
end

function test_octahealpix_multilayer_rigid_lid_transport_vertical_velocity_and_mass_conservation(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    Nz = 4
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, Nz),
                              z = (-one(FT), zero(FT)),
                              radius,
                              halo = (3, 3, 3))

    Nx = grid.Nx
    Ny = grid.Ny
    number_of_horizontal_faces = Nx * Ny
    number_of_horizontal_velocities = 2 * number_of_horizontal_faces
    Δα = Oceananigans.Operators.computational_width_uᶠᶜᶜ(1, 1, 1, grid)
    Δβ = Oceananigans.Operators.computational_width_vᶜᶠᶜ(1, 1, 1, grid)
    quarter = convert(FT, 1//4)

    function hodge_fluxes(u₁, u₂)
        F₁ = zeros(FT, Nx, Ny)
        F₂ = zeros(FT, Nx, Ny)

        for j in 1:Ny, i in 1:Nx
            i⁻ = mod1(i - 1, Nx)
            i⁺ = mod1(i + 1, Nx)
            j⁻ = mod1(j - 1, Ny)
            j⁺ = mod1(j + 1, Ny)

            u₂ᶠᶜᶜ = quarter * (u₂[i⁻, j] + u₂[i, j] + u₂[i⁻, j⁺] + u₂[i, j⁺])
            u₁ᶜᶠᶜ = quarter * (u₁[i, j⁻] + u₁[i⁺, j⁻] + u₁[i, j] + u₁[i⁺, j])

            F₁[i, j] = Δzᶠᶜᶜ(i, j, 1, grid) * Δβ *
                       (grid.metrics.G¹¹ᶠᶜᵃ[i, j] * u₁[i, j] +
                        grid.metrics.G¹²ᶠᶜᵃ[i, j] * u₂ᶠᶜᶜ)

            F₂[i, j] = Δzᶜᶠᶜ(i, j, 1, grid) * Δα *
                       (grid.metrics.G²¹ᶜᶠᵃ[i, j] * u₁ᶜᶠᶜ +
                        grid.metrics.G²²ᶜᶠᵃ[i, j] * u₂[i, j])
        end

        return F₁, F₂
    end

    hodge_matrix = zeros(FT, number_of_horizontal_velocities, number_of_horizontal_velocities)

    for n in 1:number_of_horizontal_velocities
        u₁ = zeros(FT, Nx, Ny)
        u₂ = zeros(FT, Nx, Ny)

        if n <= number_of_horizontal_faces
            u₁[n] = one(FT)
        else
            u₂[n - number_of_horizontal_faces] = one(FT)
        end

        F₁, F₂ = hodge_fluxes(u₁, u₂)
        hodge_matrix[:, n] .= vcat(vec(F₁), vec(F₂))
    end

    u₁_data = zeros(FT, Nx + 1, Ny, Nz)
    u₂_data = zeros(FT, Nx, Ny + 1, Nz)

    for k in 1:Nz
        amplitude = convert(FT, k) / convert(FT, 10Nz)

        volume_flux_x = [amplitude *
                         sin(2π * convert(FT, i) / convert(FT, Nx)) *
                         cos(2π * convert(FT, j) / convert(FT, Ny))
                         for i in 1:Nx, j in 1:Ny]

        volume_flux_y = zeros(FT, Nx, Ny)
        covariant_velocity_vector = hodge_matrix \ vcat(vec(volume_flux_x), vec(volume_flux_y))

        u₁_data[1:Nx, :, k] .= reshape(covariant_velocity_vector[1:number_of_horizontal_faces], Nx, Ny)
        u₂_data[:, 1:Ny, k] .= reshape(covariant_velocity_vector[(number_of_horizontal_faces + 1):end], Nx, Ny)

        u₁_data[Nx + 1, :, k] .= u₁_data[1, :, k]
        u₂_data[:, Ny + 1, k] .= u₂_data[:, 1, k]
    end

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    tracer = Array{FT}(undef, Nx, Ny, Nz)

    for k in 1:Nz, j in 1:Ny, i in 1:Nx
        tracer[i, j, k] = one(FT) +
                          convert(FT, 1//10) *
                          sin(2π * convert(FT, i) / convert(FT, Nx)) *
                          cos(2π * convert(FT, j) / convert(FT, Ny)) +
                          convert(FT, 1//20) * convert(FT, k) / convert(FT, Nz)
    end

    set!(model, u = u₁_data, v = u₂_data, c = tracer)

    compute_transport_velocities!(model, model.free_surface)

    bottom_w = maximum(abs(model.transport_velocities.w[i, j, 1])
                       for j in 1:grid.Ny, i in 1:grid.Nx)

    top_w = maximum(abs(model.transport_velocities.w[i, j, grid.Nz + 1])
                    for j in 1:grid.Ny, i in 1:grid.Nx)

    interior_w = maximum(abs(model.transport_velocities.w[i, j, k])
                         for k in 2:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx)

    function tracer_mass()
        return sum(volume(i, j, k, grid, Center(), Center(), Center()) *
                   model.tracers.c[i, j, k]
                   for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx)
    end

    initial_mass = tracer_mass()
    compute_tracer_tendencies!(model)
    mass_tendency = sum(volume(i, j, k, grid, Center(), Center(), Center()) *
                        model.timestepper.Gⁿ.c[i, j, k]
                        for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx)

    Δt = convert(FT, 1//100)

    for _ in 1:10
        time_step!(model, Δt)
    end

    final_mass = tracer_mass()
    velocity_scale = max(one(FT), interior_w)
    mass_scale = max(one(FT), abs(initial_mass))

    @test bottom_w ≤ 1000eps(FT) * velocity_scale
    @test top_w ≤ 1000eps(FT) * velocity_scale
    @test interior_w > sqrt(eps(FT))
    @test abs(mass_tendency) ≤ 10000eps(FT) * mass_scale / Δt
    @test abs(final_mass - initial_mass) ≤ 10000eps(FT) * mass_scale
    @test !any(isnan, parent(model.tracers.c))

    return nothing
end

function test_octahealpix_zstar_transport_sigma_uses_transport_fluxes_directly(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    z = Oceananigans.Grids.MutableVerticalDiscretization((-one(FT), zero(FT)))
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z,
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        vertical_coordinate = Oceananigans.Models.ZStarCoordinate(),
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model, u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
                v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ))

    compute_transport_velocities!(model, model.free_surface)

    samples = ((2, div(N, 2), 1),
               (N - 1, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (div(N, 2), N - 1, 1))

    for (i, j, k) in samples
        Uᴱ = model.transport_velocities.u[i + 1, j, k]
        Uᵂ = model.transport_velocities.u[i,     j, k]
        Vᴺ = model.transport_velocities.v[i, j + 1, k]
        Vˢ = model.transport_velocities.v[i, j,     k]

        expected_∂t_σ = - (Uᴱ - Uᵂ + Vᴺ - Vˢ) *
                        Oceananigans.Operators.Az⁻¹ᶜᶜᶜ(i, j, k, grid) /
                        Oceananigans.Grids.static_column_depthᶜᶜᵃ(i, j, grid)

        computed_∂t_σ = grid.z.∂t_σ[i, j, 1]
        sigma_scale = max(one(FT), abs(expected_∂t_σ), abs(computed_∂t_σ))
        @test abs(computed_∂t_σ - expected_∂t_σ) ≤ 1000eps(FT) * sigma_scale
    end

    return nothing
end

function test_octahealpix_zstar_transport_state_drives_tracer_tendency(FT, N)
