    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z,
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        vertical_coordinate = Oceananigans.Models.ZStarCoordinate(),
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model, u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
                v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ),
                c = (λ, φ, z) -> sind(λ / 2) + convert(FT, 0.2) * cosd(φ) + convert(FT, 0.1) * z)

    compute_transport_velocities!(model, model.free_surface)
    compute_tracer_tendencies!(model)

    @test any(abs(grid.z.∂t_σ[i, j, 1]) > 100eps(FT) for j in 1:2N, i in 1:2N)

    scheme = Centered(FT)
    samples = ((2, div(N, 2), 1),
               (N - 1, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (div(N, 2), N - 1, 1))

    for (i, j, k) in samples
        expected_Gc = -div_Uc(i, j, k, grid, scheme, model.transport_velocities, model.tracers.c)
        computed_Gc = model.timestepper.Gⁿ.c[i, j, k]
        tendency_scale = max(one(FT), abs(expected_Gc), abs(computed_Gc))
        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale
    end

    return nothing
end

function test_octahealpix_zstar_momentum_state_drives_momentum_tendencies(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    z = Oceananigans.Grids.MutableVerticalDiscretization((-one(FT), zero(FT)))
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z,
                              radius,
                              halo = (1, 1, 1))

    momentum = VectorInvariant()
    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        vertical_coordinate = Oceananigans.Models.ZStarCoordinate(),
                                        momentum_advection = momentum,
                                        tracer_advection = Centered(FT))

    set!(model, u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ) + convert(FT, 0.1) * z,
                v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ) + convert(FT, 0.07) * z)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.update_vertical_velocities!(model.velocities, grid, model)

    function barotropic_covariant_contravariant_flux_u_test(i, j, k, grid, u, v)
        Ū = zero(FT)
        V̄ = zero(FT)
        Nz = size(grid, 3)

        @inbounds for kk in 1:Nz
            Ū += u[i, j, kk] * Oceananigans.Operators.Δzᶠᶜᶜ(i, j, kk, grid)
            V̄ += v[i, j, kk] * Oceananigans.Operators.Δzᶜᶠᶜ(i, j, kk, grid)
        end

        return Oceananigans.Operators.transverse_computational_width_uᶠᶜᶜ(i, j, k, grid) *
               Oceananigans.Operators.covariant_to_contravariant_flux_uᶠᶜᶜ(i, j, k, grid, Ū, V̄)
    end

    function barotropic_covariant_contravariant_flux_v_test(i, j, k, grid, u, v)
        Ū = zero(FT)
        V̄ = zero(FT)
        Nz = size(grid, 3)

        @inbounds for kk in 1:Nz
            Ū += u[i, j, kk] * Oceananigans.Operators.Δzᶠᶜᶜ(i, j, kk, grid)
            V̄ += v[i, j, kk] * Oceananigans.Operators.Δzᶜᶠᶜ(i, j, kk, grid)
        end

        return Oceananigans.Operators.transverse_computational_width_vᶜᶠᶜ(i, j, k, grid) *
               Oceananigans.Operators.covariant_to_contravariant_flux_vᶜᶠᶜ(i, j, k, grid, Ū, V̄)
    end

    samples = ((2, div(N, 2), 1),
               (N - 1, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (div(N, 2), N - 1, 1))
    maximum_transformed_difference = zero(FT)

    for (i, j, k) in samples
        expected_∂t_σ =
            -(Oceananigans.Operators.δxᶜᵃᵃ(i, j, 1, grid,
                                          barotropic_covariant_contravariant_flux_u_test,
                                          model.velocities.u, model.velocities.v) +
              Oceananigans.Operators.δyᵃᶜᵃ(i, j, 1, grid,
                                          barotropic_covariant_contravariant_flux_v_test,
                                          model.velocities.u, model.velocities.v)) *
             Oceananigans.Operators.Az⁻¹ᶜᶜᶜ(i, j, 1, grid) /
             Oceananigans.Grids.static_column_depthᶜᶜᵃ(i, j, grid)

        naive_∂t_σ =
            -(Oceananigans.Operators.δxᶜᶜᶜ(i, j, 1, grid, Oceananigans.Operators.Δy_qᶠᶜᶜ,
                                          barotropic_covariant_contravariant_flux_u_test,
                                          model.velocities.u, model.velocities.v) +
              Oceananigans.Operators.δyᶜᶜᶜ(i, j, 1, grid, Oceananigans.Operators.Δx_qᶜᶠᶜ,
                                          barotropic_covariant_contravariant_flux_v_test,
                                          model.velocities.u, model.velocities.v)) *
             Oceananigans.Operators.Az⁻¹ᶜᶜᶜ(i, j, 1, grid) /
             Oceananigans.Grids.static_column_depthᶜᶜᵃ(i, j, grid)

        computed_∂t_σ = grid.z.∂t_σ[i, j, 1]
        sigma_scale = max(one(FT), abs(expected_∂t_σ), abs(computed_∂t_σ))
        @test abs(computed_∂t_σ - expected_∂t_σ) ≤ 1000eps(FT) * sigma_scale
        maximum_transformed_difference = max(maximum_transformed_difference, abs(expected_∂t_σ - naive_∂t_σ))
    end

    @test maximum_transformed_difference > 100eps(FT)

    compute_momentum_tendencies!(model, ())

    U = model.velocities
    for (i, j, k) in samples
        expected_Gu = -U_dot_∇u(i, j, k, grid, momentum, U)
        expected_Gv = -U_dot_∇v(i, j, k, grid, momentum, U)
        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        tendency_scale = max(one(FT), abs(expected_Gu), abs(expected_Gv), abs(computed_Gu), abs(computed_Gv))
        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * tendency_scale
        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * tendency_scale
    end

    return nothing
end

function test_octahealpix_zstar_momentum_state_with_split_explicit_free_surface(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    z = Oceananigans.Grids.MutableVerticalDiscretization((-one(FT), zero(FT)))
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z,
                              radius,
                              halo = (1, 1, 1))

    momentum = VectorInvariant()
    free_surface = SplitExplicitFreeSurface(substeps=8)
    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface,
                                        vertical_coordinate = Oceananigans.Models.ZStarCoordinate(),
                                        momentum_advection = momentum,
                                        tracer_advection = Centered(FT))

    set!(model, u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ) + convert(FT, 0.1) * z,
                v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ) + convert(FT, 0.07) * z)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.update_vertical_velocities!(model.velocities, grid, model)

    U = model.free_surface.barotropic_velocities.U
    V = model.free_surface.barotropic_velocities.V

    function barotropic_covariant_contravariant_flux_u_split(i, j, k, grid, U, V)
        Ū = @inbounds U[i, j, 1]
        V̄ = @inbounds V[i, j, 1]
        return Oceananigans.Operators.transverse_computational_width_uᶠᶜᶜ(i, j, k, grid) *
               Oceananigans.Operators.covariant_to_contravariant_flux_uᶠᶜᶜ(i, j, k, grid, Ū, V̄)
    end

    function barotropic_covariant_contravariant_flux_v_split(i, j, k, grid, U, V)
        Ū = @inbounds U[i, j, 1]
        V̄ = @inbounds V[i, j, 1]
        return Oceananigans.Operators.transverse_computational_width_vᶜᶠᶜ(i, j, k, grid) *
               Oceananigans.Operators.covariant_to_contravariant_flux_vᶜᶠᶜ(i, j, k, grid, Ū, V̄)
    end

    samples = ((2, div(N, 2), 1),
               (N - 1, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (div(N, 2), N - 1, 1))
    maximum_transformed_difference = zero(FT)

    for (i, j, k) in samples
        expected_∂t_σ =
            -(Oceananigans.Operators.δxᶜᵃᵃ(i, j, 1, grid,
                                          barotropic_covariant_contravariant_flux_u_split,
                                          U, V) +
              Oceananigans.Operators.δyᵃᶜᵃ(i, j, 1, grid,
                                          barotropic_covariant_contravariant_flux_v_split,
                                          U, V)) *
             Oceananigans.Operators.Az⁻¹ᶜᶜᶜ(i, j, 1, grid) /
             Oceananigans.Grids.static_column_depthᶜᶜᵃ(i, j, grid)

        naive_∂t_σ =
            -(Oceananigans.Operators.δxᶜᶜᶜ(i, j, 1, grid, Oceananigans.Operators.Δy_qᶠᶜᶜ,
                                          barotropic_covariant_contravariant_flux_u_split,
                                          U, V) +
              Oceananigans.Operators.δyᶜᶜᶜ(i, j, 1, grid, Oceananigans.Operators.Δx_qᶜᶠᶜ,
                                          barotropic_covariant_contravariant_flux_v_split,
                                          U, V)) *
             Oceananigans.Operators.Az⁻¹ᶜᶜᶜ(i, j, 1, grid) /
             Oceananigans.Grids.static_column_depthᶜᶜᵃ(i, j, grid)

        computed_∂t_σ = grid.z.∂t_σ[i, j, 1]
        sigma_scale = max(one(FT), abs(expected_∂t_σ), abs(computed_∂t_σ))
        @test abs(computed_∂t_σ - expected_∂t_σ) ≤ 1000eps(FT) * sigma_scale
        maximum_transformed_difference = max(maximum_transformed_difference, abs(expected_∂t_σ - naive_∂t_σ))
    end

    @test maximum_transformed_difference > 100eps(FT)

    compute_momentum_tendencies!(model, ())

    U3 = model.velocities
    for (i, j, k) in samples
        expected_Gu = -U_dot_∇u(i, j, k, grid, momentum, U3)
        expected_Gv = -U_dot_∇v(i, j, k, grid, momentum, U3)
        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        tendency_scale = max(one(FT), abs(expected_Gu), abs(expected_Gv), abs(computed_Gu), abs(computed_Gv))
        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * tendency_scale
        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * tendency_scale
    end

    return nothing
end

function test_octahealpix_zstar_transport_state_with_free_surface(FT, N, free_surface)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    z = Oceananigans.Grids.MutableVerticalDiscretization((-one(FT), zero(FT)))
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z,
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface,
                                        vertical_coordinate = Oceananigans.Models.ZStarCoordinate(),
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model, u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
                v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ),
                c = (λ, φ, z) -> sind(λ / 2) + convert(FT, 0.2) * cosd(φ) + convert(FT, 0.1) * z)

    compute_transport_velocities!(model, model.free_surface)
    compute_tracer_tendencies!(model)

    @test any(abs(grid.z.∂t_σ[i, j, 1]) > 100eps(FT) for j in 1:2N, i in 1:2N)

    scheme = Centered(FT)
    samples = ((2, div(N, 2), 1),
               (N - 1, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (div(N, 2), N - 1, 1))

    for (i, j, k) in samples
        expected_Gc = -div_Uc(i, j, k, grid, scheme, model.transport_velocities, model.tracers.c)
        computed_Gc = model.timestepper.Gⁿ.c[i, j, k]
        tendency_scale = max(one(FT), abs(expected_Gc), abs(computed_Gc))
        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale
    end

    return nothing
end

function test_octahealpix_zstar_transport_sigma_with_split_explicit_free_surface(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    z = Oceananigans.Grids.MutableVerticalDiscretization((-one(FT), zero(FT)))
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z,
                              radius,
                              halo = (1, 1, 1))

    free_surface = SplitExplicitFreeSurface(substeps=8)
    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface,
                                        vertical_coordinate = Oceananigans.Models.ZStarCoordinate(),
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model, u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
                v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ))

    compute_transport_velocities!(model, model.free_surface)

    Ũ = model.free_surface.filtered_state.Ũ
    Ṽ = model.free_surface.filtered_state.Ṽ

    function filtered_barotropic_transport_flux_u_test(i, j, k, grid, Ũ, Ṽ)
        return Oceananigans.Operators.transverse_computational_width_uᶠᶜᶜ(i, j, k, grid) *
               Oceananigans.Operators.covariant_to_contravariant_flux_uᶠᶜᶜ(i, j, k, grid, Ũ, Ṽ)
    end

    function filtered_barotropic_transport_flux_v_test(i, j, k, grid, Ũ, Ṽ)
        return Oceananigans.Operators.transverse_computational_width_vᶜᶠᶜ(i, j, k, grid) *
               Oceananigans.Operators.covariant_to_contravariant_flux_vᶜᶠᶜ(i, j, k, grid, Ũ, Ṽ)
    end

    samples = ((2, div(N, 2), 1),
               (N - 1, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (div(N, 2), N - 1, 1))
    maximum_transformed_difference = zero(FT)

    for (i, j, k) in samples
        expected_∂t_σ =
            -(Oceananigans.Operators.δxᶜᵃᵃ(i, j, 1, grid,
                                          filtered_barotropic_transport_flux_u_test,
                                          Ũ, Ṽ) +
              Oceananigans.Operators.δyᵃᶜᵃ(i, j, 1, grid,
                                          filtered_barotropic_transport_flux_v_test,
                                          Ũ, Ṽ)) *
             Oceananigans.Operators.Az⁻¹ᶜᶜᶜ(i, j, 1, grid) /
             Oceananigans.Grids.static_column_depthᶜᶜᵃ(i, j, grid)

        naive_∂t_σ =
            -(Oceananigans.Operators.δxᶜᶜᶜ(i, j, 1, grid, Oceananigans.Operators.Δy_qᶠᶜᶜ,
                                          filtered_barotropic_transport_flux_u_test,
                                          Ũ, Ṽ) +
              Oceananigans.Operators.δyᶜᶜᶜ(i, j, 1, grid, Oceananigans.Operators.Δx_qᶜᶠᶜ,
                                          filtered_barotropic_transport_flux_v_test,
                                          Ũ, Ṽ)) *
             Oceananigans.Operators.Az⁻¹ᶜᶜᶜ(i, j, 1, grid) /
             Oceananigans.Grids.static_column_depthᶜᶜᵃ(i, j, grid)

        computed_∂t_σ = grid.z.∂t_σ[i, j, 1]
        sigma_scale = max(one(FT), abs(expected_∂t_σ), abs(computed_∂t_σ))
        @test abs(computed_∂t_σ - expected_∂t_σ) ≤ 1000eps(FT) * sigma_scale
        maximum_transformed_difference = max(maximum_transformed_difference, abs(expected_∂t_σ - naive_∂t_σ))
    end

    @test maximum_transformed_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_split_explicit_free_surface_continuity_uses_nonorthogonal_barotropic_flux(FT, N, extend_halos = true)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (-one(FT), zero(FT)),
                              radius,
                              halo = (1, 1, 1))

    free_surface = SplitExplicitFreeSurface(substeps = 8, extend_halos = extend_halos)
    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model, u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
                v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ))

    Oceananigans.Models.HydrostaticFreeSurfaceModels.reconcile_free_surface!(model.free_surface, model.grid, model.velocities)

    η = model.free_surface.displacement
    U = model.free_surface.barotropic_velocities.U
    V = model.free_surface.barotropic_velocities.V
    free_surface_grid = η.grid
    connectivity = free_surface_grid.connectivity

    fill!(η, zero(FT))
    Oceananigans.Models.HydrostaticFreeSurfaceModels.SplitExplicitFreeSurfaces.initialize_free_surface_state!(
        model.free_surface, model.timestepper, model.free_surface.timestepper)

    fill_halo_regions!((U, V))

    for j in 0:free_surface_grid.Ny+1
        U[0,                 j, 1] = convert(FT, 11)
        U[free_surface_grid.Nx + 1, j, 1] = convert(FT, -13)
    end

    for i in 0:free_surface_grid.Nx+1
        V[i, 0,                  1] = convert(FT, 17)
        V[i, free_surface_grid.Ny + 1, 1] = convert(FT, -19)
    end

    Δτᴮ = convert(FT, 1//10)
    weights = (one(FT),)
    transport_weights = (zero(FT),)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.SplitExplicitFreeSurfaces.iterate_split_explicit!(
        model.free_surface,
        free_surface_grid,
        model.timestepper.Gⁿ.U,
        model.timestepper.Gⁿ.V,
        Δτᴮ,
        model.forcing.η,
        model.clock,
        weights,
        transport_weights,
        Val(1))

    function split_explicit_covariant_xface_source_value_test(i, j, U, V)
        if 1 <= i <= free_surface_grid.Nx && 1 <= j <= free_surface_grid.Ny
            return @inbounds U[i, j, 1]
        end

        source_field, source_i, source_j, sign =
            octahealpix_face_halo_source(i, j, connectivity, free_surface_grid.Nx, free_surface_grid.Ny, N, :u)

        return @inbounds ifelse(source_field == 1,
                                sign * U[source_i, source_j, 1],
                                sign * V[source_i, source_j, 1])
    end

    function split_explicit_covariant_yface_source_value_test(i, j, U, V)
        if 1 <= i <= free_surface_grid.Nx && 1 <= j <= free_surface_grid.Ny
            return @inbounds V[i, j, 1]
        end

        source_field, source_i, source_j, sign =
            octahealpix_face_halo_source(i, j, connectivity, free_surface_grid.Nx, free_surface_grid.Ny, N, :v)

        return @inbounds ifelse(source_field == 1,
                                sign * U[source_i, source_j, 1],
                                sign * V[source_i, source_j, 1])
    end

    function split_explicit_barotropic_contravariant_flux_u_test(i, j, k, grid, U, V)
        Ū = split_explicit_covariant_xface_source_value_test(i, j, U, V)
        V₁ = split_explicit_covariant_yface_source_value_test(i - 1, j,     U, V)
        V₂ = split_explicit_covariant_yface_source_value_test(i,     j,     U, V)
        V₃ = split_explicit_covariant_yface_source_value_test(i - 1, j + 1, U, V)
        V₄ = split_explicit_covariant_yface_source_value_test(i,     j + 1, U, V)

        quarter = convert(FT, 1//4)
        V̄ = quarter * (V₁ + V₂ + V₃ + V₄)

        return Oceananigans.Operators.G¹¹ᶠᶜᶜ(i, j, k, grid) * Ū +
               Oceananigans.Operators.G¹²ᶠᶜᶜ(i, j, k, grid) * V̄
    end

    function split_explicit_barotropic_contravariant_flux_v_test(i, j, k, grid, U, V)
        U₁ = split_explicit_covariant_xface_source_value_test(i,     j - 1, U, V)
        U₂ = split_explicit_covariant_xface_source_value_test(i + 1, j - 1, U, V)
        U₃ = split_explicit_covariant_xface_source_value_test(i,     j,     U, V)
        U₄ = split_explicit_covariant_xface_source_value_test(i + 1, j,     U, V)
        V̄ = split_explicit_covariant_yface_source_value_test(i, j, U, V)

        quarter = convert(FT, 1//4)
        Ū = quarter * (U₁ + U₂ + U₃ + U₄)

        return Oceananigans.Operators.G²¹ᶜᶠᶜ(i, j, k, grid) * Ū +
               Oceananigans.Operators.G²²ᶜᶠᶜ(i, j, k, grid) * V̄
    end

    function split_explicit_barotropic_transport_flux_u_test(i, j, k, grid, U, V)
        return Oceananigans.Operators.transverse_computational_width_uᶠᶜᶜ(i, j, k, grid) *
               split_explicit_barotropic_contravariant_flux_u_test(i, j, k, grid, U, V)
    end

    function split_explicit_barotropic_transport_flux_v_test(i, j, k, grid, U, V)
        return Oceananigans.Operators.transverse_computational_width_vᶜᶠᶜ(i, j, k, grid) *
               split_explicit_barotropic_contravariant_flux_v_test(i, j, k, grid, U, V)
    end

    δx_naive = extend_halos ? Oceananigans.Operators.δxᶜᵃᵃ : Oceananigans.Operators.δxTᶜᵃᵃ
    δy_naive = extend_halos ? Oceananigans.Operators.δyᵃᶜᵃ : Oceananigans.Operators.δyTᵃᶜᵃ

    samples = ((2, div(N, 2), free_surface_grid.Nz + 1),
               (N - 1, div(N, 2), free_surface_grid.Nz + 1),
               (div(N, 2), 2, free_surface_grid.Nz + 1),
               (div(N, 2), N - 1, free_surface_grid.Nz + 1))
    maximum_transformed_difference = zero(FT)

    for (i, j, k_top) in samples
        expected_Gη =
            -(Oceananigans.Operators.δxᶜᵃᵃ(i, j, free_surface_grid.Nz, free_surface_grid,
                                          split_explicit_barotropic_transport_flux_u_test,
                                          U, V) +
              Oceananigans.Operators.δyᵃᶜᵃ(i, j, free_surface_grid.Nz, free_surface_grid,
                                          split_explicit_barotropic_transport_flux_v_test,
                                          U, V)) *
             Oceananigans.Operators.Az⁻¹ᶜᶜᶠ(i, j, k_top, free_surface_grid)

        naive_Gη =
            -(δx_naive(i, j, free_surface_grid.Nz, free_surface_grid,
                       Oceananigans.Operators.Δy_qᶠᶜᶠ,
                       split_explicit_barotropic_contravariant_flux_u_test,
                       U, V) +
              δy_naive(i, j, free_surface_grid.Nz, free_surface_grid,
                       Oceananigans.Operators.Δx_qᶜᶠᶠ,
                       split_explicit_barotropic_contravariant_flux_v_test,
                       U, V)) *
             Oceananigans.Operators.Az⁻¹ᶜᶜᶠ(i, j, k_top, free_surface_grid)

        expected_η = -Δτᴮ * expected_Gη
        computed_η = η[i, j, k_top]
        η_scale = max(one(FT), abs(expected_η), abs(computed_η))
        @test abs(computed_η - expected_η) ≤ 1000eps(FT) * η_scale
        maximum_transformed_difference = max(maximum_transformed_difference, abs(expected_Gη - naive_Gη))
    end

    @test maximum_transformed_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_split_explicit_cfl_fill_halos_matches_fixed_substeps(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (-one(FT), zero(FT)),
                              radius,
                              halo = (1, 1, 1))

    cfl = convert(FT, 0.6)
    Δt = convert(FT, 1)

    dynamic_free_surface = SplitExplicitFreeSurface(grid; cfl, extend_halos = false)
    dynamic_model = HydrostaticFreeSurfaceModel(grid;
                                                tracers = nothing,
                                                buoyancy = nothing,
                                                free_surface = dynamic_free_surface,
                                                momentum_advection = nothing)

    dynamic_substeps = Oceananigans.Models.HydrostaticFreeSurfaceModels.calculate_substeps(dynamic_model.free_surface.substepping, Δt)
    @test dynamic_substeps ≥ 5

    fixed_free_surface = SplitExplicitFreeSurface(substeps = dynamic_substeps, extend_halos = false)
    fixed_model = HydrostaticFreeSurfaceModel(grid;
                                              tracers = nothing,
                                              buoyancy = nothing,
                                              free_surface = fixed_free_surface,
                                              momentum_advection = nothing)

    u_velocity(λ, φ, z) = convert(FT, 0.12) * sind(λ) + convert(FT, 0.04) * cosd(φ)
    v_velocity(λ, φ, z) = convert(FT, 0.08) * cosd(λ) - convert(FT, 0.03) * sind(φ)
    η₀(λ, φ, z) = convert(FT, 0.05) * sind(λ / 2) * cosd(φ)

    set!(dynamic_model, u = u_velocity, v = v_velocity)
    set!(fixed_model,   u = u_velocity, v = v_velocity)
    set!(dynamic_model.free_surface.displacement, η₀)
    set!(fixed_model.free_surface.displacement,   η₀)

    fill_halo_regions!(dynamic_model.free_surface.displacement)
    fill_halo_regions!(fixed_model.free_surface.displacement)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.reconcile_free_surface!(dynamic_model.free_surface, dynamic_model.grid, dynamic_model.velocities)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.reconcile_free_surface!(fixed_model.free_surface,   fixed_model.grid,   fixed_model.velocities)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.step_free_surface!(dynamic_model.free_surface, dynamic_model, dynamic_model.timestepper, Δt)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.step_free_surface!(fixed_model.free_surface,   fixed_model,   fixed_model.timestepper,   Δt)

    η_dynamic = Array(interior(dynamic_model.free_surface.displacement))
    η_fixed = Array(interior(fixed_model.free_surface.displacement))
    U_dynamic = Array(interior(dynamic_model.free_surface.barotropic_velocities.U))
    U_fixed = Array(interior(fixed_model.free_surface.barotropic_velocities.U))
    V_dynamic = Array(interior(dynamic_model.free_surface.barotropic_velocities.V))
    V_fixed = Array(interior(fixed_model.free_surface.barotropic_velocities.V))
    Ũ_dynamic = Array(interior(dynamic_model.free_surface.filtered_state.Ũ))
    Ũ_fixed = Array(interior(fixed_model.free_surface.filtered_state.Ũ))
    Ṽ_dynamic = Array(interior(dynamic_model.free_surface.filtered_state.Ṽ))
    Ṽ_fixed = Array(interior(fixed_model.free_surface.filtered_state.Ṽ))

    @test η_dynamic ≈ η_fixed
    @test U_dynamic ≈ U_fixed
    @test V_dynamic ≈ V_fixed
    @test Ũ_dynamic ≈ Ũ_fixed
    @test Ṽ_dynamic ≈ Ṽ_fixed

    return nothing
end

function test_octahealpix_split_explicit_cfl_default_matches_fill_halos(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (-one(FT), zero(FT)),
                              radius,
                              halo = (1, 1, 1))

    cfl = convert(FT, 0.6)
    Δt = convert(FT, 1)

    default_free_surface = SplitExplicitFreeSurface(grid; cfl)
    default_model = @test_logs (:warn, r"extend_halos = false") HydrostaticFreeSurfaceModel(grid;
                                                                                             tracers = nothing,
                                                                                             buoyancy = nothing,
                                                                                             free_surface = default_free_surface,
                                                                                             momentum_advection = nothing)

    fill_halo_free_surface = SplitExplicitFreeSurface(grid; cfl, extend_halos = false)
    fill_halo_model = HydrostaticFreeSurfaceModel(grid;
                                                  tracers = nothing,
                                                  buoyancy = nothing,
                                                  free_surface = fill_halo_free_surface,
                                                  momentum_advection = nothing)

    u_velocity(λ, φ, z) = convert(FT, 0.12) * sind(λ) + convert(FT, 0.04) * cosd(φ)
    v_velocity(λ, φ, z) = convert(FT, 0.08) * cosd(λ) - convert(FT, 0.03) * sind(φ)
    η₀(λ, φ, z) = convert(FT, 0.05) * sind(λ / 2) * cosd(φ)

    set!(default_model,   u = u_velocity, v = v_velocity)
    set!(fill_halo_model, u = u_velocity, v = v_velocity)
    set!(default_model.free_surface.displacement,   η₀)
    set!(fill_halo_model.free_surface.displacement, η₀)

    fill_halo_regions!(default_model.free_surface.displacement)
    fill_halo_regions!(fill_halo_model.free_surface.displacement)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.reconcile_free_surface!(default_model.free_surface,   default_model.grid,   default_model.velocities)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.reconcile_free_surface!(fill_halo_model.free_surface, fill_halo_model.grid, fill_halo_model.velocities)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.step_free_surface!(default_model.free_surface,   default_model,   default_model.timestepper,   Δt)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.step_free_surface!(fill_halo_model.free_surface, fill_halo_model, fill_halo_model.timestepper, Δt)

    η_default = Array(interior(default_model.free_surface.displacement))
    η_fill = Array(interior(fill_halo_model.free_surface.displacement))
    U_default = Array(interior(default_model.free_surface.barotropic_velocities.U))
    U_fill = Array(interior(fill_halo_model.free_surface.barotropic_velocities.U))
    V_default = Array(interior(default_model.free_surface.barotropic_velocities.V))
    V_fill = Array(interior(fill_halo_model.free_surface.barotropic_velocities.V))
    Ũ_default = Array(interior(default_model.free_surface.filtered_state.Ũ))
    Ũ_fill = Array(interior(fill_halo_model.free_surface.filtered_state.Ũ))
    Ṽ_default = Array(interior(default_model.free_surface.filtered_state.Ṽ))
    Ṽ_fill = Array(interior(fill_halo_model.free_surface.filtered_state.Ṽ))

    @test η_default ≈ η_fill
    @test U_default ≈ U_fill
    @test V_default ≈ V_fill
    @test Ũ_default ≈ Ũ_fill
    @test Ṽ_default ≈ Ṽ_fill

    return nothing
end

function test_octahealpix_split_explicit_barotropic_velocity_uses_covariant_surface_gradient(FT, N, extend_halos = true)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (-one(FT), zero(FT)),
                              radius,
                              halo = (1, 1, 1))

    free_surface = SplitExplicitFreeSurface(substeps = 8, extend_halos = extend_halos)
    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model, u = zero(FT), v = zero(FT))

    Oceananigans.Models.HydrostaticFreeSurfaceModels.reconcile_free_surface!(model.free_surface, model.grid, model.velocities)

    η = model.free_surface.displacement
    U = model.free_surface.barotropic_velocities.U
    V = model.free_surface.barotropic_velocities.V
    free_surface_grid = η.grid
    connectivity = free_surface_grid.connectivity
    k_top = free_surface_grid.Nz + 1

    set!(η, (λ, φ, z) -> convert(FT, 0.12) * sind(λ / 2) + convert(FT, 0.08) * cosd(φ))
    fill_halo_regions!(η)
    clean_η = copy(η.data)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.SplitExplicitFreeSurfaces.initialize_free_surface_state!(
        model.free_surface, model.timestepper, model.free_surface.timestepper)

    set!(U, zero(FT))
    set!(V, zero(FT))
    set!(model.timestepper.Gⁿ.U, zero(FT))
    set!(model.timestepper.Gⁿ.V, zero(FT))

    for j in 0:(free_surface_grid.Ny + 1)
        η[0,                      j, k_top] = convert(FT, 21)
        η[free_surface_grid.Nx + 1, j, k_top] = convert(FT, -23)
    end

    for i in 0:(free_surface_grid.Nx + 1)
        η[i, 0,                      k_top] = convert(FT, 27)
        η[i, free_surface_grid.Ny + 1, k_top] = convert(FT, -29)
    end

    Δτᴮ = convert(FT, 1//10)
    weights = (zero(FT),)
    transport_weights = (zero(FT),)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.SplitExplicitFreeSurfaces.iterate_split_explicit!(
        model.free_surface,
        free_surface_grid,
        model.timestepper.Gⁿ.U,
        model.timestepper.Gⁿ.V,
        Δτᴮ,
        model.forcing.η,
        model.clock,
        weights,
        transport_weights,
        Val(1))

    function split_explicit_surface_source_value_test(i, j, k, grid, η_data)
        if 1 <= i <= free_surface_grid.Nx && 1 <= j <= free_surface_grid.Ny
            return @inbounds η_data[i, j, k]
        end

        source_ring =
            Oceananigans.Grids.octahealpix_wrapped_ring_index(i, j,
                                                              free_surface_grid.Nx,
                                                              free_surface_grid.Ny,
                                                              connectivity)
        source_i = connectivity.ring_to_i[source_ring]
        source_j = connectivity.ring_to_j[source_ring]
        return @inbounds η_data[source_i, source_j, k]
    end

    samples = ((2, div(N, 2), 1),
               (N - 1, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (div(N, 2), N - 1, 1))
    maximum_transformed_difference = zero(FT)

    for (i, j, k) in samples
        Hᶠᶜ = Oceananigans.Models.HydrostaticFreeSurfaceModels.SplitExplicitFreeSurfaces.x_column_depth(
            i, j, k_top, free_surface_grid, Val(extend_halos), clean_η)
        Hᶜᶠ = Oceananigans.Models.HydrostaticFreeSurfaceModels.SplitExplicitFreeSurfaces.y_column_depth(
            i, j, k_top, free_surface_grid, Val(extend_halos), clean_η)

        expected_∂x = if extend_halos
            Oceananigans.Operators.covariant_gradient_xᶠᶜᶜ(i, j, k_top, free_surface_grid, clean_η)
        else
            Oceananigans.Operators.covariant_gradient_xᶠᶜᶜ(i, j, k_top, free_surface_grid,
                                                           split_explicit_surface_source_value_test,
                                                           clean_η)
        end

        expected_∂y = if extend_halos
            Oceananigans.Operators.covariant_gradient_yᶜᶠᶜ(i, j, k_top, free_surface_grid, clean_η)
        else
            Oceananigans.Operators.covariant_gradient_yᶜᶠᶜ(i, j, k_top, free_surface_grid,
                                                           split_explicit_surface_source_value_test,
                                                           clean_η)
        end

        naive_∂x = if extend_halos
            Oceananigans.Operators.δxᶠᶜᶠ(i, j, k_top, free_surface_grid, clean_η) *
            Oceananigans.Operators.Δx⁻¹ᶠᶜᶠ(i, j, k_top, free_surface_grid)
        else
            Oceananigans.Operators.∂xᵣTᶠᶜᶠ(i, j, k_top, free_surface_grid,
                                          split_explicit_surface_source_value_test,
                                          clean_η)
        end

        naive_∂y = if extend_halos
            Oceananigans.Operators.δyᶜᶠᶠ(i, j, k_top, free_surface_grid, clean_η) *
            Oceananigans.Operators.Δy⁻¹ᶜᶠᶠ(i, j, k_top, free_surface_grid)
        else
            Oceananigans.Operators.∂yᵣTᶜᶠᶠ(i, j, k_top, free_surface_grid,
                                          split_explicit_surface_source_value_test,
                                          clean_η)
        end

        expected_U = -Δτᴮ * model.free_surface.gravitational_acceleration * Hᶠᶜ * expected_∂x
        expected_V = -Δτᴮ * model.free_surface.gravitational_acceleration * Hᶜᶠ * expected_∂y
        naive_U = -Δτᴮ * model.free_surface.gravitational_acceleration * Hᶠᶜ * naive_∂x
        naive_V = -Δτᴮ * model.free_surface.gravitational_acceleration * Hᶜᶠ * naive_∂y

        computed_U = U[i, j, k]
        computed_V = V[i, j, k]
        u_scale = max(one(FT), abs(expected_U), abs(computed_U))
        v_scale = max(one(FT), abs(expected_V), abs(computed_V))

        @test abs(computed_U - expected_U) ≤ 1000eps(FT) * u_scale
        @test abs(computed_V - expected_V) ≤ 1000eps(FT) * v_scale

        maximum_transformed_difference = max(maximum_transformed_difference,
                                             abs(expected_U - naive_U),
                                             abs(expected_V - naive_V))
    end

    @test maximum_transformed_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_split_explicit_barotropic_flux_ignores_vector_halos(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (-one(FT), zero(FT)),
                              radius,
                              halo = (1, 1, 1))

    free_surface = SplitExplicitFreeSurface(substeps = 8, extend_halos = true)
    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    free_surface_grid = model.free_surface.displacement.grid
    connectivity = free_surface_grid.connectivity
    U = model.free_surface.barotropic_velocities.U
    V = model.free_surface.barotropic_velocities.V
    timestepper = model.free_surface.timestepper

    set!(U, (λ, φ, z) -> convert(FT, 0.13) * sind(λ) + convert(FT, 0.04) * cosd(φ))
    set!(V, (λ, φ, z) -> convert(FT, 0.09) * cosd(λ) - convert(FT, 0.02) * sind(φ))
    fill_halo_regions!((U, V))

    for j in 0:(free_surface_grid.Ny + 1)
        U[0,                      j, 1] = convert(FT, 31)
        U[free_surface_grid.Nx + 1, j, 1] = convert(FT, -37)
    end

    for i in 0:(free_surface_grid.Nx + 1)
        V[i, 0,                      1] = convert(FT, 41)
        V[i, free_surface_grid.Ny + 1, 1] = convert(FT, -43)
    end

    function split_explicit_covariant_xface_source_value_test(i, j, U, V)
        if 1 <= i <= free_surface_grid.Nx && 1 <= j <= free_surface_grid.Ny
            return @inbounds U[i, j, 1]
        end

        source_field, source_i, source_j, sign =
            octahealpix_face_halo_source(i, j, connectivity, free_surface_grid.Nx, free_surface_grid.Ny, N, :u)

        return @inbounds ifelse(source_field == 1,
                                sign * U[source_i, source_j, 1],
                                sign * V[source_i, source_j, 1])
    end

    function split_explicit_covariant_yface_source_value_test(i, j, U, V)
        if 1 <= i <= free_surface_grid.Nx && 1 <= j <= free_surface_grid.Ny
            return @inbounds V[i, j, 1]
        end

        source_field, source_i, source_j, sign =
            octahealpix_face_halo_source(i, j, connectivity, free_surface_grid.Nx, free_surface_grid.Ny, N, :v)

        return @inbounds ifelse(source_field == 1,
                                sign * U[source_i, source_j, 1],
                                sign * V[source_i, source_j, 1])
    end

    function expected_split_explicit_barotropic_flux_u(i, j, k, grid, U, V)
        Ū = split_explicit_covariant_xface_source_value_test(i, j, U, V)
        V₁ = split_explicit_covariant_yface_source_value_test(i - 1, j,     U, V)
        V₂ = split_explicit_covariant_yface_source_value_test(i,     j,     U, V)
        V₃ = split_explicit_covariant_yface_source_value_test(i - 1, j + 1, U, V)
        V₄ = split_explicit_covariant_yface_source_value_test(i,     j + 1, U, V)

        quarter = convert(FT, 1//4)
        V̄ = quarter * (V₁ + V₂ + V₃ + V₄)

        return Oceananigans.Operators.G¹¹ᶠᶜᶜ(i, j, k, grid) * Ū +
               Oceananigans.Operators.G¹²ᶠᶜᶜ(i, j, k, grid) * V̄
    end

    function expected_split_explicit_barotropic_flux_v(i, j, k, grid, U, V)
        U₁ = split_explicit_covariant_xface_source_value_test(i,     j - 1, U, V)
        U₂ = split_explicit_covariant_xface_source_value_test(i + 1, j - 1, U, V)
        U₃ = split_explicit_covariant_xface_source_value_test(i,     j,     U, V)
        U₄ = split_explicit_covariant_xface_source_value_test(i + 1, j,     U, V)
        V̄ = split_explicit_covariant_yface_source_value_test(i, j, U, V)

        quarter = convert(FT, 1//4)
        Ū = quarter * (U₁ + U₂ + U₃ + U₄)

        return Oceananigans.Operators.G²¹ᶜᶠᶜ(i, j, k, grid) * Ū +
               Oceananigans.Operators.G²²ᶜᶠᶜ(i, j, k, grid) * V̄
    end

    function naive_split_explicit_barotropic_flux_u(i, j, k, grid, U, V)
        quarter = convert(FT, 1//4)
        V̄ = quarter * (@inbounds V[i - 1, j, 1] + V[i, j, 1] + V[i - 1, j + 1, 1] + V[i, j + 1, 1])
        Ū = @inbounds U[i, j, 1]

        return Oceananigans.Operators.G¹¹ᶠᶜᶜ(i, j, k, grid) * Ū +
               Oceananigans.Operators.G¹²ᶠᶜᶜ(i, j, k, grid) * V̄
    end

    function naive_split_explicit_barotropic_flux_v(i, j, k, grid, U, V)
        quarter = convert(FT, 1//4)
        Ū = quarter * (@inbounds U[i, j - 1, 1] + U[i + 1, j - 1, 1] + U[i, j, 1] + U[i + 1, j, 1])
        V̄ = @inbounds V[i, j, 1]

        return Oceananigans.Operators.G²¹ᶜᶠᶜ(i, j, k, grid) * Ū +
               Oceananigans.Operators.G²²ᶜᶠᶜ(i, j, k, grid) * V̄
    end

    samples = ((1, div(N, 2), 1),
               (N, div(N, 2), 1),
               (div(N, 2), 1, 1),
               (div(N, 2), N, 1))
    maximum_transformed_difference = zero(FT)

    for (i, j, k) in samples
        computed_u =
            Oceananigans.Models.HydrostaticFreeSurfaceModels.SplitExplicitFreeSurfaces.split_explicit_barotropic_contravariant_flux_u(
                i, j, k, free_surface_grid, Val(true), timestepper, U, V)
        computed_v =
            Oceananigans.Models.HydrostaticFreeSurfaceModels.SplitExplicitFreeSurfaces.split_explicit_barotropic_contravariant_flux_v(
                i, j, k, free_surface_grid, Val(true), timestepper, U, V)

        expected_u = expected_split_explicit_barotropic_flux_u(i, j, k, free_surface_grid, U, V)
        expected_v = expected_split_explicit_barotropic_flux_v(i, j, k, free_surface_grid, U, V)
        naive_u = naive_split_explicit_barotropic_flux_u(i, j, k, free_surface_grid, U, V)
        naive_v = naive_split_explicit_barotropic_flux_v(i, j, k, free_surface_grid, U, V)

        u_scale = max(one(FT), abs(expected_u), abs(computed_u))
        v_scale = max(one(FT), abs(expected_v), abs(computed_v))

        @test abs(computed_u - expected_u) ≤ 1000eps(FT) * u_scale
        @test abs(computed_v - expected_v) ≤ 1000eps(FT) * v_scale

        maximum_transformed_difference = max(maximum_transformed_difference,
                                             abs(expected_u - naive_u),
                                             abs(expected_v - naive_v))
    end

    @test maximum_transformed_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_explicit_barotropic_pressure_gradient_uses_covariant_gradient(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (-one(FT), zero(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = ExplicitFreeSurface(),
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model, u = zero(FT), v = zero(FT))
    set!(model.free_surface.displacement, (λ, φ, z) -> convert(FT, 0.16) * sind(λ / 2) + convert(FT, 0.06) * cosd(φ))
    fill_halo_regions!(model.free_surface.displacement)

    compute_momentum_tendencies!(model, ())

    η = model.free_surface.displacement
    g = model.free_surface.gravitational_acceleration
    samples = ((2, div(N, 2), 1),
               (N - 1, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (div(N, 2), N - 1, 1))
    maximum_transformed_difference = zero(FT)

    for (i, j, k) in samples
        expected_u = -g * Oceananigans.Operators.covariant_gradient_xᶠᶜᶜ(i, j, grid.Nz + 1, grid, η)
        expected_v = -g * Oceananigans.Operators.covariant_gradient_yᶜᶠᶜ(i, j, grid.Nz + 1, grid, η)
        naive_u = -g * Oceananigans.Operators.δxᶠᶜᶜ(i, j, grid.Nz + 1, grid, η) *
                        Oceananigans.Operators.Δx⁻¹ᶠᶜᶜ(i, j, k, grid)
        naive_v = -g * Oceananigans.Operators.δyᶜᶠᶜ(i, j, grid.Nz + 1, grid, η) *
                        Oceananigans.Operators.Δy⁻¹ᶜᶠᶜ(i, j, k, grid)
        computed_u = model.timestepper.Gⁿ.u[i, j, k]
        computed_v = model.timestepper.Gⁿ.v[i, j, k]
        u_scale = max(one(FT), abs(expected_u), abs(computed_u))
        v_scale = max(one(FT), abs(expected_v), abs(computed_v))

        @test abs(computed_u - expected_u) ≤ 1000eps(FT) * u_scale
        @test abs(computed_v - expected_v) ≤ 1000eps(FT) * v_scale

        maximum_transformed_difference = max(maximum_transformed_difference,
                                             abs(expected_u - naive_u),
                                             abs(expected_v - naive_v))
    end

    @test maximum_transformed_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_zstar_split_explicit_localized_tracer_time_step_mass_conservation(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    z = Oceananigans.Grids.MutableVerticalDiscretization((-one(FT), zero(FT)))
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z,
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = SplitExplicitFreeSurface(substeps = 8),
                                        vertical_coordinate = Oceananigans.Models.ZStarCoordinate(),
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    λ₀ = convert(FT, 45)
    φ₀ = convert(FT, 15)
    bell_radius = convert(FT, 30)
    bell_amplitude = convert(FT, 1//2)

    localized_tracer(λ, φ, z) = begin
        cos_distance = sind(φ₀) * sind(φ) +
                       cosd(φ₀) * cosd(φ) * cosd(λ - λ₀)
        γ = acosd(clamp(cos_distance, -one(FT), one(FT)))
        return ifelse(γ < bell_radius,
                      bell_amplitude * (one(FT) + cospi(γ / bell_radius)),
                      zero(FT))
    end

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ),
         c = localized_tracer)

    set!(model.free_surface.η,
         (λ, φ, z) -> convert(FT, 0.02) * sind(λ) + convert(FT, 0.01) * cosd(φ))

    initial_tracer = Array(interior(model.tracers.c))
    initial_mass = sum(volume(i, j, k, grid, Center(), Center(), Center()) * model.tracers.c[i, j, k]
                       for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx)

    Δt = convert(FT, 1//10)
    maximum_velocity = zero(FT)
    maximum_surface_displacement = zero(FT)
    maximum_sigma_tendency = zero(FT)

    for step in 1:5
        time_step!(model, Δt)

        for j in 1:grid.Ny, i in 1:grid.Nx
            maximum_surface_displacement = max(maximum_surface_displacement,
                                               abs(model.free_surface.η[i, j, grid.Nz + 1]))
            maximum_sigma_tendency = max(maximum_sigma_tendency, abs(grid.z.∂t_σ[i, j, 1]))

            for k in 1:grid.Nz
                maximum_velocity = max(maximum_velocity,
                                       abs(model.velocities.u[i, j, k]),
                                       abs(model.velocities.v[i, j, k]))

                @test isfinite(model.velocities.u[i, j, k])
                @test isfinite(model.velocities.v[i, j, k])
                @test isfinite(model.tracers.c[i, j, k])
            end
        end
    end

    final_tracer = Array(interior(model.tracers.c))
    final_mass = sum(volume(i, j, k, grid, Center(), Center(), Center()) * model.tracers.c[i, j, k]
                     for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx)

    tracer_change = maximum(abs, final_tracer .- initial_tracer)
    mass_scale = max(one(FT), abs(initial_mass))

    @test maximum_surface_displacement > 100eps(FT)
    @test maximum_sigma_tendency > 100eps(FT)
    @test maximum_velocity > 100eps(FT)
    @test tracer_change > 100eps(FT)
    @test abs(final_mass - initial_mass) ≤ 100000eps(FT) * mass_scale
    @test !any(isnan, final_tracer)

    return nothing
end

