    maximum_velocity = zero(FT)
    maximum_surface_displacement = zero(FT)
    maximum_sigma_tendency = zero(FT)

    for step in 1:5
        time_step!(model, Δt)

        for j in 1:grid.Ny, i in 1:grid.Nx
            maximum_surface_displacement = max(maximum_surface_displacement,
                                               abs(model.free_surface.η[i, j, grid.Nz + 1]))
            maximum_sigma_tendency = max(maximum_sigma_tendency, abs(grid.z.∂t_σ[i, j, 1]))

            for k in 1:grid.Nz
                maximum_velocity = max(maximum_velocity,
                                       abs(model.velocities.u[i, j, k]),
                                       abs(model.velocities.v[i, j, k]))

                @test isfinite(model.velocities.u[i, j, k])
                @test isfinite(model.velocities.v[i, j, k])
                @test isfinite(model.tracers.c[i, j, k])
            end
        end
    end

    final_tracer = Array(interior(model.tracers.c))
    final_mass = sum(volume(i, j, k, grid, Center(), Center(), Center()) * model.tracers.c[i, j, k]
                     for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx)

    tracer_change = maximum(abs, final_tracer .- initial_tracer)
    mass_scale = max(one(FT), abs(initial_mass))

    @test maximum_surface_displacement > 100eps(FT)
    @test maximum_sigma_tendency > 100eps(FT)
    @test maximum_velocity > 100eps(FT)
    @test tracer_change > 100eps(FT)
    @test abs(final_mass - initial_mass) ≤ 100000eps(FT) * mass_scale
    @test minimum(final_tracer) ≥ -1000eps(FT)
    @test maximum(final_tracer) ≤ one(FT) + 1000eps(FT)
    @test !any(isnan, final_tracer)

    return nothing
end

function test_octahealpix_zstar_explicit_bounds_preserving_localized_tracer_time_step(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    z = Oceananigans.Grids.MutableVerticalDiscretization((-one(FT), zero(FT)))
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z,
                              radius,
                              halo = (1, 1, 1))

    scheme = Oceananigans.Advection.WENO(FT; order = 1, bounds = (zero(FT), one(FT)))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = ExplicitFreeSurface(),
                                        vertical_coordinate = Oceananigans.Models.ZStarCoordinate(),
                                        momentum_advection = nothing,
                                        tracer_advection = scheme)

    λ₀ = convert(FT, 45)
    φ₀ = convert(FT, 15)
    bell_radius = convert(FT, 30)
    bell_amplitude = convert(FT, 1//2)

    localized_tracer(λ, φ, z) = begin
        cos_distance = sind(φ₀) * sind(φ) +
                       cosd(φ₀) * cosd(φ) * cosd(λ - λ₀)
        γ = acosd(clamp(cos_distance, -one(FT), one(FT)))
        return ifelse(γ < bell_radius,
                      bell_amplitude * (one(FT) + cospi(γ / bell_radius)),
                      zero(FT))
    end

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ),
         c = localized_tracer)

    set!(model.free_surface.η,
         (λ, φ, z) -> convert(FT, 0.03) * sind(λ) + convert(FT, 0.02) * cosd(φ))

    initial_tracer = Array(interior(model.tracers.c))
    initial_mass = sum(volume(i, j, k, grid, Center(), Center(), Center()) * model.tracers.c[i, j, k]
                       for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx)

    Δt = convert(FT, 1//10)
    maximum_velocity = zero(FT)
    maximum_surface_displacement = zero(FT)
    maximum_sigma_tendency = zero(FT)

    for step in 1:5
        time_step!(model, Δt)

        for j in 1:grid.Ny, i in 1:grid.Nx
            maximum_surface_displacement = max(maximum_surface_displacement,
                                               abs(model.free_surface.η[i, j, grid.Nz + 1]))
            maximum_sigma_tendency = max(maximum_sigma_tendency, abs(grid.z.∂t_σ[i, j, 1]))

            for k in 1:grid.Nz
                maximum_velocity = max(maximum_velocity,
                                       abs(model.velocities.u[i, j, k]),
                                       abs(model.velocities.v[i, j, k]))

                @test isfinite(model.velocities.u[i, j, k])
                @test isfinite(model.velocities.v[i, j, k])
                @test isfinite(model.tracers.c[i, j, k])
            end
        end
    end

    final_tracer = Array(interior(model.tracers.c))
    final_mass = sum(volume(i, j, k, grid, Center(), Center(), Center()) * model.tracers.c[i, j, k]
                     for k in 1:grid.Nz, j in 1:grid.Ny, i in 1:grid.Nx)

    tracer_change = maximum(abs, final_tracer .- initial_tracer)
    mass_scale = max(one(FT), abs(initial_mass))

    @test maximum_surface_displacement > 100eps(FT)
    @test maximum_sigma_tendency > 100eps(FT)
    @test maximum_velocity > 100eps(FT)
    @test tracer_change > 100eps(FT)
    @test abs(final_mass - initial_mass) ≤ 100000eps(FT) * mass_scale
    @test minimum(final_tracer) ≥ -1000eps(FT)
    @test maximum(final_tracer) ≤ one(FT) + 1000eps(FT)
    @test !any(isnan, final_tracer)

    return nothing
end

