function test_octahealpix_zstar_explicit_free_surface_tendency_uses_nonorthogonal_barotropic_flux(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    z = Oceananigans.Grids.MutableVerticalDiscretization((-one(FT), zero(FT)))
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z,
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = ExplicitFreeSurface(),
                                        vertical_coordinate = Oceananigans.Models.ZStarCoordinate(),
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model, u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
                v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ))

    Oceananigans.Models.HydrostaticFreeSurfaceModels.compute_free_surface_tendency!(grid, model, model.free_surface)

    function explicit_free_surface_barotropic_flux_u_test(i, j, k, grid, u, v)
        Ū = Oceananigans.Models.HydrostaticFreeSurfaceModels.barotropic_U(i, j, k, grid, u)
        V̄ = Oceananigans.Models.HydrostaticFreeSurfaceModels.barotropic_V(i, j, k, grid, v)
        return Oceananigans.Operators.transverse_computational_width_uᶠᶜᶜ(i, j, k, grid) *
               Oceananigans.Operators.covariant_to_contravariant_flux_uᶠᶜᶜ(i, j, k, grid, Ū, V̄)
    end

    function explicit_free_surface_barotropic_flux_v_test(i, j, k, grid, u, v)
        Ū = Oceananigans.Models.HydrostaticFreeSurfaceModels.barotropic_U(i, j, k, grid, u)
        V̄ = Oceananigans.Models.HydrostaticFreeSurfaceModels.barotropic_V(i, j, k, grid, v)
        return Oceananigans.Operators.transverse_computational_width_vᶜᶠᶜ(i, j, k, grid) *
               Oceananigans.Operators.covariant_to_contravariant_flux_vᶜᶠᶜ(i, j, k, grid, Ū, V̄)
    end

    samples = ((2, div(N, 2), 1),
               (N - 1, div(N, 2), 1),
               (div(N, 2), 2, 1),
               (div(N, 2), N - 1, 1))
    maximum_transformed_difference = zero(FT)

    for (i, j, k) in samples
        expected_Gη =
            -(Oceananigans.Operators.δxᶜᵃᵃ(i, j, 1, grid,
                                          explicit_free_surface_barotropic_flux_u_test,
                                          model.velocities.u, model.velocities.v) +
              Oceananigans.Operators.δyᵃᶜᵃ(i, j, 1, grid,
                                          explicit_free_surface_barotropic_flux_v_test,
                                          model.velocities.u, model.velocities.v)) *
             Oceananigans.Operators.Az⁻¹ᶜᶜᶜ(i, j, 1, grid)

        naive_Gη =
            -(Oceananigans.Operators.δxᶜᶜᶜ(i, j, 1, grid, Oceananigans.Operators.Δy_qᶠᶜᶜ,
                                          explicit_free_surface_barotropic_flux_u_test,
                                          model.velocities.u, model.velocities.v) +
              Oceananigans.Operators.δyᶜᶜᶜ(i, j, 1, grid, Oceananigans.Operators.Δx_qᶜᶠᶜ,
                                          explicit_free_surface_barotropic_flux_v_test,
                                          model.velocities.u, model.velocities.v)) *
             Oceananigans.Operators.Az⁻¹ᶜᶜᶜ(i, j, 1, grid)

        computed_Gη = model.timestepper.Gⁿ.η[i, j, k]
        tendency_scale = max(one(FT), abs(expected_Gη), abs(computed_Gη))
        @test abs(computed_Gη - expected_Gη) ≤ 1000eps(FT) * tendency_scale
        maximum_transformed_difference = max(maximum_transformed_difference, abs(expected_Gη - naive_Gη))
    end

    @test maximum_transformed_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_implicit_free_surface_rhs_uses_nonorthogonal_barotropic_flux(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    free_surface = ImplicitFreeSurface()
    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model, u = (λ, φ, z) -> convert(FT, 0.15) * sind(λ) + convert(FT, 0.05) * cosd(φ),
                v = (λ, φ, z) -> convert(FT, 0.1) * cosd(λ) - convert(FT, 0.03) * sind(φ))

    rhs = model.free_surface.implicit_step_solver.right_hand_side
    g = model.free_surface.gravitational_acceleration
    Δt = one(FT)
    η = model.free_surface.displacement

    Oceananigans.Models.HydrostaticFreeSurfaceModels.compute_implicit_free_surface_right_hand_side!(rhs,
                                                                                                    model.free_surface.implicit_step_solver,
                                                                                                    g, Δt,
                                                                                                    model.velocities,
                                                                                                    η)

    function implicit_free_surface_barotropic_flux_u_test(i, j, k, grid, u, v)
        Ū = Oceananigans.Models.HydrostaticFreeSurfaceModels.barotropic_U(i, j, k, grid, u)
        V̄ = Oceananigans.Models.HydrostaticFreeSurfaceModels.barotropic_V(i, j, k, grid, v)
        return Oceananigans.Operators.transverse_computational_width_uᶠᶜᶜ(i, j, k, grid) *
               Oceananigans.Operators.covariant_to_contravariant_flux_uᶠᶜᶜ(i, j, k, grid, Ū, V̄)
    end

    function implicit_free_surface_barotropic_flux_v_test(i, j, k, grid, u, v)
        Ū = Oceananigans.Models.HydrostaticFreeSurfaceModels.barotropic_U(i, j, k, grid, u)
        V̄ = Oceananigans.Models.HydrostaticFreeSurfaceModels.barotropic_V(i, j, k, grid, v)
        return Oceananigans.Operators.transverse_computational_width_vᶜᶠᶜ(i, j, k, grid) *
               Oceananigans.Operators.covariant_to_contravariant_flux_vᶜᶠᶜ(i, j, k, grid, Ū, V̄)
    end

    kᴺ = grid.Nz
    samples = ((2, div(N, 2), kᴺ + 1),
               (N - 1, div(N, 2), kᴺ + 1),
               (div(N, 2), 2, kᴺ + 1),
               (div(N, 2), N - 1, kᴺ + 1))
    maximum_transformed_difference = zero(FT)

    for (i, j, k) in samples
        Az = Oceananigans.Operators.Azᶜᶜᶠ(i, j, kᴺ, grid)

        expected_rhs =
            (Oceananigans.Operators.δxᶜᵃᵃ(i, j, kᴺ, grid,
                                         implicit_free_surface_barotropic_flux_u_test,
                                         model.velocities.u, model.velocities.v) +
             Oceananigans.Operators.δyᵃᶜᵃ(i, j, kᴺ, grid,
                                         implicit_free_surface_barotropic_flux_v_test,
                                         model.velocities.u, model.velocities.v) -
             Az * η[i, j, k] / Δt) / (g * Δt)

        naive_rhs =
            (Oceananigans.Operators.δxᶜᶜᶜ(i, j, kᴺ, grid, Oceananigans.Operators.Δy_qᶠᶜᶜ,
                                         implicit_free_surface_barotropic_flux_u_test,
                                         model.velocities.u, model.velocities.v) +
             Oceananigans.Operators.δyᶜᶜᶜ(i, j, kᴺ, grid, Oceananigans.Operators.Δx_qᶜᶠᶜ,
                                         implicit_free_surface_barotropic_flux_v_test,
                                         model.velocities.u, model.velocities.v) -
             Az * η[i, j, k] / Δt) / (g * Δt)

        computed_rhs = rhs[i, j, k]
        rhs_scale = max(one(FT), abs(expected_rhs), abs(computed_rhs))
        @test abs(computed_rhs - expected_rhs) ≤ 1000eps(FT) * rhs_scale
        maximum_transformed_difference = max(maximum_transformed_difference, abs(expected_rhs - naive_rhs))
    end

    @test maximum_transformed_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_implicit_free_surface_linear_operator_uses_nonorthogonal_pressure_flux(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    free_surface = ImplicitFreeSurface()
    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    η = model.free_surface.displacement
    set!(η, (λ, φ, z) -> sind(λ / 2) + convert(FT, 0.2) * cosd(φ))
    fill_halo_regions!(η)

    lhs = similar(η)
    ∫ᶻ_Axᶠᶜᶜ = model.free_surface.implicit_step_solver.vertically_integrated_lateral_areas.xᶠᶜᶜ
    ∫ᶻ_Ayᶜᶠᶜ = model.free_surface.implicit_step_solver.vertically_integrated_lateral_areas.yᶜᶠᶜ
    g = model.free_surface.gravitational_acceleration
    Δt = one(FT)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.implicit_free_surface_linear_operation!(lhs, η, ∫ᶻ_Axᶠᶜᶜ, ∫ᶻ_Ayᶜᶠᶜ, g, Δt)

    function implicit_free_surface_pressure_flux_u_test(i, j, k, grid, η)
        return Oceananigans.Models.HydrostaticFreeSurfaceModels.implicit_free_surface_pressure_flux_u(i, j, k, grid, η)
    end

    function implicit_free_surface_pressure_flux_v_test(i, j, k, grid, η)
        return Oceananigans.Models.HydrostaticFreeSurfaceModels.implicit_free_surface_pressure_flux_v(i, j, k, grid, η)
    end

    k_top = grid.Nz + 1
    samples = ((2, div(N, 2), k_top),
               (N - 1, div(N, 2), k_top),
               (div(N, 2), 2, k_top),
               (div(N, 2), N - 1, k_top))
    maximum_transformed_difference = zero(FT)

    for (i, j, k) in samples
        Az = Oceananigans.Operators.Azᶜᶜᶜ(i, j, grid.Nz, grid)

        expected_lhs =
            (Oceananigans.Operators.δxᶜᵃᵃ(i, j, k, grid,
                                         implicit_free_surface_pressure_flux_u_test,
                                         η) +
             Oceananigans.Operators.δyᵃᶜᵃ(i, j, k, grid,
                                         implicit_free_surface_pressure_flux_v_test,
                                         η)) -
            Az * η[i, j, k] / (g * Δt^2)

        naive_lhs =
            (Oceananigans.Operators.δxᶜᵃᵃ(i, j, k, grid,
                                         Oceananigans.Models.HydrostaticFreeSurfaceModels.∫ᶻ_Ax_∂x_ηᶠᶜᶜ,
                                         ∫ᶻ_Axᶠᶜᶜ, η) +
             Oceananigans.Operators.δyᵃᶜᵃ(i, j, k, grid,
                                         Oceananigans.Models.HydrostaticFreeSurfaceModels.∫ᶻ_Ay_∂y_ηᶜᶠᶜ,
                                         ∫ᶻ_Ayᶜᶠᶜ, η)) -
            Az * η[i, j, k] / (g * Δt^2)

        computed_lhs = lhs[i, j, k]
        lhs_scale = max(one(FT), abs(expected_lhs), abs(computed_lhs))
        @test abs(computed_lhs - expected_lhs) ≤ 1000eps(FT) * lhs_scale
        maximum_transformed_difference = max(maximum_transformed_difference, abs(expected_lhs - naive_lhs))
    end

    @test maximum_transformed_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_implicit_free_surface_preconditioner_uses_nonorthogonal_local_diagonal(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    free_surface = ImplicitFreeSurface()
    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    residual = similar(model.free_surface.displacement)
    set!(residual, (λ, φ, z) -> convert(FT, 0.3) * sind(λ / 2) - convert(FT, 0.1) * cosd(φ))
    fill_halo_regions!(residual)

    preconditioned = similar(residual)
    ∫ᶻ_Axᶠᶜᶜ = model.free_surface.implicit_step_solver.vertically_integrated_lateral_areas.xᶠᶜᶜ
    ∫ᶻ_Ayᶜᶠᶜ = model.free_surface.implicit_step_solver.vertically_integrated_lateral_areas.yᶜᶠᶜ
    g = model.free_surface.gravitational_acceleration
    Δt = one(FT)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.diagonally_dominant_inverse_precondition!(
        preconditioned, residual, ∫ᶻ_Axᶠᶜᶜ, ∫ᶻ_Ayᶜᶠᶜ, g, Δt)

    k_top = grid.Nz + 1
    samples = ((2, div(N, 2), k_top),
               (N - 1, div(N, 2), k_top),
               (div(N, 2), 2, k_top),
               (div(N, 2), N - 1, k_top))
    maximum_safe_fallback_difference = zero(FT)
    maximum_orthogonal_difference = zero(FT)

    for (i, j, k) in samples
        diagonal = Oceananigans.Models.HydrostaticFreeSurfaceModels.local_implicit_free_surface_diagonal_coefficient(i, j, k, grid, ∫ᶻ_Axᶠᶜᶜ, ∫ᶻ_Ayᶜᶠᶜ, g, Δt)
        expected = residual[i, j, k] / diagonal
        safe_fallback = - g * Δt^2 * residual[i, j, k] / Oceananigans.Operators.Azᶜᶜᶜ(i, j, 1, grid)
        orthogonal_diagonal = Oceananigans.Models.HydrostaticFreeSurfaceModels.Ac(i, j, grid, g, Δt, ∫ᶻ_Axᶠᶜᶜ, ∫ᶻ_Ayᶜᶠᶜ)
        orthogonal = residual[i, j, k] / orthogonal_diagonal
        scale = max(one(FT), abs(expected), abs(preconditioned[i, j, k]))
        @test abs(preconditioned[i, j, k] - expected) ≤ 1000eps(FT) * scale
        maximum_safe_fallback_difference = max(maximum_safe_fallback_difference, abs(expected - safe_fallback))
        maximum_orthogonal_difference = max(maximum_orthogonal_difference, abs(expected - orthogonal))
    end

    @test maximum_safe_fallback_difference > 100eps(FT)
    @test maximum_orthogonal_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_implicit_barotropic_pressure_correction_uses_covariant_gradient(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    free_surface = ImplicitFreeSurface()
    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    η = model.free_surface.displacement
    set!(η, (λ, φ, z) -> sind(λ / 2) + convert(FT, 0.17) * cosd(φ))
    fill_halo_regions!(η)

    parent(model.velocities.u) .= zero(FT)
    parent(model.velocities.v) .= zero(FT)

    g = model.free_surface.gravitational_acceleration
    Δt = one(FT)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.correct_barotropic_mode!(model, model.free_surface, Δt)

    u_samples = ((2, div(N, 2), 1),
                 (N - 1, div(N, 2), 1),
                 (div(N, 2), 2, 1),
                 (div(N, 2), N - 1, 1))
    v_samples = ((2, div(N, 2), 1),
                 (N - 1, div(N, 2), 1),
                 (div(N, 2), 2, 1),
                 (div(N, 2), N - 1, 1))

    maximum_transformed_u_difference = zero(FT)
    maximum_transformed_v_difference = zero(FT)

    for (i, j, k) in u_samples
        expected_u = -g * Δt * covariant_gradient_xᶠᶜᶜ(i, j, grid.Nz + 1, grid, η)
        naive_u = -g * Δt * Oceananigans.Operators.δxᶠᶜᶠ(i, j, grid.Nz + 1, grid, η) *
                  Oceananigans.Operators.Δx⁻¹ᶠᶜᶠ(i, j, k, grid)
        computed_u = model.velocities.u[i, j, k]
        correction_scale = max(one(FT), abs(expected_u), abs(computed_u))

        @test abs(computed_u - expected_u) ≤ 1000eps(FT) * correction_scale
        maximum_transformed_u_difference = max(maximum_transformed_u_difference, abs(expected_u - naive_u))
    end

    for (i, j, k) in v_samples
        expected_v = -g * Δt * covariant_gradient_yᶜᶠᶜ(i, j, grid.Nz + 1, grid, η)
        naive_v = -g * Δt * Oceananigans.Operators.δyᶜᶠᶠ(i, j, grid.Nz + 1, grid, η) *
                  Oceananigans.Operators.Δy⁻¹ᶜᶠᶠ(i, j, k, grid)
        computed_v = model.velocities.v[i, j, k]
        correction_scale = max(one(FT), abs(expected_v), abs(computed_v))

        @test abs(computed_v - expected_v) ≤ 1000eps(FT) * correction_scale
        maximum_transformed_v_difference = max(maximum_transformed_v_difference, abs(expected_v - naive_v))
    end

    @test maximum_transformed_u_difference > 100eps(FT)
    @test maximum_transformed_v_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_prescribed_transport_velocity_fields_respect_target_grid(FT, N)
    radius = convert(FT, 3)
    source_mapping = OctaHEALPixMapping(div(N, 2))
    source_grid = SphericalShellGrid(CPU(), FT; mapping = source_mapping,
                                     z = (zero(FT), one(FT)),
                                     radius,
                                     halo = (1, 1, 1))

    destination_mapping = OctaHEALPixMapping(N)
    destination_grid = SphericalShellGrid(CPU(), FT; mapping = destination_mapping,
                                          z = (zero(FT), one(FT)),
                                          radius,
                                          halo = (1, 1, 1))

    qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(-one(FT))
    source_u_bcs = FieldBoundaryConditions(source_grid, (Face(), Center(), Center());
                                           south = qcov,
                                           north = qcov)
    source_v_bcs = FieldBoundaryConditions(source_grid, (Center(), Face(), Center());
                                           west = qcov,
                                           east = qcov)

    source_u = XFaceField(source_grid; boundary_conditions = source_u_bcs)
    source_v = YFaceField(source_grid; boundary_conditions = source_v_bcs)
    velocities = PrescribedVelocityFields(u = source_u, v = source_v)

    transport_velocities =
        Oceananigans.Models.HydrostaticFreeSurfaceModels.transport_velocity_fields(velocities, destination_grid)

    @test transport_velocities.u.grid === destination_grid
    @test transport_velocities.v.grid === destination_grid
    @test transport_velocities.w.grid === destination_grid
    @test transport_velocities.u.boundary_conditions.south isa Oceananigans.BoundaryConditions.QConZBC
    @test transport_velocities.u.boundary_conditions.north isa Oceananigans.BoundaryConditions.QConZBC
    @test transport_velocities.v.boundary_conditions.west isa Oceananigans.BoundaryConditions.QConZBC
    @test transport_velocities.v.boundary_conditions.east isa Oceananigans.BoundaryConditions.QConZBC
    @test transport_velocities.u.boundary_conditions.south.condition == -one(FT)
    @test transport_velocities.u.boundary_conditions.north.condition == -one(FT)
    @test transport_velocities.v.boundary_conditions.west.condition == -one(FT)
    @test transport_velocities.v.boundary_conditions.east.condition == -one(FT)

    return nothing
end

function test_octahealpix_prescribed_field_transport_state_drives_tracer_tendency(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(one(FT))
    u_bcs = FieldBoundaryConditions(grid, (Face(), Center(), Center());
                                    south = qcov,
                                    north = qcov)
    v_bcs = FieldBoundaryConditions(grid, (Center(), Face(), Center());
                                    west = qcov,
                                    east = qcov)

    u = XFaceField(grid; boundary_conditions = u_bcs)
    v = YFaceField(grid; boundary_conditions = v_bcs)

    for j in 1:grid.Ny, i in 1:grid.Nx
        ring = grid.connectivity.matrix_to_ring[i, j]
        u[i, j, 1] = convert(FT, 1000 + ring)
        v[i, j, 1] = convert(FT, 2000 + ring)
    end

    velocities = PrescribedVelocityFields(u = u, v = v)

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities,
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    @test model.transport_velocities !== model.velocities

    set!(model, c = (λ, φ, z) -> sind(2 * λ) + cosd(φ))

    compute_transport_velocities!(model, model.free_surface)
    compute_tracer_tendencies!(model)

    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    for (i, j) in sampled_points
        expected_Gc = -div_Uc(i, j, 1, grid, model.advection.c, model.transport_velocities, model.tracers.c)
        computed_Gc = model.timestepper.Gⁿ.c[i, j, 1]
        tendency_scale = max(abs(expected_Gc), one(FT))
        @test abs(expected_Gc) > 100eps(FT)
        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale
    end

    forward = Array(interior(model.timestepper.Gⁿ.c))

    set!(model.transport_velocities.u, -model.transport_velocities.u)
    set!(model.transport_velocities.v, -model.transport_velocities.v)
    fill_halo_regions!(model.transport_velocities)
    compute_tracer_tendencies!(model)
    reverse = Array(interior(model.timestepper.Gⁿ.c))

    tolerance = 200 * eps(FT) * max(one(FT), max(maximum(abs, forward), maximum(abs, reverse)))

    @test forward ≈ -reverse atol = tolerance
    @test !any(isnan, forward)
    @test !any(isnan, reverse)

    return nothing
end

