function test_octahealpix_single_component_prescribed_transport_velocity_conversion(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    velocities = PrescribedVelocityFields(u = (λ, φ, z, t) -> sind(λ) * cosd(φ))

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities,
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    @test model.transport_velocities !== model.velocities
    @test model.transport_velocities.u.boundary_conditions.south isa Oceananigans.BoundaryConditions.QConZBC
    @test model.transport_velocities.v.boundary_conditions.west isa Oceananigans.BoundaryConditions.QConZBC

    compute_transport_velocities!(model, model.free_surface)

    transport_u_error = maximum((j, i) for j in 1:grid.Ny, i in 1:grid.Nx) do (j, i)
        expected = covariant_to_volume_flux_uᶠᶜᶜ(i, j, 1, grid, model.velocities.u, model.velocities.v)
        return abs(model.transport_velocities.u[i, j, 1] - expected)
    end

    transport_v_maximum = maximum(abs, Array(interior(model.transport_velocities.v)))
    transport_scale = max(maximum(abs, Array(interior(model.transport_velocities.u))), one(FT))

    @test transport_u_error ≤ 1000eps(FT) * transport_scale
    @test transport_v_maximum == zero(FT)

    return nothing
end

function test_octahealpix_inplace_transport_velocity_conversion(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    u = Field{Face, Center, Center}(grid)
    v = Field{Center, Face, Center}(grid)

    for k in 1:size(u, 3), j in 1:size(u, 2), i in 1:size(u, 1)
        u[i, j, k] = convert(FT, 10i + 3j + k)
    end

    for k in 1:size(v, 3), j in 1:size(v, 2), i in 1:size(v, 1)
        v[i, j, k] = convert(FT, -4i + 7j - 2k)
    end

    fill_halo_regions!((u, v))

    expected_u = zeros(FT, size(u)...)
    expected_v = zeros(FT, size(v)...)

    for k in 1:size(u, 3), j in 1:size(u, 2), i in 1:size(u, 1)
        expected_u[i, j, k] = covariant_to_volume_flux_uᶠᶜᶜ(i, j, k, grid, u, v)
    end

    for k in 1:size(v, 3), j in 1:size(v, 2), i in 1:size(v, 1)
        expected_v[i, j, k] = covariant_to_volume_flux_vᶜᶠᶜ(i, j, k, grid, u, v)
    end

    Oceananigans.Models.HydrostaticFreeSurfaceModels.convert_to_volume_flux_velocities!(u, v, grid, u, v)

    transport_u_error = maximum(abs(u[i, j, k] - expected_u[i, j, k])
                                for k in 1:size(u, 3), j in 1:size(u, 2), i in 1:size(u, 1))

    transport_v_error = maximum(abs(v[i, j, k] - expected_v[i, j, k])
                                for k in 1:size(v, 3), j in 1:size(v, 2), i in 1:size(v, 1))

    transport_scale = max(maximum(abs, expected_u), maximum(abs, expected_v), one(FT))

    @test transport_u_error ≤ 1000eps(FT) * transport_scale
    @test transport_v_error ≤ 1000eps(FT) * transport_scale

    return nothing
end

function test_octahealpix_transport_seam_halo_consistency(FT, N, H=1)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (H, H, 1))
    connectivity = grid.connectivity

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    set!(model,
         u = (λ, φ, z) -> sind(λ) * cosd(φ),
         v = (λ, φ, z) -> cosd(λ) * sind(φ))

    fill_halo_regions!(model.velocities)
    compute_transport_velocities!(model, model.free_surface)

    transport_u_halo_max_error = zero(FT)
    transport_v_halo_max_error = zero(FT)
    Nx = grid.Nx
    Ny = grid.Ny

    for j in (1 - H):(Ny + H), i in (1 - H):(Nx + H)
        (1 <= i <= Nx && 1 <= j <= Ny) && continue

        source_field, source_i, source_j, sign = octahealpix_transport_face_halo_source(i, j, connectivity, Nx, Ny, N, :u)
        expected_u = source_field === :u ? sign * model.transport_velocities.u[source_i, source_j, 1] :
                                           sign * model.transport_velocities.v[source_i, source_j, 1]
        transport_u_halo_max_error = max(transport_u_halo_max_error,
                                         abs(model.transport_velocities.u[i, j, 1] - expected_u))

        source_field, source_i, source_j, sign = octahealpix_transport_face_halo_source(i, j, connectivity, Nx, Ny, N, :v)
        expected_v = source_field === :u ? sign * model.transport_velocities.u[source_i, source_j, 1] :
                                           sign * model.transport_velocities.v[source_i, source_j, 1]
        transport_v_halo_max_error = max(transport_v_halo_max_error,
                                         abs(model.transport_velocities.v[i, j, 1] - expected_v))
    end

    @test transport_u_halo_max_error == zero(FT)
    @test transport_v_halo_max_error == zero(FT)

    return nothing
end

function test_octahealpix_transport_halo_refresh_with_free_surface(FT, N, free_surface)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))
    connectivity = grid.connectivity

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    set!(model,
         u = (λ, φ, z) -> sind(λ) * cosd(φ),
         v = (λ, φ, z) -> cosd(λ) * sind(φ),
         c = (λ, φ, z) -> sind(λ / 2) * cosd(φ))

    fill_halo_regions!(model.velocities)
    compute_transport_velocities!(model, model.free_surface)

    source_field, source_i, source_j, sign = octahealpix_transport_face_halo_source(0, N + 1, connectivity, grid.Nx, grid.Ny, N, :u)
    expected_u_halo = source_field === :u ? sign * model.transport_velocities.u[source_i, source_j, 1] :
                                            sign * model.transport_velocities.v[source_i, source_j, 1]

    source_field, source_i, source_j, sign = octahealpix_transport_face_halo_source(N + 1, 0, connectivity, grid.Nx, grid.Ny, N, :v)
    expected_v_halo = source_field === :u ? sign * model.transport_velocities.u[source_i, source_j, 1] :
                                            sign * model.transport_velocities.v[source_i, source_j, 1]

    @test model.transport_velocities.u[0, N + 1, 1] == expected_u_halo
    @test model.transport_velocities.v[N + 1, 0, 1] == expected_v_halo

    return nothing
end

