function test_octahealpix_shallow_water_tracer_divergence_uses_converted_transport_bundle(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))

    h = CenterField(grid)
    uh = XFaceField(grid)
    vh = YFaceField(grid)
    c = CenterField(grid)

    set!(h, (λ, φ, z) -> convert(FT, 2) + convert(FT, 1//10) * cosd(φ))
    set!(uh, (λ, φ, z) -> convert(FT, 1) + convert(FT, 1//5) * sind(λ) + convert(FT, 1//10) * cosd(φ))
    set!(vh, (λ, φ, z) -> convert(FT, 2) - convert(FT, 1//6) * cosd(λ) + convert(FT, 1//8) * sind(φ))
    set!(c, (λ, φ, z) -> convert(FT, 1//2) + convert(FT, 1//4) * sind(λ) * cosd(φ))

    fill_halo_regions!(h)
    fill_halo_regions!(c)
    fill_halo_regions!((uh, vh))

    solution = (; h, uh, vh)
    converted_transport =
        Oceananigans.Advection.spherical_shell_horizontal_volume_flux_velocities(grid, (uh, vh))
    advection = Centered(FT)
    formulation = Oceananigans.Models.ShallowWaterModels.ConservativeFormulation()

    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    for (i, j) in sampled_points
        computed_divergence =
            Oceananigans.Models.ShallowWaterModels.div_Uc(i, j, 1, grid, advection, solution, c, formulation)

        expected_divergence =
            Oceananigans.Operators.Azᶜᶜᶜ(i, j, 1, grid)^(-1) *
            (Oceananigans.Operators.δxᶜᵃᵃ(i, j, 1, grid,
                                          Oceananigans.Models.ShallowWaterModels.transport_tracer_flux_x,
                                          advection, converted_transport, h, c) +
             Oceananigans.Operators.δyᵃᶜᵃ(i, j, 1, grid,
                                          Oceananigans.Models.ShallowWaterModels.transport_tracer_flux_y,
                                          advection, converted_transport, h, c))

        divergence_scale = max(abs(expected_divergence), one(FT))
        @test abs(expected_divergence) > 100eps(FT)
        @test abs(computed_divergence - expected_divergence) ≤ 1000eps(FT) * divergence_scale
    end

    return nothing
end

function test_octahealpix_shallow_water_momentum_divergence_uses_converted_transport_bundle(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))

    h = CenterField(grid)
    uh = XFaceField(grid)
    vh = YFaceField(grid)

    set!(h, (λ, φ, z) -> convert(FT, 2) + convert(FT, 1//10) * cosd(φ))
    set!(uh, (λ, φ, z) -> convert(FT, 1) + convert(FT, 1//5) * sind(λ) + convert(FT, 1//10) * cosd(φ))
    set!(vh, (λ, φ, z) -> convert(FT, 2) - convert(FT, 1//6) * cosd(λ) + convert(FT, 1//8) * sind(φ))

    fill_halo_regions!(h)
    fill_halo_regions!((uh, vh))

    solution = (; h, uh, vh)
    converted_transport =
        Oceananigans.Advection.spherical_shell_horizontal_volume_flux_velocities(grid, (uh, vh))
    advection = Centered(FT)
    formulation = Oceananigans.Models.ShallowWaterModels.ConservativeFormulation()

    momentum_flux_huu_converted(i, j, k, grid, advection, converted_transport, solution) =
        Oceananigans.Advection._advective_momentum_flux_Uu(i, j, k, grid, advection,
                                                           converted_transport,
                                                           solution.uh) / solution.h[i, j, k]

    momentum_flux_hvu_converted(i, j, k, grid, advection, converted_transport, solution) =
        Oceananigans.Advection._advective_momentum_flux_Vu(i, j, k, grid, advection,
                                                           converted_transport,
                                                           solution.uh) / Oceananigans.Operators.ℑxyᶠᶠᵃ(i, j, k, grid, solution.h)

    momentum_flux_huv_converted(i, j, k, grid, advection, converted_transport, solution) =
        Oceananigans.Advection._advective_momentum_flux_Uv(i, j, k, grid, advection,
                                                           converted_transport,
                                                           solution.vh) / Oceananigans.Operators.ℑxyᶠᶠᵃ(i, j, k, grid, solution.h)

    momentum_flux_hvv_converted(i, j, k, grid, advection, converted_transport, solution) =
        Oceananigans.Advection._advective_momentum_flux_Vv(i, j, k, grid, advection,
                                                           converted_transport,
                                                           solution.vh) / solution.h[i, j, k]

    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    for (i, j) in sampled_points
        computed_div_mom_u =
            Oceananigans.Models.ShallowWaterModels.div_mom_u(i, j, 1, grid, advection, solution, formulation)
        computed_div_mom_v =
            Oceananigans.Models.ShallowWaterModels.div_mom_v(i, j, 1, grid, advection, solution, formulation)

        expected_div_mom_u =
            Oceananigans.Operators.Azᶠᶜᶜ(i, j, 1, grid)^(-1) *
            (Oceananigans.Operators.δxᶠᵃᵃ(i, j, 1, grid,
                                          momentum_flux_huu_converted,
                                          advection, converted_transport, solution) +
             Oceananigans.Operators.δyᵃᶜᵃ(i, j, 1, grid,
                                          momentum_flux_hvu_converted,
                                          advection, converted_transport, solution))

        expected_div_mom_v =
            Oceananigans.Operators.Azᶜᶠᶜ(i, j, 1, grid)^(-1) *
            (Oceananigans.Operators.δxᶜᵃᵃ(i, j, 1, grid,
                                          momentum_flux_huv_converted,
                                          advection, converted_transport, solution) +
             Oceananigans.Operators.δyᵃᶠᵃ(i, j, 1, grid,
                                          momentum_flux_hvv_converted,
                                          advection, converted_transport, solution))

        divergence_scale_u = max(abs(expected_div_mom_u), one(FT))
        divergence_scale_v = max(abs(expected_div_mom_v), one(FT))

        @test abs(expected_div_mom_u) > 100eps(FT)
        @test abs(expected_div_mom_v) > 100eps(FT)
        @test abs(computed_div_mom_u - expected_div_mom_u) ≤ 1000eps(FT) * divergence_scale_u
        @test abs(computed_div_mom_v - expected_div_mom_v) ≤ 1000eps(FT) * divergence_scale_v
    end

    return nothing
end

function test_octahealpix_shallow_water_conservative_velocity_fields_use_paired_compute(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    h = CenterField(grid)
    uh = XFaceField(grid)
    vh = YFaceField(grid)

    set!(h, (λ, φ, z) -> convert(FT, 2) + convert(FT, 1//10) * cosd(φ))
    set!(uh, (λ, φ, z) -> convert(FT, 1) + convert(FT, 1//5) * sind(λ) + convert(FT, 1//10) * cosd(φ))
    set!(vh, (λ, φ, z) -> convert(FT, 2) - convert(FT, 1//6) * cosd(λ) + convert(FT, 1//8) * sind(φ))

    fill_halo_regions!(h)
    fill_halo_regions!((uh, vh))

    formulation = Oceananigans.Models.ShallowWaterModels.ConservativeFormulation()
    solution = (; h, uh, vh)

    velocities = Oceananigans.Models.ShallowWaterModels.shallow_water_velocities(formulation, solution)

    function expected_conservative_velocities(solution, velocities)
        expected_u = Field(solution.uh / solution.h;
                           boundary_conditions = velocities.u.boundary_conditions,
                           compute = false)
        expected_v = Field(solution.vh / solution.h;
                           boundary_conditions = velocities.v.boundary_conditions,
                           compute = false)

        Oceananigans.Fields.compute!((expected_u, expected_v))
        return expected_u, expected_v
    end

    function check_velocities(velocities, solution)
        expected_u, expected_v = expected_conservative_velocities(solution, velocities)

        u_error = zero(FT)
        v_error = zero(FT)

        for k in 1:grid.Nz, j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
            u_error = max(u_error, abs(velocities.u[i, j, k] - expected_u[i, j, k]))
            v_error = max(v_error, abs(velocities.v[i, j, k] - expected_v[i, j, k]))
        end

        @test u_error == zero(FT)
        @test v_error == zero(FT)
    end

    check_velocities(velocities, solution)

    set!(h, (λ, φ, z) -> convert(FT, 3) - convert(FT, 1//7) * cosd(φ))
    set!(uh, (λ, φ, z) -> convert(FT, 4) - convert(FT, 1//9) * sind(λ) + convert(FT, 1//11) * cosd(φ))
    set!(vh, (λ, φ, z) -> convert(FT, 5) + convert(FT, 1//8) * cosd(λ) - convert(FT, 1//12) * sind(φ))

    fill_halo_regions!(h)
    fill_halo_regions!((uh, vh))

    Oceananigans.Models.ShallowWaterModels.compute_velocities!(velocities, formulation)

    check_velocities(velocities, solution)

    return nothing
end

function test_octahealpix_vector_transform_distinction(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))
    connectivity = grid.connectivity

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    set!(model,
         u = (λ, φ, z) -> convert(FT, 2) + sind(λ) + convert(FT, 1//3) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 5) + cosd(λ) - convert(FT, 1//4) * sind(φ))

    parent(model.transport_velocities.u) .= parent(model.velocities.u)
    parent(model.transport_velocities.v) .= parent(model.velocities.v)

    fill_halo_regions!(model.velocities)
    fill_halo_regions!(model.transport_velocities)

    max_expected_difference = zero(FT)
    max_u_halo_difference = zero(FT)
    max_v_halo_difference = zero(FT)
    Nx = grid.Nx
    Ny = grid.Ny

    for j in 0:(Ny + 1), i in 0:(Nx + 1)
        (1 <= i <= Nx && 1 <= j <= Ny) && continue

        cov_source_field, cov_source_i, cov_source_j, cov_sign =
            octahealpix_face_halo_source(i, j, connectivity, Nx, Ny, N, :u)
        con_source_field, con_source_i, con_source_j, con_sign =
            octahealpix_transport_face_halo_source(i, j, connectivity, Nx, Ny, N, :u)

        expected_cov_u = cov_source_field === :u ? cov_sign * model.velocities.u[cov_source_i, cov_source_j, 1] :
                                                   cov_sign * model.velocities.v[cov_source_i, cov_source_j, 1]
        expected_con_u = con_source_field === :u ? con_sign * model.transport_velocities.u[con_source_i, con_source_j, 1] :
                                                   con_sign * model.transport_velocities.v[con_source_i, con_source_j, 1]

        cov_source_field, cov_source_i, cov_source_j, cov_sign =
            octahealpix_face_halo_source(i, j, connectivity, Nx, Ny, N, :v)
        con_source_field, con_source_i, con_source_j, con_sign =
            octahealpix_transport_face_halo_source(i, j, connectivity, Nx, Ny, N, :v)

        expected_cov_v = cov_source_field === :u ? cov_sign * model.velocities.u[cov_source_i, cov_source_j, 1] :
                                                   cov_sign * model.velocities.v[cov_source_i, cov_source_j, 1]
        expected_con_v = con_source_field === :u ? con_sign * model.transport_velocities.u[con_source_i, con_source_j, 1] :
                                                   con_sign * model.transport_velocities.v[con_source_i, con_source_j, 1]

        max_expected_difference = max(max_expected_difference,
                                      abs(expected_cov_u - expected_con_u),
                                      abs(expected_cov_v - expected_con_v))
        max_u_halo_difference = max(max_u_halo_difference,
                                    abs(model.velocities.u[i, j, 1] - model.transport_velocities.u[i, j, 1]))
        max_v_halo_difference = max(max_v_halo_difference,
                                    abs(model.velocities.v[i, j, 1] - model.transport_velocities.v[i, j, 1]))
    end

    @test max_expected_difference > zero(FT)
    @test max_u_halo_difference == max_expected_difference || max_v_halo_difference == max_expected_difference
    @test max(max_u_halo_difference, max_v_halo_difference) == max_expected_difference

    return nothing
end

