function test_octahealpix_single_field_vector_set_error(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    u = XFaceField(grid)
    v = YFaceField(grid)
    u_reduced = XFaceField(grid; indices = (:, :, 1))
    v_reduced = YFaceField(grid; indices = (:, :, 1))

    set!(u, (λ, φ, z) -> convert(FT, 1) + sind(λ))
    set!(v, (λ, φ, z) -> convert(FT, 2) + cosd(φ))

    @test_throws ArgumentError set!(u_reduced, u)
    @test_throws ArgumentError set!(v_reduced, v)

    source_grid = RectilinearGrid(FT; size = (2N, 2N, 1),
                                  extent = (one(FT), one(FT), one(FT)),
                                  halo = (1, 1, 1))
    source_u = XFaceField(source_grid)
    source_v = YFaceField(source_grid)

    set!(source_u, (x, y, z) -> x + y + z)
    set!(source_v, (x, y, z) -> x - y + z)

    @test_throws ArgumentError set!(u, source_u)
    @test_throws ArgumentError set!(v, source_v)

    return nothing
end

function test_octahealpix_model_set_velocity_halos(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant())

    set!(model,
         u = (λ, φ, z) -> convert(FT, 2) * sind(λ) + cosd(φ),
         v = (λ, φ, z) -> cosd(λ) - convert(FT, 3) * sind(φ))

    connectivity = grid.connectivity
    Nx = grid.Nx
    Ny = grid.Ny

    u_halo_max_error = zero(FT)
    v_halo_max_error = zero(FT)

    for j in 0:(Ny + 1), i in 0:(Nx + 1)
        (1 <= i <= Nx && 1 <= j <= Ny) && continue

        source_field, source_i, source_j, sign =
            octahealpix_face_halo_source(i, j, connectivity, Nx, Ny, N, :u)

        expected_u = if source_field === :u
            sign * model.velocities.u[source_i, source_j, 1]
        else
            sign * model.velocities.v[source_i, source_j, 1]
        end

        u_halo_max_error = max(u_halo_max_error, abs(model.velocities.u[i, j, 1] - expected_u))

        source_field, source_i, source_j, sign =
            octahealpix_face_halo_source(i, j, connectivity, Nx, Ny, N, :v)

        expected_v = if source_field === :u
            sign * model.velocities.u[source_i, source_j, 1]
        else
            sign * model.velocities.v[source_i, source_j, 1]
        end

        v_halo_max_error = max(v_halo_max_error, abs(model.velocities.v[i, j, 1] - expected_v))
    end

    @test u_halo_max_error == zero(FT)
    @test v_halo_max_error == zero(FT)

    return nothing
end

function test_octahealpix_model_set_velocity_fields(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    source_u = XFaceField(grid; indices = (:, :, 1))
    source_v = YFaceField(grid; indices = (:, :, 1))

    set!(source_u, (λ, φ, z) -> convert(FT, 2) * sind(λ) + cosd(φ))
    set!(source_v, (λ, φ, z) -> cosd(λ) - convert(FT, 3) * sind(φ))
    fill_halo_regions!((source_u, source_v))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant())

    set!(model, u = source_u, v = source_v)

    u_interior_error = zero(FT)
    v_interior_error = zero(FT)
    u_halo_error = zero(FT)
    v_halo_error = zero(FT)

    for j in 1:grid.Ny, i in 1:grid.Nx
        u_interior_error = max(u_interior_error, abs(model.velocities.u[i, j, 1] - source_u[i, j, 1]))
        v_interior_error = max(v_interior_error, abs(model.velocities.v[i, j, 1] - source_v[i, j, 1]))
    end

    for j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue
        u_halo_error = max(u_halo_error, abs(model.velocities.u[i, j, 1] - source_u[i, j, 1]))
        v_halo_error = max(v_halo_error, abs(model.velocities.v[i, j, 1] - source_v[i, j, 1]))
    end

    @test u_interior_error == zero(FT)
    @test v_interior_error == zero(FT)
    @test u_halo_error == zero(FT)
    @test v_halo_error == zero(FT)

    return nothing
