                                          radius,
                                          halo = (1, 1, 1))

    source_u = XFaceField(source_grid)
    source_v = YFaceField(source_grid;
                          boundary_conditions =
                              Oceananigans.BoundaryConditions.FieldBoundaryConditions(
                                  source_grid,
                                  (Center(), Face(), Center());
                                  west = source_u.boundary_conditions.south,
                                  east = source_u.boundary_conditions.north,
                                  bottom = source_u.boundary_conditions.bottom,
                                  top = source_u.boundary_conditions.top,
                                  immersed = source_u.boundary_conditions.immersed))

    set!(source_u, (λ, φ, z) -> convert(FT, 2) * sind(λ) + cosd(φ) + convert(FT, 0.1) * z)
    set!(source_v, zero(FT))

    expected_u = XFaceField(destination_grid)
    expected_v = YFaceField(destination_grid)
    Oceananigans.Fields.set_paired_quadfolded_vector_fields!(expected_u, expected_v, source_u, source_v)

    model = HydrostaticFreeSurfaceModel(destination_grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant())
    set!(model, u = source_u, v = ZeroField())

    u_error = zero(FT)
    v_error = zero(FT)

    for k in 0:(destination_grid.Nz + 1), j in 0:(destination_grid.Ny + 1), i in 0:(destination_grid.Nx + 1)
        u_error = max(u_error, abs(model.velocities.u[i, j, k] - expected_u[i, j, k]))
        v_error = max(v_error, abs(model.velocities.v[i, j, k] - expected_v[i, j, k]))
    end

    @test u_error == zero(FT)
    @test v_error == zero(FT)

    return nothing
end

