        v_error = max(v_error, abs(velocities_from_namedtuple.v[i, j, 1] - expected_v[i, j, 1]))
    end

    @test u_error == zero(FT)
    @test v_error == zero(FT)

    constant_source_v = Oceananigans.Fields.ConstantField(convert(FT, 1//2))
    constant_companion_v = YFaceField(source_grid;
                                      boundary_conditions =
                                          Oceananigans.BoundaryConditions.FieldBoundaryConditions(
                                              source_grid,
                                              (Center(), Face(), Center());
                                              west = source_u.boundary_conditions.south,
                                              east = source_u.boundary_conditions.north))
