        u_error = max(u_error, abs(velocities_constant_keyword.u[i, j, 1] - expected_u[i, j, 1]))
        v_error = max(v_error, abs(velocities_constant_keyword.v[i, j, 1] - expected_v[i, j, 1]))
    end

    @test u_error == zero(FT)
    @test v_error == zero(FT)

