    v_error = zero(FT)

    for j in 0:(destination_grid.Ny + 1), i in 0:(destination_grid.Nx + 1)
        u_error = max(u_error, abs(velocities_constant_namedtuple.u[i, j, 1] - expected_u[i, j, 1]))
        v_error = max(v_error, abs(velocities_constant_namedtuple.v[i, j, 1] - expected_v[i, j, 1]))
    end

    @test u_error == zero(FT)
    @test v_error == zero(FT)

    one_source_v = Oceananigans.Fields.OneField()
    one_companion_v = YFaceField(source_grid;
                                 boundary_conditions =
                                     Oceananigans.BoundaryConditions.FieldBoundaryConditions(
                                         source_grid,
                                         (Center(), Face(), Center());
                                         west = source_u.boundary_conditions.south,
                                         east = source_u.boundary_conditions.north))
    set!(one_companion_v, one_source_v)

    Oceananigans.Fields.set_paired_quadfolded_vector_fields!(expected_u, expected_v, source_u, one_companion_v)

    velocities_one_keyword = (u = XFaceField(destination_grid),
                              v = YFaceField(destination_grid),
                              w = ZFaceField(destination_grid))
    set!(velocities_one_keyword, u = source_u, v = one_source_v)
    fill_halo_regions!(velocities_one_keyword)
    fill_halo_regions!((expected_u, expected_v))

    u_error = zero(FT)
    v_error = zero(FT)

    for j in 0:(destination_grid.Ny + 1), i in 0:(destination_grid.Nx + 1)
        u_error = max(u_error, abs(velocities_one_keyword.u[i, j, 1] - expected_u[i, j, 1]))
        v_error = max(v_error, abs(velocities_one_keyword.v[i, j, 1] - expected_v[i, j, 1]))
    end

    @test u_error == zero(FT)
    @test v_error == zero(FT)

    velocities_one_namedtuple = (u = XFaceField(destination_grid),
                                 v = YFaceField(destination_grid),
                                 w = ZFaceField(destination_grid))
    set!(velocities_one_namedtuple, (u = source_u, v = one_source_v))
    fill_halo_regions!(velocities_one_namedtuple)

    u_error = zero(FT)
    v_error = zero(FT)

    for j in 0:(destination_grid.Ny + 1), i in 0:(destination_grid.Nx + 1)
        u_error = max(u_error, abs(velocities_one_namedtuple.u[i, j, 1] - expected_u[i, j, 1]))
        v_error = max(v_error, abs(velocities_one_namedtuple.v[i, j, 1] - expected_v[i, j, 1]))
    end

    @test u_error == zero(FT)
    @test v_error == zero(FT)

    Oceananigans.Fields.set_paired_quadfolded_vector_fields!(expected_u, expected_v, alternate_source_u, alternate_source_v)

    @test_throws ArgumentError set!(velocities, v = alternate_source_v)
    @test_throws ArgumentError set!(velocities, (v = alternate_source_v,))

    velocities_from_v = (u = XFaceField(destination_grid),
                         v = YFaceField(destination_grid),
                         w = ZFaceField(destination_grid))
    set!(velocities_from_v, u = ZeroField(), v = alternate_source_v)
    fill_halo_regions!(velocities_from_v)
    fill_halo_regions!((expected_u, expected_v))

    u_error = zero(FT)
    v_error = zero(FT)

    for j in 0:(destination_grid.Ny + 1), i in 0:(destination_grid.Nx + 1)
        u_error = max(u_error, abs(velocities_from_v.u[i, j, 1] - expected_u[i, j, 1]))
        v_error = max(v_error, abs(velocities_from_v.v[i, j, 1] - expected_v[i, j, 1]))
    end

    @test u_error == zero(FT)
    @test v_error == zero(FT)

    velocities_from_v_namedtuple = (u = XFaceField(destination_grid),
                                    v = YFaceField(destination_grid),
                                    w = ZFaceField(destination_grid))
    set!(velocities_from_v_namedtuple, (u = ZeroField(), v = alternate_source_v))
    fill_halo_regions!(velocities_from_v_namedtuple)

    u_error = zero(FT)
    v_error = zero(FT)

    for j in 0:(destination_grid.Ny + 1), i in 0:(destination_grid.Nx + 1)
        u_error = max(u_error, abs(velocities_from_v_namedtuple.u[i, j, 1] - expected_u[i, j, 1]))
        v_error = max(v_error, abs(velocities_from_v_namedtuple.v[i, j, 1] - expected_v[i, j, 1]))
    end

    @test u_error == zero(FT)
    @test v_error == zero(FT)

    return nothing
end

function test_octahealpix_model_partial_velocity_field_set(FT, N)
    radius = convert(FT, 3)
    source_mapping = OctaHEALPixMapping(div(N, 2))
    source_grid = SphericalShellGrid(CPU(), FT; mapping = source_mapping,
                                     z = (zero(FT), one(FT)),
                                     radius,
                                     halo = (1, 1, 1))

    destination_mapping = OctaHEALPixMapping(N)
    destination_grid = SphericalShellGrid(CPU(), FT; mapping = destination_mapping,
                                          z = (zero(FT), one(FT)),
                                          radius,
                                          halo = (1, 1, 1))

    source_u = XFaceField(source_grid)
    set!(source_u, (λ, φ, z) -> convert(FT, 2) * sind(λ) + cosd(φ))
    source_v = YFaceField(source_grid;
                          boundary_conditions =
                              Oceananigans.BoundaryConditions.FieldBoundaryConditions(
                                  source_grid,
                                  (Center(), Face(), Center());
                                  west = source_u.boundary_conditions.south,
                                  east = source_u.boundary_conditions.north))
    set!(source_v, zero(FT))
    alternate_source_v = YFaceField(source_grid)
    set!(alternate_source_v, (λ, φ, z) -> cosd(λ) - convert(FT, 3) * sind(φ))
    alternate_source_u = XFaceField(source_grid;
                                    boundary_conditions =
                                        Oceananigans.BoundaryConditions.FieldBoundaryConditions(
                                            source_grid,
                                            (Face(), Center(), Center());
                                            south = alternate_source_v.boundary_conditions.west,
                                            north = alternate_source_v.boundary_conditions.east))
    set!(alternate_source_u, zero(FT))

    model = HydrostaticFreeSurfaceModel(destination_grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant())
    expected_u = XFaceField(destination_grid)
    expected_v = YFaceField(destination_grid)

    Oceananigans.Fields.set_paired_quadfolded_vector_fields!(expected_u, expected_v, source_u, source_v)
    set!(model, u = source_u)
    fill_halo_regions!((expected_u, expected_v))

    u_error = zero(FT)
    v_error = zero(FT)

    for j in 0:(destination_grid.Ny + 1), i in 0:(destination_grid.Nx + 1)
        u_error = max(u_error, abs(model.velocities.u[i, j, 1] - expected_u[i, j, 1]))
        v_error = max(v_error, abs(model.velocities.v[i, j, 1] - expected_v[i, j, 1]))
    end

    @test u_error == zero(FT)
    @test v_error == zero(FT)

    Oceananigans.Fields.set_paired_quadfolded_vector_fields!(expected_u, expected_v, alternate_source_u, alternate_source_v)
    set!(model, v = alternate_source_v)

    u_error = zero(FT)
    v_error = zero(FT)

    for j in 0:(destination_grid.Ny + 1), i in 0:(destination_grid.Nx + 1)
        u_error = max(u_error, abs(model.velocities.u[i, j, 1] - expected_u[i, j, 1]))
        v_error = max(v_error, abs(model.velocities.v[i, j, 1] - expected_v[i, j, 1]))
    end

    @test u_error == zero(FT)
    @test v_error == zero(FT)

    return nothing
end

function test_octahealpix_split_explicit_partial_barotropic_velocity_field_set(FT, N)
    radius = convert(FT, 3)
    source_mapping = OctaHEALPixMapping(div(N, 2))
    source_grid = SphericalShellGrid(CPU(), FT; mapping = source_mapping,
                                     size = (N, N, 2),
                                     z = (zero(FT), one(FT)),
                                     radius,
                                     halo = (1, 1, 1))

    destination_mapping = OctaHEALPixMapping(N)
    destination_grid = SphericalShellGrid(CPU(), FT; mapping = destination_mapping,
                                          size = (2N, 2N, 2),
                                          z = (zero(FT), one(FT)),
                                          radius,
                                          halo = (1, 1, 1))

    source_model = HydrostaticFreeSurfaceModel(source_grid;
                                               tracers = nothing,
                                               buoyancy = nothing,
                                               free_surface = SplitExplicitFreeSurface(substeps = 8),
                                               momentum_advection = nothing)

    keyword_model = HydrostaticFreeSurfaceModel(destination_grid;
                                                tracers = nothing,
                                                buoyancy = nothing,
                                                free_surface = SplitExplicitFreeSurface(substeps = 8),
                                                momentum_advection = nothing)

    namedtuple_model = HydrostaticFreeSurfaceModel(destination_grid;
                                                   tracers = nothing,
                                                   buoyancy = nothing,
                                                   free_surface = SplitExplicitFreeSurface(substeps = 8),
                                                   momentum_advection = nothing)

    expected_model = HydrostaticFreeSurfaceModel(destination_grid;
                                                 tracers = nothing,
                                                 buoyancy = nothing,
                                                 free_surface = SplitExplicitFreeSurface(substeps = 8),
                                                 momentum_advection = nothing)

    source_u = source_model.free_surface.filtered_state.Ũ
    source_v = source_model.free_surface.filtered_state.Ṽ
    set!(source_u, (λ, φ, z) -> convert(FT, 2) * sind(λ) + cosd(φ))
    set!(source_v, zero(FT))

    expected_u = expected_model.free_surface.filtered_state.Ũ
    expected_v = expected_model.free_surface.filtered_state.Ṽ

    Oceananigans.Fields.set_paired_quadfolded_vector_fields!(expected_u, expected_v, source_u, source_v)

    keyword_fields = (u = keyword_model.free_surface.filtered_state.Ũ,
                      v = keyword_model.free_surface.filtered_state.Ṽ)
    set!(keyword_fields, u = source_u, v = ZeroField())
    fill_halo_regions!(keyword_fields)
    fill_halo_regions!((expected_u, expected_v))

    u_error = maximum(abs, parent(keyword_fields.u) .- parent(expected_u))
    v_error = maximum(abs, parent(keyword_fields.v) .- parent(expected_v))

    @test u_error == zero(FT)
    @test v_error == zero(FT)

    namedtuple_fields = (u = namedtuple_model.free_surface.filtered_state.Ũ,
                         v = namedtuple_model.free_surface.filtered_state.Ṽ)
    set!(namedtuple_fields, (u = source_u, v = ZeroField()))
    fill_halo_regions!(namedtuple_fields)

    u_error = maximum(abs, parent(namedtuple_fields.u) .- parent(expected_u))
    v_error = maximum(abs, parent(namedtuple_fields.v) .- parent(expected_v))

    @test u_error == zero(FT)
    @test v_error == zero(FT)

    alternate_source_u = source_model.free_surface.barotropic_velocities.U
    alternate_source_v = source_model.free_surface.barotropic_velocities.V
    set!(alternate_source_u, zero(FT))
    set!(alternate_source_v, (λ, φ, z) -> cosd(λ) - convert(FT, 3) * sind(φ))

    Oceananigans.Fields.set_paired_quadfolded_vector_fields!(expected_u, expected_v, alternate_source_u, alternate_source_v)

    set!(keyword_fields, u = ZeroField(), v = alternate_source_v)
    fill_halo_regions!(keyword_fields)
    fill_halo_regions!((expected_u, expected_v))

    u_error = maximum(abs, parent(keyword_fields.u) .- parent(expected_u))
    v_error = maximum(abs, parent(keyword_fields.v) .- parent(expected_v))

    @test u_error == zero(FT)
    @test v_error == zero(FT)

    set!(namedtuple_fields, (u = ZeroField(), v = alternate_source_v))
    fill_halo_regions!(namedtuple_fields)

    u_error = maximum(abs, parent(namedtuple_fields.u) .- parent(expected_u))
    v_error = maximum(abs, parent(namedtuple_fields.v) .- parent(expected_v))

    @test u_error == zero(FT)
    @test v_error == zero(FT)

    return nothing
end

function test_octahealpix_split_explicit_model_field_collections_fill_all_horizontal_pairs(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = SplitExplicitFreeSurface(substeps = 8),
                                        momentum_advection = nothing)

    reference_model = HydrostaticFreeSurfaceModel(grid;
                                                  tracers = nothing,
                                                  buoyancy = nothing,
                                                  free_surface = SplitExplicitFreeSurface(substeps = 8),
                                                  momentum_advection = nothing)

    model_u = model.velocities.u
    model_v = model.velocities.v
    model_U = model.free_surface.barotropic_velocities.U
    model_V = model.free_surface.barotropic_velocities.V

    reference_u = reference_model.velocities.u
    reference_v = reference_model.velocities.v
    reference_U = reference_model.free_surface.barotropic_velocities.U
    reference_V = reference_model.free_surface.barotropic_velocities.V

    set!(model_u, (λ, φ, z) -> convert(FT, 0.2) * sind(λ) + convert(FT, 0.1) * cosd(φ) + convert(FT, 0.05) * z)
    set!(model_v, (λ, φ, z) -> convert(FT, 0.15) * cosd(λ) - convert(FT, 0.05) * sind(φ) - convert(FT, 0.02) * z)
    set!(model_U, (λ, φ, z) -> convert(FT, 0.6) * cosd(λ / 2) + convert(FT, 0.1) * sind(φ))
    set!(model_V, (λ, φ, z) -> convert(FT, -0.4) * sind(λ / 3) + convert(FT, 0.2) * cosd(φ / 2))

    set!(reference_u, (λ, φ, z) -> convert(FT, 0.2) * sind(λ) + convert(FT, 0.1) * cosd(φ) + convert(FT, 0.05) * z)
    set!(reference_v, (λ, φ, z) -> convert(FT, 0.15) * cosd(λ) - convert(FT, 0.05) * sind(φ) - convert(FT, 0.02) * z)
    set!(reference_U, (λ, φ, z) -> convert(FT, 0.6) * cosd(λ / 2) + convert(FT, 0.1) * sind(φ))
    set!(reference_V, (λ, φ, z) -> convert(FT, -0.4) * sind(λ / 3) + convert(FT, 0.2) * cosd(φ / 2))

    reference_fields = Oceananigans.Models.fields(reference_model)
    fill_halo_regions!((reference_u, reference_v), reference_model.clock, reference_fields)
    fill_halo_regions!((reference_U, reference_V), reference_model.clock, reference_fields)

    function corrupt_halos!(field, reference_field, halo_value)
        field.data .= halo_value

        for k in 1:size(field, 3), j in 1:size(field, 2), i in 1:size(field, 1)
            field[i, j, k] = reference_field[i, j, k]
        end

        return nothing
    end

    corrupt_halos!(model_u, reference_u, convert(FT, -13))
    corrupt_halos!(model_v, reference_v, convert(FT, 17))
    corrupt_halos!(model_U, reference_U, convert(FT, -19))
    corrupt_halos!(model_V, reference_V, convert(FT, 23))

    model_fields = Oceananigans.Models.fields(model)
    fill_halo_regions!(model_fields, model.clock, model_fields)

    u_error = maximum(abs, parent(model_u) .- parent(reference_u))
    v_error = maximum(abs, parent(model_v) .- parent(reference_v))
    U_error = maximum(abs, parent(model_U) .- parent(reference_U))
    V_error = maximum(abs, parent(model_V) .- parent(reference_V))

    @test u_error == zero(FT)
    @test v_error == zero(FT)
    @test U_error == zero(FT)
    @test V_error == zero(FT)

    corrupt_halos!(model_u, reference_u, convert(FT, -29))
    corrupt_halos!(model_v, reference_v, convert(FT, 31))
    corrupt_halos!(model_U, reference_U, convert(FT, -37))
    corrupt_halos!(model_V, reference_V, convert(FT, 41))

    fill_halo_regions!((model_u,
                        model_v,
                        model.velocities.w,
                        model_U,
                        model_V),
                       model.clock,
                       model_fields)

    u_error = maximum(abs, parent(model_u) .- parent(reference_u))
    v_error = maximum(abs, parent(model_v) .- parent(reference_v))
    U_error = maximum(abs, parent(model_U) .- parent(reference_U))
    V_error = maximum(abs, parent(model_V) .- parent(reference_V))

    @test u_error == zero(FT)
    @test v_error == zero(FT)
    @test U_error == zero(FT)
    @test V_error == zero(FT)

    return nothing
end

function test_octahealpix_same_grid_partial_velocity_field_set_preserves_unspecified_component(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    source_u = XFaceField(grid)
    initial_u = XFaceField(grid)
    initial_v = YFaceField(grid)

    set!(source_u, (λ, φ, z) -> convert(FT, 2) * sind(λ) + cosd(φ))
    set!(initial_u, (λ, φ, z) -> convert(FT, 0.2) * cosd(λ) - convert(FT, 0.1) * sind(φ))
    set!(initial_v, (λ, φ, z) -> convert(FT, 0.3) * cosd(λ / 2) + convert(FT, 0.1) * sind(φ))
    fill_halo_regions!((source_u, initial_u, initial_v))

    velocities = (u = XFaceField(grid),
                  v = YFaceField(grid),
                  w = ZFaceField(grid))
    set!(velocities, u = initial_u, v = initial_v)
    set!(velocities, u = source_u)
    fill_halo_regions!(velocities)

    u_error = zero(FT)
    v_error = zero(FT)

    for j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        u_error = max(u_error, abs(velocities.u[i, j, 1] - source_u[i, j, 1]))
        v_error = max(v_error, abs(velocities.v[i, j, 1] - initial_v[i, j, 1]))
    end

    @test u_error == zero(FT)
    @test v_error == zero(FT)

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant())
    set!(model, u = initial_u, v = initial_v)
    set!(model, u = source_u)

    u_error = zero(FT)
    v_error = zero(FT)

    for j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        u_error = max(u_error, abs(model.velocities.u[i, j, 1] - source_u[i, j, 1]))
        v_error = max(v_error, abs(model.velocities.v[i, j, 1] - initial_v[i, j, 1]))
    end

    @test u_error == zero(FT)
    @test v_error == zero(FT)

    return nothing
end

