function test_octahealpix_reconcile_state_refreshes_pressure_and_transport_state(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :b,
                                        buoyancy = BuoyancyTracer(),
                                        free_surface = nothing,
                                        momentum_advection = Centered(),
                                        tracer_advection = Centered(FT))

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.2) * sind(λ) + convert(FT, 0.1) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.15) * cosd(λ) - convert(FT, 0.05) * sind(φ),
         b = (λ, φ, z) -> convert(FT, 0.2) * sind(λ / 2) * cosd(φ) + convert(FT, 0.1) * z)

    expected_pressure = CenterField(grid)
    set!(expected_pressure, model.pressure.pHY′)

    expected_u = XFaceField(grid;
                            boundary_conditions = model.transport_velocities.u.boundary_conditions)
    expected_v = YFaceField(grid;
                            boundary_conditions = model.transport_velocities.v.boundary_conditions)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.convert_to_volume_flux_velocities!(
        expected_u, expected_v, grid, model.velocities.u, model.velocities.v)
    fill_halo_regions!((expected_u, expected_v))

    parent(model.pressure.pHY′) .= convert(FT, 7)
    parent(model.transport_velocities.u) .= convert(FT, 6)
    parent(model.transport_velocities.v) .= convert(FT, -8)
    parent(model.transport_velocities.w) .= convert(FT, 4)

    Oceananigans.TimeSteppers.reconcile_state!(model)

    pressure_error = maximum(abs, parent(model.pressure.pHY′) .- parent(expected_pressure))
    u_error = maximum(abs, parent(model.transport_velocities.u) .- parent(expected_u))
    v_error = maximum(abs, parent(model.transport_velocities.v) .- parent(expected_v))

    pressure_scale = max(one(FT), maximum(abs, parent(expected_pressure)))
    transport_scale = max(max(maximum(abs, parent(expected_u)),
                              maximum(abs, parent(expected_v))),
                          one(FT))

    pressure_tolerance = convert(FT, 1000) * eps(FT) * pressure_scale
    transport_tolerance = convert(FT, 1000) * eps(FT) * transport_scale

    @test pressure_error ≤ pressure_tolerance
    @test u_error ≤ transport_tolerance
    @test v_error ≤ transport_tolerance
    @test maximum(abs, parent(model.transport_velocities.w) .- convert(FT, 4)) > 100eps(FT)

    return nothing
end

function test_octahealpix_restore_prognostic_state_refreshes_split_explicit_transport_state(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    source_model = HydrostaticFreeSurfaceModel(grid;
                                               tracers = :c,
                                               buoyancy = nothing,
                                               free_surface = SplitExplicitFreeSurface(substeps = 8),
                                               momentum_advection = nothing)

    set!(source_model,
         u = (λ, φ, z) -> zero(FT),
         v = (λ, φ, z) -> zero(FT),
         c = (λ, φ, z) -> zero(FT))

    set!(source_model.free_surface.η,
         (λ, φ, z) -> convert(FT, 0.02) * sind(λ) + convert(FT, 0.01) * cosd(φ))

    Δt = convert(FT, 1//10)
    time_step!(source_model, Δt)

    restored_model = HydrostaticFreeSurfaceModel(grid;
                                                 tracers = :c,
                                                 buoyancy = nothing,
                                                 free_surface = SplitExplicitFreeSurface(substeps = 8),
                                                 momentum_advection = nothing)

    parent(restored_model.transport_velocities.u) .= convert(FT, 3)
    parent(restored_model.transport_velocities.v) .= convert(FT, -2)
    parent(restored_model.transport_velocities.w) .= convert(FT, 5)

    Oceananigans.restore_prognostic_state!(restored_model, prognostic_state(source_model))

    u_error = maximum(abs, parent(restored_model.transport_velocities.u) .- parent(source_model.transport_velocities.u))
    v_error = maximum(abs, parent(restored_model.transport_velocities.v) .- parent(source_model.transport_velocities.v))
    w_error = maximum(abs, parent(restored_model.transport_velocities.w) .- parent(source_model.transport_velocities.w))
    Ũ_error = maximum(abs, parent(restored_model.free_surface.filtered_state.Ũ) .- parent(source_model.free_surface.filtered_state.Ũ))
    Ṽ_error = maximum(abs, parent(restored_model.free_surface.filtered_state.Ṽ) .- parent(source_model.free_surface.filtered_state.Ṽ))

    transport_scale = max(max(maximum(abs, parent(source_model.transport_velocities.u)),
                              maximum(abs, parent(source_model.transport_velocities.v))),
                          one(FT))
    tolerance = convert(FT, 500) * eps(FT) * transport_scale

    @test u_error ≤ tolerance
    @test v_error ≤ tolerance
    @test w_error ≤ tolerance
    @test Ũ_error ≤ tolerance
    @test Ṽ_error ≤ tolerance

    return nothing
end

function test_octahealpix_hydrostatic_restore_prognostic_state_refreshes_pressure_without_clobbering_timestepper(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    source_model = HydrostaticFreeSurfaceModel(grid;
                                               tracers = :b,
                                               buoyancy = BuoyancyTracer(),
                                               free_surface = nothing,
                                               momentum_advection = Centered(),
                                               tracer_advection = Centered(FT))

    set!(source_model,
         u = (λ, φ, z) -> convert(FT, 0.16) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.11) * cosd(λ) - convert(FT, 0.03) * sind(φ),
         b = (λ, φ, z) -> convert(FT, 0.2) * sind(λ / 2) * cosd(φ) + convert(FT, 0.1) * z)

    Oceananigans.TimeSteppers.update_state!(source_model)

    restored_model = HydrostaticFreeSurfaceModel(grid;
                                                 tracers = :b,
                                                 buoyancy = BuoyancyTracer(),
                                                 free_surface = nothing,
                                                 momentum_advection = Centered(),
                                                 tracer_advection = Centered(FT))

    parent(restored_model.pressure.pHY′) .= convert(FT, 7)
    parent(restored_model.transport_velocities.u) .= convert(FT, 3)
    parent(restored_model.transport_velocities.v) .= convert(FT, -2)

    Oceananigans.restore_prognostic_state!(restored_model, prognostic_state(source_model))

    pressure_error = maximum(abs, parent(restored_model.pressure.pHY′) .- parent(source_model.pressure.pHY′))
    transport_u_error = maximum(abs, parent(restored_model.transport_velocities.u) .- parent(source_model.transport_velocities.u))
    transport_v_error = maximum(abs, parent(restored_model.transport_velocities.v) .- parent(source_model.transport_velocities.v))
    Gⁿ_u_error = maximum(abs, parent(restored_model.timestepper.Gⁿ.u) .- parent(source_model.timestepper.Gⁿ.u))
    Gⁿ_v_error = maximum(abs, parent(restored_model.timestepper.Gⁿ.v) .- parent(source_model.timestepper.Gⁿ.v))

    pressure_scale = max(one(FT), maximum(abs, parent(source_model.pressure.pHY′)))
    transport_scale = max(one(FT),
                          maximum(abs, parent(source_model.transport_velocities.u)),
                          maximum(abs, parent(source_model.transport_velocities.v)))
    tendency_scale = max(one(FT),
                         maximum(abs, parent(source_model.timestepper.Gⁿ.u)),
                         maximum(abs, parent(source_model.timestepper.Gⁿ.v)))

    pressure_tolerance = convert(FT, 1000) * eps(FT) * pressure_scale
    transport_tolerance = convert(FT, 1000) * eps(FT) * transport_scale
    tendency_tolerance = convert(FT, 1000) * eps(FT) * tendency_scale

    @test pressure_error ≤ pressure_tolerance
    @test transport_u_error ≤ transport_tolerance
    @test transport_v_error ≤ transport_tolerance
    @test Gⁿ_u_error ≤ tendency_tolerance
    @test Gⁿ_v_error ≤ tendency_tolerance

    return nothing
end

function test_octahealpix_nonhydrostatic_restore_prognostic_state_refreshes_pressure_and_background_halos(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    source_background_u = XFaceField(grid)
    source_background_v = YFaceField(grid)
    source_background_c = CenterField(grid)

    restored_background_u = XFaceField(grid)
    restored_background_v = YFaceField(grid)
    restored_background_c = CenterField(grid)

    set!((u = source_background_u, v = source_background_v);
         u = (λ, φ, z) -> convert(FT, 0.17) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.12) * cosd(λ) - convert(FT, 0.04) * sind(φ))

    set!((u = restored_background_u, v = restored_background_v);
         u = (λ, φ, z) -> convert(FT, 0.17) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.12) * cosd(λ) - convert(FT, 0.04) * sind(φ))

    set!(source_background_c,
         (λ, φ, z) -> convert(FT, 0.3) + convert(FT, 0.15) * sind(λ) + convert(FT, 0.08) * cosd(φ))

    set!(restored_background_c,
         (λ, φ, z) -> convert(FT, 0.3) + convert(FT, 0.15) * sind(λ) + convert(FT, 0.08) * cosd(φ))

    source_background_fields = BackgroundFields(u = source_background_u,
                                                v = source_background_v,
                                                c = source_background_c)

    restored_background_fields = BackgroundFields(u = restored_background_u,
                                                  v = restored_background_v,
                                                  c = restored_background_c)

    source_model = NonhydrostaticModel(grid;
                                       tracers = :c,
                                       buoyancy = BuoyancyTracer(),
                                       advection = Centered(FT),
                                       background_fields = source_background_fields)

    set!(source_model,
         u = (λ, φ, z) -> convert(FT, 0.16) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.11) * cosd(λ) - convert(FT, 0.03) * sind(φ),
         w = (λ, φ, z) -> convert(FT, 0.02) * sind(λ / 2) * cosd(φ),
         c = (λ, φ, z) -> convert(FT, 0.2) * sind(λ / 2) * cosd(φ) + convert(FT, 0.1) * z)

    Oceananigans.TimeSteppers.update_state!(source_model)

    restored_model = NonhydrostaticModel(grid;
                                         tracers = :c,
                                         buoyancy = BuoyancyTracer(),
                                         advection = Centered(FT),
                                         background_fields = restored_background_fields)

    parent(restored_model.pressures.pHY′) .= convert(FT, 7)

    for k in 0:(grid.Nz + 1), j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        (1 <= i <= grid.Nx && 1 <= j <= grid.Ny && 1 <= k <= grid.Nz) && continue
        restored_background_u[i, j, k] = convert(FT, 111)
        restored_background_v[i, j, k] = convert(FT, -222)
        restored_background_c[i, j, k] = convert(FT, 333)
    end

    Oceananigans.restore_prognostic_state!(restored_model, prognostic_state(source_model))

    pressure_error = maximum(abs, parent(restored_model.pressures.pHY′) .- parent(source_model.pressures.pHY′))
    background_u_error = maximum(abs, parent(restored_model.background_fields.velocities.u) .- parent(source_model.background_fields.velocities.u))
    background_v_error = maximum(abs, parent(restored_model.background_fields.velocities.v) .- parent(source_model.background_fields.velocities.v))
    background_c_error = maximum(abs, parent(restored_model.background_fields.tracers.c) .- parent(source_model.background_fields.tracers.c))

    pressure_scale = max(one(FT), maximum(abs, parent(source_model.pressures.pHY′)))
    background_scale = max(one(FT),
                           maximum(abs, parent(source_model.background_fields.velocities.u)),
                           maximum(abs, parent(source_model.background_fields.velocities.v)),
                           maximum(abs, parent(source_model.background_fields.tracers.c)))

    pressure_tolerance = convert(FT, 1000) * eps(FT) * pressure_scale
    background_tolerance = convert(FT, 1000) * eps(FT) * background_scale

    @test pressure_error ≤ pressure_tolerance
    @test background_u_error ≤ background_tolerance
    @test background_v_error ≤ background_tolerance
    @test background_c_error ≤ background_tolerance

    return nothing
end

function test_octahealpix_split_explicit_reconcile_free_surface_refreshes_filtered_transport_state(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = SplitExplicitFreeSurface(substeps = 8),
                                        momentum_advection = nothing)

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.2) * sind(λ) + convert(FT, 0.1) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.15) * cosd(λ) - convert(FT, 0.05) * sind(φ),
         c = (λ, φ, z) -> zero(FT))

    set!(model.free_surface.η,
         (λ, φ, z) -> convert(FT, 0.03) * sind(λ / 2) - convert(FT, 0.01) * cosd(φ))

    parent(model.free_surface.filtered_state.η̅) .= convert(FT, 4)
    parent(model.free_surface.filtered_state.U̅) .= convert(FT, 5)
    parent(model.free_surface.filtered_state.V̅) .= convert(FT, -6)
    parent(model.free_surface.filtered_state.Ũ) .= convert(FT, 7)
    parent(model.free_surface.filtered_state.Ṽ) .= convert(FT, -8)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.reconcile_free_surface!(model.free_surface, model.grid, model.velocities)
    Oceananigans.Models.HydrostaticFreeSurfaceModels.compute_transport_velocities!(model, model.free_surface)

    η̅_error = maximum(abs, parent(model.free_surface.filtered_state.η̅) .- parent(model.free_surface.displacement))
    U̅_error = maximum(abs, parent(model.free_surface.filtered_state.U̅) .- parent(model.free_surface.barotropic_velocities.U))
    V̅_error = maximum(abs, parent(model.free_surface.filtered_state.V̅) .- parent(model.free_surface.barotropic_velocities.V))
    Ũ_error = maximum(abs, parent(model.free_surface.filtered_state.Ũ) .- parent(model.free_surface.barotropic_velocities.U))
    Ṽ_error = maximum(abs, parent(model.free_surface.filtered_state.Ṽ) .- parent(model.free_surface.barotropic_velocities.V))

    expected_u = XFaceField(grid;
                            boundary_conditions = model.transport_velocities.u.boundary_conditions)
    expected_v = YFaceField(grid;
                            boundary_conditions = model.transport_velocities.v.boundary_conditions)

    Oceananigans.Models.HydrostaticFreeSurfaceModels.convert_to_volume_flux_velocities!(
        expected_u, expected_v, grid, model.velocities.u, model.velocities.v)
    fill_halo_regions!((expected_u, expected_v))

    transport_u_error = maximum(abs, parent(model.transport_velocities.u) .- parent(expected_u))
    transport_v_error = maximum(abs, parent(model.transport_velocities.v) .- parent(expected_v))

    state_scale = max(max(maximum(abs, parent(model.free_surface.barotropic_velocities.U)),
                          maximum(abs, parent(model.free_surface.barotropic_velocities.V))),
                      one(FT))
    transport_scale = max(max(maximum(abs, parent(expected_u)),
                              maximum(abs, parent(expected_v))),
                          one(FT))

    state_tolerance = convert(FT, 500) * eps(FT) * state_scale
    transport_tolerance = convert(FT, 500) * eps(FT) * transport_scale

    @test η̅_error ≤ state_tolerance
    @test U̅_error ≤ state_tolerance
    @test V̅_error ≤ state_tolerance
    @test Ũ_error ≤ state_tolerance
    @test Ṽ_error ≤ state_tolerance
    @test transport_u_error ≤ transport_tolerance
    @test transport_v_error ≤ transport_tolerance

    return nothing
end

