function test_octahealpix_transport_velocity_boundary_condition_sign_propagation(N, H=1)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), Float64; mapping,
                              z = (0.0, 1.0),
                              radius = 1.0,
                              halo = (H, H, 1))
    connectivity = grid.connectivity
    Nx = grid.Nx
    Ny = grid.Ny

    for halo_sign in (-1.0, 1.0)
        qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(halo_sign)
        u_bcs = FieldBoundaryConditions(grid, (Face(), Center(), Center());
                                        south = qcov,
                                        north = qcov)
        v_bcs = FieldBoundaryConditions(grid, (Center(), Face(), Center());
                                        west = qcov,
                                        east = qcov)

        velocities = (u = XFaceField(grid; boundary_conditions = u_bcs),
                      v = YFaceField(grid; boundary_conditions = v_bcs),
                      w = ZFaceField(grid))

        transport_velocities =
            Oceananigans.Models.HydrostaticFreeSurfaceModels.transport_velocity_fields(velocities)

        @test transport_velocities.u.boundary_conditions.south isa Oceananigans.BoundaryConditions.QConZBC
        @test transport_velocities.u.boundary_conditions.north isa Oceananigans.BoundaryConditions.QConZBC
        @test transport_velocities.v.boundary_conditions.west isa Oceananigans.BoundaryConditions.QConZBC
        @test transport_velocities.v.boundary_conditions.east isa Oceananigans.BoundaryConditions.QConZBC
        @test transport_velocities.u.boundary_conditions.south.condition == halo_sign
        @test transport_velocities.u.boundary_conditions.north.condition == halo_sign
        @test transport_velocities.v.boundary_conditions.west.condition == halo_sign
        @test transport_velocities.v.boundary_conditions.east.condition == halo_sign

        for j in 1:grid.Ny, i in 1:grid.Nx
            ring = connectivity.matrix_to_ring[i, j]
            transport_velocities.u[i, j, 1] = Float64(1000 + ring)
            transport_velocities.v[i, j, 1] = Float64(2000 + ring)
        end

        fill_halo_regions!((transport_velocities.u, transport_velocities.v))

        u_halo_max_error = 0.0
        v_halo_max_error = 0.0

        for j in (1 - H):(Ny + H), i in (1 - H):(Nx + H)
            (1 <= i <= Nx && 1 <= j <= Ny) && continue

            source_field, source_i, source_j, sign =
                octahealpix_transport_face_halo_source(i, j, connectivity, Nx, Ny, N, :u)
            source_ring = connectivity.matrix_to_ring[source_i, source_j]
            expected_u = source_field === :u ? halo_sign * sign * Float64(1000 + source_ring) :
                                               halo_sign * sign * Float64(2000 + source_ring)
            u_halo_max_error = max(u_halo_max_error, abs(transport_velocities.u[i, j, 1] - expected_u))

            source_field, source_i, source_j, sign =
                octahealpix_transport_face_halo_source(i, j, connectivity, Nx, Ny, N, :v)
            source_ring = connectivity.matrix_to_ring[source_i, source_j]
            expected_v = source_field === :u ? halo_sign * sign * Float64(1000 + source_ring) :
                                               halo_sign * sign * Float64(2000 + source_ring)
            v_halo_max_error = max(v_halo_max_error, abs(transport_velocities.v[i, j, 1] - expected_v))
        end

        @test u_halo_max_error == 0.0
        @test v_halo_max_error == 0.0
    end

    return nothing
end

function test_octahealpix_single_vector_field_halo_fill_requires_companion(N)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), Float64; mapping,
                              z = (0.0, 1.0),
                              radius = 1.0,
                              halo = (1, 1, 1))

    qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition()
    qcon = Oceananigans.BoundaryConditions.QuadFoldedContravariantZipperBoundaryCondition()

    u_covariant_bcs = FieldBoundaryConditions(grid, (Face(), Center(), Center());
                                              south = qcov,
                                              north = qcov)
    v_covariant_bcs = FieldBoundaryConditions(grid, (Center(), Face(), Center());
                                              west = qcov,
                                              east = qcov)
    u_contravariant_bcs = FieldBoundaryConditions(grid, (Face(), Center(), Center());
                                                  south = qcon,
                                                  north = qcon)
    v_contravariant_bcs = FieldBoundaryConditions(grid, (Center(), Face(), Center());
                                                  west = qcon,
                                                  east = qcon)

    u_covariant = XFaceField(grid; boundary_conditions = u_covariant_bcs)
    v_covariant = YFaceField(grid; boundary_conditions = v_covariant_bcs)
    u_contravariant = XFaceField(grid; boundary_conditions = u_contravariant_bcs)
    v_contravariant = YFaceField(grid; boundary_conditions = v_contravariant_bcs)

    @test_throws ArgumentError fill_halo_regions!(u_covariant)
    @test_throws ArgumentError fill_halo_regions!(v_covariant)
    @test_throws ArgumentError fill_halo_regions!(u_contravariant)
    @test_throws ArgumentError fill_halo_regions!(v_contravariant)

    return nothing
end

function test_octahealpix_inconsistent_vector_halo_signs_throw(N)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), Float64; mapping,
                              z = (0.0, 1.0),
                              radius = 1.0,
                              halo = (1, 1, 1))

    qcov_negative = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(-1.0)
    qcov_positive = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(+1.0)
    qcon_negative = Oceananigans.BoundaryConditions.QuadFoldedContravariantZipperBoundaryCondition(-1.0)
    qcon_positive = Oceananigans.BoundaryConditions.QuadFoldedContravariantZipperBoundaryCondition(+1.0)

    u_covariant_bcs = FieldBoundaryConditions(grid, (Face(), Center(), Center());
                                              south = qcov_negative,
                                              north = qcov_negative)
    v_covariant_bcs = FieldBoundaryConditions(grid, (Center(), Face(), Center());
                                              west = qcov_positive,
                                              east = qcov_positive)
    u_contravariant_bcs = FieldBoundaryConditions(grid, (Face(), Center(), Center());
                                                  south = qcon_negative,
                                                  north = qcon_negative)
    v_contravariant_bcs = FieldBoundaryConditions(grid, (Center(), Face(), Center());
                                                  west = qcon_positive,
                                                  east = qcon_positive)

    u_covariant = XFaceField(grid; boundary_conditions = u_covariant_bcs)
    v_covariant = YFaceField(grid; boundary_conditions = v_covariant_bcs)
    u_contravariant = XFaceField(grid; boundary_conditions = u_contravariant_bcs)
    v_contravariant = YFaceField(grid; boundary_conditions = v_contravariant_bcs)

    @test_throws ArgumentError fill_halo_regions!((u_covariant, v_covariant))
    @test_throws ArgumentError fill_halo_regions!((u_contravariant, v_contravariant))

    return nothing
end

function test_octahealpix_face_face_halo_consistency(N, H=1)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), Float64; mapping,
                              z = (0.0, 1.0),
                              radius = 1.0,
                              halo = (H, H, 1))
    connectivity = grid.connectivity

    face_field = Field{Face, Face, Center}(grid)

    for j in 1:grid.Ny, i in 1:grid.Nx
        face_field[i, j, 1] = Float64(100i + j)
    end

    fill_halo_regions!(face_field)

    halo_max_error = 0.0
    Nx = grid.Nx
    Ny = grid.Ny

    for j in (1 - H):(Ny + H), i in (1 - H):(Nx + H)
        (1 <= i <= Nx && 1 <= j <= Ny) && continue

        source_ring = Oceananigans.Grids.octahealpix_halo_source_ring_index(i, j, Nx, Ny, connectivity)
        source_i = connectivity.ring_to_i[source_ring]
        source_j = connectivity.ring_to_j[source_ring]
        expected_value = Float64(100source_i + source_j)
        halo_max_error = max(halo_max_error, abs(face_field[i, j, 1] - expected_value))
    end

    @test halo_max_error == 0.0

    return nothing
end

function test_octahealpix_reduced_z_seam_halo_consistency(N, H=1)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), Float64;
                              mapping,
                              size = (2N, 2N, 2),
                              z = (0.0, 1.0),
                              radius = 1.0,
                              halo = (H, H, 1))
    connectivity = grid.connectivity

    tracer = CenterField(grid; indices = (:, :, 1))
    face_field = Field{Face, Face, Center}(grid; indices = (:, :, 1))
    w = Field{Center, Center, Face}(grid; indices = (:, :, 2))
    u = XFaceField(grid; indices = (:, :, 1))
    v = YFaceField(grid; indices = (:, :, 1))

    for j in 1:grid.Ny, i in 1:grid.Nx
        ring = connectivity.matrix_to_ring[i, j]
        tracer[i, j, 1] = Float64(ring)
        face_field[i, j, 1] = Float64(100i + j)
        w[i, j, 2] = Float64(3000 + ring)
        u[i, j, 1] = Float64(1000 + ring)
        v[i, j, 1] = Float64(2000 + ring)
    end

    fill_halo_regions!(tracer)
    fill_halo_regions!(face_field)
    fill_halo_regions!(w)
    fill_halo_regions!((u, v))

    center_halo_max_error = 0.0
    face_face_halo_max_error = 0.0
    w_halo_max_error = 0.0
    u_halo_max_error = 0.0
    v_halo_max_error = 0.0
    Nx = grid.Nx
    Ny = grid.Ny

    for j in (1 - H):(Ny + H), i in (1 - H):(Nx + H)
        (1 <= i <= Nx && 1 <= j <= Ny) && continue

        source_ring = Oceananigans.Grids.octahealpix_halo_source_ring_index(i, j, Nx, Ny, connectivity)
        source_i = connectivity.ring_to_i[source_ring]
        source_j = connectivity.ring_to_j[source_ring]
        center_expected = Float64(source_ring)
        face_face_expected = Float64(100source_i + source_j)

        center_halo_max_error = max(center_halo_max_error, abs(tracer[i, j, 1] - center_expected))
        face_face_halo_max_error = max(face_face_halo_max_error, abs(face_field[i, j, 1] - face_face_expected))
        w_halo_max_error = max(w_halo_max_error, abs(w[i, j, 2] - Float64(3000 + source_ring)))

        source_field, source_i, source_j, sign = octahealpix_face_halo_source(i, j, connectivity, Nx, Ny, N, :u)
        source_ring = connectivity.matrix_to_ring[source_i, source_j]
        expected_u = source_field === :u ? sign * Float64(1000 + source_ring) : sign * Float64(2000 + source_ring)
        u_halo_max_error = max(u_halo_max_error, abs(u[i, j, 1] - expected_u))

        source_field, source_i, source_j, sign = octahealpix_face_halo_source(i, j, connectivity, Nx, Ny, N, :v)
        source_ring = connectivity.matrix_to_ring[source_i, source_j]
        expected_v = source_field === :u ? sign * Float64(1000 + source_ring) : sign * Float64(2000 + source_ring)
        v_halo_max_error = max(v_halo_max_error, abs(v[i, j, 1] - expected_v))
    end

    @test center_halo_max_error == 0.0
    @test face_face_halo_max_error == 0.0
    @test w_halo_max_error == 0.0
    @test u_halo_max_error == 0.0
    @test v_halo_max_error == 0.0

    return nothing
end

function test_octahealpix_vertical_halo_consistency(N)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), Float64;
                              mapping,
                              size = (2N, 2N, 2),
                              z = (0.0, 1.0),
                              radius = 1.0,
                              halo = (1, 1, 1))
    connectivity = grid.connectivity

    tracer = CenterField(grid)

    for k in 1:grid.Nz, ij in 1:octahealpix_number_of_cells(mapping)
        i = connectivity.ring_to_i[ij]
        j = connectivity.ring_to_j[ij]
        tracer[i, j, k] = Float64(100k + ij)
    end

    fill_halo_regions!(tracer)

    bottom_halo_max_error = 0.0
    top_halo_max_error = 0.0

    for ij in 1:octahealpix_number_of_cells(mapping)
        i = connectivity.ring_to_i[ij]
        j = connectivity.ring_to_j[ij]

        bottom_halo_max_error = max(bottom_halo_max_error, abs(tracer[i, j, 0] - tracer[i, j, 1]))
        top_halo_max_error = max(top_halo_max_error, abs(tracer[i, j, grid.Nz + 1] - tracer[i, j, grid.Nz]))
    end

    @test bottom_halo_max_error == 0.0
    @test top_halo_max_error == 0.0

    return nothing
end

function test_octahealpix_boundary_condition_defaults(FT)
    mapping = OctaHEALPixMapping(4)
    radius = convert(FT, 2)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    regularized_center_bc = regularize_field_boundary_conditions(FieldBoundaryConditions(), grid, :c)
    @test regularized_center_bc.west isa Oceananigans.BoundaryConditions.QZBC
    @test regularized_center_bc.east isa Oceananigans.BoundaryConditions.QZBC
    @test regularized_center_bc.south isa Oceananigans.BoundaryConditions.QZBC
    @test regularized_center_bc.north isa Oceananigans.BoundaryConditions.QZBC
    @test regularized_center_bc.bottom isa ZFBC
    @test regularized_center_bc.top isa ZFBC

    regularized_u_bc = regularize_field_boundary_conditions(FieldBoundaryConditions(), grid, :u)
    @test regularized_u_bc.west isa OBC
    @test regularized_u_bc.east isa OBC
    @test regularized_u_bc.south isa Oceananigans.BoundaryConditions.QCovZBC
    @test regularized_u_bc.north isa Oceananigans.BoundaryConditions.QCovZBC
    @test regularized_u_bc.bottom isa ZFBC
    @test regularized_u_bc.top isa ZFBC

    regularized_v_bc = regularize_field_boundary_conditions(FieldBoundaryConditions(), grid, :v)
    @test regularized_v_bc.west isa Oceananigans.BoundaryConditions.QCovZBC
    @test regularized_v_bc.east isa Oceananigans.BoundaryConditions.QCovZBC
    @test regularized_v_bc.south isa OBC
    @test regularized_v_bc.north isa OBC
    @test regularized_v_bc.bottom isa ZFBC
    @test regularized_v_bc.top isa ZFBC

    regularized_w_bc = regularize_field_boundary_conditions(FieldBoundaryConditions(), grid, :w)
    @test regularized_w_bc.west isa Oceananigans.BoundaryConditions.QZBC
    @test regularized_w_bc.east isa Oceananigans.BoundaryConditions.QZBC
    @test regularized_w_bc.south isa Oceananigans.BoundaryConditions.QZBC
    @test regularized_w_bc.north isa Oceananigans.BoundaryConditions.QZBC
    @test regularized_w_bc.bottom isa OBC
    @test regularized_w_bc.top isa OBC

    regularized_auxiliary_face_bc = FieldBoundaryConditions(grid, (Face(), Center(), Center()))
    @test regularized_auxiliary_face_bc.west === nothing
    @test regularized_auxiliary_face_bc.east === nothing
    @test regularized_auxiliary_face_bc.south isa Oceananigans.BoundaryConditions.QCovZBC
    @test regularized_auxiliary_face_bc.north isa Oceananigans.BoundaryConditions.QCovZBC
    @test regularized_auxiliary_face_bc.bottom isa ZFBC
    @test regularized_auxiliary_face_bc.top isa ZFBC

    return nothing
end

function test_octahealpix_prescribed_field_time_series_transport_state_drives_tracer_tendency(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))
    connectivity = grid.connectivity
    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times)
    v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times)

    set!(u_fts, (λ, φ, z, t) -> t)
    set!(v_fts, (λ, φ, z, t) -> convert(FT, 2) * t)

    velocities = PrescribedVelocityFields(u = u_fts, v = v_fts)

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities,
                                        tracers = :c,
                                        buoyancy = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = Centered(FT))

    time_step!(model, half)

    @test model.velocities.u[1, 1, 1] ≈ half
    @test model.velocities.v[1, 1, 1] ≈ convert(FT, 2) * half

    set!(model, c = (λ, φ, z) -> sind(λ / 2) * cosd(φ))

    compute_transport_velocities!(model, model.free_surface)

    source_field, source_i, source_j, sign =
        octahealpix_transport_face_halo_source(0, N + 1, connectivity, grid.Nx, grid.Ny, N, :u)
    expected_u_halo = source_field === :u ? sign * model.transport_velocities.u[source_i, source_j, 1] :
                                            sign * model.transport_velocities.v[source_i, source_j, 1]

    source_field, source_i, source_j, sign =
        octahealpix_transport_face_halo_source(N + 1, 0, connectivity, grid.Nx, grid.Ny, N, :v)
    expected_v_halo = source_field === :u ? sign * model.transport_velocities.u[source_i, source_j, 1] :
                                            sign * model.transport_velocities.v[source_i, source_j, 1]

    @test model.transport_velocities.u[0, N + 1, 1] == expected_u_halo
    @test model.transport_velocities.v[N + 1, 0, 1] == expected_v_halo

    compute_tracer_tendencies!(model)

    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    for (i, j) in sampled_points
        expected_Gc = -div_Uc(i, j, 1, grid, model.advection.c, model.transport_velocities, model.tracers.c)
        computed_Gc = model.timestepper.Gⁿ.c[i, j, 1]
        tendency_scale = max(abs(expected_Gc), one(FT))
        @test abs(expected_Gc) > 100eps(FT)
        @test abs(computed_Gc - expected_Gc) ≤ 1000eps(FT) * tendency_scale
    end

    forward = Array(interior(model.timestepper.Gⁿ.c))

    set!(model.transport_velocities.u, -model.transport_velocities.u)
    set!(model.transport_velocities.v, -model.transport_velocities.v)
    fill_halo_regions!(model.transport_velocities)
    compute_tracer_tendencies!(model)
    reverse = Array(interior(model.timestepper.Gⁿ.c))

    tolerance = 200 * eps(FT) * max(one(FT), max(maximum(abs, forward), maximum(abs, reverse)))

    @test forward ≈ -reverse atol = tolerance
    @test !any(isnan, forward)
    @test !any(isnan, reverse)

    return nothing
end

function test_octahealpix_prescribed_field_time_series_momentum_tendencies_same_grid(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))
    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(grid, times)
    v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(grid, times)

    set!(u_fts, (λ, φ, z, t) -> sind(λ) * cosd(φ) + t)
    set!(v_fts, (λ, φ, z, t) -> cosd(λ) * sind(φ) - t)

    velocities = PrescribedVelocityFields(u = u_fts, v = v_fts)

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities,
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant())

    @test model.velocities.u isa Oceananigans.OutputReaders.TimeSeriesInterpolation
    @test model.velocities.v isa Oceananigans.OutputReaders.TimeSeriesInterpolation

    time_step!(model, half)

    momentum = model.advection.momentum
    U = (u = model.velocities.u, v = model.velocities.v, w = model.velocities.w)
    k = 1

    compute_momentum_tendencies!(model, ())
    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    for (i, j) in sampled_points
        expected_Gu = -U_dot_∇u(i, j, k, grid, momentum, U)
        expected_Gv = -U_dot_∇v(i, j, k, grid, momentum, U)
        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        magnitude_scale = max(abs(expected_Gu), abs(expected_Gv), one(FT))

        @test abs(expected_Gu) > 100eps(FT)
        @test abs(expected_Gv) > 100eps(FT)
        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * magnitude_scale
        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * magnitude_scale
    end

    @test !any(isnan, Array(interior(model.timestepper.Gⁿ.u)))
    @test !any(isnan, Array(interior(model.timestepper.Gⁿ.v)))

    return nothing
end

