function test_octahealpix_prescribed_field_time_series_momentum_tendencies(FT, N)
    radius = convert(FT, 3)
    source_mapping = OctaHEALPixMapping(div(N, 2))
    source_grid = SphericalShellGrid(CPU(), FT; mapping = source_mapping,
                                     z = (zero(FT), one(FT)),
                                     radius,
                                     halo = (3, 3, 3))

    destination_mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping = destination_mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))

    qcov = Oceananigans.BoundaryConditions.QuadFoldedCovariantZipperBoundaryCondition(one(FT))
    source_u_bcs = FieldBoundaryConditions(source_grid, (Face(), Center(), Center());
                                           south = qcov,
                                           north = qcov)
    source_v_bcs = FieldBoundaryConditions(source_grid, (Center(), Face(), Center());
                                           west = qcov,
                                           east = qcov)

    times = [zero(FT), one(FT)]
    half = convert(FT, 1//2)

    u_fts = Oceananigans.FieldTimeSeries{Face, Center, Center}(source_grid, times;
                                                               boundary_conditions = source_u_bcs)
    v_fts = Oceananigans.FieldTimeSeries{Center, Face, Center}(source_grid, times;
                                                               boundary_conditions = source_v_bcs)

    set!(u_fts, (λ, φ, z, t) -> sind(λ) * cosd(φ) + t)
    set!(v_fts, (λ, φ, z, t) -> cosd(λ) * sind(φ) - t)

    velocities = PrescribedVelocityFields(u = u_fts, v = v_fts)

    model = HydrostaticFreeSurfaceModel(grid;
                                        velocities,
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant())

    @test model.velocities.u isa Oceananigans.OutputReaders.TimeSeriesInterpolation
    @test model.velocities.v isa Oceananigans.OutputReaders.TimeSeriesInterpolation
    @test model.velocities.u.grid === grid
    @test model.velocities.v.grid === grid

    time_step!(model, half)

    momentum = model.advection.momentum
    U = (u = model.velocities.u, v = model.velocities.v, w = model.velocities.w)
    k = 1

    compute_momentum_tendencies!(model, ())
    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    for (i, j) in sampled_points
        expected_Gu = -U_dot_∇u(i, j, k, grid, momentum, U)
        expected_Gv = -U_dot_∇v(i, j, k, grid, momentum, U)
        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        magnitude_scale = max(abs(expected_Gu), abs(expected_Gv), one(FT))

        @test abs(expected_Gu) > 100eps(FT)
        @test abs(expected_Gv) > 100eps(FT)
        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * magnitude_scale
        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * magnitude_scale
    end

    @test !any(isnan, Array(interior(model.timestepper.Gⁿ.u)))
    @test !any(isnan, Array(interior(model.timestepper.Gⁿ.v)))

    return nothing
end

function test_octahealpix_horizontal_momentum_advective_forcing_uses_covariant_velocity_and_refreshes_halos(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (3, 3, 3))

    forcing_u = XFaceField(grid)
    forcing_v = YFaceField(grid)
    reference_u = XFaceField(grid)
    reference_v = YFaceField(grid)

    set!((u = forcing_u, v = forcing_v);
         u = (λ, φ, z) -> convert(FT, 0.13) * sind(λ) + convert(FT, 0.04) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.09) * cosd(λ) - convert(FT, 0.03) * sind(φ))

    set!((u = reference_u, v = reference_v);
         u = (λ, φ, z) -> convert(FT, 0.13) * sind(λ) + convert(FT, 0.04) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.09) * cosd(λ) - convert(FT, 0.03) * sind(φ))

    fill_halo_regions!((reference_u, reference_v))

    forcing = (u = AdvectiveForcing(u = forcing_u, v = forcing_v),
               v = AdvectiveForcing(u = forcing_u, v = forcing_v))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        forcing,
                                        free_surface = nothing,
                                        momentum_advection = VectorInvariant())

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.16) * sind(λ) + convert(FT, 0.05) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.12) * cosd(λ) - convert(FT, 0.04) * sind(φ))

    for j in 0:(grid.Ny + 1), i in 0:(grid.Nx + 1)
        (1 <= i <= grid.Nx && 1 <= j <= grid.Ny) && continue
        forcing_u[i, j, 1] = convert(FT, 111)
        forcing_v[i, j, 1] = convert(FT, -222)
    end

    momentum = model.advection.momentum
    expected_U = Oceananigans.Forcings.with_advective_forcing(AdvectiveForcing(u = reference_u, v = reference_v), model.velocities)
    corrupted_U = Oceananigans.Forcings.with_advective_forcing(AdvectiveForcing(u = forcing_u, v = forcing_v), model.velocities)
    k = 1

    compute_momentum_tendencies!(model, ())
    sampled_points = ((N + 2, N + 2),
                      (1, N + 1),
                      (N + 1, 1),
                      (2N, N + 1),
                      (N + 1, 2N))

    maximum_corrupted_u_difference = zero(FT)
    maximum_corrupted_v_difference = zero(FT)

    for (i, j) in sampled_points
        expected_Gu = -(U_dot_∇u(i, j, k, grid, momentum, expected_U) +
                        Oceananigans.Advection.U_dot_∇u_hydrostatic_metric(i, j, k, grid, momentum, expected_U, model.velocities))

        expected_Gv = -(U_dot_∇v(i, j, k, grid, momentum, expected_U) +
                        Oceananigans.Advection.U_dot_∇v_hydrostatic_metric(i, j, k, grid, momentum, expected_U, model.velocities))

        corrupted_Gu = -(U_dot_∇u(i, j, k, grid, momentum, corrupted_U) +
                         Oceananigans.Advection.U_dot_∇u_hydrostatic_metric(i, j, k, grid, momentum, corrupted_U, model.velocities))

        corrupted_Gv = -(U_dot_∇v(i, j, k, grid, momentum, corrupted_U) +
                         Oceananigans.Advection.U_dot_∇v_hydrostatic_metric(i, j, k, grid, momentum, corrupted_U, model.velocities))

        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        magnitude_scale = max(abs(expected_Gu), abs(expected_Gv), one(FT))

        @test abs(expected_Gu) > 100eps(FT)
        @test abs(expected_Gv) > 100eps(FT)
        @test abs(computed_Gu - expected_Gu) ≤ 2000eps(FT) * magnitude_scale
        @test abs(computed_Gv - expected_Gv) ≤ 2000eps(FT) * magnitude_scale

        maximum_corrupted_u_difference = max(maximum_corrupted_u_difference, abs(expected_Gu - corrupted_Gu))
        maximum_corrupted_v_difference = max(maximum_corrupted_v_difference, abs(expected_Gv - corrupted_Gv))
    end

    @test maximum_corrupted_u_difference > 100eps(FT)
    @test maximum_corrupted_v_difference > 100eps(FT)
    @test !any(isnan, Array(interior(model.timestepper.Gⁿ.u)))
    @test !any(isnan, Array(interior(model.timestepper.Gⁿ.v)))

    return nothing
end

function test_octahealpix_single_component_prescribed_field_time_series_transport_state_drives_tracer_tendency(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
