function test_octahealpix_vector_invariant_self_upwinding_uses_nonorthogonal_divergence_flux(FT, N)
    grid = SphericalShellGrid(size = (2N, 2N, 2),
                              halo = (5, 5, 3),
                              z = (-one(FT), zero(FT)),
                              radius = one(FT),
                              topology = (Connected, Connected, Bounded),
                              mapping = OctaHEALPixMapping(N))

    scheme = WENOVectorInvariant(FT; order = 5,
                                 upwinding = OnlySelfUpwinding(cross_scheme = Centered()))

    model = HydrostaticFreeSurfaceModel(grid; momentum_advection = scheme)

    uᵢ(λ, φ, z) = convert(FT, 21//100) * cosd(φ) * sind(λ) + convert(FT, 1//25) * z
    vᵢ(λ, φ, z) = convert(FT, 17//100) * sind(φ) * cosd(λ) - convert(FT, 3//100) * z

    set!(model, u = uᵢ, v = vᵢ)

    u = model.velocities.u
    v = model.velocities.v

    nonorthogonal_δx_U(i, j, k, grid, u, v) =
        Oceananigans.Operators.δxᶜᶜᶜ(i, j, k, grid, Oceananigans.Operators.covariant_to_volume_flux_uᶠᶜᶜ, u, v)

    nonorthogonal_δy_V(i, j, k, grid, u, v) =
        Oceananigans.Operators.δyᶜᶜᶜ(i, j, k, grid, Oceananigans.Operators.covariant_to_volume_flux_vᶜᶠᶜ, u, v)

    orthogonal_δx_U(i, j, k, grid, u, v) =
        Oceananigans.Operators.δxᶜᶜᶜ(i, j, k, grid, Oceananigans.Operators.Ax_qᶠᶜᶜ, u)

    orthogonal_δy_V(i, j, k, grid, u, v) =
        Oceananigans.Operators.δyᶜᶜᶜ(i, j, k, grid, Oceananigans.Operators.Ay_qᶜᶠᶜ, v)

    expected_nonorthogonal_flux_u(i, j, k) = begin
        û = @inbounds u[i, j, k]
        δvˢ = Oceananigans.Advection._symmetric_interpolate_xᶠᵃᵃ(i, j, k, grid, scheme,
                                                                 scheme.upwinding.cross_scheme,
                                                                 nonorthogonal_δy_V,
                                                                 u, v)
        δuᴿ = Oceananigans.Advection._biased_interpolate_xᶠᵃᵃ(i, j, k, grid, scheme,
                                                              scheme.divergence_scheme,
                                                              Oceananigans.Advection.bias(û),
                                                              nonorthogonal_δx_U,
                                                              scheme.upwinding.δU_stencil,
                                                              u, v)
        return û * (δvˢ + δuᴿ)
    end

    expected_nonorthogonal_flux_v(i, j, k) = begin
        v̂ = @inbounds v[i, j, k]
        δuˢ = Oceananigans.Advection._symmetric_interpolate_yᵃᶠᵃ(i, j, k, grid, scheme,
                                                                 scheme.upwinding.cross_scheme,
                                                                 nonorthogonal_δx_U,
                                                                 u, v)
        δvᴿ = Oceananigans.Advection._biased_interpolate_yᵃᶠᵃ(i, j, k, grid, scheme,
                                                              scheme.divergence_scheme,
                                                              Oceananigans.Advection.bias(v̂),
                                                              nonorthogonal_δy_V,
                                                              scheme.upwinding.δV_stencil,
                                                              u, v)
        return v̂ * (δuˢ + δvᴿ)
    end

    expected_old_flux_u(i, j, k) = begin
        û = @inbounds u[i, j, k]
        δvˢ = Oceananigans.Advection._symmetric_interpolate_xᶠᵃᵃ(i, j, k, grid, scheme,
                                                                 scheme.upwinding.cross_scheme,
                                                                 orthogonal_δy_V,
                                                                 u, v)
        δuᴿ = Oceananigans.Advection._biased_interpolate_xᶠᵃᵃ(i, j, k, grid, scheme,
                                                              scheme.divergence_scheme,
                                                              Oceananigans.Advection.bias(û),
                                                              orthogonal_δx_U,
                                                              scheme.upwinding.δU_stencil,
                                                              u, v)
        return û * (δvˢ + δuᴿ)
    end

    expected_old_flux_v(i, j, k) = begin
        v̂ = @inbounds v[i, j, k]
        δuˢ = Oceananigans.Advection._symmetric_interpolate_yᵃᶠᵃ(i, j, k, grid, scheme,
                                                                 scheme.upwinding.cross_scheme,
                                                                 orthogonal_δx_U,
                                                                 u, v)
        δvᴿ = Oceananigans.Advection._biased_interpolate_yᵃᶠᵃ(i, j, k, grid, scheme,
                                                              scheme.divergence_scheme,
                                                              Oceananigans.Advection.bias(v̂),
                                                              orthogonal_δy_V,
                                                              scheme.upwinding.δV_stencil,
                                                              u, v)
        return v̂ * (δuˢ + δvᴿ)
    end

    samples = ((1, N, 1),
               (N, 2N, 2),
               (N + 1, N + 1, 1),
               (2N, N + 1, 2))

    actual_u = FT[]
    actual_v = FT[]
    expected_u = FT[]
    expected_v = FT[]
    old_u = FT[]
    old_v = FT[]

    for (i, j, k) in samples
        push!(actual_u, Oceananigans.Advection.upwinded_divergence_flux_Uᶠᶜᶜ(i, j, k, grid, scheme, u, v))
        push!(actual_v, Oceananigans.Advection.upwinded_divergence_flux_Vᶜᶠᶜ(i, j, k, grid, scheme, u, v))
        push!(expected_u, expected_nonorthogonal_flux_u(i, j, k))
        push!(expected_v, expected_nonorthogonal_flux_v(i, j, k))
        push!(old_u, expected_old_flux_u(i, j, k))
        push!(old_v, expected_old_flux_v(i, j, k))
    end

    atol = eps(FT)
    rtol = sqrt(eps(FT))

    for n in eachindex(actual_u)
        scale_u = max(abs(expected_u[n]), one(FT))
        scale_v = max(abs(expected_v[n]), one(FT))

        @test isapprox(actual_u[n], expected_u[n]; atol = atol * scale_u, rtol)
        @test isapprox(actual_v[n], expected_v[n]; atol = atol * scale_v, rtol)
    end

    magnitude_scale = maximum(vcat(abs.(actual_u), abs.(actual_v), [one(FT)]))
    max_old_difference = maximum(vcat(abs.(actual_u .- old_u), abs.(actual_v .- old_v)))

    @test max_old_difference > convert(FT, 100) * eps(FT) * magnitude_scale

    return nothing
end

function test_octahealpix_vector_invariant_kinetic_energy_upwinding_uses_covariant_kinetic_energy_gradient(FT, N)
    grid = SphericalShellGrid(size = (2N, 2N, 2),
                              halo = (5, 5, 3),
                              z = (-one(FT), zero(FT)),
                              radius = one(FT),
                              topology = (Connected, Connected, Bounded),
                              mapping = OctaHEALPixMapping(N))

    scheme = WENOVectorInvariant(FT; order = 5,
                                 upwinding = OnlySelfUpwinding(cross_scheme = Centered()))

    model = HydrostaticFreeSurfaceModel(grid; momentum_advection = scheme)

    uᵢ(λ, φ, z) = convert(FT, 21//100) * cosd(φ) * sind(λ) + convert(FT, 1//25) * z
    vᵢ(λ, φ, z) = convert(FT, 17//100) * sind(φ) * cosd(λ) - convert(FT, 3//100) * z

    set!(model, u = uᵢ, v = vᵢ)

    u = model.velocities.u
    v = model.velocities.v

    expected_nonorthogonal_head_u(i, j, k) = begin
        û = @inbounds u[i, j, k]
        δKᴿ = Oceananigans.Advection._biased_interpolate_xᶠᵃᵃ(i, j, k, grid, scheme,
                                                             scheme.kinetic_energy_gradient_scheme,
                                                             Oceananigans.Advection.bias(û),
                                                             Oceananigans.Advection.δx_covariant_kinetic_energy,
                                                             scheme.upwinding.δu²_stencil,
                                                             u, v)
        return δKᴿ / Oceananigans.Operators.computational_width_uᶠᶜᶜ(i, j, k, grid)
    end

    expected_nonorthogonal_head_v(i, j, k) = begin
        v̂ = @inbounds v[i, j, k]
        δKᴿ = Oceananigans.Advection._biased_interpolate_yᵃᶠᵃ(i, j, k, grid, scheme,
                                                             scheme.kinetic_energy_gradient_scheme,
                                                             Oceananigans.Advection.bias(v̂),
                                                             Oceananigans.Advection.δy_covariant_kinetic_energy,
                                                             scheme.upwinding.δv²_stencil,
                                                             u, v)
        return δKᴿ / Oceananigans.Operators.computational_width_vᶜᶠᶜ(i, j, k, grid)
    end

    expected_old_head_u(i, j, k) = begin
        û = @inbounds u[i, j, k]
        δKvˢ = Oceananigans.Advection._symmetric_interpolate_yᵃᶜᵃ(i, j, k, grid, scheme,
                                                                 scheme.upwinding.cross_scheme,
                                                                 Oceananigans.Advection.δx_v²,
                                                                 u, v)
        δKuᴿ = Oceananigans.Advection._biased_interpolate_xᶠᵃᵃ(i, j, k, grid, scheme,
                                                              scheme.kinetic_energy_gradient_scheme,
                                                              Oceananigans.Advection.bias(û),
                                                              Oceananigans.Advection.δx_u²,
                                                              scheme.upwinding.δu²_stencil,
                                                              u, v)
        return (δKuᴿ + δKvˢ) * Oceananigans.Operators.Δx⁻¹ᶠᶜᶜ(i, j, k, grid)
    end

    expected_old_head_v(i, j, k) = begin
        v̂ = @inbounds v[i, j, k]
        δKuˢ = Oceananigans.Advection._symmetric_interpolate_xᶜᵃᵃ(i, j, k, grid, scheme,
                                                                 scheme.upwinding.cross_scheme,
                                                                 Oceananigans.Advection.δy_u²,
                                                                 u, v)
        δKvᴿ = Oceananigans.Advection._biased_interpolate_yᵃᶠᵃ(i, j, k, grid, scheme,
                                                              scheme.kinetic_energy_gradient_scheme,
                                                              Oceananigans.Advection.bias(v̂),
                                                              Oceananigans.Advection.δy_v²,
                                                              scheme.upwinding.δv²_stencil,
                                                              u, v)
        return (δKvᴿ + δKuˢ) * Oceananigans.Operators.Δy⁻¹ᶜᶠᶜ(i, j, k, grid)
    end

    samples = ((1, N, 1),
               (N, 2N, 2),
               (N + 1, N + 1, 1),
               (2N, N + 1, 2))

    actual_u = FT[]
    actual_v = FT[]
    expected_u = FT[]
    expected_v = FT[]
    old_u = FT[]
    old_v = FT[]

    for (i, j, k) in samples
        push!(actual_u, Oceananigans.Advection.bernoulli_head_U(i, j, k, grid, scheme, u, v))
        push!(actual_v, Oceananigans.Advection.bernoulli_head_V(i, j, k, grid, scheme, u, v))
        push!(expected_u, expected_nonorthogonal_head_u(i, j, k))
        push!(expected_v, expected_nonorthogonal_head_v(i, j, k))
        push!(old_u, expected_old_head_u(i, j, k))
        push!(old_v, expected_old_head_v(i, j, k))
    end

    atol = eps(FT)
    rtol = sqrt(eps(FT))

    for n in eachindex(actual_u)
        scale_u = max(abs(expected_u[n]), one(FT))
        scale_v = max(abs(expected_v[n]), one(FT))

        @test isapprox(actual_u[n], expected_u[n]; atol = atol * scale_u, rtol)
        @test isapprox(actual_v[n], expected_v[n]; atol = atol * scale_v, rtol)
    end

    magnitude_scale = maximum(vcat(abs.(actual_u), abs.(actual_v), [one(FT)]))
    max_old_difference = maximum(vcat(abs.(actual_u .- old_u), abs.(actual_v .- old_v)))

    @test max_old_difference > convert(FT, 100) * eps(FT) * magnitude_scale

    return nothing
end

function test_octahealpix_vector_invariant_vorticity_upwinding_uses_covariant_vorticity_and_contravariant_velocity(FT, N)
    grid = SphericalShellGrid(size = (2N, 2N, 2),
                              halo = (5, 5, 3),
                              z = (-one(FT), zero(FT)),
                              radius = one(FT),
                              topology = (Connected, Connected, Bounded),
                              mapping = OctaHEALPixMapping(N))

    scheme = WENOVectorInvariant(FT; order = 5,
                                 upwinding = OnlySelfUpwinding(cross_scheme = Centered()))

    model = HydrostaticFreeSurfaceModel(grid; momentum_advection = scheme)

    uᵢ(λ, φ, z) = convert(FT, 21//100) * cosd(φ) * sind(λ) + convert(FT, 1//25) * z
    vᵢ(λ, φ, z) = convert(FT, 17//100) * sind(φ) * cosd(λ) - convert(FT, 3//100) * z

    set!(model, u = uᵢ, v = vᵢ)

    u = model.velocities.u
    v = model.velocities.v

    expected_nonorthogonal_advection_u(i, j, k) = begin
        v̂ = Oceananigans.Operators.contravariant_velocity_vᶠᶠᶜ(i, j, k, grid, u, v)
        ζᴿ = Oceananigans.Advection._biased_interpolate_yᵃᶜᵃ(i, j, k, grid, scheme,
                                                            scheme.vorticity_scheme,
                                                            Oceananigans.Advection.bias(v̂),
                                                            Oceananigans.Operators.covariant_vertical_vorticity_componentᶠᶠᶜ,
                                                            scheme.vorticity_stencil,
                                                            u, v)
        return -v̂ * ζᴿ
    end

    expected_nonorthogonal_advection_v(i, j, k) = begin
        û = Oceananigans.Operators.contravariant_velocity_uᶠᶠᶜ(i, j, k, grid, u, v)
        ζᴿ = Oceananigans.Advection._biased_interpolate_xᶜᵃᵃ(i, j, k, grid, scheme,
                                                            scheme.vorticity_scheme,
                                                            Oceananigans.Advection.bias(û),
                                                            Oceananigans.Operators.covariant_vertical_vorticity_componentᶠᶠᶜ,
                                                            scheme.vorticity_stencil,
                                                            u, v)
        return û * ζᴿ
    end

    expected_old_advection_u(i, j, k) = begin
        v̂ = Oceananigans.Operators.ℑxᶠᵃᵃ(i, j, k, grid,
                                         Oceananigans.Operators.ℑyᵃᶜᵃ,
                                         Oceananigans.Operators.Δx_qᶜᶠᶜ,
                                         v) * Oceananigans.Operators.Δx⁻¹ᶠᶜᶜ(i, j, k, grid)
        ζᴿ = Oceananigans.Advection._biased_interpolate_yᵃᶜᵃ(i, j, k, grid, scheme,
                                                            scheme.vorticity_scheme,
                                                            Oceananigans.Advection.bias(v̂),
                                                            Oceananigans.Operators.ζ₃ᶠᶠᶜ,
                                                            scheme.vorticity_stencil,
                                                            u, v)
        return -v̂ * ζᴿ
    end

    expected_old_advection_v(i, j, k) = begin
        û = Oceananigans.Operators.ℑyᵃᶠᵃ(i, j, k, grid,
                                         Oceananigans.Operators.ℑxᶜᵃᵃ,
                                         Oceananigans.Operators.Δy_qᶠᶜᶜ,
                                         u) * Oceananigans.Operators.Δy⁻¹ᶜᶠᶜ(i, j, k, grid)
        ζᴿ = Oceananigans.Advection._biased_interpolate_xᶜᵃᵃ(i, j, k, grid, scheme,
                                                            scheme.vorticity_scheme,
                                                            Oceananigans.Advection.bias(û),
                                                            Oceananigans.Operators.ζ₃ᶠᶠᶜ,
                                                            scheme.vorticity_stencil,
                                                            u, v)
        return û * ζᴿ
    end

    samples = ((1, N, 1),
               (N, 2N, 2),
               (N + 1, N + 1, 1),
               (2N, N + 1, 2))

    actual_u = FT[]
    actual_v = FT[]
    expected_u = FT[]
    expected_v = FT[]
    old_u = FT[]
    old_v = FT[]

    for (i, j, k) in samples
        push!(actual_u, Oceananigans.Advection.horizontal_advection_U(i, j, k, grid, scheme, u, v))
        push!(actual_v, Oceananigans.Advection.horizontal_advection_V(i, j, k, grid, scheme, u, v))
        push!(expected_u, expected_nonorthogonal_advection_u(i, j, k))
        push!(expected_v, expected_nonorthogonal_advection_v(i, j, k))
        push!(old_u, expected_old_advection_u(i, j, k))
        push!(old_v, expected_old_advection_v(i, j, k))
    end

    atol = eps(FT)
    rtol = sqrt(eps(FT))

    for n in eachindex(actual_u)
        scale_u = max(abs(expected_u[n]), one(FT))
        scale_v = max(abs(expected_v[n]), one(FT))

        @test isapprox(actual_u[n], expected_u[n]; atol = atol * scale_u, rtol)
        @test isapprox(actual_v[n], expected_v[n]; atol = atol * scale_v, rtol)
    end

    magnitude_scale = maximum(vcat(abs.(actual_u), abs.(actual_v), [one(FT)]))
    max_old_difference = maximum(vcat(abs.(actual_u .- old_u), abs.(actual_v .- old_v)))

    @test max_old_difference > convert(FT, 100) * eps(FT) * magnitude_scale

    return nothing
end

function test_octahealpix_weno_vector_invariant_momentum_tendencies_match_live_advection(FT, N)
    grid = SphericalShellGrid(size = (2N, 2N, 2),
                              halo = (5, 5, 3),
                              z = (-one(FT), zero(FT)),
                              radius = one(FT),
                              topology = (Connected, Connected, Bounded),
                              mapping = OctaHEALPixMapping(N))

    scheme = WENOVectorInvariant(FT; order = 5,
                                 upwinding = OnlySelfUpwinding(cross_scheme = Centered()))

    centered_scheme = VectorInvariant(FT;
                                      vorticity_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                      vertical_advection_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                      kinetic_energy_gradient_scheme = Oceananigans.Advection.EnergyConserving(FT),
                                      divergence_scheme = Oceananigans.Advection.EnergyConserving(FT))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = scheme)

    set!(model,
         u = (λ, φ, z) -> convert(FT, 0.14) * sind(λ) + convert(FT, 0.09) * z + convert(FT, 0.03) * cosd(φ),
         v = (λ, φ, z) -> convert(FT, 0.07) * cosd(λ) - convert(FT, 0.05) * z + convert(FT, 0.02) * sind(φ))

    Oceananigans.TimeSteppers.compute_tendencies!(model, ())

    samples = ((1, N, 1),
               (N, 2N, 2),
               (N + 1, N + 1, 1),
               (2N, N + 1, 2))

    maximum_centered_difference = zero(FT)

    for (i, j, k) in samples
        computed_Gu = @inbounds model.timestepper.Gⁿ.u[i, j, k]
        computed_Gv = @inbounds model.timestepper.Gⁿ.v[i, j, k]

        expected_Gu = -Oceananigans.Advection.U_dot_∇u(i, j, k, grid, scheme, model.velocities)
        expected_Gv = -Oceananigans.Advection.U_dot_∇v(i, j, k, grid, scheme, model.velocities)

        centered_Gu = -Oceananigans.Advection.U_dot_∇u(i, j, k, grid, centered_scheme, model.velocities)
        centered_Gv = -Oceananigans.Advection.U_dot_∇v(i, j, k, grid, centered_scheme, model.velocities)

        u_scale = max(one(FT), abs(expected_Gu), abs(computed_Gu))
        v_scale = max(one(FT), abs(expected_Gv), abs(computed_Gv))

        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * u_scale
        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * v_scale

        maximum_centered_difference = max(maximum_centered_difference,
                                          abs(expected_Gu - centered_Gu),
                                          abs(expected_Gv - centered_Gv))
    end

    @test maximum_centered_difference > 100eps(FT)

    return nothing
end

function test_octahealpix_cross_and_self_vector_invariant_momentum_tendencies_match_live_advection(FT, N)
    grid = SphericalShellGrid(size = (2N, 2N, 2),
                              halo = (5, 5, 3),
