        expected_Gu = -Oceananigans.Advection.U_dot_∇u(i, j, k, grid, scheme, model.velocities)
        expected_Gv = -Oceananigans.Advection.U_dot_∇v(i, j, k, grid, scheme, model.velocities)

        centered_Gu = -Oceananigans.Advection.U_dot_∇u(i, j, k, grid, centered_scheme, model.velocities)
        centered_Gv = -Oceananigans.Advection.U_dot_∇v(i, j, k, grid, centered_scheme, model.velocities)

        u_scale = max(one(FT), abs(expected_Gu), abs(computed_Gu))
        v_scale = max(one(FT), abs(expected_Gv), abs(computed_Gv))

        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * u_scale
        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * v_scale

        maximum_centered_difference = max(maximum_centered_difference,
                                          abs(expected_Gu - centered_Gu),
                                          abs(expected_Gv - centered_Gv))
    end

    @test maximum_centered_difference > 100eps(FT)

    return nothing
end

@testset "OctaHEALPix vector invariant self upwinding" begin
    for FT in (Float32, Float64)
        test_octahealpix_vector_invariant_self_upwinding_uses_nonorthogonal_divergence_flux(FT, 4)
        test_octahealpix_vector_invariant_kinetic_energy_upwinding_uses_covariant_kinetic_energy_gradient(FT, 4)
        test_octahealpix_vector_invariant_vorticity_upwinding_uses_covariant_vorticity_and_contravariant_velocity(FT, 4)
        test_octahealpix_weno_vector_invariant_momentum_tendencies_match_live_advection(FT, 4)
        test_octahealpix_cross_and_self_vector_invariant_momentum_tendencies_match_live_advection(FT, 4)
    end
end

function test_octahealpix_centered_flux_form_momentum_fluxes_use_nonorthogonal_transport(FT, N)
    grid = SphericalShellGrid(size = (2N, 2N, 2),
                              halo = (3, 3, 3),
                              z = (-one(FT), zero(FT)),
                              radius = one(FT),
                              topology = (Connected, Connected, Bounded),
                              mapping = OctaHEALPixMapping(N))

    model = NonhydrostaticModel(grid)

    uᵢ(λ, φ, z) = convert(FT, 19//100) * cosd(φ) * sind(λ) + convert(FT, 1//20) * z
    vᵢ(λ, φ, z) = convert(FT, 23//100) * sind(φ) * cosd(λ) - convert(FT, 1//25) * z
    wᵢ(λ, φ, z) = convert(FT, 7//100) * cosd(φ) * cosd(λ) * (one(FT) + z)

    set!(model, u = uᵢ, v = vᵢ, w = wᵢ)

    U = model.velocities
    scheme = Centered()

    expected_nonorthogonal_fluxes(i, j, k) = (
        Uu = Oceananigans.Advection._symmetric_interpolate_xᶜᵃᵃ(i, j, k, grid, scheme,
                                                                Oceananigans.Operators.covariant_to_volume_flux_uᶠᶜᶜ,
                                                                U.u, U.v) *
             Oceananigans.Advection._symmetric_interpolate_xᶜᵃᵃ(i, j, k, grid, scheme, U.u),
        Vu = Oceananigans.Advection._symmetric_interpolate_xᶠᵃᵃ(i, j, k, grid, scheme,
                                                                Oceananigans.Operators.covariant_to_volume_flux_vᶜᶠᶜ,
                                                                U.u, U.v) *
             Oceananigans.Advection._symmetric_interpolate_yᵃᶠᵃ(i, j, k, grid, scheme, U.u),
        Uv = Oceananigans.Advection._symmetric_interpolate_yᵃᶠᵃ(i, j, k, grid, scheme,
                                                                Oceananigans.Operators.covariant_to_volume_flux_uᶠᶜᶜ,
                                                                U.u, U.v) *
             Oceananigans.Advection._symmetric_interpolate_xᶠᵃᵃ(i, j, k, grid, scheme, U.v),
        Vv = Oceananigans.Advection._symmetric_interpolate_yᵃᶜᵃ(i, j, k, grid, scheme,
                                                                Oceananigans.Operators.covariant_to_volume_flux_vᶜᶠᶜ,
                                                                U.u, U.v) *
             Oceananigans.Advection._symmetric_interpolate_yᵃᶜᵃ(i, j, k, grid, scheme, U.v),
        Uw = Oceananigans.Advection._symmetric_interpolate_zᵃᵃᶠ(i, j, k, grid, scheme,
                                                                Oceananigans.Operators.covariant_to_volume_flux_uᶠᶜᶜ,
                                                                U.u, U.v) *
             Oceananigans.Advection._symmetric_interpolate_xᶠᵃᵃ(i, j, k, grid, scheme, U.w),
        Vw = Oceananigans.Advection._symmetric_interpolate_zᵃᵃᶠ(i, j, k, grid, scheme,
                                                                Oceananigans.Operators.covariant_to_volume_flux_vᶜᶠᶜ,
                                                                U.u, U.v) *
             Oceananigans.Advection._symmetric_interpolate_yᵃᶠᵃ(i, j, k, grid, scheme, U.w)
    )

    expected_old_fluxes(i, j, k) = (
        Uu = Oceananigans.Operators.Axᶜᶜᶜ(i, j, k, grid) *
             Oceananigans.Advection._symmetric_interpolate_xᶜᵃᵃ(i, j, k, grid, scheme, U.u) *
             Oceananigans.Advection._symmetric_interpolate_xᶜᵃᵃ(i, j, k, grid, scheme, U.u),
        Vu = Oceananigans.Operators.Ayᶠᶠᶜ(i, j, k, grid) *
             Oceananigans.Advection._symmetric_interpolate_xᶠᵃᵃ(i, j, k, grid, scheme, U.v) *
             Oceananigans.Advection._symmetric_interpolate_yᵃᶠᵃ(i, j, k, grid, scheme, U.u),
        Uv = Oceananigans.Operators.Axᶠᶠᶜ(i, j, k, grid) *
             Oceananigans.Advection._symmetric_interpolate_yᵃᶠᵃ(i, j, k, grid, scheme, U.u) *
             Oceananigans.Advection._symmetric_interpolate_xᶠᵃᵃ(i, j, k, grid, scheme, U.v),
        Vv = Oceananigans.Operators.Ayᶜᶜᶜ(i, j, k, grid) *
             Oceananigans.Advection._symmetric_interpolate_yᵃᶜᵃ(i, j, k, grid, scheme, U.v) *
             Oceananigans.Advection._symmetric_interpolate_yᵃᶜᵃ(i, j, k, grid, scheme, U.v),
        Uw = Oceananigans.Operators.Axᶠᶜᶠ(i, j, k, grid) *
             Oceananigans.Advection._symmetric_interpolate_zᵃᵃᶠ(i, j, k, grid, scheme, U.u) *
             Oceananigans.Advection._symmetric_interpolate_xᶠᵃᵃ(i, j, k, grid, scheme, U.w),
        Vw = Oceananigans.Operators.Ayᶜᶠᶠ(i, j, k, grid) *
             Oceananigans.Advection._symmetric_interpolate_zᵃᵃᶠ(i, j, k, grid, scheme, U.v) *
             Oceananigans.Advection._symmetric_interpolate_yᵃᶠᵃ(i, j, k, grid, scheme, U.w)
    )

    samples = ((1, N, 1), (N, 2N, 2), (N + 1, N + 1, 1), (2N, N + 1, 2))

    actual = FT[]
    expected = FT[]
    old = FT[]

    for (i, j, k) in samples
        actual_fluxes = (
            Oceananigans.Advection.advective_momentum_flux_Uu(i, j, k, grid, scheme, U, U.u),
            Oceananigans.Advection.advective_momentum_flux_Vu(i, j, k, grid, scheme, U, U.u),
            Oceananigans.Advection.advective_momentum_flux_Uv(i, j, k, grid, scheme, U, U.v),
            Oceananigans.Advection.advective_momentum_flux_Vv(i, j, k, grid, scheme, U, U.v),
            Oceananigans.Advection.advective_momentum_flux_Uw(i, j, k, grid, scheme, U, U.w),
            Oceananigans.Advection.advective_momentum_flux_Vw(i, j, k, grid, scheme, U, U.w)
        )

        expected_fluxes = expected_nonorthogonal_fluxes(i, j, k)
        old_fluxes = expected_old_fluxes(i, j, k)

        append!(actual, actual_fluxes)
        append!(expected, (expected_fluxes.Uu, expected_fluxes.Vu, expected_fluxes.Uv,
                           expected_fluxes.Vv, expected_fluxes.Uw, expected_fluxes.Vw))
        append!(old, (old_fluxes.Uu, old_fluxes.Vu, old_fluxes.Uv,
                      old_fluxes.Vv, old_fluxes.Uw, old_fluxes.Vw))
    end

    atol = eps(FT)
    rtol = sqrt(eps(FT))

    for n in eachindex(actual)
        scale = max(abs(expected[n]), one(FT))
        @test isapprox(actual[n], expected[n]; atol = atol * scale, rtol)
    end

    magnitude_scale = maximum(vcat(abs.(actual), [one(FT)]))
    @test maximum(abs.(actual .- old)) > convert(FT, 100) * eps(FT) * magnitude_scale

    return nothing
end

function test_octahealpix_upwind_flux_form_momentum_fluxes_use_nonorthogonal_transport(FT, N)
    grid = SphericalShellGrid(size = (2N, 2N, 2),
                              halo = (5, 5, 3),
                              z = (-one(FT), zero(FT)),
                              radius = one(FT),
                              topology = (Connected, Connected, Bounded),
                              mapping = OctaHEALPixMapping(N))

    model = NonhydrostaticModel(grid)

    uᵢ(λ, φ, z) = convert(FT, 11//50) * cosd(φ) * sind(λ) + convert(FT, 1//30) * z
    vᵢ(λ, φ, z) = convert(FT, 9//50) * sind(φ) * cosd(λ) - convert(FT, 1//35) * z
    wᵢ(λ, φ, z) = convert(FT, 1//12) * sind(λ) * (one(FT) + z)

    set!(model, u = uᵢ, v = vᵢ, w = wᵢ)

    U = model.velocities
    scheme = WENO(FT; order = 5)

    expected_nonorthogonal_fluxes(i, j, k) = begin
        ũᶜᶜᶜ = Oceananigans.Advection._symmetric_interpolate_xᶜᵃᵃ(i, j, k, grid, scheme,
                                                                  Oceananigans.Operators.covariant_to_volume_flux_uᶠᶜᶜ,
                                                                  U.u, U.v)
        ṽᶠᶠᶜ = Oceananigans.Advection._symmetric_interpolate_xᶠᵃᵃ(i, j, k, grid, scheme,
                                                                  Oceananigans.Operators.covariant_to_volume_flux_vᶜᶠᶜ,
                                                                  U.u, U.v)
        ũᶠᶠᶜ = Oceananigans.Advection._symmetric_interpolate_yᵃᶠᵃ(i, j, k, grid, scheme,
                                                                  Oceananigans.Operators.covariant_to_volume_flux_uᶠᶜᶜ,
                                                                  U.u, U.v)
        ṽᶜᶜᶜ = Oceananigans.Advection._symmetric_interpolate_yᵃᶜᵃ(i, j, k, grid, scheme,
                                                                  Oceananigans.Operators.covariant_to_volume_flux_vᶜᶠᶜ,
                                                                  U.u, U.v)
        ũᶠᶜᶠ = Oceananigans.Advection._symmetric_interpolate_zᵃᵃᶠ(i, j, k, grid, scheme,
                                                                  Oceananigans.Operators.covariant_to_volume_flux_uᶠᶜᶜ,
                                                                  U.u, U.v)
        ṽᶜᶠᶠ = Oceananigans.Advection._symmetric_interpolate_zᵃᵃᶠ(i, j, k, grid, scheme,
                                                                  Oceananigans.Operators.covariant_to_volume_flux_vᶜᶠᶜ,
                                                                  U.u, U.v)

        return (
            Uu = ũᶜᶜᶜ * Oceananigans.Advection._biased_interpolate_xᶜᵃᵃ(i, j, k, grid, scheme, Oceananigans.Advection.bias(ũᶜᶜᶜ), U.u),
            Vu = ṽᶠᶠᶜ * Oceananigans.Advection._biased_interpolate_yᵃᶠᵃ(i, j, k, grid, scheme, Oceananigans.Advection.bias(ṽᶠᶠᶜ), U.u),
            Uv = ũᶠᶠᶜ * Oceananigans.Advection._biased_interpolate_xᶠᵃᵃ(i, j, k, grid, scheme, Oceananigans.Advection.bias(ũᶠᶠᶜ), U.v),
            Vv = ṽᶜᶜᶜ * Oceananigans.Advection._biased_interpolate_yᵃᶜᵃ(i, j, k, grid, scheme, Oceananigans.Advection.bias(ṽᶜᶜᶜ), U.v),
            Uw = ũᶠᶜᶠ * Oceananigans.Advection._biased_interpolate_xᶠᵃᵃ(i, j, k, grid, scheme, Oceananigans.Advection.bias(ũᶠᶜᶠ), U.w),
            Vw = ṽᶜᶠᶠ * Oceananigans.Advection._biased_interpolate_yᵃᶠᵃ(i, j, k, grid, scheme, Oceananigans.Advection.bias(ṽᶜᶠᶠ), U.w)
        )
    end

    expected_old_fluxes(i, j, k) = begin
        ũᶜᶜᶜ = Oceananigans.Advection._symmetric_interpolate_xᶜᵃᵃ(i, j, k, grid, scheme, Oceananigans.Operators.Ax_qᶠᶜᶜ, U.u)
        ṽᶠᶠᶜ = Oceananigans.Advection._symmetric_interpolate_xᶠᵃᵃ(i, j, k, grid, scheme, Oceananigans.Operators.Ay_qᶜᶠᶜ, U.v)
        ũᶠᶠᶜ = Oceananigans.Advection._symmetric_interpolate_yᵃᶠᵃ(i, j, k, grid, scheme, Oceananigans.Operators.Ax_qᶠᶜᶜ, U.u)
        ṽᶜᶜᶜ = Oceananigans.Advection._symmetric_interpolate_yᵃᶜᵃ(i, j, k, grid, scheme, Oceananigans.Operators.Ay_qᶜᶠᶜ, U.v)
        ũᶠᶜᶠ = Oceananigans.Advection._symmetric_interpolate_zᵃᵃᶠ(i, j, k, grid, scheme, Oceananigans.Operators.Ax_qᶠᶜᶜ, U.u)
        ṽᶜᶠᶠ = Oceananigans.Advection._symmetric_interpolate_zᵃᵃᶠ(i, j, k, grid, scheme, Oceananigans.Operators.Ay_qᶜᶠᶜ, U.v)

        return (
            Uu = ũᶜᶜᶜ * Oceananigans.Advection._biased_interpolate_xᶜᵃᵃ(i, j, k, grid, scheme, Oceananigans.Advection.bias(ũᶜᶜᶜ), U.u),
            Vu = ṽᶠᶠᶜ * Oceananigans.Advection._biased_interpolate_yᵃᶠᵃ(i, j, k, grid, scheme, Oceananigans.Advection.bias(ṽᶠᶠᶜ), U.u),
            Uv = ũᶠᶠᶜ * Oceananigans.Advection._biased_interpolate_xᶠᵃᵃ(i, j, k, grid, scheme, Oceananigans.Advection.bias(ũᶠᶠᶜ), U.v),
            Vv = ṽᶜᶜᶜ * Oceananigans.Advection._biased_interpolate_yᵃᶜᵃ(i, j, k, grid, scheme, Oceananigans.Advection.bias(ṽᶜᶜᶜ), U.v),
            Uw = ũᶠᶜᶠ * Oceananigans.Advection._biased_interpolate_xᶠᵃᵃ(i, j, k, grid, scheme, Oceananigans.Advection.bias(ũᶠᶜᶠ), U.w),
            Vw = ṽᶜᶠᶠ * Oceananigans.Advection._biased_interpolate_yᵃᶠᵃ(i, j, k, grid, scheme, Oceananigans.Advection.bias(ṽᶜᶠᶠ), U.w)
        )
    end

    samples = ((1, N, 1), (N, 2N, 2), (N + 1, N + 1, 1), (2N, N + 1, 2))

    actual = FT[]
    expected = FT[]
    old = FT[]

    for (i, j, k) in samples
        actual_fluxes = (
            Oceananigans.Advection.advective_momentum_flux_Uu(i, j, k, grid, scheme, U, U.u),
            Oceananigans.Advection.advective_momentum_flux_Vu(i, j, k, grid, scheme, U, U.u),
            Oceananigans.Advection.advective_momentum_flux_Uv(i, j, k, grid, scheme, U, U.v),
            Oceananigans.Advection.advective_momentum_flux_Vv(i, j, k, grid, scheme, U, U.v),
            Oceananigans.Advection.advective_momentum_flux_Uw(i, j, k, grid, scheme, U, U.w),
            Oceananigans.Advection.advective_momentum_flux_Vw(i, j, k, grid, scheme, U, U.w)
        )

        expected_fluxes = expected_nonorthogonal_fluxes(i, j, k)
        old_fluxes = expected_old_fluxes(i, j, k)

        append!(actual, actual_fluxes)
        append!(expected, (expected_fluxes.Uu, expected_fluxes.Vu, expected_fluxes.Uv,
                           expected_fluxes.Vv, expected_fluxes.Uw, expected_fluxes.Vw))
        append!(old, (old_fluxes.Uu, old_fluxes.Vu, old_fluxes.Uv,
                      old_fluxes.Vv, old_fluxes.Uw, old_fluxes.Vw))
    end

    atol = eps(FT)
    rtol = sqrt(eps(FT))

    for n in eachindex(actual)
        scale = max(abs(expected[n]), one(FT))
        @test isapprox(actual[n], expected[n]; atol = atol * scale, rtol)
    end

    magnitude_scale = maximum(vcat(abs.(actual), [one(FT)]))
    @test maximum(abs.(actual .- old)) > convert(FT, 100) * eps(FT) * magnitude_scale

    return nothing
end

function test_octahealpix_direct_momentum_flux_operators_accept_tuple_velocity_state(FT, N)
    grid = SphericalShellGrid(size = (2N, 2N, 2),
                              halo = (5, 5, 3),
                              z = (-one(FT), zero(FT)),
                              radius = one(FT),
                              topology = (Connected, Connected, Bounded),
                              mapping = OctaHEALPixMapping(N))

    model = NonhydrostaticModel(grid)

    set!(model,
         u = (λ, φ, z) -> convert(FT, 11//50) * cosd(φ) * sind(λ) + convert(FT, 1//30) * z,
         v = (λ, φ, z) -> convert(FT, 9//50) * sind(φ) * cosd(λ) - convert(FT, 1//35) * z,
         w = (λ, φ, z) -> convert(FT, 1//12) * sind(λ) * (one(FT) + z))

    U = model.velocities
    U_tuple = (U.u, U.v, U.w)
    samples = ((1, N, 1), (N, 2N, 2), (N + 1, N + 1, 1), (2N, N + 1, 2))

    for scheme in (Centered(FT), WENO(FT; order = 5))
        for (i, j, k) in samples
            named_fluxes = (
                Oceananigans.Advection.advective_momentum_flux_Uu(i, j, k, grid, scheme, U, U.u),
                Oceananigans.Advection.advective_momentum_flux_Vu(i, j, k, grid, scheme, U, U.u),
                Oceananigans.Advection.advective_momentum_flux_Uv(i, j, k, grid, scheme, U, U.v),
                Oceananigans.Advection.advective_momentum_flux_Vv(i, j, k, grid, scheme, U, U.v),
                Oceananigans.Advection.advective_momentum_flux_Uw(i, j, k, grid, scheme, U, U.w),
                Oceananigans.Advection.advective_momentum_flux_Vw(i, j, k, grid, scheme, U, U.w)
            )

            tuple_fluxes = (
                Oceananigans.Advection.advective_momentum_flux_Uu(i, j, k, grid, scheme, U_tuple, U_tuple[1]),
                Oceananigans.Advection.advective_momentum_flux_Vu(i, j, k, grid, scheme, U_tuple, U_tuple[1]),
                Oceananigans.Advection.advective_momentum_flux_Uv(i, j, k, grid, scheme, U_tuple, U_tuple[2]),
                Oceananigans.Advection.advective_momentum_flux_Vv(i, j, k, grid, scheme, U_tuple, U_tuple[2]),
                Oceananigans.Advection.advective_momentum_flux_Uw(i, j, k, grid, scheme, U_tuple, U_tuple[3]),
                Oceananigans.Advection.advective_momentum_flux_Vw(i, j, k, grid, scheme, U_tuple, U_tuple[3])
            )

            for n in eachindex(named_fluxes)
                scale = max(abs(named_fluxes[n]), one(FT))
                @test isapprox(tuple_fluxes[n], named_fluxes[n]; atol = 1000eps(FT) * scale, rtol = zero(FT))
            end
        end
    end

    return nothing
end

function test_octahealpix_vector_invariant_direct_operators_accept_tuple_velocity_state(FT, N)
    grid = SphericalShellGrid(size = (2N, 2N, 2),
                              halo = (5, 5, 3),
                              z = (-one(FT), zero(FT)),
                              radius = one(FT),
                              topology = (Connected, Connected, Bounded),
                              mapping = OctaHEALPixMapping(N))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = nothing,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing)

    set!(model,
         u = (λ, φ, z) -> convert(FT, 11//50) * cosd(φ) * sind(λ) + convert(FT, 1//30) * z,
         v = (λ, φ, z) -> convert(FT, 9//50) * sind(φ) * cosd(λ) - convert(FT, 1//35) * z,
         w = (λ, φ, z) -> convert(FT, 1//12) * sind(λ) * (one(FT) + z))

    U = model.velocities
    U_tuple = (U.u, U.v, U.w)
    samples = ((1, N, 1), (N, 2N, 2), (N + 1, N + 1, 1), (2N, N + 1, 2))

    schemes = (
        VectorInvariant(FT),
        WENOVectorInvariant(FT; order = 5,
                            upwinding = OnlySelfUpwinding(cross_scheme = Centered(FT)))
    )

    for scheme in schemes
        for (i, j, k) in samples
            named_Gu = Oceananigans.Advection.U_dot_∇u(i, j, k, grid, scheme, U)
            named_Gv = Oceananigans.Advection.U_dot_∇v(i, j, k, grid, scheme, U)
            tuple_Gu = Oceananigans.Advection.U_dot_∇u(i, j, k, grid, scheme, U_tuple)
            tuple_Gv = Oceananigans.Advection.U_dot_∇v(i, j, k, grid, scheme, U_tuple)

            u_scale = max(abs(named_Gu), one(FT))
            v_scale = max(abs(named_Gv), one(FT))

            @test isapprox(tuple_Gu, named_Gu; atol = 1000eps(FT) * u_scale, rtol = zero(FT))
            @test isapprox(tuple_Gv, named_Gv; atol = 1000eps(FT) * v_scale, rtol = zero(FT))
        end
    end

    return nothing
end

