function test_octahealpix_flux_form_momentum_transport_accepts_tuple_velocity_state(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = NonhydrostaticModel(grid;
                                tracers = (),
                                buoyancy = nothing,
                                free_surface = nothing,
                                momentum_advection = Centered())

    set!(model.velocities.u, (λ, φ, z) -> convert(FT, 0.11) * sind(λ) +
                                       convert(FT, 0.03) * cosd(φ) +
                                       convert(FT, 0.02) * z)
    set!(model.velocities.v, (λ, φ, z) -> -convert(FT, 0.07) * cosd(λ) +
                                        convert(FT, 0.05) * sind(φ) -
                                        convert(FT, 0.01) * z)
    set!(model.velocities.w, (λ, φ, z) -> convert(FT, 0.04) * sind(λ) * cosd(φ) * z)
    fill_halo_regions!(model.velocities)

    named_state = model.velocities
    tuple_state = (model.velocities.u, model.velocities.v, model.velocities.w)

    samples = ((1, div(grid.Ny, 3), 1),
               (grid.Nx + 1, div(grid.Ny, 2), 2),
               (div(grid.Nx, 2), 1, 1),
               (div(2 * grid.Nx, 3), grid.Ny + 1, 2))

    for (i, j, k) in samples
        named_div_u = Oceananigans.Advection.div_𝐯u(i, j, k, grid, Centered(), named_state, model.velocities.u)
        tuple_div_u = Oceananigans.Advection.div_𝐯u(i, j, k, grid, Centered(), tuple_state, model.velocities.u)

        named_div_v = Oceananigans.Advection.div_𝐯v(i, j, k, grid, Centered(), named_state, model.velocities.v)
        tuple_div_v = Oceananigans.Advection.div_𝐯v(i, j, k, grid, Centered(), tuple_state, model.velocities.v)

        named_div_w = Oceananigans.Advection.div_𝐯w(i, j, k, grid, Centered(), named_state, model.velocities.w)
        tuple_div_w = Oceananigans.Advection.div_𝐯w(i, j, k, grid, Centered(), tuple_state, model.velocities.w)

        u_scale = max(one(FT), abs(named_div_u), abs(tuple_div_u))
        v_scale = max(one(FT), abs(named_div_v), abs(tuple_div_v))
        w_scale = max(one(FT), abs(named_div_w), abs(tuple_div_w))

        @test abs(named_div_u - tuple_div_u) ≤ 1000eps(FT) * u_scale
        @test abs(named_div_v - tuple_div_v) ≤ 1000eps(FT) * v_scale
        @test abs(named_div_w - tuple_div_w) ≤ 1000eps(FT) * w_scale
    end

    return nothing
end

function test_octahealpix_nonorthogonal_tracer_transport_accepts_tuple_velocity_state(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = NonhydrostaticModel(grid;
                                tracers = :c,
                                buoyancy = nothing,
                                free_surface = nothing,
                                momentum_advection = nothing,
                                tracer_advection = Centered())

    set!(model.velocities.u, (λ, φ, z) -> convert(FT, 0.11) * sind(λ) +
                                       convert(FT, 0.03) * cosd(φ) +
                                       convert(FT, 0.02) * z)
    set!(model.velocities.v, (λ, φ, z) -> -convert(FT, 0.07) * cosd(λ) +
                                        convert(FT, 0.05) * sind(φ) -
                                        convert(FT, 0.01) * z)
    set!(model.velocities.w, (λ, φ, z) -> convert(FT, 0.04) * sind(λ) * cosd(φ) * z)
    set!(model.tracers.c, (λ, φ, z) -> convert(FT, 0.21) * sind(λ) +
                                    convert(FT, 0.08) * cosd(φ) +
                                    convert(FT, 0.03) * z)

    fill_halo_regions!(model.velocities)
    fill_halo_regions!(model.tracers.c)

    named_state = model.velocities
    tuple_state = (model.velocities.u, model.velocities.v, model.velocities.w)

    samples = ((1, div(grid.Ny, 3), 1),
               (grid.Nx + 1, div(grid.Ny, 2), 2),
               (div(grid.Nx, 2), 1, 1),
               (div(2 * grid.Nx, 3), grid.Ny + 1, 2))

    for (i, j, k) in samples
        named_div_c = Oceananigans.Advection.div_Uc(i, j, k, grid, Centered(), named_state, model.tracers.c)
        tuple_div_c = Oceananigans.Advection.div_Uc(i, j, k, grid, Centered(), tuple_state, model.tracers.c)

        scale = max(one(FT), abs(named_div_c), abs(tuple_div_c))
        @test abs(named_div_c - tuple_div_c) ≤ 1000eps(FT) * scale
    end

    return nothing
end

function test_octahealpix_direct_tracer_flux_operators_use_nonorthogonal_transport(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = NonhydrostaticModel(grid;
                                tracers = :c,
                                buoyancy = nothing,
                                free_surface = nothing,
                                momentum_advection = nothing,
                                tracer_advection = Centered(FT))

    set!(model.velocities.u, (λ, φ, z) -> convert(FT, 0.11) * sind(λ) +
                                       convert(FT, 0.03) * cosd(φ) +
                                       convert(FT, 0.02) * z)
    set!(model.velocities.v, (λ, φ, z) -> -convert(FT, 0.07) * cosd(λ) +
                                        convert(FT, 0.05) * sind(φ) -
                                        convert(FT, 0.01) * z)
    set!(model.tracers.c, (λ, φ, z) -> convert(FT, 0.21) * sind(λ) +
                                    convert(FT, 0.08) * cosd(φ) +
                                    convert(FT, 0.03) * z)

    fill_halo_regions!(model.velocities)
    fill_halo_regions!(model.tracers.c)

    converted_transport = (u = OctaHEALPixConvertedTransportU(grid, model.velocities.u, model.velocities.v),
                           v = OctaHEALPixConvertedTransportV(grid, model.velocities.u, model.velocities.v))
    tuple_transport = (converted_transport.u, converted_transport.v)
    tracer = model.tracers.c

    centered = Centered(FT)
    upwind = UpwindBiased(FT; order = 1)

    naive_centered_flux_x(i, j, k) =
        Oceananigans.Operators.Ax_qᶠᶜᶜ(i, j, k, grid, converted_transport.u) *
        Oceananigans.Advection._symmetric_interpolate_xᶠᵃᵃ(i, j, k, grid, centered, tracer)

    naive_centered_flux_y(i, j, k) =
        Oceananigans.Operators.Ay_qᶜᶠᶜ(i, j, k, grid, converted_transport.v) *
        Oceananigans.Advection._symmetric_interpolate_yᵃᶠᵃ(i, j, k, grid, centered, tracer)

    naive_upwind_flux_x(i, j, k) = begin
        ũ = converted_transport.u[i, j, k]
        cᴿ = Oceananigans.Advection._biased_interpolate_xᶠᵃᵃ(i, j, k, grid, upwind, Oceananigans.Advection.bias(ũ), tracer)
        return Oceananigans.Operators.Axᶠᶜᶜ(i, j, k, grid) * ũ * cᴿ
    end

    naive_upwind_flux_y(i, j, k) = begin
        ṽ = converted_transport.v[i, j, k]
        cᴿ = Oceananigans.Advection._biased_interpolate_yᵃᶠᵃ(i, j, k, grid, upwind, Oceananigans.Advection.bias(ṽ), tracer)
        return Oceananigans.Operators.Ayᶜᶠᶜ(i, j, k, grid) * ṽ * cᴿ
    end

    samples = ((1, div(grid.Ny, 3), 1),
               (grid.Nx + 1, div(grid.Ny, 2), 2),
               (div(grid.Nx, 2), 1, 1),
               (div(2 * grid.Nx, 3), grid.Ny + 1, 2))

    actual = FT[]
    wrapper_actual = FT[]
    expected = FT[]
    tuple_actual = FT[]
    scalar_actual = FT[]
    naive = FT[]

    for scheme in (centered, upwind)
        for (i, j, k) in samples
            push!(actual, Oceananigans.Advection.advective_tracer_flux_x(i, j, k, grid, scheme, converted_transport, tracer))
            push!(actual, Oceananigans.Advection.advective_tracer_flux_y(i, j, k, grid, scheme, converted_transport, tracer))

            push!(tuple_actual, Oceananigans.Advection.advective_tracer_flux_x(i, j, k, grid, scheme, tuple_transport, tracer))
            push!(tuple_actual, Oceananigans.Advection.advective_tracer_flux_y(i, j, k, grid, scheme, tuple_transport, tracer))

            push!(scalar_actual, Oceananigans.Advection.advective_tracer_flux_x(i, j, k, grid, scheme, converted_transport.u, tracer))
            push!(scalar_actual, Oceananigans.Advection.advective_tracer_flux_y(i, j, k, grid, scheme, converted_transport.v, tracer))

            push!(wrapper_actual, Oceananigans.Advection._nonorthogonal_advective_tracer_flux_x(i, j, k, grid, scheme, converted_transport, tracer))
            push!(wrapper_actual, Oceananigans.Advection._nonorthogonal_advective_tracer_flux_y(i, j, k, grid, scheme, converted_transport, tracer))

            if scheme === centered
                push!(expected, converted_transport.u[i, j, k] *
                                Oceananigans.Advection._symmetric_interpolate_xᶠᵃᵃ(i, j, k, grid, centered, tracer))
                push!(expected, converted_transport.v[i, j, k] *
                                Oceananigans.Advection._symmetric_interpolate_yᵃᶠᵃ(i, j, k, grid, centered, tracer))
                push!(naive, naive_centered_flux_x(i, j, k))
                push!(naive, naive_centered_flux_y(i, j, k))
            else
                push!(expected, begin
                    ũ = converted_transport.u[i, j, k]
                    cᴿ = Oceananigans.Advection._biased_interpolate_xᶠᵃᵃ(i, j, k, grid, upwind, Oceananigans.Advection.bias(ũ), tracer)
                    ũ * cᴿ
                end)
                push!(expected, begin
                    ṽ = converted_transport.v[i, j, k]
                    cᴿ = Oceananigans.Advection._biased_interpolate_yᵃᶠᵃ(i, j, k, grid, upwind, Oceananigans.Advection.bias(ṽ), tracer)
                    ṽ * cᴿ
                end)
                push!(naive, naive_upwind_flux_x(i, j, k))
                push!(naive, naive_upwind_flux_y(i, j, k))
            end
        end
    end

    atol = eps(FT)
    rtol = sqrt(eps(FT))

    for n in eachindex(actual)
        scale = max(abs(expected[n]), one(FT))
        @test isapprox(actual[n], expected[n]; atol = atol * scale, rtol)
        @test isapprox(wrapper_actual[n], expected[n]; atol = atol * scale, rtol)
        @test isapprox(tuple_actual[n], expected[n]; atol = atol * scale, rtol)
        @test isapprox(scalar_actual[n], expected[n]; atol = atol * scale, rtol)
    end

    magnitude_scale = maximum(vcat(abs.(actual), [one(FT)]))
    max_naive_difference = maximum(abs.(actual .- naive))

    @test max_naive_difference > convert(FT, 100) * eps(FT) * magnitude_scale

    return nothing
end

function test_octahealpix_bounds_preserving_nonorthogonal_tracer_transport_accepts_tuple_velocity_state(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    scheme = WENO(FT; order = 1, bounds = (zero(FT), one(FT)))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = scheme)

    set!(model.velocities.u, (λ, φ, z) -> convert(FT, 0.11) * sind(λ) +
                                       convert(FT, 0.03) * cosd(φ) +
                                       convert(FT, 0.02) * z)
    set!(model.velocities.v, (λ, φ, z) -> -convert(FT, 0.07) * cosd(λ) +
                                        convert(FT, 0.05) * sind(φ) -
                                        convert(FT, 0.01) * z)
    set!(model.transport_velocities.w, (λ, φ, z) -> convert(FT, 0.04) * sind(λ) * cosd(φ) * z)
    set!(model.tracers.c, (λ, φ, z) -> convert(FT, 0.35) +
                                    convert(FT, 0.2) * sind(λ) * cosd(φ) +
                                    convert(FT, 0.1) * z)

    fill_halo_regions!(model.velocities)
    fill_halo_regions!(model.transport_velocities)
    fill_halo_regions!(model.tracers.c)

    named_state = (u = OctaHEALPixConvertedTransportU(grid, model.velocities.u, model.velocities.v),
                   v = OctaHEALPixConvertedTransportV(grid, model.velocities.u, model.velocities.v),
                   w = model.transport_velocities.w)
    tuple_state = (named_state.u, named_state.v, named_state.w)

    samples = ((1, div(grid.Ny, 3), 1),
               (grid.Nx + 1, div(grid.Ny, 2), 2),
               (div(grid.Nx, 2), 1, 1),
               (div(2 * grid.Nx, 3), grid.Ny + 1, 2))

    for (i, j, k) in samples
        named_div_c = Oceananigans.Advection.div_Uc(i, j, k, grid, scheme, named_state, model.tracers.c)
        tuple_div_c = Oceananigans.Advection.div_Uc(i, j, k, grid, scheme, tuple_state, model.tracers.c)

        scale = max(one(FT), abs(named_div_c), abs(tuple_div_c))
        @test abs(named_div_c - tuple_div_c) ≤ 1000eps(FT) * scale
    end

    return nothing
end

function test_octahealpix_bounds_preserving_direct_tracer_flux_operators_accept_transport_state_forms(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    scheme = WENO(FT; order = 1, bounds = (zero(FT), one(FT)))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :c,
                                        buoyancy = nothing,
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = scheme)

    set!(model.velocities.u, (λ, φ, z) -> convert(FT, 0.11) * sind(λ) +
                                       convert(FT, 0.03) * cosd(φ) +
                                       convert(FT, 0.02) * z)
    set!(model.velocities.v, (λ, φ, z) -> -convert(FT, 0.07) * cosd(λ) +
                                        convert(FT, 0.05) * sind(φ) -
                                        convert(FT, 0.01) * z)
    set!(model.tracers.c, (λ, φ, z) -> convert(FT, 0.35) +
                                    convert(FT, 0.2) * sind(λ) * cosd(φ) +
                                    convert(FT, 0.1) * z)

    fill_halo_regions!(model.velocities)
    fill_halo_regions!(model.tracers.c)

    converted_transport = (u = OctaHEALPixConvertedTransportU(grid, model.velocities.u, model.velocities.v),
                           v = OctaHEALPixConvertedTransportV(grid, model.velocities.u, model.velocities.v))
    tuple_transport = (converted_transport.u, converted_transport.v)
    tracer = model.tracers.c

    samples = ((1, div(grid.Ny, 3), 1),
               (grid.Nx + 1, div(grid.Ny, 2), 2),
               (div(grid.Nx, 2), 1, 1),
               (div(2 * grid.Nx, 3), grid.Ny + 1, 2))

    for (i, j, k) in samples
        named_fx = Oceananigans.Advection.advective_tracer_flux_x(i, j, k, grid, scheme, converted_transport, tracer)
        tuple_fx = Oceananigans.Advection.advective_tracer_flux_x(i, j, k, grid, scheme, tuple_transport, tracer)
        scalar_fx = Oceananigans.Advection.advective_tracer_flux_x(i, j, k, grid, scheme, converted_transport.u, tracer)

        named_fy = Oceananigans.Advection.advective_tracer_flux_y(i, j, k, grid, scheme, converted_transport, tracer)
        tuple_fy = Oceananigans.Advection.advective_tracer_flux_y(i, j, k, grid, scheme, tuple_transport, tracer)
        scalar_fy = Oceananigans.Advection.advective_tracer_flux_y(i, j, k, grid, scheme, converted_transport.v, tracer)

        fx_scale = max(one(FT), abs(named_fx), abs(tuple_fx), abs(scalar_fx))
        fy_scale = max(one(FT), abs(named_fy), abs(tuple_fy), abs(scalar_fy))

        @test abs(named_fx - tuple_fx) ≤ 1000eps(FT) * fx_scale
        @test abs(named_fx - scalar_fx) ≤ 1000eps(FT) * fx_scale
        @test abs(named_fy - tuple_fy) ≤ 1000eps(FT) * fy_scale
        @test abs(named_fy - scalar_fy) ≤ 1000eps(FT) * fy_scale
    end

    return nothing
end

