function test_octahealpix_nonhydrostatic_pressure_correction_uses_covariant_gradient(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = NonhydrostaticModel(grid;
                                tracers = (),
                                buoyancy = nothing,
                                free_surface = nothing,
                                momentum_advection = nothing)

    pressure_correction(λ, φ, z) = convert(FT, 0.12) * sind(λ) +
                                   convert(FT, 0.07) * cosd(φ) +
                                   convert(FT, 0.03) * z

    set!(model.pressures.pNHS, pressure_correction)
    fill_halo_regions!(model.pressures.pNHS)

    Oceananigans.Models.NonhydrostaticModels.make_pressure_correction!(model, one(FT))

    samples = ((1, div(grid.Ny, 4), 1),
               (grid.Nx + 1, div(grid.Ny, 4), 2),
               (div(grid.Nx, 3), 1, 1),
               (div(2 * grid.Nx, 3), grid.Ny + 1, 2))

    maximum_naive_u_difference = zero(FT)
    maximum_naive_v_difference = zero(FT)

    for (i, j, k) in samples
        expected_u = -Oceananigans.Operators.covariant_gradient_xᶠᶜᶜ(i, j, k, grid, model.pressures.pNHS)
        expected_v = -Oceananigans.Operators.covariant_gradient_yᶜᶠᶜ(i, j, k, grid, model.pressures.pNHS)

        naive_u = -Oceananigans.Operators.δxᶠᶜᶜ(i, j, k, grid, model.pressures.pNHS) *
                    Oceananigans.Operators.Δx⁻¹ᶠᶜᶜ(i, j, k, grid)
        naive_v = -Oceananigans.Operators.δyᶜᶠᶜ(i, j, k, grid, model.pressures.pNHS) *
                    Oceananigans.Operators.Δy⁻¹ᶜᶠᶜ(i, j, k, grid)

        computed_u = model.velocities.u[i, j, k]
        computed_v = model.velocities.v[i, j, k]

        u_scale = max(one(FT), abs(expected_u), abs(computed_u))
        v_scale = max(one(FT), abs(expected_v), abs(computed_v))

        @test abs(computed_u - expected_u) ≤ 1000eps(FT) * u_scale
        @test abs(computed_v - expected_v) ≤ 1000eps(FT) * v_scale

        maximum_naive_u_difference = max(maximum_naive_u_difference, abs(expected_u - naive_u))
        maximum_naive_v_difference = max(maximum_naive_v_difference, abs(expected_v - naive_v))
    end

    @test maximum_naive_u_difference > 100eps(FT)
    @test maximum_naive_v_difference > 100eps(FT)

    return nothing
end

@testset "OctaHEALPix nonhydrostatic pressure correction" begin
    for FT in (Float32, Float64)
        test_octahealpix_nonhydrostatic_pressure_correction_uses_covariant_gradient(FT, 8)
    end
end

function test_octahealpix_hydrostatic_pressure_anomaly_uses_covariant_gradient(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    model = HydrostaticFreeSurfaceModel(grid;
                                        tracers = :b,
                                        buoyancy = BuoyancyTracer(),
                                        free_surface = nothing,
                                        momentum_advection = nothing,
                                        tracer_advection = nothing)

    set!(model, b = (λ, φ, z) -> convert(FT, 0.2) * sind(λ) +
                               convert(FT, 0.1) * cosd(φ) +
                               convert(FT, 0.05) * z)

    Oceananigans.TimeSteppers.update_state!(model)
    compute_tendencies!(model, ())

    pressure = model.pressure.pHY′

    u_samples = ((1, div(grid.Ny, 4), 1),
                 (grid.Nx + 1, div(grid.Ny, 4), 2),
                 (1, div(3 * grid.Ny, 4), 1),
                 (grid.Nx + 1, div(3 * grid.Ny, 4), 2))

    v_samples = ((div(grid.Nx, 4), 1, 1),
                 (div(grid.Nx, 4), grid.Ny + 1, 2),
                 (div(3 * grid.Nx, 4), 1, 1),
                 (div(3 * grid.Nx, 4), grid.Ny + 1, 2))

    maximum_naive_u_difference = zero(FT)
    maximum_naive_v_difference = zero(FT)

    for (i, j, k) in u_samples
        expected_Gu = -Oceananigans.Operators.covariant_gradient_xᶠᶜᶜ(i, j, k, grid, pressure)
        naive_Gu = -Oceananigans.Operators.δxᶠᶜᶜ(i, j, k, grid, pressure) *
                    Oceananigans.Operators.Δx⁻¹ᶠᶜᶜ(i, j, k, grid)
        computed_Gu = model.timestepper.Gⁿ.u[i, j, k]
        tendency_scale = max(one(FT), abs(expected_Gu), abs(computed_Gu))

        @test abs(computed_Gu - expected_Gu) ≤ 1000eps(FT) * tendency_scale
        maximum_naive_u_difference = max(maximum_naive_u_difference, abs(expected_Gu - naive_Gu))
    end

    for (i, j, k) in v_samples
        expected_Gv = -Oceananigans.Operators.covariant_gradient_yᶜᶠᶜ(i, j, k, grid, pressure)
        naive_Gv = -Oceananigans.Operators.δyᶜᶠᶜ(i, j, k, grid, pressure) *
                    Oceananigans.Operators.Δy⁻¹ᶜᶠᶜ(i, j, k, grid)
        computed_Gv = model.timestepper.Gⁿ.v[i, j, k]
        tendency_scale = max(one(FT), abs(expected_Gv), abs(computed_Gv))

        @test abs(computed_Gv - expected_Gv) ≤ 1000eps(FT) * tendency_scale
        maximum_naive_v_difference = max(maximum_naive_v_difference, abs(expected_Gv - naive_Gv))
    end

    @test maximum_naive_u_difference > 100eps(FT)
    @test maximum_naive_v_difference > 100eps(FT)

    return nothing
end

@testset "OctaHEALPix hydrostatic pressure anomaly" begin
    for FT in (Float32, Float64)
        test_octahealpix_hydrostatic_pressure_anomaly_uses_covariant_gradient(FT, 8)
    end
end

function test_octahealpix_zipper_boundary_conditions_are_not_flux_bcs(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    c = CenterField(grid)
    u = XFaceField(grid)
    v = YFaceField(grid)

    Gc = CenterField(grid)
    Gu = XFaceField(grid)
    Gv = YFaceField(grid)

    @test c.boundary_conditions.west isa Oceananigans.BoundaryConditions.QZBC
    @test c.boundary_conditions.south isa Oceananigans.BoundaryConditions.QZBC
    @test u.boundary_conditions.west isa Oceananigans.BoundaryConditions.QCovZBC
    @test u.boundary_conditions.east isa Oceananigans.BoundaryConditions.QCovZBC
    @test v.boundary_conditions.south isa Oceananigans.BoundaryConditions.QCovZBC
    @test v.boundary_conditions.north isa Oceananigans.BoundaryConditions.QCovZBC

    @test Oceananigans.BoundaryConditions.compute_x_bcs!(Gc, c, CPU()) === nothing
    @test Oceananigans.BoundaryConditions.compute_y_bcs!(Gc, c, CPU()) === nothing
    @test Oceananigans.BoundaryConditions.compute_x_bcs!(Gu, u, CPU()) === nothing
    @test Oceananigans.BoundaryConditions.compute_y_bcs!(Gv, v, CPU()) === nothing

    return nothing
end

@testset "OctaHEALPix zipper boundary conditions are not flux boundary conditions" begin
    for FT in (Float32, Float64)
        test_octahealpix_zipper_boundary_conditions_are_not_flux_bcs(FT, 8)
    end
end

function test_octahealpix_extrinsic_velocity_rotation_uses_covariant_basis(FT, N)
    radius = convert(FT, 3)
    mapping = OctaHEALPixMapping(N)
    grid = SphericalShellGrid(CPU(), FT; mapping,
                              size = (2N, 2N, 2),
                              z = (zero(FT), one(FT)),
                              radius,
                              halo = (1, 1, 1))

    uₑ(λ, φ, z) = convert(FT, 0.3) * cosd(λ) + convert(FT, 0.07) * sind(φ)
    vₑ(λ, φ, z) = -convert(FT, 0.11) * sind(λ) + convert(FT, 0.05) * cosd(φ)

    function expected_intrinsic_components(i, j,
                                           LX = Oceananigans.Grids.Center(),
                                           LY = Oceananigans.Grids.Center())
        if LX isa Oceananigans.Grids.Face && LY isa Oceananigans.Grids.Center
            λ = grid.λᶠᶜᵃ[i, j]
            φ = grid.φᶠᶜᵃ[i, j]
        elseif LX isa Oceananigans.Grids.Center && LY isa Oceananigans.Grids.Face
            λ = grid.λᶜᶠᵃ[i, j]
            φ = grid.φᶜᶠᵃ[i, j]
        else
            λ = grid.λᶜᶜᵃ[i, j]
            φ = grid.φᶜᶜᵃ[i, j]
        end

        u = uₑ(λ, φ, zero(FT))
        v = vₑ(λ, φ, zero(FT))
        half = convert(FT, 1//2)

        eλ, eφ, _ = Oceananigans.Grids.spherical_shell_tangent_basis(i, j, 1, grid,
                                                                     LX,
                                                                     LY,
                                                                     Oceananigans.Grids.Center())

        x⁺ᶦ, y⁺ᶦ, z⁺ᶦ = Oceananigans.Operators.spherical_shell_reference_cartesian_node(i + 1, j,     1, grid, LX, LY, Oceananigans.Grids.Center())
        x⁻ᶦ, y⁻ᶦ, z⁻ᶦ = Oceananigans.Operators.spherical_shell_reference_cartesian_node(i - 1, j,     1, grid, LX, LY, Oceananigans.Grids.Center())
        x⁺ʲ, y⁺ʲ, z⁺ʲ = Oceananigans.Operators.spherical_shell_reference_cartesian_node(i,     j + 1, 1, grid, LX, LY, Oceananigans.Grids.Center())
        x⁻ʲ, y⁻ʲ, z⁻ʲ = Oceananigans.Operators.spherical_shell_reference_cartesian_node(i,     j - 1, 1, grid, LX, LY, Oceananigans.Grids.Center())

        a₁x = half * (x⁺ᶦ - x⁻ᶦ)
        a₁y = half * (y⁺ᶦ - y⁻ᶦ)
        a₁z = half * (z⁺ᶦ - z⁻ᶦ)

        a₂x = half * (x⁺ʲ - x⁻ʲ)
        a₂y = half * (y⁺ʲ - y⁻ʲ)
        a₂z = half * (z⁺ʲ - z⁻ʲ)

        Vx = u * eλ[1] + v * eφ[1]
        Vy = u * eλ[2] + v * eφ[2]
        Vz = u * eλ[3] + v * eφ[3]

        return a₁x * Vx + a₁y * Vy + a₁z * Vz,
               a₂x * Vx + a₂y * Vy + a₂z * Vz,
               u,
               v
    end

    center_samples = ((1, div(grid.Ny, 4), 1),
                      (div(grid.Nx, 3), div(grid.Ny, 2), 1),
                      (grid.Nx, div(3 * grid.Ny, 4), 1),
                      (div(2 * grid.Nx, 3), grid.Ny, 1))

    saw_nontrivial_u_rotation = false
    saw_nontrivial_v_rotation = false

    for (i, j, k) in center_samples
        expected_uᵢ, expected_vᵢ, naive_u, naive_v = expected_intrinsic_components(i, j)
        computed_uᵢ, computed_vᵢ = Oceananigans.Operators.intrinsic_vector(i, j, k, grid, naive_u, naive_v)

        u_scale = max(one(FT), abs(expected_uᵢ), abs(computed_uᵢ))
        v_scale = max(one(FT), abs(expected_vᵢ), abs(computed_vᵢ))

        @test abs(computed_uᵢ - expected_uᵢ) ≤ 1000eps(FT) * u_scale
        @test abs(computed_vᵢ - expected_vᵢ) ≤ 1000eps(FT) * v_scale

        saw_nontrivial_u_rotation |= abs(expected_uᵢ - naive_u) > 100eps(FT)
        saw_nontrivial_v_rotation |= abs(expected_vᵢ - naive_v) > 100eps(FT)
    end

    @test saw_nontrivial_u_rotation
    @test saw_nontrivial_v_rotation

    rotated_model = HydrostaticFreeSurfaceModel(grid;
                                                tracers = (),
                                                buoyancy = nothing,
                                                free_surface = nothing,
                                                momentum_advection = nothing,
                                                tracer_advection = nothing)

    intrinsic_model = HydrostaticFreeSurfaceModel(grid;
                                                  tracers = (),
                                                  buoyancy = nothing,
                                                  free_surface = nothing,
                                                  momentum_advection = nothing,
                                                  tracer_advection = nothing)

    set!(rotated_model; u = uₑ, v = vₑ)
    set!(intrinsic_model; u = uₑ, v = vₑ, intrinsic_velocities = true)

    xface_samples = ((1, div(grid.Ny, 4), 1),
                     (grid.Nx + 1, div(grid.Ny, 2), 1),
                     (div(grid.Nx, 3), div(grid.Ny, 2), 1),
                     (div(2 * grid.Nx, 3), grid.Ny, 1))

    yface_samples = ((div(grid.Nx, 3), 1, 1),
                     (div(2 * grid.Nx, 3), grid.Ny + 1, 1),
                     (div(grid.Nx, 2), div(grid.Ny, 3), 1),
                     (grid.Nx, div(2 * grid.Ny, 3), 1))

    for (i, j, k) in xface_samples
        expected_uᵢ, _, _, _ =
            expected_intrinsic_components(i, j, Oceananigans.Grids.Face(), Oceananigans.Grids.Center())

        rotated_u = rotated_model.velocities.u[i, j, k]
        u_scale = max(one(FT), abs(expected_uᵢ), abs(rotated_u))

        @test abs(rotated_u - expected_uᵢ) ≤ 1000eps(FT) * u_scale
    end

    for (i, j, k) in yface_samples
        _, expected_vᵢ, _, _ =
            expected_intrinsic_components(i, j, Oceananigans.Grids.Center(), Oceananigans.Grids.Face())

        rotated_v = rotated_model.velocities.v[i, j, k]
        v_scale = max(one(FT), abs(expected_vᵢ), abs(rotated_v))

        @test abs(rotated_v - expected_vᵢ) ≤ 1000eps(FT) * v_scale
    end

    face_samples = ((1, div(grid.Ny, 4), 1),
                    (grid.Nx + 1, div(grid.Ny, 2), 1),
                    (div(grid.Nx, 3), 1, 1),
                    (div(2 * grid.Nx, 3), grid.Ny + 1, 1))

    saw_rotated_u_difference = false
    saw_rotated_v_difference = false

    for (i, j, k) in face_samples
        rotated_u = rotated_model.velocities.u[i, j, k]
        intrinsic_u = intrinsic_model.velocities.u[i, j, k]
        rotated_v = rotated_model.velocities.v[i, j, k]
        intrinsic_v = intrinsic_model.velocities.v[i, j, k]

        u_scale = max(one(FT), abs(rotated_u), abs(intrinsic_u))
        v_scale = max(one(FT), abs(rotated_v), abs(intrinsic_v))

        saw_rotated_u_difference |= abs(rotated_u - intrinsic_u) > 100eps(FT) * u_scale
        saw_rotated_v_difference |= abs(rotated_v - intrinsic_v) > 100eps(FT) * v_scale
    end

    @test saw_rotated_u_difference
    @test saw_rotated_v_difference

    rotated_nonhydrostatic_model = NonhydrostaticModel(grid;
                                                       tracers = (),
                                                       buoyancy = nothing,
                                                       free_surface = nothing,
                                                       advection = nothing)

    intrinsic_nonhydrostatic_model = NonhydrostaticModel(grid;
                                                         tracers = (),
                                                         buoyancy = nothing,
                                                         free_surface = nothing,
                                                         advection = nothing)

    set!(rotated_nonhydrostatic_model; u = uₑ, v = vₑ, enforce_incompressibility = false)
    set!(intrinsic_nonhydrostatic_model.velocities; u = uₑ, v = vₑ)
    compute!(intrinsic_nonhydrostatic_model.auxiliary_fields)
    fill_halo_regions!(intrinsic_nonhydrostatic_model.velocities,
                       intrinsic_nonhydrostatic_model.clock,
                       fields(intrinsic_nonhydrostatic_model))

    for (i, j, k) in xface_samples
        expected_uᵢ, _, _, _ =
            expected_intrinsic_components(i, j, Oceananigans.Grids.Face(), Oceananigans.Grids.Center())

        rotated_u = rotated_nonhydrostatic_model.velocities.u[i, j, k]
        u_scale = max(one(FT), abs(expected_uᵢ), abs(rotated_u))

        @test abs(rotated_u - expected_uᵢ) ≤ 1000eps(FT) * u_scale
    end

    for (i, j, k) in yface_samples
        _, expected_vᵢ, _, _ =
            expected_intrinsic_components(i, j, Oceananigans.Grids.Center(), Oceananigans.Grids.Face())

        rotated_v = rotated_nonhydrostatic_model.velocities.v[i, j, k]
        v_scale = max(one(FT), abs(expected_vᵢ), abs(rotated_v))

        @test abs(rotated_v - expected_vᵢ) ≤ 1000eps(FT) * v_scale
    end

    saw_rotated_nonhydrostatic_u_difference = false
    saw_rotated_nonhydrostatic_v_difference = false

    for (i, j, k) in face_samples
        rotated_u = rotated_nonhydrostatic_model.velocities.u[i, j, k]
        intrinsic_u = intrinsic_nonhydrostatic_model.velocities.u[i, j, k]
        rotated_v = rotated_nonhydrostatic_model.velocities.v[i, j, k]
        intrinsic_v = intrinsic_nonhydrostatic_model.velocities.v[i, j, k]

        u_scale = max(one(FT), abs(rotated_u), abs(intrinsic_u))
        v_scale = max(one(FT), abs(rotated_v), abs(intrinsic_v))

        saw_rotated_nonhydrostatic_u_difference |= abs(rotated_u - intrinsic_u) > 100eps(FT) * u_scale
        saw_rotated_nonhydrostatic_v_difference |= abs(rotated_v - intrinsic_v) > 100eps(FT) * v_scale
    end

    @test saw_rotated_nonhydrostatic_u_difference
    @test saw_rotated_nonhydrostatic_v_difference

    rotated_shallow_water_model = ShallowWaterModel(grid;
                                                    gravitational_acceleration = one(FT),
                                                    momentum_advection = nothing,
                                                    tracer_advection = nothing,
                                                    mass_advection = nothing,
                                                    formulation = VectorInvariantFormulation())

    intrinsic_shallow_water_model = ShallowWaterModel(grid;
                                                      gravitational_acceleration = one(FT),
                                                      momentum_advection = nothing,
                                                      tracer_advection = nothing,
                                                      mass_advection = nothing,
                                                      formulation = VectorInvariantFormulation())

    set!(rotated_shallow_water_model; u = uₑ, v = vₑ)
    set!(intrinsic_shallow_water_model.solution; u = uₑ, v = vₑ)
    Oceananigans.TimeSteppers.update_state!(intrinsic_shallow_water_model)

    for (i, j, k) in xface_samples
        expected_uᵢ, _, _, _ =
            expected_intrinsic_components(i, j, Oceananigans.Grids.Face(), Oceananigans.Grids.Center())

        rotated_u = rotated_shallow_water_model.solution.u[i, j, k]
        u_scale = max(one(FT), abs(expected_uᵢ), abs(rotated_u))

        @test abs(rotated_u - expected_uᵢ) ≤ 1000eps(FT) * u_scale
    end

    for (i, j, k) in yface_samples
        _, expected_vᵢ, _, _ =
            expected_intrinsic_components(i, j, Oceananigans.Grids.Center(), Oceananigans.Grids.Face())

        rotated_v = rotated_shallow_water_model.solution.v[i, j, k]
        v_scale = max(one(FT), abs(expected_vᵢ), abs(rotated_v))

        @test abs(rotated_v - expected_vᵢ) ≤ 1000eps(FT) * v_scale
    end

    saw_rotated_shallow_water_u_difference = false
    saw_rotated_shallow_water_v_difference = false

    for (i, j, k) in face_samples
        rotated_u = rotated_shallow_water_model.solution.u[i, j, k]
        intrinsic_u = intrinsic_shallow_water_model.solution.u[i, j, k]
        rotated_v = rotated_shallow_water_model.solution.v[i, j, k]
        intrinsic_v = intrinsic_shallow_water_model.solution.v[i, j, k]

        u_scale = max(one(FT), abs(rotated_u), abs(intrinsic_u))
        v_scale = max(one(FT), abs(rotated_v), abs(intrinsic_v))

        saw_rotated_shallow_water_u_difference |= abs(rotated_u - intrinsic_u) > 100eps(FT) * u_scale
        saw_rotated_shallow_water_v_difference |= abs(rotated_v - intrinsic_v) > 100eps(FT) * v_scale
    end

    @test saw_rotated_shallow_water_u_difference
    @test saw_rotated_shallow_water_v_difference

    updated_vₑ(λ, φ, z) = vₑ(λ, φ, z) + convert(FT, 0.09) * sind(λ / 2) - convert(FT, 0.04) * z

    partial_rotated_model = HydrostaticFreeSurfaceModel(grid;
                                                        tracers = (),
                                                        buoyancy = nothing,
                                                        free_surface = nothing,
                                                        momentum_advection = nothing,
                                                        tracer_advection = nothing)

    reference_rotated_model = HydrostaticFreeSurfaceModel(grid;
                                                          tracers = (),
                                                          buoyancy = nothing,
                                                          free_surface = nothing,
                                                          momentum_advection = nothing,
                                                          tracer_advection = nothing)

    set!(partial_rotated_model; u = uₑ, v = vₑ)
    set!(partial_rotated_model; v = updated_vₑ)
    set!(reference_rotated_model; u = uₑ, v = updated_vₑ)

    for (i, j, k) in xface_samples
        partial_u = partial_rotated_model.velocities.u[i, j, k]
        reference_u = reference_rotated_model.velocities.u[i, j, k]
        u_scale = max(one(FT), abs(partial_u), abs(reference_u))

        @test abs(partial_u - reference_u) ≤ 1000eps(FT) * u_scale
    end

    for (i, j, k) in yface_samples
        partial_v = partial_rotated_model.velocities.v[i, j, k]
        reference_v = reference_rotated_model.velocities.v[i, j, k]
        v_scale = max(one(FT), abs(partial_v), abs(reference_v))

        @test abs(partial_v - reference_v) ≤ 1000eps(FT) * v_scale
    end

    return nothing
end

@testset "OctaHEALPix extrinsic velocity rotation" begin
    for FT in (Float32, Float64)
        test_octahealpix_extrinsic_velocity_rotation_uses_covariant_basis(FT, 8)
    end
end
